function buildEffectiveAdjudicationMemos(submittedMemos = [], baseMemos = adjudicationMemos) {
  const normalizedSubmittedMemos = submittedMemos.map(normalizeSubmittedAdjudicationMemo).filter(Boolean);
  return mergeByArtifactId(baseMemos, normalizedSubmittedMemos);
}

function normalizeSubmittedAdjudicationMemo(memo) {
  const { positionId, critiqueId } = itemRefFromWorkflowArtifact(memo);
  if (!memo?.id || !positionId || !critiqueId) return null;
  const critiqueRefutesInterpretations = optionalStringArray(
    firstDefined([memo.critiqueRefutesInterpretations, memo.critiqueRefutesInterpretationsConsidered, memo.refutedInterpretations]),
  );
  return {
    ...memo,
    id: memo.id,
    memoSource: "submitted_workflow_adjudication_memo",
    positionId,
    critiqueId,
    itemId: makeItemId(positionId, critiqueId),
    contestedInterpretation: firstDefined([memo.contestedInterpretation, memo.issueSummary, memo.discussionSummary]),
    plausibleInterpretations: optionalStringArray(firstDefined([memo.plausibleInterpretations, memo.plausibleInterpretationsConsidered])) ?? [],
    ...(critiqueRefutesInterpretations ? { critiqueRefutesInterpretations } : {}),
    worstPlausibleInterpretationConsidered: firstDefined([memo.worstPlausibleInterpretationConsidered, memo.worstCaseInterpretation]),
    adversarialPlausibilityWeightingDecision: firstDefined([
      memo.adversarialPlausibilityWeightingDecision,
      memo.adversarialInterpretationWeightingSummary,
      memo.plausibilityWeightingDecision,
      memo.postDiscussionResolutionStatus,
    ]),
    bottomLineDependence: Boolean(firstDefined([memo.bottomLineDependence, memo.bottomLineDependent])),
    minorityRationales: Array.isArray(memo.minorityRationales) ? memo.minorityRationales : [],
    clearlyUnsatisfactoryImprecision: Boolean(memo.clearlyUnsatisfactoryImprecision),
    obfuscatedOrMaskedFallacyRisk: Boolean(memo.obfuscatedOrMaskedFallacyRisk),
    stableJudgment: firstDefined([memo.stableJudgment, memo.postDiscussionResolutionStatus]),
    benchmarkEligibilityDecision: firstDefined([memo.benchmarkEligibilityDecision, memo.benchmarkEligibilityStatus]),
    splitDecision: memo.splitDecision,
    disagreementTaxonomy: optionalStringArray(firstDefined([memo.disagreementTaxonomy, memo.disagreementTaxonomyCodes])) ?? [],
    unresolvedDisagreementClass: firstDefined([memo.unresolvedDisagreementClass, memo.postDiscussionResolutionStatus]),
    timestamp: firstDefined([memo.timestamp, memo.createdAt, memo.submittedAt, memo.finalizedAt]),
    createdAt: firstDefined([memo.createdAt, memo.submittedAt, memo.finalizedAt]),
  };
}

function buildEffectiveVerificationRecords(submittedRecords = [], baseRecords = verificationRecords) {
  const normalizedSubmittedRecords = submittedRecords.map(normalizeSubmittedVerificationRecord).filter(Boolean);
  return mergeByArtifactId(baseRecords, normalizedSubmittedRecords);
}

const VERIFICATION_EVIDENCE_SOURCE_EXPOSURE_STATUSES = ["source_blind", "post_lock_source_visible", "source_identifiable", "not_applicable"];
const VERIFICATION_EVIDENCE_PROTECTED_CONTENT_STATUSES = ["none", "protected_content_absent", "protected_content_redacted", "protected_content_present_authorized"];
const VERIFICATION_EVIDENCE_MODEL_ASSISTANCE_STATUSES = ["none", "model_assisted_retrieval", "model_generated_summary", "model_suggested_source"];
const VERIFICATION_EVIDENCE_TYPES = [
  "external_citation",
  "immutable_snapshot",
  "internal_expert_note",
  "supplied_item_text",
  "model_assisted_material",
  "no_external_material_required",
];
const VERIFICATION_EVIDENCE_BLINDING_IMPACT_STATUSES = [
  "source_blind_release_safe",
  "post_lock_nonblind_evidence",
  "source_assisted_review_required",
  "protected_content_quarantined",
];
const VERIFICATION_EVIDENCE_AUDIENCE_FIELDS = ["shownToOriginalRater", "shownToChecker", "shownToAdjudicator"];

function normalizeSubmittedVerificationRecord(record) {
  const { positionId, critiqueId } = itemRefFromWorkflowArtifact(record);
  if (!record?.id || !positionId || !critiqueId) return null;
  return {
    ...record,
    id: record.id,
    recordSource: "submitted_workflow_verification_record",
    positionId,
    critiqueId,
    itemId: makeItemId(positionId, critiqueId),
    relatedRatingId: firstDefined([record.relatedRatingId, record.ratingId]),
    claimChecked: firstDefined([record.claimChecked, record.claim, record.claimSummary]),
    verificationType: firstDefined([record.verificationType, record.type, "submitted_workflow"]),
    verificationMaterials: optionalStringArray(firstDefined([record.verificationMaterials, record.materials, record.evidence])) ?? [],
    verifierId: firstDefined([record.verifierId, record.adjudicatorId, record.adjudicatorIds?.[0], record.submittedBy]),
    verifierRole: firstDefined([record.verifierRole, record.adjudicatorRole, record.role]),
    verificationStatus: firstDefined([record.verificationStatus, record.status, "unresolved"]),
    verificationResult: firstDefined([record.verificationResult, record.resultSummary, record.note, "Submitted workflow verification record attached."]),
    confidence: record.confidence,
    exposureStatus: firstDefined([record.exposureStatus, record.exposurePolicy, "post_initial_lock_adjudication"]),
    evidenceArtifactIds: optionalStringArray(record.evidenceArtifactIds) ?? [],
    timestamp: firstDefined([record.timestamp, record.createdAt, record.submittedAt, record.finalizedAt]),
    createdAt: firstDefined([record.createdAt, record.submittedAt, record.finalizedAt]),
  };
}

function buildEffectiveVerificationEvidenceArtifacts(submittedArtifacts = [], records = verificationRecords) {
  const seedArtifacts = records.flatMap((record) => defaultVerificationEvidenceArtifactsForRecord(record));
  const normalizedSubmittedArtifacts = submittedArtifacts.map((artifact) => normalizeSubmittedVerificationEvidenceArtifact(artifact)).filter(Boolean);
  return mergeByArtifactId(seedArtifacts, normalizedSubmittedArtifacts);
}

function defaultVerificationEvidenceArtifactsForRecord(record) {
  const materials = optionalStringArray(record.verificationMaterials) ?? [];
  return materials.map((material, index) =>
    normalizeSubmittedVerificationEvidenceArtifact({
      id: `verification-evidence-${record.id}-${index + 1}`,
      verificationRecordId: record.id,
      itemId: makeItemId(record.positionId, record.critiqueId),
      claimRef: record.claimChecked ?? record.claim ?? record.id,
      evidenceType: record.verificationStatus === "not_needed" ? "no_external_material_required" : "internal_expert_note",
      citation: material,
      snapshotContentHash: `sha256:verification-evidence-${record.id}-${index + 1}`,
      retrievedAt: record.createdAt ?? record.timestamp ?? "2026-10-01T00:00:00.000Z",
      sourceExposureStatus: String(record.exposureStatus ?? "").includes("post_initial_lock") ? "post_lock_source_visible" : "source_blind",
      protectedContentExposureStatus: "protected_content_absent",
      modelAssistanceStatus: "none",
      nonblindEvidenceFlag: String(record.exposureStatus ?? "").includes("post_initial_lock"),
      sourceAssistedFlag: false,
      sourceIdentifiabilityFlag: false,
      protectedContentFlag: false,
      shownToOriginalRater: false,
      shownToChecker: true,
      shownToAdjudicator: String(record.exposureStatus ?? "").includes("adjudication"),
      blindingImpactStatus: String(record.exposureStatus ?? "").includes("post_initial_lock") ? "post_lock_nonblind_evidence" : "source_blind_release_safe",
      evidenceUsePolicy: "post-lock correctness evidence only; not visible before blind initial rating and not a direct score override",
      createdBy: record.verifierId ?? "seed-verifier",
      createdAt: record.createdAt ?? record.timestamp ?? "2026-10-01T00:00:00.000Z",
    }, "seed_verification_evidence_artifact"),
  );
}

function normalizeSubmittedVerificationEvidenceArtifact(artifact, rowSource = "submitted_workflow_verification_evidence_artifact") {
  const { positionId, critiqueId } = itemRefFromWorkflowArtifact(artifact);
  if (!artifact?.id || !positionId || !critiqueId) return null;
  const sourceExposureStatus = artifact.sourceExposureStatus ?? artifact.sourceIdentifiabilityExposureStatus ?? null;
  const protectedContentExposureStatus = artifact.protectedContentExposureStatus ?? artifact.protectedContentStatus ?? null;
  const modelAssistanceStatus = artifact.modelAssistanceStatus ?? artifact.modelAssistedStatus ?? null;
  const blindingImpactStatus = artifact.blindingImpactStatus ?? artifact.blindingStatus ?? null;
  const evidenceType = artifact.evidenceType ?? artifact.type ?? null;
  const citation = firstDefined([artifact.citation, artifact.sourceCitation, artifact.evidenceCitation, artifact.url]);
  const snapshotContentHash = firstDefined([artifact.snapshotContentHash, artifact.snapshotHash, artifact.sourceSnapshotHash]);
  const nonblindEvidenceFlag = artifact.nonblindEvidenceFlag === true;
  const sourceAssistedFlag = artifact.sourceAssistedFlag === true;
  const sourceIdentifiabilityFlag = artifact.sourceIdentifiabilityFlag === true;
  const protectedContentFlag = artifact.protectedContentFlag === true;
  const audienceReviewReasons = VERIFICATION_EVIDENCE_AUDIENCE_FIELDS
    .map((field) => (typeof artifact[field] === "boolean" ? null : field))
    .filter(Boolean);
  const reviewReasons = [
    requiredPromptFieldReason("claimRef", artifact.claimRef ?? artifact.claimChecked ?? artifact.claimId),
    VERIFICATION_EVIDENCE_TYPES.includes(evidenceType) ? null : "evidenceType",
    requiredPromptFieldReason("citation", citation),
    requiredPromptFieldReason("snapshotContentHash", snapshotContentHash),
    String(snapshotContentHash ?? "").startsWith("sha256:") ? null : "snapshotContentHash",
    requiredPromptFieldReason("retrievedAt", artifact.retrievedAt ?? artifact.retrievalTime),
    VERIFICATION_EVIDENCE_SOURCE_EXPOSURE_STATUSES.includes(sourceExposureStatus) ? null : "sourceExposureStatus",
    VERIFICATION_EVIDENCE_PROTECTED_CONTENT_STATUSES.includes(protectedContentExposureStatus) ? null : "protectedContentExposureStatus",
    VERIFICATION_EVIDENCE_MODEL_ASSISTANCE_STATUSES.includes(modelAssistanceStatus) ? null : "modelAssistanceStatus",
    typeof artifact.nonblindEvidenceFlag === "boolean" ? null : "nonblindEvidenceFlag",
    typeof artifact.sourceAssistedFlag === "boolean" ? null : "sourceAssistedFlag",
    typeof artifact.sourceIdentifiabilityFlag === "boolean" ? null : "sourceIdentifiabilityFlag",
    typeof artifact.protectedContentFlag === "boolean" ? null : "protectedContentFlag",
    ...audienceReviewReasons,
    sourceExposureStatus && !["source_blind", "not_applicable"].includes(sourceExposureStatus) && !nonblindEvidenceFlag ? "nonblindEvidenceFlag" : null,
    sourceExposureStatus === "source_identifiable" && !sourceIdentifiabilityFlag ? "sourceIdentifiabilityFlag" : null,
    modelAssistanceStatus && modelAssistanceStatus !== "none" && !sourceAssistedFlag ? "sourceAssistedFlag" : null,
    protectedContentExposureStatus === "protected_content_present_authorized" && !protectedContentFlag ? "protectedContentFlag" : null,
    VERIFICATION_EVIDENCE_BLINDING_IMPACT_STATUSES.includes(blindingImpactStatus) ? null : "blindingImpactStatus",
    requiredPromptFieldReason("evidenceUsePolicy", artifact.evidenceUsePolicy),
    requiredPromptFieldReason("createdBy", artifact.createdBy ?? artifact.verifierId),
    requiredPromptFieldReason("createdAt", artifact.createdAt ?? artifact.timestamp),
  ].filter(Boolean);
  return {
    ...artifact,
    id: artifact.id,
    rowSource,
    positionId,
    critiqueId,
    itemId: makeItemId(positionId, critiqueId),
    verificationRecordId: artifact.verificationRecordId ?? artifact.recordId ?? null,
    verificationWorkspaceId: artifact.verificationWorkspaceId ?? artifact.workspaceId ?? null,
    claimRef: artifact.claimRef ?? artifact.claimChecked ?? artifact.claimId ?? null,
    evidenceType,
    citation,
    snapshotArtifactId: artifact.snapshotArtifactId ?? null,
    snapshotContentHash,
    retrievedAt: artifact.retrievedAt ?? artifact.retrievalTime ?? null,
    sourceExposureStatus,
    protectedContentExposureStatus,
    modelAssistanceStatus,
    nonblindEvidenceFlag,
    sourceAssistedFlag,
    sourceIdentifiabilityFlag,
    protectedContentFlag,
    shownToOriginalRater: artifact.shownToOriginalRater === true,
    shownToChecker: artifact.shownToChecker === true,
    shownToAdjudicator: artifact.shownToAdjudicator === true,
    blindingImpactStatus,
    evidenceUsePolicy: artifact.evidenceUsePolicy ?? null,
    createdBy: artifact.createdBy ?? artifact.verifierId ?? null,
    createdAt: artifact.createdAt ?? artifact.timestamp ?? null,
    reviewReasons,
    status: reviewReasons.length ? "verification_evidence_artifact_review_required" : "verification_evidence_artifact_complete",
  };
}

function itemRefFromWorkflowArtifact(artifact) {
  if (!artifact || typeof artifact !== "object") return {};
  if (artifact.positionId && artifact.critiqueId) {
    return { positionId: artifact.positionId, critiqueId: artifact.critiqueId };
  }
  const [positionId, critiqueId] = typeof artifact.itemId === "string" ? artifact.itemId.split("::") : [];
  return { positionId, critiqueId };
}

function buildVerificationEvidenceProvenanceSummary(evidenceArtifacts = [], evidenceReviewSections = []) {
  const artifactIds = (predicate) => evidenceArtifacts.filter(predicate).map((artifact) => artifact.id);
  const completeArtifactIds = artifactIds((artifact) => artifact.reviewReasons.length === 0);
  const reviewRequiredArtifactIds = artifactIds((artifact) => artifact.reviewReasons.length > 0);
  const postLockNonblindArtifactIds = artifactIds(
    (artifact) =>
      artifact.nonblindEvidenceFlag === true ||
      (artifact.sourceExposureStatus && !["source_blind", "not_applicable"].includes(artifact.sourceExposureStatus)),
  );
  const sourceIdentifiableArtifactIds = artifactIds((artifact) => artifact.sourceExposureStatus === "source_identifiable" || artifact.sourceIdentifiabilityFlag === true);
  const sourceAssistedArtifactIds = artifactIds((artifact) => artifact.sourceAssistedFlag === true);
  const protectedContentArtifactIds = artifactIds(
    (artifact) => artifact.protectedContentFlag === true || artifact.protectedContentExposureStatus === "protected_content_present_authorized",
  );
  const modelAssistedArtifactIds = artifactIds((artifact) => artifact.modelAssistanceStatus && artifact.modelAssistanceStatus !== "none");
  const shownToOriginalRaterArtifactIds = artifactIds((artifact) => artifact.shownToOriginalRater === true);
  const shownToCheckerArtifactIds = artifactIds((artifact) => artifact.shownToChecker === true);
  const shownToAdjudicatorArtifactIds = artifactIds((artifact) => artifact.shownToAdjudicator === true);
  const totalArtifactCount = evidenceArtifacts.length;
  const releaseUseStatus =
    !totalArtifactCount
      ? "verification_evidence_provenance_not_applicable"
      : reviewRequiredArtifactIds.length || protectedContentArtifactIds.length
        ? "verification_evidence_provenance_review_required"
        : postLockNonblindArtifactIds.length || sourceIdentifiableArtifactIds.length || sourceAssistedArtifactIds.length || modelAssistedArtifactIds.length
          ? "post_lock_nonblind_verification_evidence_disclosed"
          : "source_blind_verification_evidence_ready";
  return {
    totalArtifactCount,
    completeArtifactCount: completeArtifactIds.length,
    reviewRequiredArtifactCount: reviewRequiredArtifactIds.length,
    sourceBlindEvidenceCount: evidenceArtifacts.filter((artifact) => artifact.sourceExposureStatus === "source_blind").length,
    postLockNonblindEvidenceCount: postLockNonblindArtifactIds.length,
    sourceIdentifiableEvidenceCount: sourceIdentifiableArtifactIds.length,
    sourceAssistedEvidenceCount: sourceAssistedArtifactIds.length,
    protectedContentEvidenceCount: protectedContentArtifactIds.length,
    modelAssistedEvidenceCount: modelAssistedArtifactIds.length,
    shownToOriginalRaterEvidenceCount: shownToOriginalRaterArtifactIds.length,
    shownToCheckerEvidenceCount: shownToCheckerArtifactIds.length,
    shownToAdjudicatorEvidenceCount: shownToAdjudicatorArtifactIds.length,
    byEvidenceType: countBy(evidenceArtifacts, "evidenceType"),
    bySourceExposureStatus: countBy(evidenceArtifacts, "sourceExposureStatus"),
    byProtectedContentExposureStatus: countBy(evidenceArtifacts, "protectedContentExposureStatus"),
    byModelAssistanceStatus: countBy(evidenceArtifacts, "modelAssistanceStatus"),
    byBlindingImpactStatus: countBy(evidenceArtifacts, "blindingImpactStatus"),
    completeArtifactIds,
    reviewRequiredArtifactIds,
    postLockNonblindArtifactIds,
    sourceIdentifiableArtifactIds,
    sourceAssistedArtifactIds,
    protectedContentArtifactIds,
    modelAssistedArtifactIds,
    shownToOriginalRaterArtifactIds,
    shownToCheckerArtifactIds,
    shownToAdjudicatorArtifactIds,
    reviewSections: evidenceReviewSections,
    releaseUseStatus,
  };
}

function optionalStringArray(value) {
  if (Array.isArray(value)) return value.filter((entry) => typeof entry === "string" && entry);
  if (typeof value === "string" && value) return [value];
  return undefined;
}

function mergeByArtifactId(baseItems, submittedItems) {
  const items = new Map(baseItems.map((item) => [item.id, item]));
  submittedItems.forEach((item) => {
    items.set(item.id, item);
  });
  return [...items.values()];
}

