function buildEffectiveBenchmarkExposureEvents(seedEvents = seedBenchmarkExposureEvents, exposureLogs = []) {
  return [...seedEvents, ...exposureLogs.map(normalizeSubmittedExposureLog).filter(Boolean)];
}

function normalizeSubmittedExposureLog(log) {
  if (!log?.id) return null;
  return {
    ...log,
    id: log.id,
    type: log.type ?? "workflow_exposure_log_submitted",
    exposureSource: "submitted_workflow_exposure_log",
    occurredAt: firstDefined([log.occurredAt, log.timestamp, log.createdAt, log.loggedAt]),
    actorRole: firstDefined([log.actorRole, log.userRole, log.role, "admin"]),
    action: log.action ?? "access_logged",
    artifactId: log.artifactId ?? log.artifact_id ?? null,
    purpose: log.purpose ?? "not_declared",
    allowed: log.allowed ?? true,
    accessPhase: log.accessPhase ?? log.phase ?? null,
    splitName: log.splitName ?? log.split ?? null,
  };
}

export function isValidScore(value) {
  return typeof value === "number" && Number.isFinite(value) && value >= 0 && value <= 1;
}

function requireScores(scores, fieldNames, label) {
  const missing = fieldNames.filter((name) => scores[name] === null || scores[name] === undefined);
  if (missing.length) throw new Error(`${label} missing required rating fields: ${missing.join(", ")}`);
}

function validateUnitInterval(scores, fieldNames, label) {
  const invalid = fieldNames
    .filter((name) => !isValidScore(scores[name]))
    .map((name) => `${name}=${String(scores[name])}`);
  if (invalid.length) {
    throw new Error(`${label} fields must be finite non-boolean numeric values in [0, 1]: ${invalid.join(", ")}`);
  }
}

export function customWeightedLoss(human, model) {
  requireScores(human, ["overall", "clarity"], "human");
  requireScores(model, ["overall", "clarity"], "model");
  validateUnitInterval(human, ["overall", "clarity"], "human");
  validateUnitInterval(model, ["overall", "clarity"], "model");

  if (human.clarity < 0.5) {
    return 0.5 * Math.abs(human.overall - model.overall) + 0.5 * Math.abs(human.clarity - model.clarity);
  }

  requireScores(human, FULL_RUBRIC_FIELDS, "human");
  requireScores(model, FULL_RUBRIC_FIELDS, "model");
  validateUnitInterval(human, FULL_RUBRIC_FIELDS, "human");
  validateUnitInterval(model, FULL_RUBRIC_FIELDS, "model");
  return (
    0.5 * Math.abs(human.overall - model.overall) +
    0.2 * Math.abs(human.centrality * human.strength - model.centrality * model.strength) +
    0.1 * Math.abs(human.clarity - model.clarity) +
    0.1 * Math.abs(human.correctness - model.correctness) +
    0.05 * Math.abs(human.dead_weight - model.dead_weight) +
    0.05 * Math.abs(human.single_issue - model.single_issue)
  );
}

export function validateScoreMap(scoreMap, label) {
  const invalid = Object.entries(scoreMap)
    .filter(([, value]) => !isValidScore(value))
    .map(([id, value]) => `${id}=${String(value)}`);
  if (invalid.length) throw new Error(`${label} scores must be finite non-boolean numeric values in [0, 1]: ${invalid.join(", ")}`);
}

export function isTie(diff, tieTolerance = 0) {
  if (tieTolerance < 0) throw new Error("tie_tolerance must be non-negative");
  return Math.abs(diff) <= tieTolerance;
}

function resolvePairwiseTieTolerances(tieConfig = 0) {
  const options = typeof tieConfig === "object" && tieConfig !== null ? tieConfig : { tieTolerance: tieConfig };
  const declaredTieTolerance = numberOrDefault(options.tieTolerance ?? options.pairwiseTieTolerance, 0);
  const humanTieTolerance = numberOrDefault(options.humanTieTolerance ?? options.pairwiseHumanTieTolerance, declaredTieTolerance);
  const modelTieTolerance = numberOrDefault(options.modelTieTolerance ?? options.pairwiseModelTieTolerance, declaredTieTolerance);
  if (declaredTieTolerance < 0 || humanTieTolerance < 0 || modelTieTolerance < 0) {
    throw new Error("pairwise tie tolerances must be non-negative");
  }
  return {
    tieTolerance: declaredTieTolerance,
    humanTieTolerance,
    modelTieTolerance,
  };
}

function assertSameKeys(a, b, subject) {
  const aKeys = Object.keys(a).sort();
  const bKeys = Object.keys(b).sort();
  const missingFromB = aKeys.filter((key) => !(key in b));
  const extraInB = bKeys.filter((key) => !(key in a));
  if (missingFromB.length || extraInB.length) {
    throw new Error(`${subject} sets must match: missing_from_model=${missingFromB.join(",") || "none"}, extra_in_model=${extraInB.join(",") || "none"}`);
  }
}

export function weightedPairwiseLossForPosition(humanOveralls, modelOveralls, tieConfig = 0) {
  validateScoreMap(humanOveralls, "human_overalls");
  validateScoreMap(modelOveralls, "model_overalls");
  assertSameKeys(humanOveralls, modelOveralls, "Human/model critique");
  const { humanTieTolerance, modelTieTolerance } = resolvePairwiseTieTolerances(tieConfig);
  const losses = [];
  let nHumanTiePairsExcluded = 0;
  let nModelTiePairsScored = 0;
  const ids = Object.keys(humanOveralls);
  ids.forEach((a, index) => {
    ids.slice(index + 1).forEach((b) => {
      const hdiff = humanOveralls[a] - humanOveralls[b];
      if (isTie(hdiff, humanTieTolerance)) {
        nHumanTiePairsExcluded += 1;
        return;
      }
      const humanPref = hdiff > 0 ? 1 : -1;
      const mdiff = modelOveralls[a] - modelOveralls[b];
      const weight = Math.abs(hdiff);
      if (isTie(mdiff, modelTieTolerance)) {
        nModelTiePairsScored += 1;
        losses.push(weight / 2);
      } else if ((mdiff > 0 ? 1 : -1) === humanPref) losses.push(0);
      else losses.push(weight);
    });
  });
  return { loss: losses.length ? mean(losses) : null, coverage: { nPairsScored: losses.length, nHumanTiePairsExcluded, nModelTiePairsScored } };
}

export function unweightedPairwiseLossForPosition(humanOveralls, modelOveralls, tieConfig = 0) {
  validateScoreMap(humanOveralls, "human_overalls");
  validateScoreMap(modelOveralls, "model_overalls");
  assertSameKeys(humanOveralls, modelOveralls, "Human/model critique");
  const { humanTieTolerance, modelTieTolerance } = resolvePairwiseTieTolerances(tieConfig);
  const losses = [];
  let nHumanTiePairsExcluded = 0;
  let nModelTiePairsScored = 0;
  const ids = Object.keys(humanOveralls);
  ids.forEach((a, index) => {
    ids.slice(index + 1).forEach((b) => {
      const hdiff = humanOveralls[a] - humanOveralls[b];
      if (isTie(hdiff, humanTieTolerance)) {
        nHumanTiePairsExcluded += 1;
        return;
      }
      const humanPref = hdiff > 0 ? 1 : -1;
      const mdiff = modelOveralls[a] - modelOveralls[b];
      if (isTie(mdiff, modelTieTolerance)) {
        nModelTiePairsScored += 1;
        losses.push(0.5);
      } else if ((mdiff > 0 ? 1 : -1) === humanPref) losses.push(0);
      else losses.push(1);
    });
  });
  return { loss: losses.length ? mean(losses) : null, coverage: { nPairsScored: losses.length, nHumanTiePairsExcluded, nModelTiePairsScored } };
}

export function weightedPairwiseErrorRateByPosition(human, model, tieConfig = 0) {
  return pairwiseErrorRateByPosition(human, model, weightedPairwiseLossForPosition, tieConfig);
}

export function unweightedPairwiseErrorRateByPosition(human, model, tieConfig = 0) {
  return pairwiseErrorRateByPosition(human, model, unweightedPairwiseLossForPosition, tieConfig);
}

function pairwiseErrorRateByPosition(positionToHuman, positionToModel, scorer, tieConfig) {
  assertSameKeys(positionToHuman, positionToModel, "Human/model position");
  const positionLosses = [];
  const excludedNoNonTiedPairs = [];
  const coverage = {
    nPositionsScored: 0,
    nPositionsExcludedNoNonTiedPairs: 0,
    nPairsScored: 0,
    nHumanTiePairsExcluded: 0,
    nModelTiePairsScored: 0,
  };
  Object.entries(positionToHuman).forEach(([positionId, humanOveralls]) => {
    const result = scorer(humanOveralls, positionToModel[positionId], tieConfig);
    coverage.nPairsScored += result.coverage.nPairsScored;
    coverage.nHumanTiePairsExcluded += result.coverage.nHumanTiePairsExcluded;
    coverage.nModelTiePairsScored += result.coverage.nModelTiePairsScored;
    if (result.loss === null) {
      excludedNoNonTiedPairs.push(positionId);
      coverage.nPositionsExcludedNoNonTiedPairs += 1;
    } else {
      coverage.nPositionsScored += 1;
      positionLosses.push(result.loss);
    }
  });
  return { loss: positionLosses.length ? mean(positionLosses) : null, coverage, excludedNoNonTiedPairs };
}

export function defaultFullRubricUtility(label, targetLabel) {
  const lowClarityController = targetLabel ?? label;
  requireScores(lowClarityController, ["clarity"], "low_clarity_controller");
  validateUnitInterval(lowClarityController, ["clarity"], "low_clarity_controller");
  requireScores(label, ["overall", "clarity"], "label");
  validateUnitInterval(label, ["overall", "clarity"], "label");
  if (lowClarityController.clarity < 0.5) return 0.5 * label.overall + 0.5 * label.clarity;
  requireScores(label, FULL_RUBRIC_FIELDS, "label");
  validateUnitInterval(label, FULL_RUBRIC_FIELDS, "label");
  return 0.5 * label.overall + 0.2 * label.centrality * label.strength + 0.1 * label.clarity + 0.1 * label.correctness + 0.05 * (1 - label.dead_weight) + 0.05 * label.single_issue;
}

export function derivedUtilityPairwiseErrorRateByPosition(humanRatings, modelRatings, tieConfig = 0) {
  assertSameKeys(humanRatings, modelRatings, "Human/model position");
  const humanUtilities = {};
  const modelUtilities = {};
  Object.entries(humanRatings).forEach(([positionId, ratings]) => {
    assertSameKeys(ratings, modelRatings[positionId], "Human/model critique");
    humanUtilities[positionId] = {};
    modelUtilities[positionId] = {};
    Object.entries(ratings).forEach(([critiqueId, human]) => {
      const model = modelRatings[positionId][critiqueId];
      humanUtilities[positionId][critiqueId] = defaultFullRubricUtility(human);
      modelUtilities[positionId][critiqueId] = defaultFullRubricUtility(model, human);
    });
  });
  return weightedPairwiseErrorRateByPosition(humanUtilities, modelUtilities, tieConfig);
}

export function customWeightedLossForDataset(humanRatings, modelRatings) {
  assertSameKeys(humanRatings, modelRatings, "Human/model item");
  const losses = [];
  const coverage = { nItemsScored: 0, nLowClarityBranchItems: 0, nFullRubricItems: 0 };
  Object.entries(humanRatings).forEach(([itemId, human]) => {
    losses.push(customWeightedLoss(human, modelRatings[itemId]));
    coverage.nItemsScored += 1;
    if (human.clarity < 0.5) coverage.nLowClarityBranchItems += 1;
    else coverage.nFullRubricItems += 1;
  });
  return { loss: losses.length ? mean(losses) : null, coverage };
}

export function buildPairwiseComparisonSnapshot(id, labelSnapshotId, targetLabelVersion, positionToHumanOveralls, tieTolerance = 0) {
  const options = typeof tieTolerance === "object" && tieTolerance !== null ? tieTolerance : { tieTolerance };
  const { humanTieTolerance, modelTieTolerance } = resolvePairwiseTieTolerances(options);
  const positionTextVersionIdsByPosition = options.positionTextVersionIdsByPosition ?? {};
  const critiqueTextVersionIdsByPosition = options.critiqueTextVersionIdsByPosition ?? {};
  const itemTextVersionIdsByItem = options.itemTextVersionIdsByItem ?? {};
  const nonTiedEdges = [];
  let excludedHumanTieEdges = 0;
  const excludedHumanTieEdgeRows = [];
  const excludedNoPairPositions = [];
  Object.entries(positionToHumanOveralls).forEach(([positionId, critiqueScores]) => {
    const ids = Object.keys(critiqueScores);
    let positionEdgeCount = 0;
    ids.forEach((a, index) => {
      ids.slice(index + 1).forEach((b) => {
        const margin = Math.abs(critiqueScores[a] - critiqueScores[b]);
        const textVersionRefs = pairwiseEdgeTextVersionRefs(
          positionId,
          a,
          b,
          positionTextVersionIdsByPosition,
          critiqueTextVersionIdsByPosition,
          itemTextVersionIdsByItem,
        );
        if (isTie(margin, humanTieTolerance)) {
          excludedHumanTieEdges += 1;
          excludedHumanTieEdgeRows.push({ positionId, critiqueA: a, critiqueB: b, humanMargin: margin, ...textVersionRefs });
          return;
        }
        positionEdgeCount += 1;
        nonTiedEdges.push({
          positionId,
          critiqueA: a,
          critiqueB: b,
          humanMargin: margin,
          marginBin: margin < 0.15 ? "low" : margin < 0.35 ? "medium" : "high",
          ...textVersionRefs,
        });
      });
    });
    if (positionEdgeCount === 0) excludedNoPairPositions.push(positionId);
  });
  return {
    id,
    labelSnapshotId,
    targetLabelVersion,
    targetScoreField: options.targetScoreField ?? "overall",
    humanTargetScoreSource: options.humanTargetScoreSource ?? `${labelSnapshotId}:${targetLabelVersion}:weighted_mean_overall`,
    tieTolerance: humanTieTolerance,
    humanTieTolerance,
    modelTieTolerance,
    humanTiePolicy: options.humanTiePolicy ?? options.pairwiseHumanTiePolicy ?? "exclude_human_tied_pairs_from_pairwise_loss",
    modelTiePolicy: options.modelTiePolicy ?? options.pairwiseModelTiePolicy ?? "score_model_tied_predictions_as_half_error",
    scoreRoundingPolicy: options.scoreRoundingPolicy ?? (humanTieTolerance === 0 && modelTieTolerance === 0 ? "stored_exact" : "declared_tolerance"),
    scoreQuantizationPolicy: options.scoreQuantizationPolicy ?? "unit_interval_decimal_scores_no_bucket_quantization",
    positionIds: Object.keys(positionToHumanOveralls),
    critiqueIdsByPosition: Object.fromEntries(Object.entries(positionToHumanOveralls).map(([positionId, scores]) => [positionId, Object.keys(scores)])),
    positionTextVersionIdsByPosition,
    critiqueTextVersionIdsByPosition,
    itemTextVersionIds: pairwiseSnapshotItemTextVersionIds(itemTextVersionIdsByItem, positionTextVersionIdsByPosition, critiqueTextVersionIdsByPosition),
    itemTextVersionIdsByItem,
    nonTiedEdges,
    excludedHumanTieEdges,
    excludedHumanTieEdgeRows,
    excludedNoPairPositions,
    exclusions: {
      humanTieEdgeCount: excludedHumanTieEdges,
      humanTieEdges: excludedHumanTieEdgeRows,
      noPairPositionIds: excludedNoPairPositions,
      missingTextVersionItemIds: pairwiseMissingTextVersionItemIds(positionToHumanOveralls, itemTextVersionIdsByItem),
    },
    frozenAt: new Date().toISOString(),
  };
}

function pairwiseEdgeTextVersionRefs(positionId, critiqueA, critiqueB, positionTextVersionIdsByPosition, critiqueTextVersionIdsByPosition, itemTextVersionIdsByItem) {
  const itemA = makeItemId(positionId, critiqueA);
  const itemB = makeItemId(positionId, critiqueB);
  return {
    positionTextVersionIds: positionTextVersionIdsByPosition[positionId] ?? [],
    critiqueATextVersionIds: normalizeStringArray(critiqueTextVersionIdsByPosition[positionId]?.[critiqueA]) ?? [],
    critiqueBTextVersionIds: normalizeStringArray(critiqueTextVersionIdsByPosition[positionId]?.[critiqueB]) ?? [],
    itemATextVersionIds: normalizeStringArray(itemTextVersionIdsByItem[itemA]) ?? [],
    itemBTextVersionIds: normalizeStringArray(itemTextVersionIdsByItem[itemB]) ?? [],
  };
}

function pairwiseSnapshotItemTextVersionIds(itemTextVersionIdsByItem, positionTextVersionIdsByPosition, critiqueTextVersionIdsByPosition) {
  return uniqueStrings([
    ...Object.values(itemTextVersionIdsByItem).flatMap((ids) => normalizeStringArray(ids) ?? []),
    ...Object.values(positionTextVersionIdsByPosition).flatMap((ids) => normalizeStringArray(ids) ?? []),
    ...Object.values(critiqueTextVersionIdsByPosition).flatMap((byCritique) =>
      Object.values(byCritique ?? {}).flatMap((ids) => normalizeStringArray(ids) ?? []),
    ),
  ]);
}

function pairwiseMissingTextVersionItemIds(positionToHumanOveralls, itemTextVersionIdsByItem) {
  return Object.entries(positionToHumanOveralls).flatMap(([positionId, critiqueScores]) =>
    Object.keys(critiqueScores)
      .map((critiqueId) => makeItemId(positionId, critiqueId))
      .filter((itemId) => !(normalizeStringArray(itemTextVersionIdsByItem[itemId]) ?? []).length),
  );
}

export function pairwiseMarginDistribution(snapshot) {
  const margins = snapshot.nonTiedEdges.map((edge) => edge.humanMargin).sort((a, b) => a - b);
  const totalWeight = margins.reduce((sum, margin) => sum + margin, 0);
  const lowWeight = snapshot.nonTiedEdges.filter((edge) => edge.marginBin === "low").reduce((sum, edge) => sum + edge.humanMargin, 0);
  return {
    min: margins[0] ?? null,
    median: margins.length ? percentile(margins, 0.5) : null,
    mean: margins.length ? mean(margins) : null,
    max: margins.at(-1) ?? null,
    bins: {
      low: snapshot.nonTiedEdges.filter((edge) => edge.marginBin === "low").length,
      medium: snapshot.nonTiedEdges.filter((edge) => edge.marginBin === "medium").length,
      high: snapshot.nonTiedEdges.filter((edge) => edge.marginBin === "high").length,
    },
    lowMarginPairShare: snapshot.nonTiedEdges.length ? snapshot.nonTiedEdges.filter((edge) => edge.marginBin === "low").length / snapshot.nonTiedEdges.length : 0,
    lowMarginWeightShare: totalWeight ? lowWeight / totalWeight : 0,
  };
}

export function createBlindRatingView(assignment, positionList = positions, critiqueList = critiques) {
  const position = mustFind(positionList, assignment.positionId);
  const critique = mustFind(critiqueList, assignment.critiqueId);
  return {
    assignmentId: assignment.id,
    positionText: latestText(position).text,
    critiqueText: latestText(critique).text,
    hiddenMetadata: [
      "source metadata",
      "admin tags",
      "benchmark status",
      "model-judge scores",
      "active-learning flags",
      "intake screening notes",
      "peer ratings",
      "candidate-selection reasons",
    ],
  };
}

export function appendRatingRevision(original, patch = {}) {
  if (!["blind_initial", "self_check", "expert_check"].includes(original.kind)) {
    throw new Error("Only human rating records can be revised through the revision workflow.");
  }
  return {
    ...original,
    ...patch,
    id: patch.id ?? `${original.id}-rev-${Date.now()}`,
    kind: "revision",
    parentRatingId: original.id,
    submittedAt: new Date().toISOString(),
    lockedAt: new Date().toISOString(),
  };
}

export function buildRatingRevisionAuditReport(releaseId, ratings = seedRatings, positionList = positions, options = {}) {
  const ratingById = new Map(ratings.map((rating) => [rating.id, rating]));
  const positionById = new Map(positionList.map((position) => [position.id, position]));
  const revisionRows = ratings
    .filter((rating) => rating.kind === "revision")
    .map((rating) => {
      const parent = ratingById.get(rating.parentRatingId);
      const position = positionById.get(rating.positionId);
      const hasReasonCode = typeof rating.revisionReasonCode === "string" && rating.revisionReasonCode.length > 0;
      const hasObjectLevelComment = typeof rating.revisionComment === "string" && rating.revisionComment.trim().length > 0;
      return {
        ratingId: rating.id,
        parentRatingId: rating.parentRatingId ?? null,
        itemId: makeItemId(rating.positionId, rating.critiqueId),
        split: position?.split ?? "unknown",
        raterId: rating.raterId,
        parentFound: Boolean(parent),
        parentKind: parent?.kind ?? null,
        originalPreserved: Boolean(parent) && parent.id !== rating.id && parent.kind !== "revision",
        revisionReasonCode: rating.revisionReasonCode ?? null,
        revisionComment: rating.revisionComment ?? null,
        hasReasonCode,
        hasObjectLevelComment,
        metadataStatus:
          Boolean(parent) && parent.kind !== "revision" && hasReasonCode && hasObjectLevelComment
            ? "revision_metadata_complete"
            : "revision_metadata_incomplete",
      };
    });
  const checkRows = ratings
    .filter((rating) => ["self_check", "expert_check", "model_assisted_check"].includes(rating.kind))
    .map((rating) => {
      const position = positionById.get(rating.positionId);
      return {
        ratingId: rating.id,
        itemId: makeItemId(rating.positionId, rating.critiqueId),
        split: position?.split ?? "unknown",
        kind: rating.kind,
        raterId: rating.raterId,
        checkExposure:
          rating.kind === "model_assisted_check"
            ? rating.modelAssistance?.exposureTiming ?? rating.checkExposure ?? "model_assisted_exposure_unknown"
            : rating.kind === "expert_check"
              ? "expert_check"
              : "human_only_self_check",
        modelAssisted: rating.kind === "model_assisted_check",
        postHumanOnlySelfCheckLock:
          rating.kind !== "model_assisted_check" ||
          rating.modelAssistance?.exposureTiming === "post_human_only_self_check_lock",
      };
    });
  const independentCoverageRows = ratings
    .filter((rating) => rating.kind === "blind_initial")
    .map((rating) => ({
      ratingId: rating.id,
      itemId: makeItemId(rating.positionId, rating.critiqueId),
      raterId: rating.raterId,
      kind: rating.kind,
    }));
  const denominatorInflationRows = ratings
    .filter((rating) => rating.kind !== "blind_initial")
    .map((rating) => ({
      ratingId: rating.id,
      itemId: makeItemId(rating.positionId, rating.critiqueId),
      raterId: rating.raterId,
      kind: rating.kind,
      denominatorPolicy: "excluded_from_independent_blind_initial_coverage",
    }));
  const incompleteRevisionRows = revisionRows.filter((row) => row.metadataStatus !== "revision_metadata_complete");
  const modelAssistedStagingRows = checkRows.filter((row) => row.modelAssisted && !row.postHumanOnlySelfCheckLock);
  const submittedRevisionRecordEvidence = buildSubmittedRevisionRecordEvidence(releaseId, options.revisionRecords ?? [], ratingById);
  return {
    id: `rating-revision-audit-${releaseId}`,
    releaseId,
    generatedAt: new Date().toISOString(),
    policy: {
      immutableOriginalRule:
        "Revisions append a child row with parentRatingId; the first blind, self-check, or expert-check row remains immutable and separately counted.",
      reasonMetadataRule:
        "Every revision must carry a structured revisionReasonCode and a free-text object-level revisionComment.",
      denominatorRule:
        "Blind initial ratings, revisions, self-checks, expert checks, model-assisted checks, and adjudication labels are counted separately so checks and revisions cannot inflate independent blind-rater coverage.",
      modelAssistanceRule:
        "Release-critical model-assisted checks should occur only after a locked human-only self-check where feasible and must be reported as intervention exposure.",
    },
    counts: {
      totalRatingRows: ratings.length,
      blindInitialRows: countKind(ratings, "blind_initial"),
      revisionRows: revisionRows.length,
      selfCheckRows: countKind(ratings, "self_check"),
      expertCheckRows: countKind(ratings, "expert_check"),
      modelAssistedCheckRows: countKind(ratings, "model_assisted_check"),
      adjudicationRows: countKind(ratings, "adjudication"),
      independentBlindInitialCoverageRows: independentCoverageRows.length,
      denominatorInflationExcludedRows: denominatorInflationRows.length,
      incompleteRevisionMetadataRows: incompleteRevisionRows.length,
      modelAssistedStagingViolationRows: modelAssistedStagingRows.length,
      submittedRevisionRecordCount: submittedRevisionRecordEvidence.submittedRecordCount,
      submittedRevisionRecordReviewCount: submittedRevisionRecordEvidence.reviewRows.length,
    },
    byKind: countBy(ratings, "kind"),
    revisionRows,
    checkRows,
    independentCoverageRows,
    denominatorInflationRows,
    incompleteRevisionRows,
    modelAssistedStagingRows,
    submittedRevisionRecordEvidence,
    releaseUseStatus:
      incompleteRevisionRows.length > 0 || submittedRevisionRecordEvidence.reviewRows.length > 0
        ? "revision_metadata_review_required"
        : modelAssistedStagingRows.length > 0
          ? "model_assisted_check_staging_review_required"
          : "revision_and_check_denominators_separated",
  };
}

function buildSubmittedRevisionRecordEvidence(releaseId, revisionRecords = [], ratingById = new Map()) {
  const rows = revisionRecords.map((record) => normalizeSubmittedRevisionRecord(record, ratingById)).filter(Boolean);
  const reviewRows = rows.filter((row) => row.recordStatus !== "submitted_revision_record_complete");
  return {
    id: `submitted-revision-record-evidence-${releaseId}`,
    releaseId,
    submittedRecordCount: rows.length,
    completeRecordCount: rows.filter((row) => row.recordStatus === "submitted_revision_record_complete").length,
    rows,
    reviewRows,
    policy: {
      immutableOriginalRule:
        "Submitted RevisionRecord artifacts must identify a preserved prior rating row, a distinct new rating id, a structured reason code, and an object-level revision comment.",
      denominatorRule: "Submitted RevisionRecord artifacts are provenance evidence and do not increase independent blind-initial rating denominators.",
    },
    releaseUseStatus: !rows.length
      ? "no_submitted_revision_records"
      : reviewRows.length
        ? "submitted_revision_records_require_review"
        : "submitted_revision_records_complete",
  };
}

function normalizeSubmittedRevisionRecord(record, ratingById) {
  if (!record?.id) return null;
  const priorRatingId = record.ratingIdPrior ?? record.priorRatingId ?? record.parentRatingId ?? record.ratingId;
  const newRatingId = record.ratingIdNew ?? record.newRatingId ?? record.revisionRatingId ?? record.resultingRevisionId;
  const priorRating = ratingById.get(priorRatingId);
  const reasonCode = record.reasonCode ?? record.revisionReasonCode ?? null;
  const revisionComment = record.revisionComment ?? record.comment ?? null;
  const reviewReasons = [
    priorRating ? null : "prior_rating_missing",
    priorRating && priorRating.kind === "revision" ? "prior_rating_is_revision" : null,
    newRatingId && newRatingId !== priorRatingId ? null : "distinct_new_rating_id_missing",
    reasonCode ? null : "reason_code_missing",
    typeof revisionComment === "string" && revisionComment.trim() ? null : "revision_comment_missing",
  ].filter(Boolean);
  return {
    recordId: record.id,
    recordSource: "submitted_workflow_revision_record",
    priorRatingId,
    newRatingId: newRatingId ?? null,
    priorRatingFound: Boolean(priorRating),
    priorRatingKind: priorRating?.kind ?? null,
    originalPreserved: Boolean(priorRating) && priorRating.kind !== "revision" && priorRating.id !== newRatingId,
    reasonCode,
    revisionComment,
    discussionThreadId: record.discussionThreadId ?? null,
    reviewReasons,
    recordStatus: reviewReasons.length ? "submitted_revision_record_review_required" : "submitted_revision_record_complete",
  };
}

export const RATING_ESCALATION_TRIGGER_RULES = [
  "low_clarity_single",
  "low_clarity_two_or_more",
  "overall_spread",
  "centrality_strength_product_spread",
  "correctness_spread",
  "insufficient_topic_expertise",
  "needs_verification",
  "zero_correctness_nonzero_strength",
  "nonclarity_provisional_with_clarity_gte_threshold",
  "correctness_not_assessable_with_clarity_gte_threshold",
  "materially_different_plausible_interpretations",
  "vague_good_objection_gesture",
  "clearly_unsatisfactory_imprecision",
  "background_knowledge_dispute",
];

export const RATING_ESCALATION_LOW_CLARITY_THRESHOLD = 0.5;
export const RATING_ESCALATION_LOW_CLARITY_ADJUDICATION_COUNT = 2;
export const RATING_ESCALATION_OVERALL_SPREAD_THRESHOLD = 0.35;
export const RATING_ESCALATION_PRODUCT_SPREAD_THRESHOLD = 0.3;
export const RATING_ESCALATION_CORRECTNESS_SPREAD_THRESHOLD = 0.35;
export const RATING_ESCALATION_POST_DISCUSSION_MAX_SPREAD_TARGET = 0.3;
export const DISAGREEMENT_THRESHOLD_POLICY_VERSION = "disagreement-threshold-rlhf90-v1";
export const REQUIRED_DISAGREEMENT_THRESHOLDS = {
  lowClarityThreshold: RATING_ESCALATION_LOW_CLARITY_THRESHOLD,
  lowClarityAdjudicationCount: RATING_ESCALATION_LOW_CLARITY_ADJUDICATION_COUNT,
  initialOverallSpreadThreshold: RATING_ESCALATION_OVERALL_SPREAD_THRESHOLD,
  centralityStrengthProductSpreadThreshold: RATING_ESCALATION_PRODUCT_SPREAD_THRESHOLD,
  correctnessSpreadThreshold: RATING_ESCALATION_CORRECTNESS_SPREAD_THRESHOLD,
  postDiscussionMaxSpreadTarget: RATING_ESCALATION_POST_DISCUSSION_MAX_SPREAD_TARGET,
  highSpreadResidualClassificationThreshold: RATING_ESCALATION_POST_DISCUSSION_MAX_SPREAD_TARGET,
  thinOverlapFinalRaterCountMin: 2,
};
export const REQUIRED_DISAGREEMENT_ESCALATION_RULES = {
  lowClarity: "clarity_below_0_50_routes_to_low_clarity_review_and_two_or_more_routes_to_adjudication",
  initialOverallSpread: "initial_overall_spread_above_0_35_routes_to_object_level_discussion_or_adjudication",
  centralityStrengthProductSpread: "centrality_strength_product_spread_above_0_30_routes_to_target_map_or_adjudication",
  correctnessSpread: "correctness_spread_above_0_35_routes_to_correctness_verification_review",
  postDiscussionResidualSpread: "post_discussion_final_max_spread_above_0_30_requires_residual_disagreement_classification_and_memo",
  thinOverlap: "fewer_than_two_final_raters_is_thin_overlap_and_cannot_support_consensus_claims",
};

export function defaultRatingEscalationPolicy(releaseId = "october-2026-demo") {
  return {
    id: `rating-escalation-policy-${releaseId}`,
    policyVersion: "rating-escalation-policy-rlhf90-v1",
    triggerList: RATING_ESCALATION_TRIGGER_RULES,
    lowClarityThreshold: RATING_ESCALATION_LOW_CLARITY_THRESHOLD,
    lowClarityAdjudicationCount: RATING_ESCALATION_LOW_CLARITY_ADJUDICATION_COUNT,
    initialOverallSpreadThreshold: RATING_ESCALATION_OVERALL_SPREAD_THRESHOLD,
    centralityStrengthProductSpreadThreshold: RATING_ESCALATION_PRODUCT_SPREAD_THRESHOLD,
    correctnessSpreadThreshold: RATING_ESCALATION_CORRECTNESS_SPREAD_THRESHOLD,
    postDiscussionMaxSpreadTarget: RATING_ESCALATION_POST_DISCUSSION_MAX_SPREAD_TARGET,
    serviceLevelByTrigger: {
      low_clarity_single: "enter_low_clarity_workflow_expert_review_before_hidden_benchmark_eligibility",
      low_clarity_two_or_more: "auto_escalate_to_adjudication",
      overall_spread: "auto_escalate_to_adjudication_before_release",
      centrality_strength_product_spread: "auto_escalate_to_adjudication_before_release",
      correctness_spread: "route_to_correctness_review_escalate_if_unresolved",
      insufficient_topic_expertise: "route_to_topic_fit_review_or_expert_reassignment",
      needs_verification: "create_or_link_verification_record_block_release_until_resolved_or_not_practicable",
      zero_correctness_nonzero_strength: "route_to_rubric_consistency_review_no_auto_correction",
      nonclarity_provisional_with_clarity_gte_threshold: "route_to_completion_consistency_review",
      correctness_not_assessable_with_clarity_gte_threshold: "route_to_rubric_consistency_review_or_adjudicated_exception",
      materially_different_plausible_interpretations: "auto_escalate_to_interpretation_adjudication",
      vague_good_objection_gesture: "route_to_expert_review_do_not_steelman_missing_reasoning",
      clearly_unsatisfactory_imprecision: "preserve_low_quality_diagnosis_escalate_release_critical_only",
      background_knowledge_dispute: "route_to_topic_expert_review_when_background_assumption_disputed",
    },
    protectedStatusBlindRoutingCopy: "Generic workflow policy requires additional review for this item.",
    lmcaSourceBoundary: "numeric_thresholds_are_project_defaults_not_lmca_source_stated_rules",
    createdBy: "seed-policy-admin",
    frozenAt: "2026-10-01T00:00:00.000Z",
    timestamp: "2026-10-01T00:00:00.000Z",
  };
}

function defaultDisagreementThresholdPolicy(releaseId = "october-2026-demo") {
  return {
    id: `disagreement-threshold-policy-${releaseId}`,
    policyVersion: DISAGREEMENT_THRESHOLD_POLICY_VERSION,
    thresholds: REQUIRED_DISAGREEMENT_THRESHOLDS,
    escalationRules: REQUIRED_DISAGREEMENT_ESCALATION_RULES,
    postDiscussionResidualRule:
      "Post-discussion final max spread above 0.30 requires residual disagreement classification, an adjudication memo, and minority-rationale preservation before release use.",
    thinOverlapRule:
      "Fewer than two final raters is thin overlap and must be disclosed rather than counted as low-disagreement consensus evidence.",
    lmcaSourceBoundary:
      "Project default numeric disagreement thresholds are frozen here; LMCA motivates disagreement reporting but does not state every platform escalation threshold.",
    frozenAt: "2026-10-01T00:00:00.000Z",
  };
}

function disagreementThresholdValues(policy) {
  const thresholds = policy?.thresholds && typeof policy.thresholds === "object" && !Array.isArray(policy.thresholds) ? policy.thresholds : {};
  return { ...REQUIRED_DISAGREEMENT_THRESHOLDS, ...thresholds };
}

export function detectEscalations(ratings, escalationPolicy = defaultRatingEscalationPolicy("runtime")) {
  const policy = normalizeRuntimeRatingEscalationPolicy(escalationPolicy);
  const triggers = [];
  if (ratings.some((rating) => value(rating, "clarity") !== null && value(rating, "clarity") < policy.lowClarityThreshold)) triggers.push("low clarity workflow required");
  if (ratings.filter((rating) => (value(rating, "clarity") ?? 1) < policy.lowClarityThreshold).length >= policy.lowClarityAdjudicationCount) {
    triggers.push(`two or more raters gave clarity below ${policy.lowClarityThreshold}`);
  }
  const overallSpread = spread(ratings, "overall");
  if (overallSpread !== null && overallSpread > policy.initialOverallSpreadThreshold) {
    triggers.push(`initial overall score spread above ${formatThreshold(policy.initialOverallSpreadThreshold)}`);
  }
  const productSpread = centralityStrengthSpread(ratings);
  if (productSpread !== null && productSpread > policy.centralityStrengthProductSpreadThreshold) {
    triggers.push(`centrality * strength spread above ${formatThreshold(policy.centralityStrengthProductSpreadThreshold)}`);
  }
  const correctnessSpread = spread(ratings, "correctness");
  if (correctnessSpread !== null && correctnessSpread > policy.correctnessSpreadThreshold) {
    triggers.push(`correctness spread above ${formatThreshold(policy.correctnessSpreadThreshold)}`);
  }
  if (ratings.some((rating) => rating.flags?.insufficientTopicExpertise)) triggers.push("topic-fit review required");
  if (ratings.some((rating) => rating.flags?.needsVerification)) triggers.push("correctness verification record required");
  if (ratings.some((rating) => value(rating, "correctness") === 0 && (value(rating, "strength") ?? 0) > 0)) triggers.push("zero correctness with nonzero strength consistency review");
  if (
    ratings.some(
      (rating) =>
        (value(rating, "clarity") ?? 0) >= policy.lowClarityThreshold &&
        (rating.provisionalDimensions ?? []).some((dimension) => dimension !== "clarity" && dimension !== "overall"),
    )
  ) {
    triggers.push("non-clarity provisional fields with clarity >= 0.5");
  }
  if (
    ratings.some(
      (rating) => rating.flags?.correctnessNotAssessableDueToClarity === true && (value(rating, "clarity") ?? 0) >= policy.lowClarityThreshold,
    )
  ) {
    triggers.push("correctness not assessable due to clarity with clarity >= 0.5");
  }
  if (ratings.some((rating) => rating.flags?.materiallyDifferentPlausibleInterpretations === true || rating.flags?.interpretationDispute === true)) {
    triggers.push("materially different plausible interpretations require adjudication");
  }
  if (ratings.some((rating) => rating.flags?.vagueGoodObjectionGesture === true)) {
    triggers.push("vague good-objection gesture requires expert review");
  }
  if (ratings.some((rating) => rating.flags?.clearlyUnsatisfactoryDueToImprecision === true)) {
    triggers.push("clearly unsatisfactory imprecision retained as review diagnosis");
  }
  if (ratings.some((rating) => rating.flags?.backgroundKnowledgeNote === true || rating.flags?.backgroundKnowledgeDispute === true)) {
    triggers.push("background-knowledge assumption requires topic review");
  }
  return triggers;
}

function normalizeRuntimeRatingEscalationPolicy(policy = {}) {
  return {
    lowClarityThreshold: numberOrDefault(policy.lowClarityThreshold, RATING_ESCALATION_LOW_CLARITY_THRESHOLD),
    lowClarityAdjudicationCount: numberOrDefault(policy.lowClarityAdjudicationCount, RATING_ESCALATION_LOW_CLARITY_ADJUDICATION_COUNT),
    initialOverallSpreadThreshold: numberOrDefault(policy.initialOverallSpreadThreshold, RATING_ESCALATION_OVERALL_SPREAD_THRESHOLD),
    centralityStrengthProductSpreadThreshold: numberOrDefault(
      policy.centralityStrengthProductSpreadThreshold,
      RATING_ESCALATION_PRODUCT_SPREAD_THRESHOLD,
    ),
    correctnessSpreadThreshold: numberOrDefault(policy.correctnessSpreadThreshold, RATING_ESCALATION_CORRECTNESS_SPREAD_THRESHOLD),
  };
}

function formatThreshold(value) {
  return Number(value).toFixed(2);
}

export const SCORE_CONFIDENCE_LEVELS = ["low", "medium", "high"];
export const SCORE_EXPLANATION_TRIGGER_RULES = [
  "extreme_score",
  "score_inconsistency",
  "overall_product_gap",
  "surprising_score",
  "unclear_target",
  "high_stakes_workflow",
  "post_discussion_revision",
  "exposure_familiarity_conflict_uncertainty",
];

export const SCORE_EXPLANATION_EXTREME_THRESHOLD_LOW = 0.1;
export const SCORE_EXPLANATION_EXTREME_THRESHOLD_HIGH = 0.9;
export const SCORE_EXPLANATION_CORRECTNESS_INCONSISTENCY_MAX = 0.25;
export const SCORE_EXPLANATION_STRENGTH_INCONSISTENCY_MIN = 0.75;
export const SCORE_EXPLANATION_OVERALL_PRODUCT_GAP_THRESHOLD = 0.25;
export const SCORE_EXPLANATION_INCONSISTENCY_RULES = ["correctness_lte_0_25_and_strength_gte_0_75"];
export const SCORE_EXPLANATION_ORDINARY_REQUIRED_FIELDS = ["seven_scores", "confidence_low_medium_high"];
export const SCORE_EXPLANATION_OPTIONAL_FIELDS = ["general_rating_note", "optional_evidence_spans"];

const SCORE_EXPLANATION_EXTREME_DIMENSIONS = RUBRIC_DIMENSIONS;
const SCORE_EXPLANATION_HIGH_STAKES_QUEUE_TYPES = new Set([
  "validation",
  "validation_subset",
  "internal_validation",
  "protected_validation",
  "benchmark_candidate_review",
  "hidden_benchmark",
  "hidden_benchmark_review",
  "gold_certification",
  "release_critical",
  "release_review",
]);

export function scoreExplanationTriggersForRating({ scores = {}, flags = {}, assignment = {}, kind = "blind_initial", workflowProfileId = "", revisionReasonCode = "" } = {}) {
  const triggers = [];
  if (
    SCORE_EXPLANATION_EXTREME_DIMENSIONS.some(
      (dimension) => scoreExplanationExtremeScoreTriggered(dimension, scores?.[dimension]),
    )
  ) {
    triggers.push("extreme_score");
  }
  if (
    Number.isFinite(scores?.correctness) &&
    Number.isFinite(scores?.strength) &&
    scores.correctness <= SCORE_EXPLANATION_CORRECTNESS_INCONSISTENCY_MAX &&
    scores.strength >= SCORE_EXPLANATION_STRENGTH_INCONSISTENCY_MIN
  ) {
    triggers.push("score_inconsistency");
  }
  if (Number.isFinite(scores?.overall) && Number.isFinite(scores?.centrality) && Number.isFinite(scores?.strength)) {
    const productGap = Math.abs(scores.overall - scores.centrality * scores.strength);
    if (productGap >= SCORE_EXPLANATION_OVERALL_PRODUCT_GAP_THRESHOLD) triggers.push("overall_product_gap");
  }
  if (flags?.surprisingScore === true) {
    triggers.push("surprising_score");
  }
  if (flags?.targetUnclear === true || flags?.clarityAfterEffortIssue === true || flags?.strengthCentralityAllocationAmbiguity === true) {
    triggers.push("unclear_target");
  }
  const queueType = assignment?.queueType ?? assignment?.assignmentType ?? "";
  if (
    SCORE_EXPLANATION_HIGH_STAKES_QUEUE_TYPES.has(queueType) ||
    /validation|benchmark|gold|certification|release/.test(String(workflowProfileId))
  ) {
    triggers.push("high_stakes_workflow");
  }
  if (kind === "revision" && (revisionReasonCode === "post_discussion_revision" || assignment?.exposure === "post_lock_discussion")) {
    triggers.push("post_discussion_revision");
  }
  if (
    flags?.sourceExposureConflictUncertainty === true ||
    flags?.sourceExposureUncertainty === true ||
    flags?.priorFamiliarityUncertainty === true ||
    flags?.conflictUncertainty === true
  ) {
    triggers.push("exposure_familiarity_conflict_uncertainty");
  }
  return [...new Set(triggers)];
}

function scoreExplanationExtremeScoreTriggered(dimension, score) {
  if (!Number.isFinite(score)) return false;
  if (dimension === "dead_weight") return score > SCORE_EXPLANATION_EXTREME_THRESHOLD_HIGH;
  if (dimension === "clarity" || dimension === "single_issue") return score < SCORE_EXPLANATION_EXTREME_THRESHOLD_LOW;
  return score < SCORE_EXPLANATION_EXTREME_THRESHOLD_LOW || score > SCORE_EXPLANATION_EXTREME_THRESHOLD_HIGH;
}

export function scoreExplanationRequiredForRating(input) {
  return scoreExplanationTriggersForRating(input).length > 0;
}

const SCORE_EXPLANATION_MIN_CHARS = 12;
const SCORE_EXPLANATION_MAX_CHARS = 360;
const SCORE_EXPLANATION_MAX_SENTENCES = 2;
const RATING_OBFUSCATION_NOTE_MIN_CHARS = 12;
const RATING_OBFUSCATION_NOTE_MAX_CHARS = 500;

function scoreExplanationSentenceCount(text) {
  const normalized = String(text)
    .replace(/\b(e\.g|i\.e)\./gi, (match) => match.replaceAll(".", ""))
    .replace(/\betc\./gi, "etc");
  const terminalMarks = normalized.match(/[.!?]+(?=\s|$)/g);
  return terminalMarks?.length ?? 1;
}

export function validateTriggeredScoreExplanation(text) {
  const value = typeof text === "string" ? text.trim() : "";
  if (value.length < SCORE_EXPLANATION_MIN_CHARS) {
    return { ok: false, detail: "scoreExplanation is required when ScoreExplanationPolicy triggers" };
  }
  if (value.length > SCORE_EXPLANATION_MAX_CHARS) {
    return { ok: false, detail: "scoreExplanation must be brief one- or two-sentence text" };
  }
  if (scoreExplanationSentenceCount(value) > SCORE_EXPLANATION_MAX_SENTENCES) {
    return { ok: false, detail: "scoreExplanation must be one or two sentences when ScoreExplanationPolicy triggers" };
  }
  return { ok: true };
}

export function scoreExplanationCompletionStatusForRating({ explanationRequired = false, scoreExplanationRequired = false, scoreExplanation = "" } = {}) {
  if (!explanationRequired) {
    const explanationText = typeof scoreExplanation === "string" ? scoreExplanation.trim() : "";
    return explanationText || scoreExplanationRequired === true ? "ordinary_explanation_not_allowed" : "ordinary_note_optional";
  }
  return scoreExplanationRequired === true && validateTriggeredScoreExplanation(scoreExplanation).ok
    ? "triggered_explanation_complete"
    : "triggered_explanation_review_required";
}

export function ratingObfuscationNoteForRating(rating = {}) {
  const value = rating.obfuscationNote ?? rating.obfuscation_note ?? "";
  return typeof value === "string" ? value.trim() : value;
}

export function validateRatingObfuscationNote(text) {
  const value = typeof text === "string" ? text.trim() : "";
  if (value.length < RATING_OBFUSCATION_NOTE_MIN_CHARS) {
    return { ok: false, detail: "obfuscationNote is required when obfuscatedArgumentRisk is flagged" };
  }
  if (value.length > RATING_OBFUSCATION_NOTE_MAX_CHARS) {
    return { ok: false, detail: "obfuscationNote must be a short blind-safe note" };
  }
  return { ok: true };
}

export function buildScoreExplanationAuditReport(releaseId, ratings = seedRatings, options = {}) {
  const assignmentRows = [...assignments, ...(options.assignments ?? []), ...(options.workflowAssignments ?? [])].filter((assignment) => assignment?.id);
  const assignmentById = new Map(assignmentRows.map((assignment) => [assignment.id, assignment]));
  const seedPolicyRows = uniqueRowsById([
    normalizeScoreExplanationPolicy(defaultScoreExplanationPolicy("october-2026-demo"), "seed_score_explanation_policy"),
    normalizeScoreExplanationPolicy(defaultScoreExplanationPolicy(releaseId), "seed_score_explanation_policy"),
  ]);
  const submittedPolicyRows = (options.scoreExplanationPolicies ?? [])
    .map((policy) => normalizeScoreExplanationPolicy(policy, "submitted_workflow_score_explanation_policy"))
    .filter(Boolean);
  const scoreExplanationPolicyRows = uniqueRowsById([...seedPolicyRows, ...submittedPolicyRows]);
  const scoreExplanationPolicyById = new Map(scoreExplanationPolicyRows.map((policy) => [policy.id, policy]));
  const rows = ratings.map((rating) =>
    normalizeScoreExplanationAuditRow(rating, assignmentById.get(rating.assignmentId) ?? null, scoreExplanationPolicyById),
  );
  const reviewSections = rows.flatMap((row) =>
    row.reviewReasons.map((reason) => ({
      artifactType: "rating_score_explanation",
      artifactId: row.ratingId,
      reason,
    })),
  );
  const policyReviewSections = submittedPolicyRows.flatMap((row) =>
    row.reviewReasons.map((reason) => ({ artifactType: "score_explanation_policy", artifactId: row.id, reason })),
  );
  const byExpectedTrigger = Object.fromEntries(
    SCORE_EXPLANATION_TRIGGER_RULES.map((trigger) => [trigger, rows.filter((row) => row.expectedTriggers.includes(trigger)).length]),
  );
  const bySubmittedTrigger = Object.fromEntries(
    SCORE_EXPLANATION_TRIGGER_RULES.map((trigger) => [trigger, rows.filter((row) => row.submittedTriggers.includes(trigger)).length]),
  );
  return {
    id: `score-explanation-audit-${releaseId}`,
    releaseId,
    generatedAt: new Date().toISOString(),
    policy: {
      ordinaryRequiredFields: SCORE_EXPLANATION_ORDINARY_REQUIRED_FIELDS,
      optionalFields: SCORE_EXPLANATION_OPTIONAL_FIELDS,
      triggerList: SCORE_EXPLANATION_TRIGGER_RULES,
      explanationRequirednessRule:
        "Ordinary ratings require seven scores plus low/medium/high confidence; scoreExplanation is required only when the server-derived trigger set is non-empty.",
      blindPromptRule: "Triggered explanations must be short, blind-safe, and hidden from source, peer, model, gold, and protected-status context.",
    },
    scoreExplanationPolicyRows,
    rows,
    byExpectedTrigger,
    bySubmittedTrigger,
    counts: {
      ratingRows: rows.length,
      confidenceJudgmentRows: rows.filter((row) => row.confidenceJudgmentPresent).length,
      missingConfidenceJudgmentRows: rows.filter((row) => !row.confidenceJudgmentPresent).length,
      triggerRequiredRows: rows.filter((row) => row.explanationRequired).length,
      triggerExplanationCompleteRows: rows.filter((row) => row.explanationRequired && row.explanationStatus === "triggered_explanation_complete").length,
      missingTriggeredExplanationRows: rows.filter((row) => row.reviewReasons.some((reason) => reason.startsWith("scoreExplanation"))).length,
      ordinaryRows: rows.filter((row) => !row.explanationRequired).length,
      ordinaryRowsWithGeneralNotes: rows.filter((row) => !row.explanationRequired && row.generalRatingNotePresent).length,
      ordinaryRowsWithDisallowedScoreExplanation: rows.filter((row) => row.reviewReasons.includes("scoreExplanation:ordinary_not_allowed")).length,
      triggerMismatchRows: rows.filter((row) => row.missingExpectedTriggers.length || row.unexpectedSubmittedTriggers.length).length,
      requiredReasonMismatchRows: rows.filter((row) => row.reviewReasons.some((reason) => reason.startsWith("scoreExplanationRequiredReasons"))).length,
      promptVisibilityViolationRows: rows.filter((row) => row.reviewReasons.includes("scoreExplanationPromptVisibility")).length,
      promptShownMismatchRows: rows.filter((row) => row.reviewReasons.some((reason) => reason.startsWith("scoreExplanationPromptShown"))).length,
      completionStatusMismatchRows: rows.filter((row) => row.reviewReasons.some((reason) => reason.startsWith("scoreExplanationCompletionStatus"))).length,
      productDiagnosticMismatchRows: rows.filter((row) => row.reviewReasons.some((reason) => reason.startsWith("overallVsCentralityStrengthDiagnostic"))).length,
      submittedScoreExplanationPolicyCount: submittedPolicyRows.length,
      policyBoundRows: rows.filter((row) => row.policyBindingStatus === "score_explanation_policy_bound").length,
      policyBindingReviewRows: rows.filter((row) => row.policyBindingStatus !== "score_explanation_policy_bound").length,
      policyReviewSectionCount: policyReviewSections.length,
      reviewSectionCount: reviewSections.length + policyReviewSections.length,
    },
    reviewSections: [...policyReviewSections, ...reviewSections],
    releaseUseStatus: reviewSections.length || policyReviewSections.length ? "score_explanation_audit_review_required" : "score_explanation_audit_passed",
  };
}

function normalizeScoreExplanationAuditRow(rating, assignment, scoreExplanationPolicyById = new Map()) {
  const submittedTriggers = normalizeStringArray(rating.scoreExplanationTriggers);
  const expectedTriggers = scoreExplanationTriggersForRating({
    scores: rating.scores ?? {},
    flags: rating.flags ?? {},
    assignment: assignment ?? {},
    kind: rating.kind,
    workflowProfileId: rating.workflowProfileId,
    revisionReasonCode: rating.revisionReasonCode,
  });
  const missingExpectedTriggers = expectedTriggers.filter((trigger) => !submittedTriggers.includes(trigger));
  const unexpectedSubmittedTriggers = submittedTriggers.filter((trigger) => !expectedTriggers.includes(trigger));
  const submittedRequiredReasons = normalizeStringArray(rating.scoreExplanationRequiredReasons);
  const missingRequiredReasons = expectedTriggers.filter((trigger) => !submittedRequiredReasons.includes(trigger));
  const unexpectedRequiredReasons = submittedRequiredReasons.filter((trigger) => !expectedTriggers.includes(trigger));
  const explanationRequired = expectedTriggers.length > 0;
  const explanationText = typeof rating.scoreExplanation === "string" ? rating.scoreExplanation.trim() : "";
  const triggeredExplanationValidation = explanationRequired ? validateTriggeredScoreExplanation(explanationText) : { ok: true };
  const expectedCompletionStatus = scoreExplanationCompletionStatusForRating({
    explanationRequired,
    scoreExplanationRequired: rating.scoreExplanationRequired === true,
    scoreExplanation: rating.scoreExplanation,
  });
  const expectedOverallProductDiagnostic = scoreExplanationOverallProductDiagnostic(rating.scores ?? {});
  const productDiagnosticMatches = scoreExplanationDiagnosticMatches(
    rating.overallVsCentralityStrengthDiagnostic,
    expectedOverallProductDiagnostic,
  );
  const confidenceJudgmentPresent = SCORE_CONFIDENCE_LEVELS.includes(rating.scoreConfidenceJudgment);
  const scoreExplanationPolicyId = rating.scoreExplanationPolicyId ?? null;
  const scoreExplanationPolicy = scoreExplanationPolicyId ? scoreExplanationPolicyById.get(scoreExplanationPolicyId) : null;
  const policyBindingStatus = !scoreExplanationPolicyId
    ? "score_explanation_policy_missing"
    : !scoreExplanationPolicy
      ? "score_explanation_policy_not_found"
      : scoreExplanationPolicy.reviewReasons.length
        ? "score_explanation_policy_review_required"
        : "score_explanation_policy_bound";
  const reviewReasons = [
    scoreExplanationPolicyId ? null : "scoreExplanationPolicyId",
    scoreExplanationPolicyId && !scoreExplanationPolicy ? "scoreExplanationPolicyId:not_found" : null,
    scoreExplanationPolicy?.reviewReasons.length ? "scoreExplanationPolicyId:review_required" : null,
    confidenceJudgmentPresent ? null : "scoreConfidenceJudgment",
    missingExpectedTriggers.length ? `scoreExplanationTriggers:missing:${missingExpectedTriggers.join(",")}` : null,
    unexpectedSubmittedTriggers.length ? `scoreExplanationTriggers:unexpected:${unexpectedSubmittedTriggers.join(",")}` : null,
    Array.isArray(rating.scoreExplanationRequiredReasons) ? null : "scoreExplanationRequiredReasons",
    missingRequiredReasons.length ? `scoreExplanationRequiredReasons:missing:${missingRequiredReasons.join(",")}` : null,
    unexpectedRequiredReasons.length ? `scoreExplanationRequiredReasons:unexpected:${unexpectedRequiredReasons.join(",")}` : null,
    explanationRequired && rating.scoreExplanationRequired !== true ? "scoreExplanationRequired" : null,
    typeof rating.scoreExplanationPromptShown === "boolean" ? null : "scoreExplanationPromptShown",
    rating.scoreExplanationPromptShown === explanationRequired ? null : `scoreExplanationPromptShown:${explanationRequired}`,
    explanationRequired && rating.scoreExplanationPromptVisibility !== "label_source_protected_status_blind" ? "scoreExplanationPromptVisibility" : null,
    explanationRequired && !triggeredExplanationValidation.ok ? `scoreExplanation:${triggeredExplanationValidation.detail}` : null,
    rating.scoreExplanationCompletionStatus ? null : "scoreExplanationCompletionStatus",
    rating.scoreExplanationCompletionStatus && rating.scoreExplanationCompletionStatus !== expectedCompletionStatus
      ? `scoreExplanationCompletionStatus:${expectedCompletionStatus}`
      : null,
    productDiagnosticMatches ? null : "overallVsCentralityStrengthDiagnostic",
    !explanationRequired && rating.scoreExplanationRequired === true ? "scoreExplanationRequired:ordinary_not_allowed" : null,
    !explanationRequired && explanationText ? "scoreExplanation:ordinary_not_allowed" : null,
  ].filter(Boolean);
  const explanationStatus = explanationRequired
    ? triggeredExplanationValidation.ok && rating.scoreExplanationRequired === true
      ? "triggered_explanation_complete"
      : "triggered_explanation_review_required"
    : explanationText || rating.scoreExplanationRequired === true
      ? "ordinary_explanation_not_allowed"
      : "ordinary_note_optional";
  return {
    ratingId: rating.id,
    assignmentId: rating.assignmentId ?? null,
    itemId: makeItemId(rating.positionId, rating.critiqueId),
    kind: rating.kind ?? null,
    raterId: rating.raterId ?? null,
    queueType: assignment?.queueType ?? null,
    workflowProfileId: rating.workflowProfileId ?? null,
    scoreExplanationPolicyId,
    scoreExplanationPolicySource: scoreExplanationPolicy?.rowSource ?? null,
    policyBindingStatus,
    scoreConfidenceJudgment: rating.scoreConfidenceJudgment ?? null,
    confidenceJudgmentPresent,
    expectedTriggers,
    submittedTriggers,
    submittedRequiredReasons,
    missingExpectedTriggers,
    unexpectedSubmittedTriggers,
    missingRequiredReasons,
    unexpectedRequiredReasons,
    explanationRequired,
    scoreExplanationRequired: rating.scoreExplanationRequired === true,
    scoreExplanationPromptShown: rating.scoreExplanationPromptShown ?? null,
    scoreExplanationPresent: Boolean(explanationText),
    generalRatingNotePresent: typeof rating.generalRatingNote === "string" && Boolean(rating.generalRatingNote.trim()),
    promptVisibility: rating.scoreExplanationPromptVisibility ?? null,
    submittedCompletionStatus: rating.scoreExplanationCompletionStatus ?? null,
    expectedCompletionStatus,
    submittedOverallProductDiagnostic: rating.overallVsCentralityStrengthDiagnostic ?? null,
    expectedOverallProductDiagnostic,
    explanationStatus,
    reviewReasons,
  };
}

function scoreExplanationDiagnosticMatches(submitted, expected) {
  if (!submitted || typeof submitted !== "object" || Array.isArray(submitted)) return false;
  return (
    submitted.overallScore === expected.overallScore &&
    submitted.centralityStrengthProduct === expected.centralityStrengthProduct &&
    submitted.absoluteGap === expected.absoluteGap &&
    submitted.threshold === expected.threshold &&
    submitted.triggerFired === expected.triggerFired &&
    submitted.status === expected.status
  );
}

