function discussionAdjudicationThreadCoverageRow(thread, groups) {
  const completeDiscussions = groups.discussionRows.filter((row) => row.linkedDiscussionThreadId === thread.id && !row.reviewReasons.length);
  const completeSessions = groups.postLockSessionRows.filter((row) => row.discussionThreadId === thread.id && !row.reviewReasons.length);
  const completeComments = groups.commentRows.filter((row) => row.discussionThreadId === thread.id && !row.reviewReasons.length);
  const completeRevisionProposals = groups.revisionProposalRows.filter((row) => row.discussionThreadId === thread.id && !row.reviewReasons.length);
  const completeAdjudications = groups.adjudicationRows.filter((row) => row.discussionThreadId === thread.id && !row.reviewReasons.length);
  const completeReviewSessions = groups.adjudicationReviewSessionRows.filter((row) => row.discussionThreadId === thread.id && !row.reviewReasons.length);
  const completeMemos = groups.memoRows.filter((row) => row.discussionThreadId === thread.id && !row.reviewReasons.length);
  const completeFinalizations = groups.finalizationRows.filter(
    (row) =>
      !row.reviewReasons.length &&
      (completeAdjudications.some((adjudication) => adjudication.id === row.adjudicationId) ||
        completeMemos.some((memo) => memo.id === row.memoId)),
  );
  const sessionCommentRefs = new Set(completeSessions.flatMap((session) => session.objectLevelCommentRecords));
  const sessionRevisionRefs = new Set(completeSessions.flatMap((session) => session.revisionProposalIds));
  const commentsLinkedFromSession = completeComments.some((comment) => sessionCommentRefs.has(comment.id));
  const revisionsLinkedFromSession = completeRevisionProposals.some((proposal) => sessionRevisionRefs.has(proposal.id));
  const reviewReasons = [
    thread.reviewReasons.length ? "discussionThread" : null,
    completeDiscussions.length ? null : "discussionOpen",
    completeSessions.length ? null : "postLockDiscussionSession",
    completeComments.length && commentsLinkedFromSession ? null : "objectLevelCommentThread",
    completeRevisionProposals.length && revisionsLinkedFromSession ? null : "revisionProposalPreservingOriginalRating",
    completeAdjudications.length ? null : "adjudicationRecord",
    completeReviewSessions.length ? null : "adjudicationReviewSession",
    completeMemos.length ? null : "adjudicationMemo",
    completeFinalizations.length ? null : "adjudicationFinalization",
  ].filter(Boolean);
  return {
    discussionThreadId: thread.id,
    itemKeys: thread.itemKeys,
    linkedDiscussionIds: completeDiscussions.map((row) => row.id),
    postLockDiscussionSessionIds: completeSessions.map((row) => row.id),
    objectLevelCommentIds: completeComments.map((row) => row.id),
    revisionProposalIds: completeRevisionProposals.map((row) => row.id),
    adjudicationIds: completeAdjudications.map((row) => row.id),
    adjudicationReviewSessionIds: completeReviewSessions.map((row) => row.id),
    adjudicationMemoIds: completeMemos.map((row) => row.id),
    adjudicationFinalizationIds: completeFinalizations.map((row) => row.id),
    reviewReasons,
    status: reviewReasons.length ? "discussion_adjudication_workflow_review_required" : "discussion_adjudication_workflow_complete",
  };
}

function workflowItemKeys(resource) {
  const explicit = normalizeStringArray(resource?.itemKeys ?? resource?.item_keys);
  if (explicit.length) return explicit;
  const { positionId, critiqueId } = itemRefFromWorkflowArtifact(resource);
  if (positionId && critiqueId) return [makeItemId(positionId, critiqueId)];
  const itemId = resource?.itemId ?? resource?.item_id;
  return typeof itemId === "string" && itemId.trim() ? [itemId.trim()] : [];
}

function workflowDiscussionThreadId(resource) {
  return resource?.discussionThreadId ?? resource?.discussion_thread_id ?? resource?.threadId ?? resource?.thread_id ?? null;
}

function linkedDiscussionThreadForResource(resource, threadRows) {
  const explicitThreadId = workflowDiscussionThreadId(resource);
  if (explicitThreadId) return threadRows.find((thread) => thread.id === explicitThreadId) ?? null;
  const itemKeys = new Set(workflowItemKeys(resource));
  if (!itemKeys.size) return null;
  const matches = threadRows.filter((thread) => thread.itemKeys.some((itemKey) => itemKeys.has(itemKey)));
  return matches.length === 1 ? matches[0] : null;
}

function normalizeDisagreementThresholdPolicy(policy, rowSource) {
  const id = policy?.id ?? policy?.disagreementThresholdPolicyId;
  if (!id) return null;
  const thresholds = policy.thresholds && typeof policy.thresholds === "object" && !Array.isArray(policy.thresholds) ? policy.thresholds : {};
  const escalationRules =
    policy.escalationRules && typeof policy.escalationRules === "object" && !Array.isArray(policy.escalationRules)
      ? policy.escalationRules
      : {};
  const missingThresholdKeys = Object.keys(REQUIRED_DISAGREEMENT_THRESHOLDS).filter((key) => !Object.hasOwn(thresholds, key));
  const missingRuleKeys = Object.keys(REQUIRED_DISAGREEMENT_ESCALATION_RULES).filter((key) => !Object.hasOwn(escalationRules, key));
  const reviewReasons = [
    (policy.policyVersion ?? policy.version) === DISAGREEMENT_THRESHOLD_POLICY_VERSION
      ? null
      : `policyVersion:${DISAGREEMENT_THRESHOLD_POLICY_VERSION}`,
    missingThresholdKeys.length ? `thresholds:${missingThresholdKeys.join(",")}` : null,
    stableJsonKey(thresholds) === stableJsonKey(REQUIRED_DISAGREEMENT_THRESHOLDS) ? null : "thresholds",
    missingRuleKeys.length ? `escalationRules:${missingRuleKeys.join(",")}` : null,
    stableJsonKey(escalationRules) === stableJsonKey(REQUIRED_DISAGREEMENT_ESCALATION_RULES) ? null : "escalationRules",
    policyMentions(policy.postDiscussionResidualRule, ["0.30", "classification", "memo"]) ? null : "postDiscussionResidualRule",
    policyMentions(policy.thinOverlapRule, ["two", "final raters"]) ? null : "thinOverlapRule",
    policyMentions(policy.lmcaSourceBoundary, ["project", "lmca"]) ? null : "lmcaSourceBoundary",
    requiredPromptFieldReason("frozenAt", policy.frozenAt),
  ].filter(Boolean);
  return {
    id,
    rowSource,
    policyVersion: policy.policyVersion ?? policy.version ?? null,
    thresholds,
    escalationRules,
    postDiscussionResidualRule: policy.postDiscussionResidualRule ?? null,
    thinOverlapRule: policy.thinOverlapRule ?? null,
    lmcaSourceBoundary: policy.lmcaSourceBoundary ?? null,
    frozenAt: policy.frozenAt ?? null,
    reviewReasons,
    status: reviewReasons.length ? "disagreement_threshold_policy_review_required" : "disagreement_threshold_policy_complete",
  };
}

export function buildDisagreementThresholdPolicyEvidenceReport(releaseId, submittedPolicies = []) {
  const submittedRows = submittedPolicies
    .map((policy) => normalizeDisagreementThresholdPolicy(policy, "submitted_workflow_disagreement_threshold_policy"))
    .filter(Boolean);
  const seedRows = [normalizeDisagreementThresholdPolicy(defaultDisagreementThresholdPolicy(releaseId), "seed_disagreement_threshold_policy")];
  const activePolicy = submittedRows.find((row) => row.reviewReasons.length === 0) ?? seedRows[0];
  const reviewRows = submittedRows.filter((row) => row.reviewReasons.length);
  return {
    id: `disagreement-threshold-policy-evidence-${releaseId}`,
    releaseId,
    requiredThresholds: REQUIRED_DISAGREEMENT_THRESHOLDS,
    requiredEscalationRules: REQUIRED_DISAGREEMENT_ESCALATION_RULES,
    policyRows: [...seedRows, ...submittedRows],
    activePolicy,
    activePolicyId: activePolicy?.id ?? null,
    reviewRows,
    counts: {
      submittedPolicyCount: submittedRows.length,
      reviewRequiredPolicyCount: reviewRows.length,
    },
    releaseUseStatus: !submittedRows.length
      ? "seed_disagreement_threshold_policy_active"
      : reviewRows.length
        ? "submitted_disagreement_threshold_policy_review_required"
        : "submitted_disagreement_threshold_policy_active",
  };
}

function resolveDisagreementThresholdPolicy(releaseId, thresholdOrPolicy, options = {}) {
  if (typeof thresholdOrPolicy === "number") {
    return {
      activePolicy: null,
      activePolicyId: null,
      releaseUseStatus: "legacy_numeric_threshold_argument",
      thresholds: {
        ...REQUIRED_DISAGREEMENT_THRESHOLDS,
        postDiscussionMaxSpreadTarget: thresholdOrPolicy,
        highSpreadResidualClassificationThreshold: thresholdOrPolicy,
      },
      escalationRules: REQUIRED_DISAGREEMENT_ESCALATION_RULES,
    };
  }
  const evidence = options.disagreementThresholdPolicyEvidence ?? null;
  const activePolicy =
    evidence?.activePolicy ??
    normalizeDisagreementThresholdPolicy(thresholdOrPolicy, "runtime_disagreement_threshold_policy") ??
    normalizeDisagreementThresholdPolicy(defaultDisagreementThresholdPolicy(releaseId), "seed_disagreement_threshold_policy");
  return {
    activePolicy,
    activePolicyId: activePolicy?.id ?? null,
    releaseUseStatus: evidence?.releaseUseStatus ?? activePolicy?.rowSource ?? "runtime_disagreement_threshold_policy",
    thresholds: disagreementThresholdValues(activePolicy),
    escalationRules:
      activePolicy?.escalationRules && Object.keys(activePolicy.escalationRules).length
        ? activePolicy.escalationRules
        : REQUIRED_DISAGREEMENT_ESCALATION_RULES,
  };
}

export function buildPostDiscussionDisagreementReport(
  releaseId,
  labelSnapshot,
  ratings = seedRatings,
  positionList = positions,
  critiqueList = critiques,
  memos = adjudicationMemos,
  thresholdOrPolicy = null,
  options = {},
) {
  const thresholdPolicy = resolveDisagreementThresholdPolicy(releaseId, thresholdOrPolicy, options);
  const threshold = thresholdPolicy.thresholds.highSpreadResidualClassificationThreshold ?? thresholdPolicy.thresholds.postDiscussionMaxSpreadTarget;
  const thinOverlapFinalRaterCountMin = thresholdPolicy.thresholds.thinOverlapFinalRaterCountMin;
  const positionById = new Map(positionList.map((position) => [position.id, position]));
  const memosByItemId = memos.reduce((acc, memo) => {
    const itemId = makeItemId(memo.positionId, memo.critiqueId);
    acc[itemId] ??= [];
    acc[itemId].push(memo);
    return acc;
  }, {});
  const itemRows = critiqueList
    .map((critique) => {
      const position = positionById.get(critique.positionId);
      const releaseCritical = isReleaseCriticalSplit(position?.split);
      if (!releaseCritical) return null;
      const itemId = makeItemId(critique.positionId, critique.id);
      const itemRatings = ratings.filter((rating) => rating.positionId === critique.positionId && rating.critiqueId === critique.id);
      const finalRaterIds = [...new Set(itemRatings.map((rating) => rating.raterId))].sort();
      const byDimensionFinalSpread = Object.fromEntries(RUBRIC_DIMENSIONS.map((dimension) => [dimension, spread(itemRatings, dimension)]));
      const measuredSpreads = Object.entries(byDimensionFinalSpread).filter(([, value]) => typeof value === "number");
      const maxEntry = measuredSpreads.sort((left, right) => right[1] - left[1])[0] ?? [null, null];
      const itemMemos = memosByItemId[itemId] ?? [];
      const label = labelSnapshot.itemLabels[itemId];
      const highSpread = typeof maxEntry[1] === "number" && maxEntry[1] > threshold;
      const insufficientFinalOverlap = finalRaterIds.length < thinOverlapFinalRaterCountMin;
      const classification = highSpread
        ? itemMemos.length
          ? "high_post_discussion_spread_classified_with_memo"
          : "high_post_discussion_spread_requires_adjudication_memo"
        : insufficientFinalOverlap
          ? "insufficient_final_rater_overlap"
          : "post_discussion_spread_within_threshold";
      return {
        itemId,
        itemHash: `sha256:${itemId}:post-discussion-disagreement`,
        split: position?.split ?? "unknown",
        topicFamily: position?.topicFamily ?? "unknown",
        releaseCritical,
        targetLabelPresent: Boolean(label),
        blindInitialRatingCount: itemRatings.filter((rating) => rating.kind === "blind_initial").length,
        finalRatingCount: itemRatings.length,
        finalRaterIds,
        ratingKinds: countBy(itemRatings, "kind"),
        threshold,
        disagreementThresholdPolicyId: thresholdPolicy.activePolicyId,
        disagreementThresholdPolicyReleaseUseStatus: thresholdPolicy.releaseUseStatus,
        thresholdsApplied: thresholdPolicy.thresholds,
        spreadPreDiscussionOverall: label?.spreadPreDiscussion ?? null,
        spreadPostDiscussionOverall: label?.spreadPostDiscussion ?? null,
        byDimensionFinalSpread,
        maxFinalSpreadDimension: maxEntry[0],
        maxFinalSpread: maxEntry[1],
        highSpread,
        adjudicationMemoIds: itemMemos.map((memo) => memo.id),
        unresolvedDisagreementClasses: itemMemos.map((memo) => memo.unresolvedDisagreementClass).filter(Boolean),
        disagreementTaxonomy: uniqueStrings(itemMemos.flatMap((memo) => memo.disagreementTaxonomy ?? [])),
        minorityRationaleCount: itemMemos.reduce((sum, memo) => sum + (memo.minorityRationales?.length ?? 0), 0),
        classification,
        releaseAction:
          classification === "high_post_discussion_spread_requires_adjudication_memo"
            ? "block_release_until_residual_disagreement_is_classified"
            : classification === "high_post_discussion_spread_classified_with_memo"
              ? "publish_residual_disagreement_class_and_minority_rationale"
              : classification === "insufficient_final_rater_overlap"
                ? "disclose_thin_overlap_and_do_not_claim_consensus"
                : "eligible_for_low_spread_release_claims",
      };
    })
    .filter(Boolean)
    .sort((left, right) => Number(right.highSpread) - Number(left.highSpread) || left.itemId.localeCompare(right.itemId));
  const highSpreadRows = itemRows.filter((row) => row.highSpread);
  const missingMemoRows = itemRows.filter((row) => row.classification === "high_post_discussion_spread_requires_adjudication_memo");
  const classifiedHighSpreadRows = itemRows.filter((row) => row.classification === "high_post_discussion_spread_classified_with_memo");
  const insufficientOverlapRows = itemRows.filter((row) => row.classification === "insufficient_final_rater_overlap");
  return {
    id: `post-discussion-disagreement-${releaseId}-${labelSnapshot.id}`,
    releaseId,
    labelSnapshotId: labelSnapshot.id,
    targetLabelVersion: labelSnapshot.targetLabelVersion,
    generatedAt: new Date().toISOString(),
    disagreementThresholdPolicyId: thresholdPolicy.activePolicyId,
    disagreementThresholdPolicyReleaseUseStatus: thresholdPolicy.releaseUseStatus,
    thresholdsApplied: thresholdPolicy.thresholds,
    policy: {
      disagreementThresholdPolicyId: thresholdPolicy.activePolicyId,
      policyVersion: thresholdPolicy.activePolicy?.policyVersion ?? DISAGREEMENT_THRESHOLD_POLICY_VERSION,
      maxSpreadThreshold: threshold,
      thresholds: thresholdPolicy.thresholds,
      escalationRules: thresholdPolicy.escalationRules,
      finalSpreadDefinition:
        "Final spread is the maximum per-dimension spread across rating rows included in the release label after blind initial ratings, checks, revisions, or adjudication rows are recorded.",
      releaseRule:
        "Release-critical items with final max rater spread above the threshold must keep a structured adjudication memo and residual-disagreement class; they must not be forced into silent consensus.",
      thinOverlapRule: "Items with fewer than two final raters are disclosed as thin overlap rather than treated as low-disagreement evidence.",
    },
    counts: {
      releaseCriticalItemCount: itemRows.length,
      highSpreadItemCount: highSpreadRows.length,
      classifiedHighSpreadItemCount: classifiedHighSpreadRows.length,
      missingMemoHighSpreadItemCount: missingMemoRows.length,
      insufficientFinalOverlapItemCount: insufficientOverlapRows.length,
    },
    byClassification: countBy(itemRows, "classification"),
    itemRows,
    highSpreadRows,
    classifiedHighSpreadRows,
    missingMemoRows,
    insufficientOverlapRows,
    releaseUseStatus: missingMemoRows.length
      ? "post_discussion_disagreement_memo_required"
      : classifiedHighSpreadRows.length
        ? "post_discussion_disagreement_classified"
        : insufficientOverlapRows.length
          ? "post_discussion_spread_check_thin_no_high_spread_observed"
          : "post_discussion_disagreement_checked",
  };
}

export function buildCommonMaps(labelSnapshot, run = fullRubricEvaluationRun) {
  const modelOveralls = {};
  const humanOveralls = {};
  const modelFullRatings = {};
  const humanFullRatings = {};
  const modelFullByPosition = {};
  const humanFullByPosition = {};
  run.predictions.forEach((prediction) => {
    const label = labelSnapshot.itemLabels[makeItemId(prediction.positionId, prediction.critiqueId)];
    const humanOverall = label?.weightedMeanScores.overall;
    const modelOverall = prediction.scores.overall;
    if (typeof humanOverall !== "number" || typeof modelOverall !== "number") return;
    humanOveralls[prediction.positionId] ??= {};
    modelOveralls[prediction.positionId] ??= {};
    humanFullByPosition[prediction.positionId] ??= {};
    modelFullByPosition[prediction.positionId] ??= {};
    humanOveralls[prediction.positionId][prediction.critiqueId] = humanOverall;
    modelOveralls[prediction.positionId][prediction.critiqueId] = modelOverall;
    humanFullRatings[makeItemId(prediction.positionId, prediction.critiqueId)] = label.weightedMeanScores;
    modelFullRatings[makeItemId(prediction.positionId, prediction.critiqueId)] = prediction.scores;
    humanFullByPosition[prediction.positionId][prediction.critiqueId] = label.weightedMeanScores;
    modelFullByPosition[prediction.positionId][prediction.critiqueId] = prediction.scores;
  });
  return { humanOveralls, modelOveralls, humanFullRatings, modelFullRatings, humanFullByPosition, modelFullByPosition };
}

const CERTIFICATION_THRESHOLD_POLICY_VERSION = "certification-threshold-rlhf90-v1";
const REQUIRED_CERTIFICATION_THRESHOLDS = {
  customWeightedLossMax: 0.14,
  pairwiseErrorMax: 0.14,
  duplicateInconsistencyMax: 0.12,
  meanAbsErrorMax: 0.14,
  perDimensionCalibrationErrorMax: 0.15,
  restrictionDimensionErrorMax: 0.2,
};
const REQUIRED_CERTIFICATION_REMEDIATION_RULES = {
  dimensionErrorAbovePerDimensionMax: "targeted_retraining_required_before_live_or_release_critical_rating",
  restrictionDimensionErrorAboveMax: "hold_matching_sensitive_assignments_until_recertified",
  duplicateInconsistencyAboveMax: "duplicate_consistency_review_required_before_tier_unlock",
  hardAmbiguityReviewFailure: "hard_ambiguity_review_required_before_tier_unlock",
  rubricVersionMismatch: "recertification_or_grandfathering_review_required",
};
const REQUIRED_CERTIFICATION_CADENCE_POLICY = {
  goldInjectionSchedule: {
    hiddenGoldEveryNReleaseCriticalAssignments: 10,
    minimumHiddenGoldItemsPerActiveRaterPerMonth: 3,
    stratification: "topic_difficulty_lmca_dimension_and_low_clarity_branch",
  },
  recertificationSchedule: {
    routineIntervalDays: 180,
    inactivityIntervalDays: 90,
    rubricVersionChange: "required_before_release_critical_use",
    targetedRetrainingExit: "pass_targeted_pack_before_assignment_unlock",
  },
  thresholdLogic: {
    rollingWindowGoldItemsMin: 20,
    certificationPassRateMin: 0.85,
    consecutiveGoldFailuresTriggerRestriction: 2,
    meanAbsErrorMax: REQUIRED_CERTIFICATION_THRESHOLDS.meanAbsErrorMax,
    perDimensionCalibrationErrorMax: REQUIRED_CERTIFICATION_THRESHOLDS.perDimensionCalibrationErrorMax,
  },
};

function defaultCertificationThresholdPolicy(releaseId) {
  return {
    id: `certification-threshold-policy-${releaseId}`,
    policyVersion: CERTIFICATION_THRESHOLD_POLICY_VERSION,
    thresholds: REQUIRED_CERTIFICATION_THRESHOLDS,
    remediationRules: REQUIRED_CERTIFICATION_REMEDIATION_RULES,
    cadencePolicy: REQUIRED_CERTIFICATION_CADENCE_POLICY,
    certificationStatusRule:
      "A rater is certified only when completion is met, the rubric is current, mean absolute error and every dimension stay within the frozen numeric thresholds, and no restriction flags remain.",
    retrainingRule:
      "Any dimension above the per-dimension calibration threshold creates a targeted retraining flag before live or release-critical rating.",
    restrictionRule:
      "Restriction thresholds hold correctness-sensitive, low-clarity, dead-weight, duplicate-consistency, or hard-ambiguity assignments until recertification or approved review.",
    recertificationRule:
      "Rubric-version mismatch requires recertification or grandfathering review before certification evidence can support release use.",
    frozenAt: "2026-10-01T00:00:00.000Z",
  };
}

function certificationThresholdValues(policy) {
  const thresholds = policy?.thresholds && typeof policy.thresholds === "object" && !Array.isArray(policy.thresholds) ? policy.thresholds : {};
  return { ...REQUIRED_CERTIFICATION_THRESHOLDS, ...thresholds };
}

function normalizeCertificationThresholdPolicy(policy, rowSource) {
  const id = policy?.id ?? policy?.certificationThresholdPolicyId;
  if (!id) return null;
  const thresholds = policy.thresholds && typeof policy.thresholds === "object" && !Array.isArray(policy.thresholds) ? policy.thresholds : {};
  const remediationRules =
    policy.remediationRules && typeof policy.remediationRules === "object" && !Array.isArray(policy.remediationRules)
      ? policy.remediationRules
      : {};
  const cadencePolicy =
    policy.cadencePolicy && typeof policy.cadencePolicy === "object" && !Array.isArray(policy.cadencePolicy)
      ? policy.cadencePolicy
      : {};
  const missingThresholdKeys = Object.keys(REQUIRED_CERTIFICATION_THRESHOLDS).filter((key) => !Object.hasOwn(thresholds, key));
  const missingRuleKeys = Object.keys(REQUIRED_CERTIFICATION_REMEDIATION_RULES).filter((key) => !Object.hasOwn(remediationRules, key));
  const missingCadenceKeys = Object.keys(REQUIRED_CERTIFICATION_CADENCE_POLICY).filter((key) => !Object.hasOwn(cadencePolicy, key));
  const reviewReasons = [
    (policy.policyVersion ?? policy.version) === CERTIFICATION_THRESHOLD_POLICY_VERSION
      ? null
      : `policyVersion:${CERTIFICATION_THRESHOLD_POLICY_VERSION}`,
    missingThresholdKeys.length ? `thresholds:${missingThresholdKeys.join(",")}` : null,
    stableJsonKey(thresholds) === stableJsonKey(REQUIRED_CERTIFICATION_THRESHOLDS) ? null : "thresholds",
    missingRuleKeys.length ? `remediationRules:${missingRuleKeys.join(",")}` : null,
    stableJsonKey(remediationRules) === stableJsonKey(REQUIRED_CERTIFICATION_REMEDIATION_RULES) ? null : "remediationRules",
    missingCadenceKeys.length ? `cadencePolicy:${missingCadenceKeys.join(",")}` : null,
    stableJsonKey(cadencePolicy) === stableJsonKey(REQUIRED_CERTIFICATION_CADENCE_POLICY) ? null : "cadencePolicy",
    policyMentions(policy.certificationStatusRule, ["mean absolute error", "certified"]) ? null : "certificationStatusRule",
    policyMentions(policy.retrainingRule, ["dimension", "retraining"]) ? null : "retrainingRule",
    policyMentions(policy.restrictionRule, ["restriction"]) ? null : "restrictionRule",
    policyMentions(policy.recertificationRule, ["rubric", "recertification"]) ? null : "recertificationRule",
    requiredPromptFieldReason("frozenAt", policy.frozenAt),
  ].filter(Boolean);
  return {
    id,
    rowSource,
    policyVersion: policy.policyVersion ?? policy.version ?? null,
    thresholds,
    remediationRules,
    cadencePolicy,
    certificationStatusRule: policy.certificationStatusRule ?? null,
    retrainingRule: policy.retrainingRule ?? null,
    restrictionRule: policy.restrictionRule ?? null,
    recertificationRule: policy.recertificationRule ?? null,
    reviewReasons,
    status: reviewReasons.length ? "certification_threshold_policy_review_required" : "certification_threshold_policy_complete",
  };
}

export function buildCertificationAudit(packs = certificationPacks, items = goldLibraryItems, targets = OCTOBER_RELEASE_TARGETS, options = {}) {
  const modelJudgeViolations = items.filter((item) => item.modelJudgeAcceptedAsGold || !item.humanAdjudicated);
  const submittedThresholdPolicyRows = (options.certificationThresholdPolicies ?? [])
    .map((policy) => normalizeCertificationThresholdPolicy(policy, "submitted_workflow_certification_threshold_policy"))
    .filter(Boolean);
  const seedThresholdPolicyRows = [normalizeCertificationThresholdPolicy(defaultCertificationThresholdPolicy(options.releaseId ?? "october-2026-demo"), "seed_certification_threshold_policy")];
  const activeThresholdPolicy = submittedThresholdPolicyRows.find((row) => row.reviewReasons.length === 0) ?? seedThresholdPolicyRows[0];
  const thresholdPolicyReviewRows = submittedThresholdPolicyRows.filter((row) => row.reviewReasons.length);
  const certificationRecordEvidence = buildSubmittedCertificationRecordEvidence(
    options.releaseId ?? "october-2026-demo",
    options.certificationRecords ?? [],
    packs,
    items,
    activeThresholdPolicy,
  );
  return {
    id: "certification-audit-october-2026",
    targetGoldLibraryItems: targets.goldLibraryItems,
    loadedGoldLibraryItems: items.length,
    goldLibraryStatus: items.length >= targets.goldLibraryItems ? "pass" : "incomplete",
    modelJudgeGoldViolations: modelJudgeViolations.map((item) => item.id),
    trainingExposureOnly: items.every((item) => item.splitExposure === "training_qa_only" && item.protectedSplitExcluded),
    packs: packs.map((pack) => ({
      id: pack.id,
      raterTier: pack.raterTier,
      rubricVersion: pack.rubricVersion,
      totalRequiredItems: pack.requiredItems.gold + pack.requiredItems.duplicates + pack.requiredItems.hardAmbiguity,
      requiredItems: pack.requiredItems,
      clusterIsolationStatus:
        pack.hiddenBenchmarkClusterOverlap.length === 0 && pack.protectedValidationClusterOverlap.length === 0 ? "pass" : "blocked",
      recertificationPolicy: pack.recertificationPolicy,
      status: pack.status,
    })),
    certificationThresholdPolicyRows: [...seedThresholdPolicyRows, ...submittedThresholdPolicyRows],
    activeCertificationThresholdPolicy: activeThresholdPolicy,
    activeCertificationThresholdPolicyId: activeThresholdPolicy?.id ?? null,
    requiredCertificationThresholds: REQUIRED_CERTIFICATION_THRESHOLDS,
    requiredCertificationRemediationRules: REQUIRED_CERTIFICATION_REMEDIATION_RULES,
    requiredCertificationCadencePolicy: REQUIRED_CERTIFICATION_CADENCE_POLICY,
    thresholdPolicyReviewRows,
    thresholdPolicyReleaseUseStatus: !submittedThresholdPolicyRows.length
      ? "seed_certification_threshold_policy_active"
      : thresholdPolicyReviewRows.length
        ? "submitted_certification_threshold_policy_review_required"
        : "submitted_certification_threshold_policy_active",
    certificationRecordEvidence,
  };
}

export function buildSubmittedCertificationRecordEvidence(
  releaseId,
  submittedRecords = [],
  packs = certificationPacks,
  items = goldLibraryItems,
  activeThresholdPolicy = normalizeCertificationThresholdPolicy(defaultCertificationThresholdPolicy(releaseId), "seed_certification_threshold_policy"),
) {
  const packById = new Map(packs.map((pack) => [pack.id, pack]));
  const itemById = new Map(items.map((item) => [item.id, item]));
  const rows = submittedRecords.map((record) => normalizeSubmittedCertificationRecord(record, packById, itemById, activeThresholdPolicy)).filter(Boolean);
  const reviewRows = rows.filter(
    (row) =>
      row.packStatus !== "known_live_certification_pack" ||
      row.rubricStatus !== "certification_record_matches_pack_rubric" ||
      row.protectedSplitConflictStatus !== "protected_split_excluded_training_exposure_acknowledged" ||
      row.goldCoverageStatus !== "submitted_gold_ids_present" ||
      row.thresholdPolicyStatus !== "certification_threshold_policy_matched" ||
      row.scoreStatus !== "certification_scores_within_policy" ||
      row.retrainingStatus !== "no_targeted_retraining_flags" ||
      row.tierUnlockStatus !== "tier_unlocked_recorded",
  );
  return {
    id: `certification-record-evidence-${releaseId}`,
    releaseId,
    submittedRecordCount: rows.length,
    certifiedRecordCount: rows.filter((row) => row.recordStatus === "certified_or_tier_unlocked").length,
    protectedSplitConflictReviewCount: rows.filter((row) => row.protectedSplitConflictStatus !== "protected_split_excluded_training_exposure_acknowledged").length,
    targetedRetrainingRecordCount: rows.filter((row) => row.targetedRetrainingFlags.length > 0).length,
    rows,
    reviewRows,
    policy: {
      protectedSplitRule:
        "Submitted CertificationRecord artifacts must declare certification-pack training exposure, protected-split conflict checks, and rater acknowledgement before they count as gatekeeping evidence.",
      scoreRule:
        "Submitted custom weighted loss, pairwise error, duplicate inconsistency, and per-dimension calibration fields are release evidence only when they stay inside the certification policy thresholds or explicitly route to retraining/restriction review.",
      modelJudgeRule: "Certification records can document human gatekeeping only; they do not turn model-judge outputs into gold labels.",
      activeCertificationThresholdPolicyId: activeThresholdPolicy?.id ?? null,
      thresholds: certificationThresholdValues(activeThresholdPolicy),
    },
    releaseUseStatus: !rows.length
      ? "no_submitted_certification_records"
      : reviewRows.length
        ? "submitted_certification_records_require_review"
        : "submitted_certification_records_gatekeeping_evidence_complete",
  };
}

function normalizeSubmittedCertificationRecord(record, packById, itemById, activeThresholdPolicy) {
  if (!record?.id || !record.raterId) return null;
  const packId = record.packId ?? record.packVersion;
  const pack = packById.get(packId);
  const thresholds = certificationThresholdValues(activeThresholdPolicy);
  const activeThresholdPolicyId = activeThresholdPolicy?.id ?? null;
  const certificationThresholdPolicyId = record.certificationThresholdPolicyId ?? record.thresholdPolicyId ?? null;
  const goldItemIds = optionalStringArray(record.goldItemIds) ?? [];
  const duplicateItemIds = optionalStringArray(record.duplicateItemIds) ?? [];
  const hardAmbiguityItemIds = optionalStringArray(record.hardAmbiguityItemIds) ?? [];
  const referencedItemIds = uniqueStrings([...goldItemIds, ...duplicateItemIds, ...hardAmbiguityItemIds]);
  const missingItemIds = referencedItemIds.filter((itemId) => !itemById.has(itemId));
  const protectedSplitConflictCheck = record.protectedSplitConflictCheck ?? record.protectedSplitConflictStatus ?? null;
  const protectedSplitConflictStatus =
    protectedSplitConflictCheck === "training_exposure_only_no_hidden_or_validation_overlap" && record.trainingExposureAcknowledged === true
      ? "protected_split_excluded_training_exposure_acknowledged"
      : "protected_split_conflict_review_required";
  const customWeightedLoss = numberOrNull(record.customWeightedLoss);
  const pairwiseError = numberOrNull(record.pairwiseError);
  const duplicateInconsistency = numberOrNull(record.duplicateInconsistency ?? record.duplicateConsistencyMeanAbsDiff);
  const targetedRetrainingFlags = optionalStringArray(record.targetedRetrainingFlags) ?? [];
  const perDimensionCalibrationError =
    record.perDimensionCalibrationError ?? record.perDimensionCalibrationErrorProfile ?? record.dimensionMeanAbsError ?? {};
  const dimensionReviewFlags = Object.entries(perDimensionCalibrationError)
    .filter(([, value]) => typeof value === "number" && value > thresholds.perDimensionCalibrationErrorMax)
    .map(([dimension]) => dimension);
  const scoreStatus =
    (customWeightedLoss === null || customWeightedLoss <= thresholds.customWeightedLossMax) &&
    (pairwiseError === null || pairwiseError <= thresholds.pairwiseErrorMax) &&
    (duplicateInconsistency === null || duplicateInconsistency <= thresholds.duplicateInconsistencyMax) &&
    dimensionReviewFlags.length === 0
      ? "certification_scores_within_policy"
      : "certification_score_review_required";
  const thresholdPolicyStatus =
    certificationThresholdPolicyId === activeThresholdPolicyId ? "certification_threshold_policy_matched" : "certification_threshold_policy_review_required";
  const tierUnlocked = record.tierUnlocked ?? record.tier_unlocked ?? null;
  return {
    recordId: record.id,
    recordSource: "submitted_workflow_certification_record",
    raterId: record.raterId,
    packId,
    certificationThresholdPolicyId,
    activeCertificationThresholdPolicyId: activeThresholdPolicyId,
    thresholdPolicyStatus,
    thresholdsApplied: thresholds,
    packStatus: pack?.status === "live" ? "known_live_certification_pack" : "unknown_or_inactive_certification_pack",
    rubricVersion: record.rubricVersion ?? null,
    packRubricVersion: pack?.rubricVersion ?? null,
    rubricCurrent: pack ? record.rubricVersion === pack.rubricVersion : false,
    rubricStatus: pack && record.rubricVersion === pack.rubricVersion ? "certification_record_matches_pack_rubric" : "certification_record_rubric_review_required",
    goldItemIds,
    duplicateItemIds,
    hardAmbiguityItemIds,
    missingItemIds,
    goldCoverageStatus: missingItemIds.length ? "submitted_gold_ids_missing_from_library" : "submitted_gold_ids_present",
    protectedSplitConflictCheck,
    trainingExposureAcknowledged: record.trainingExposureAcknowledged === true,
    protectedSplitConflictStatus,
    recertificationReason: record.recertificationReason ?? null,
    customWeightedLoss,
    pairwiseError,
    duplicateInconsistency,
    perDimensionCalibrationError,
    dimensionReviewFlags,
    scoreStatus,
    targetedRetrainingFlags: uniqueStrings([...targetedRetrainingFlags, ...dimensionReviewFlags]),
    retrainingStatus:
      targetedRetrainingFlags.length || dimensionReviewFlags.length ? "targeted_retraining_flags_present" : "no_targeted_retraining_flags",
    tierUnlocked,
    tierUnlockStatus: tierUnlocked ? "tier_unlocked_recorded" : "tier_unlock_missing",
    timestamp: record.timestamp ?? record.createdAt ?? record.submittedAt ?? null,
    recordStatus:
      tierUnlocked &&
      pack?.status === "live" &&
      record.rubricVersion === pack.rubricVersion &&
      protectedSplitConflictStatus === "protected_split_excluded_training_exposure_acknowledged" &&
      missingItemIds.length === 0 &&
      thresholdPolicyStatus === "certification_threshold_policy_matched" &&
      scoreStatus === "certification_scores_within_policy" &&
      !targetedRetrainingFlags.length
        ? "certified_or_tier_unlocked"
        : "review_required",
  };
}

export function buildReleaseGoldLibraryItems(submittedGoldItems = [], positionList = positions, baseItems = goldLibraryItems) {
  const positionClusterById = new Map(positionList.map((position) => [position.id, position.clusterId]));
  const itemsById = new Map(baseItems.map((item) => [item.id, item]));
  submittedGoldItems.forEach((item) => {
    if (!item || typeof item !== "object" || !item.id) return;
    const base = itemsById.get(item.id) ?? {};
    itemsById.set(item.id, normalizeSubmittedGoldItem(item, positionClusterById, base));
  });
  return [...itemsById.values()];
}

function normalizeSubmittedGoldItem(item, positionClusterById, base = {}) {
  const hasHumanAdjudicationEvidence =
    item.humanAdjudicated === true || Boolean(item.adjudicatedRatings || item.adjudicatedScores || item.adjudicationRationale);
  const protectedSplitExcluded =
    item.protectedSplitExcluded ?? item.protectedEvaluationExclusion ?? item.excludedFromProtectedEvaluation ?? base.protectedSplitExcluded ?? false;
  return {
    ...base,
    ...item,
    id: item.id,
    clusterId:
      item.clusterId ??
      item.positionClusterId ??
      positionClusterById.get(item.positionId) ??
      base.clusterId ??
      item.itemId ??
      item.id,
    rubricVersion: item.rubricVersion ?? base.rubricVersion ?? CURRENT_RUBRIC_VERSION,
    itemType: item.itemType ?? base.itemType ?? "gold",
    splitExposure: item.splitExposure ?? base.splitExposure ?? "training_qa_only",
    humanAdjudicated: hasHumanAdjudicationEvidence,
    modelJudgeAcceptedAsGold: item.modelJudgeAcceptedAsGold === true,
    protectedSplitExcluded: protectedSplitExcluded === true,
  };
}

export function buildProtectedSplitIsolationReport(
  releaseId,
  positionList = positions,
  packs = certificationPacks,
  goldItems = goldLibraryItems,
  options = {},
) {
  const protectedSplits = options.protectedSplits ?? ["internal_validation", "hidden_benchmark"];
  const protectedSplitSet = new Set(protectedSplits);
  const exceptionRows = (options.deprotectionExceptions ?? []).map((exception, index) => ({
    id: exception.id ?? `deprotection-exception-${index + 1}`,
    clusterId: exception.clusterId,
    fromSplit: exception.fromSplit ?? "unknown",
    toSplit: exception.toSplit ?? "unknown",
    loggedAt: exception.loggedAt ?? null,
    reason: exception.reason ?? "not recorded",
    excludedFromOrdinaryHiddenBenchmarkClaims: exception.excludedFromOrdinaryHiddenBenchmarkClaims === true,
    status:
      exception.clusterId && exception.excludedFromOrdinaryHiddenBenchmarkClaims === true
        ? "logged_excluded_from_ordinary_hidden_benchmark_claims"
        : "logged_but_not_excluded_from_ordinary_hidden_benchmark_claims",
  }));
  const exceptionsByCluster = exceptionRows.reduce((acc, exception) => {
    acc[exception.clusterId] ??= [];
    acc[exception.clusterId].push(exception);
    return acc;
  }, {});
  const clusters = positionList.reduce((acc, position) => {
    acc[position.clusterId] ??= [];
    acc[position.clusterId].push(position);
    return acc;
  }, {});
  const clusterRows = Object.entries(clusters)
    .map(([clusterId, clusterPositions]) => {
      const splits = [...new Set(clusterPositions.map((position) => position.split))].sort();
      const protectedClusterSplits = splits.filter((split) => protectedSplitSet.has(split));
      const ordinarySplits = splits.filter((split) => !protectedSplitSet.has(split));
      const crossSplit = splits.length > 1;
      const protectedCrossSplit = crossSplit && protectedClusterSplits.length > 0;
      const clusterExceptions = exceptionsByCluster[clusterId] ?? [];
      const validException = clusterExceptions.some((exception) => exception.excludedFromOrdinaryHiddenBenchmarkClaims);
      return {
        clusterId,
        positionIds: clusterPositions.map((position) => position.id).sort(),
        splits,
        protectedSplits: protectedClusterSplits,
        ordinarySplits,
        crossSplit,
        protectedCrossSplit,
        deprotectionExceptionIds: clusterExceptions.map((exception) => exception.id),
        ordinaryHiddenBenchmarkClaimExcluded: protectedCrossSplit,
        isolationStatus: protectedCrossSplit
          ? validException
            ? "deprotection_exception_logged_excluded"
            : "blocked_unlogged_protected_cross_split"
          : "pass",
      };
    })
    .sort((a, b) => a.clusterId.localeCompare(b.clusterId));
  const protectedClusterIds = new Set(
    clusterRows.filter((row) => row.protectedSplits.length > 0).map((row) => row.clusterId),
  );
  const packRows = packs.map((pack) => {
    const hiddenOverlap = pack.hiddenBenchmarkClusterOverlap ?? [];
    const validationOverlap = pack.protectedValidationClusterOverlap ?? [];
    const overlapClusterIds = [...new Set([...hiddenOverlap, ...validationOverlap])].sort();
    const validExceptionCount = overlapClusterIds.filter((clusterId) =>
      (exceptionsByCluster[clusterId] ?? []).some((exception) => exception.excludedFromOrdinaryHiddenBenchmarkClaims),
    ).length;
    return {
      packId: pack.id,
      raterTier: pack.raterTier,
      exposureClass: pack.exposureClass,
      clusterIsolationPolicy: pack.clusterIsolationPolicy,
      hiddenBenchmarkClusterOverlap: hiddenOverlap,
      protectedValidationClusterOverlap: validationOverlap,
      overlapClusterIds,
      deprotectionExceptionCount: validExceptionCount,
      isolationStatus:
        overlapClusterIds.length === 0
          ? "pass"
          : validExceptionCount === overlapClusterIds.length
            ? "deprotection_exception_logged_excluded"
            : "blocked_gold_certification_protected_overlap",
    };
  });
  const goldRows = goldItems.map((item) => {
    const protectedOverlap = protectedClusterIds.has(item.clusterId);
    const validException = (exceptionsByCluster[item.clusterId] ?? []).some((exception) => exception.excludedFromOrdinaryHiddenBenchmarkClaims);
    return {
      itemId: item.id,
      clusterId: item.clusterId,
      itemType: item.itemType,
      splitExposure: item.splitExposure,
      protectedSplitExcluded: item.protectedSplitExcluded === true,
      protectedClusterOverlap: protectedOverlap,
      isolationStatus:
        item.splitExposure === "training_qa_only" && item.protectedSplitExcluded === true && !protectedOverlap
          ? "pass"
          : protectedOverlap && validException
            ? "deprotection_exception_logged_excluded"
            : "blocked_gold_protected_overlap",
    };
  });
  const protectedCrossSplitRows = clusterRows.filter((row) => row.protectedCrossSplit);
  const unloggedProtectedCrossSplitRows = protectedCrossSplitRows.filter((row) => row.isolationStatus === "blocked_unlogged_protected_cross_split");
  const blockedPackRows = packRows.filter((row) => row.isolationStatus === "blocked_gold_certification_protected_overlap");
  const blockedGoldRows = goldRows.filter((row) => row.isolationStatus === "blocked_gold_protected_overlap");
  const ordinaryHiddenBenchmarkClaimExcludedRows = [
    ...protectedCrossSplitRows.map((row) => ({
      kind: "position_cluster",
      id: row.clusterId,
      splits: row.splits,
      reason: row.deprotectionExceptionIds.length
        ? "deprotection_exception_logged"
        : "unlogged_protected_cross_split_overlap",
      claimUse: "excluded_from_ordinary_hidden_benchmark_claims",
    })),
    ...packRows
      .filter((row) => row.overlapClusterIds.length > 0)
      .map((row) => ({
        kind: "certification_pack",
        id: row.packId,
        overlapClusterIds: row.overlapClusterIds,
        reason: "training_exposure_overlaps_protected_cluster",
        claimUse: "excluded_from_ordinary_hidden_benchmark_claims",
      })),
    ...goldRows
      .filter((row) => row.protectedClusterOverlap)
      .map((row) => ({
        kind: "gold_item",
        id: row.itemId,
        clusterId: row.clusterId,
        reason: "training_exposure_overlaps_protected_cluster",
        claimUse: "excluded_from_ordinary_hidden_benchmark_claims",
      })),
  ];
  const blockingIssueCount = unloggedProtectedCrossSplitRows.length + blockedPackRows.length + blockedGoldRows.length;
  return {
    id: `protected-split-isolation-${releaseId}`,
    releaseId,
    protectedSplits,
    policy: {
      protectedSplitRule:
        "Position clusters cannot straddle protected evaluation and public/training splits unless a deprotection exception is logged and excluded from ordinary hidden-benchmark claims.",
      goldCertificationExposureRule:
        "Gold, duplicate, and hard-ambiguity certification items are training exposure and cannot overlap hidden-benchmark/protected-validation clusters without recertification or deprotection review.",
      ordinaryClaimExclusionRule:
        "Any protected cross-split or deprotected cluster is removed from ordinary hidden-benchmark denominators and claim language until reviewed.",
    },
    counts: {
      positionClusterCount: clusterRows.length,
      crossSplitClusterCount: clusterRows.filter((row) => row.crossSplit).length,
      protectedCrossSplitClusterCount: protectedCrossSplitRows.length,
      unloggedProtectedCrossSplitClusterCount: unloggedProtectedCrossSplitRows.length,
      deprotectionExceptionCount: exceptionRows.length,
      certificationPackOverlapCount: packRows.filter((row) => row.overlapClusterIds.length > 0).length,
      goldProtectedOverlapCount: goldRows.filter((row) => row.protectedClusterOverlap).length,
      ordinaryClaimExcludedCount: ordinaryHiddenBenchmarkClaimExcludedRows.length,
    },
    clusterRows,
    protectedCrossSplitRows,
    deprotectionExceptionRows: exceptionRows,
    packRows,
    goldRows,
    ordinaryHiddenBenchmarkClaimExcludedRows,
    releaseUseStatus:
      blockingIssueCount > 0
        ? "protected_split_isolation_review_required"
        : ordinaryHiddenBenchmarkClaimExcludedRows.length > 0 || exceptionRows.length > 0
          ? "protected_split_exceptions_logged_excluded_from_claims"
          : "protected_split_cluster_isolation_pass",
  };
}

export function scoreCertificationAttempt(attempt, packs = certificationPacks, thresholdPolicy = null) {
  const pack = packs.find((item) => item.id === attempt.packId);
  if (!pack) throw new Error(`Unknown certification pack: ${attempt.packId}`);
  const thresholds = certificationThresholdValues(thresholdPolicy);
  const completion = {
    gold: attempt.goldItemsCompleted ?? 0,
    duplicates: attempt.duplicateItemsCompleted ?? 0,
    hardAmbiguity: attempt.hardAmbiguityItemsCompleted ?? 0,
  };
  const completionPass =
    completion.gold >= pack.requiredItems.gold &&
    completion.duplicates >= pack.requiredItems.duplicates &&
    completion.hardAmbiguity >= pack.requiredItems.hardAmbiguity;
  const dimensionMeanAbsError = Object.fromEntries(
    RUBRIC_DIMENSIONS.map((dimension) => {
      const values = (attempt.itemResults ?? [])
        .map((result) => result.dimensionErrors?.[dimension])
        .filter((value) => typeof value === "number" && Number.isFinite(value));
      return [dimension, values.length ? round(mean(values)) : null];
    }),
  );
  const validDimensionValues = Object.values(dimensionMeanAbsError).filter((value) => typeof value === "number");
  const meanAbsError = validDimensionValues.length ? round(mean(validDimensionValues)) : null;
  const targetedRetrainingFlags = Object.entries(dimensionMeanAbsError)
    .filter(([, value]) => typeof value === "number" && value > thresholds.perDimensionCalibrationErrorMax)
    .map(([dimension]) => dimension);
  const restrictionFlags = [];
  if ((dimensionMeanAbsError.correctness ?? 0) > thresholds.restrictionDimensionErrorMax) restrictionFlags.push("hold_correctness_sensitive_assignments");
  if ((dimensionMeanAbsError.clarity ?? 0) > thresholds.restrictionDimensionErrorMax) restrictionFlags.push("hold_low_clarity_workflows");
  if ((dimensionMeanAbsError.dead_weight ?? 0) > thresholds.restrictionDimensionErrorMax) restrictionFlags.push("hold_obfuscation_dead_weight_items");
  if ((attempt.duplicateConsistencyMeanAbsDiff ?? 1) > thresholds.duplicateInconsistencyMax) restrictionFlags.push("duplicate_consistency_review_required");
  if (!attempt.hardAmbiguityReviewPass) restrictionFlags.push("hard_ambiguity_review_required");

  const rubricCurrent = attempt.rubricVersion === pack.rubricVersion;
  const passed =
    completionPass &&
    rubricCurrent &&
    meanAbsError !== null &&
    meanAbsError <= thresholds.meanAbsErrorMax &&
    targetedRetrainingFlags.length === 0 &&
    restrictionFlags.length === 0;
  return {
    attemptId: attempt.id,
    raterId: attempt.raterId,
    packId: pack.id,
    rubricVersion: attempt.rubricVersion,
    status: passed ? "certified" : completionPass ? "restricted_pending_retraining" : "incomplete",
    completion,
    requiredItems: pack.requiredItems,
    completionPass,
    rubricCurrent,
    duplicateConsistencyMeanAbsDiff: attempt.duplicateConsistencyMeanAbsDiff,
    hardAmbiguityReviewPass: Boolean(attempt.hardAmbiguityReviewPass),
    certificationThresholdPolicyId: thresholdPolicy?.id ?? null,
    thresholdsApplied: thresholds,
    meanAbsError,
    dimensionMeanAbsError,
    targetedRetrainingFlags,
    restrictionFlags,
    recertificationRequired: !rubricCurrent,
  };
}

export function buildRaterCertificationReport(raterId, attempts = seedCertificationAttempts, packs = certificationPacks, thresholdPolicy = null) {
  const scoredAttempts = attempts.filter((attempt) => attempt.raterId === raterId).map((attempt) => scoreCertificationAttempt(attempt, packs, thresholdPolicy));
  const latestAttempt = scoredAttempts.at(-1) ?? null;
  return {
    id: `certification-report-${raterId}`,
    raterId,
    generatedAt: new Date().toISOString(),
    certified: latestAttempt?.status === "certified",
    currentStatus: latestAttempt?.status ?? "not_started",
    latestAttempt,
    attemptCount: scoredAttempts.length,
    attemptHistory: scoredAttempts,
    certificationThresholdPolicyId: thresholdPolicy?.id ?? null,
    thresholdsApplied: certificationThresholdValues(thresholdPolicy),
    availablePacks: packs.map((pack) => ({
      id: pack.id,
      raterTier: pack.raterTier,
      rubricVersion: pack.rubricVersion,
      totalRequiredItems: pack.requiredItems.gold + pack.requiredItems.duplicates + pack.requiredItems.hardAmbiguity,
      requiredItems: pack.requiredItems,
      recertificationPolicy: pack.recertificationPolicy,
    })),
  };
}

export function buildRubricVersionDriftReport(
  releaseId,
  labelSnapshot,
  ratings = seedRatings,
  certificationAttempts = seedCertificationAttempts,
  packs = certificationPacks,
  goldItems = goldLibraryItems,
  currentRubricVersion = CURRENT_RUBRIC_VERSION,
) {
  const ratingRubricVersionCounts = countBy(ratings, "rubricVersion");
  const ratingRubricVersions = Object.keys(ratingRubricVersionCounts).filter(Boolean).sort();
  const labelSnapshotRubricVersion = labelSnapshot?.rubricVersion ?? null;
  const mixedRatingVersions = ratingRubricVersions.length > 1;
  const snapshotRubricCurrent = labelSnapshotRubricVersion === null || labelSnapshotRubricVersion === currentRubricVersion;
  const mixedRubricSnapshotStatus =
    mixedRatingVersions || !snapshotRubricCurrent
      ? "mixed_or_noncurrent_rubric_snapshot_disclosed"
      : "single_rubric_version_current";

  const packRows = packs.map((pack) => {
    const current = pack.rubricVersion === currentRubricVersion;
    return {
      packId: pack.id,
      rubricVersion: pack.rubricVersion,
      current,
      recertificationPolicy: pack.recertificationPolicy,
      reviewAction: current ? "current_pack_no_review_required" : "material_change_requires_recertification_or_grandfathering_review",
    };
  });
  const goldItemRows = goldItems.map((item) => {
    const current = item.rubricVersion === currentRubricVersion;
    return {
      itemId: item.id,
      itemType: item.itemType,
      rubricVersion: item.rubricVersion,
      current,
      humanAdjudicated: Boolean(item.humanAdjudicated),
      modelJudgeAcceptedAsGold: Boolean(item.modelJudgeAcceptedAsGold),
      reviewAction: current ? "current_gold_no_review_required" : "gold_item_recertification_or_grandfathering_review_required",
    };
  });
  const raterCalibrationRows = certificationAttempts.map((attempt) => {
    const scored = scoreCertificationAttempt(attempt, packs);
    const pack = packs.find((item) => item.id === attempt.packId);
    const currentRubricAligned = scored.rubricVersion === currentRubricVersion && pack?.rubricVersion === currentRubricVersion;
    return {
      attemptId: scored.attemptId,
      raterId: scored.raterId,
      packId: scored.packId,
      rubricVersion: scored.rubricVersion,
      packRubricVersion: pack?.rubricVersion ?? null,
      currentRubricAligned,
      status: scored.status,
      meanAbsError: scored.meanAbsError,
      dimensionMeanAbsError: scored.dimensionMeanAbsError,
      targetedRetrainingFlags: scored.targetedRetrainingFlags,
      restrictionFlags: scored.restrictionFlags,
      recertificationRequired: scored.recertificationRequired || !currentRubricAligned,
      reviewAction: currentRubricAligned
        ? "current_attempt_calibration_applies"
        : "material_change_requires_recertification_or_grandfathering_review",
    };
  });
  const reviewRows = [
    ...packRows.filter((row) => !row.current).map((row) => ({ kind: "certification_pack", id: row.packId, action: row.reviewAction })),
    ...goldItemRows.filter((row) => !row.current).map((row) => ({ kind: "gold_item", id: row.itemId, action: row.reviewAction })),
    ...raterCalibrationRows
      .filter((row) => row.recertificationRequired)
      .map((row) => ({ kind: "rater_certification_attempt", id: row.attemptId, raterId: row.raterId, action: row.reviewAction })),
  ];
  const retrainingRows = raterCalibrationRows.filter((row) => row.targetedRetrainingFlags.length > 0);
  const restrictionRows = raterCalibrationRows.filter((row) => row.restrictionFlags.length > 0);
  return {
    id: `rubric-version-drift-${releaseId}`,
    releaseId,
    currentRubricVersion,
    labelSnapshotId: labelSnapshot?.id ?? null,
    labelSnapshotRubricVersion,
    generatedAt: new Date().toISOString(),
    policy: {
      materialChangeRule:
        "Material rubric-version changes require certification-pack, gold-item, and rater-attempt recertification or an explicit grandfathering review before release-critical use.",
      mixedRubricRule: "Label snapshots and release reports disclose mixed or non-current rubric versions rather than silently aggregating them.",
      calibrationRule:
        "Certification and drift reports preserve per-dimension calibration error, targeted retraining flags, restriction flags, and recertification requirements.",
    },
    ratingRubricVersionCounts,
    mixedRubricSnapshotStatus,
    packRows,
    goldItemRows,
    raterCalibrationRows,
    reviewRows,
    counts: {
      ratingRowCount: ratings.length,
      ratingRubricVersionCount: ratingRubricVersions.length,
      certificationPackCount: packRows.length,
      goldItemCount: goldItemRows.length,
      raterCalibrationAttemptCount: raterCalibrationRows.length,
      recertificationOrGrandfatheringReviewCount: reviewRows.length,
      raterAttemptRecertificationRequiredCount: raterCalibrationRows.filter((row) => row.recertificationRequired).length,
      ratersWithTargetedRetrainingFlags: new Set(retrainingRows.map((row) => row.raterId)).size,
      ratersWithRestrictionFlags: new Set(restrictionRows.map((row) => row.raterId)).size,
    },
    releaseUseStatus: reviewRows.length
      ? "rubric_version_recertification_review_required"
      : retrainingRows.length || restrictionRows.length
        ? "rater_retraining_or_restriction_flags_active"
        : mixedRubricSnapshotStatus === "mixed_or_noncurrent_rubric_snapshot_disclosed"
          ? "mixed_rubric_snapshot_disclosed"
          : "rubric_version_drift_controls_current",
  };
}

const REQUIRED_SUBMITTED_RIGHTS_RECORD_FIELDS = [
  "id",
  "releaseId",
  "rightsClearancePolicyId",
  "artifactId",
  "artifactKind",
  "sourceOrigin",
  "legalBasis",
  "clearanceStandard",
  "evidenceArtifactIds",
  "licenseType",
  "rightsStatus",
  "releaseScope",
  "legalReviewJurisdiction",
  "thirdPartyContentCheck",
  "takedownOrRemovalSlaDays",
  "reviewerId",
  "reviewedAt",
  "sourceLanguage",
  "translationRoute",
  "taskFormat",
  "sourceDomainSuitability",
  "removalPolicy",
];
const SUBMITTED_RIGHTS_STATUS_FRAGMENTS = ["allowed", "cleared"];
const SUBMITTED_RIGHTS_RELEASE_SCOPE_FRAGMENTS = ["public", "training", "internal", "hidden", "benchmark"];
const RIGHTS_CLEARANCE_POLICY_VERSION = "rights-clearance-rlhf90-v1";
const REQUIRED_RIGHTS_LEGAL_BASES = [
  "project_owned",
  "public_domain",
  "open_license",
  "explicit_permission",
  "fair_use_memo",
  "internal_only_restricted",
];
const REQUIRED_RIGHTS_EVIDENCE_BY_LEGAL_BASIS = {
  project_owned: ["authorship_attestation", "contributor_license_or_assignment", "third_party_content_check"],
  public_domain: ["public_domain_basis", "jurisdiction_or_publication_date", "source_url_or_archive"],
  open_license: ["license_identifier", "license_text_or_url", "attribution_requirements", "commercial_derivative_benchmark_use_allowed"],
  explicit_permission: ["permission_grant", "permitted_release_scopes", "revocation_or_expiry_terms"],
  fair_use_memo: ["factor_analysis", "excerpt_minimization", "public_release_risk_review", "fallback_removal_plan"],
  internal_only_restricted: ["internal_use_basis", "raw_public_release_block", "access_control_plan"],
};
const REQUIRED_RIGHTS_SCOPE_STANDARDS = {
  public: "explicit_public_export_public_summary_and_attribution_allowed",
  training: "training_or_model_improvement_export_allowed_without_provider_training_conflict",
  hidden_benchmark: "internal_hidden_benchmark_use_allowed_raw_public_release_blocked",
  internal: "internal_research_review_and_adjudication_use_allowed",
};
const REQUIRED_RIGHTS_TAKEDOWN_SLA_DAYS = 14;

function defaultRightsClearancePolicy(releaseId) {
  return {
    id: `rights-clearance-policy-${releaseId}`,
    policyVersion: RIGHTS_CLEARANCE_POLICY_VERSION,
    allowedLegalBases: REQUIRED_RIGHTS_LEGAL_BASES,
    requiredEvidenceByLegalBasis: REQUIRED_RIGHTS_EVIDENCE_BY_LEGAL_BASIS,
    releaseScopeStandards: REQUIRED_RIGHTS_SCOPE_STANDARDS,
    takedownOrRemovalSlaDays: REQUIRED_RIGHTS_TAKEDOWN_SLA_DAYS,
    publicReleaseRule:
      "public or training export requires project-owned, public-domain, open-license, explicit-permission, or approved fair-use memo evidence with attribution and removal plan",
    hiddenBenchmarkRule:
      "hidden-benchmark use may rely on internal-only restricted clearance only when raw public release is blocked and access control is documented",
    reviewerIndependenceRule: "rights reviewer must be independent from item author when legal basis is fair-use memo or explicit permission",
    frozenAt: "2026-10-01T00:00:00.000Z",
  };
}

export function auditProvenanceRights(exportKind = "public", positionList = positions, records = provenanceRightsRecords) {
  const includedSplits = allowedSplitsForExport(exportKind);
  const includedPositions = positionList.filter((position) => includedSplits.includes(position.split));
  const recordsByPosition = new Map(records.map((record) => [record.positionId, record]));
  const missingRecords = [];
  const releaseScopeFailures = [];
  const unclearedRecords = [];
  const submittedRightsRecordContractFailures = [];
  includedPositions.forEach((position) => {
    const record = recordsByPosition.get(position.id);
    if (!record) {
      missingRecords.push(position.id);
      return;
    }
    if (!record.releaseScopes.includes(exportKind)) releaseScopeFailures.push(position.id);
    if (!isRightsStatusAllowed(exportKind, record.rightsStatus)) unclearedRecords.push(position.id);
    if (record.submittedRightsRecord && record.submittedRightsRecordContractViolations?.length) {
      submittedRightsRecordContractFailures.push({
        positionId: position.id,
        recordId: record.id,
        contractViolations: record.submittedRightsRecordContractViolations,
      });
    }
  });
  return {
    id: `${exportKind}-provenance-rights-audit`,
    exportKind,
    includedSplits,
    checkedPositionCount: includedPositions.length,
    missingRecords,
    releaseScopeFailures,
    unclearedRecords,
    submittedRightsRecordContractFailures,
    status: missingRecords.length || releaseScopeFailures.length || unclearedRecords.length || submittedRightsRecordContractFailures.length ? "blocked" : "pass",
    adaptedSourceFieldsPresent: records.every(
      (record) => record.sourceLanguage && record.translationRoute && record.taskFormat && record.sourceDomainSuitability,
    ),
  };
}

export function buildReleaseRightsRecords(submittedRightsRecords = [], baseRecords = provenanceRightsRecords) {
  const recordsByPosition = new Map(baseRecords.map((record) => [record.positionId, record]));
  submittedRightsRecords.forEach((record) => {
    if (!record || typeof record !== "object") return;
    const positionId = record.positionId ?? parsePositionIdFromItemId(record.artifactId) ?? parsePositionIdFromItemId(record.itemId) ?? record.artifactId;
    if (!positionId || typeof positionId !== "string") return;
    const base = recordsByPosition.get(positionId) ?? {};
    recordsByPosition.set(positionId, normalizeSubmittedRightsRecord(record, positionId, base));
  });
  return [...recordsByPosition.values()];
}

function normalizeSubmittedRightsRecord(record, positionId, base = {}) {
  const releaseScopes = normalizeRightsReleaseScopes(record, base);
  const contractViolations = submittedRightsRecordContractViolations(record);
  return {
    ...base,
    ...record,
    id: record.id ?? base.id ?? `rights-${positionId}`,
    positionId,
    rightsStatus: normalizeRightsStatus(record.rightsStatus, releaseScopes, base.rightsStatus),
    releaseScopes,
    sourceLanguage: record.sourceLanguage ?? base.sourceLanguage ?? "unknown",
    translationRoute: record.translationRoute ?? base.translationRoute ?? "unknown",
    taskFormat: record.taskFormat ?? record.sourceTaskFormat ?? base.taskFormat ?? "unknown",
    sourceDomainSuitability: record.sourceDomainSuitability ?? base.sourceDomainSuitability ?? "unknown",
    singleTopicConcentration: record.singleTopicConcentration ?? base.singleTopicConcentration ?? "unknown",
    lsatDerived: record.lsatDerived ?? base.lsatDerived ?? false,
    clearedAt: record.clearedAt ?? record.reviewedAt ?? base.clearedAt ?? null,
    submittedRightsRecord: true,
    submittedRightsRecordContractViolations: contractViolations,
  };
}

function submittedRightsRecordContractViolations(record) {
  const missingFields = REQUIRED_SUBMITTED_RIGHTS_RECORD_FIELDS.filter((field) => !hasRequiredValue(record[field]));
  const rightsStatus = String(record.rightsStatus ?? "").toLowerCase();
  const releaseScope = String(record.releaseScope ?? "").toLowerCase();
  const legalBasis = record.legalBasis ?? null;
  const evidenceArtifactIds = normalizeStringArray(record.evidenceArtifactIds);
  const missingBasisEvidence = (REQUIRED_RIGHTS_EVIDENCE_BY_LEGAL_BASIS[legalBasis] ?? []).filter((evidenceKey) => !evidenceArtifactIds.includes(evidenceKey));
  return [
    ...missingFields,
    REQUIRED_RIGHTS_LEGAL_BASES.includes(legalBasis) ? null : "legalBasis",
    missingBasisEvidence.length ? `evidenceArtifactIds:${missingBasisEvidence.join(",")}` : null,
    record.takedownOrRemovalSlaDays === REQUIRED_RIGHTS_TAKEDOWN_SLA_DAYS ? null : "takedownOrRemovalSlaDays",
    SUBMITTED_RIGHTS_STATUS_FRAGMENTS.some((fragment) => rightsStatus.includes(fragment))
      ? null
      : "rightsStatus:allowed_or_cleared",
    SUBMITTED_RIGHTS_RELEASE_SCOPE_FRAGMENTS.some((fragment) => releaseScope.includes(fragment))
      ? null
      : "releaseScope:release_scope_class",
  ].filter(Boolean);
}

function normalizeRightsClearancePolicy(policy, rowSource) {
  const id = policy?.id ?? policy?.rightsClearancePolicyId;
  if (!id) return null;
  const allowedLegalBases = normalizeStringArray(policy.allowedLegalBases);
  const requiredEvidenceByLegalBasis =
    policy.requiredEvidenceByLegalBasis && typeof policy.requiredEvidenceByLegalBasis === "object" && !Array.isArray(policy.requiredEvidenceByLegalBasis)
      ? policy.requiredEvidenceByLegalBasis
      : {};
  const releaseScopeStandards =
    policy.releaseScopeStandards && typeof policy.releaseScopeStandards === "object" && !Array.isArray(policy.releaseScopeStandards)
      ? policy.releaseScopeStandards
      : {};
  const missingLegalBases = REQUIRED_RIGHTS_LEGAL_BASES.filter((basis) => !allowedLegalBases.includes(basis));
  const missingEvidenceKeys = Object.entries(REQUIRED_RIGHTS_EVIDENCE_BY_LEGAL_BASIS).flatMap(([basis, requiredEvidence]) => {
    const observed = normalizeStringArray(requiredEvidenceByLegalBasis[basis]);
    const missing = requiredEvidence.filter((evidenceKey) => !observed.includes(evidenceKey));
    return missing.length ? [`${basis}:${missing.join(",")}`] : [];
  });
  const missingScopeStandards = Object.keys(REQUIRED_RIGHTS_SCOPE_STANDARDS).filter((scope) => !Object.hasOwn(releaseScopeStandards, scope));
  const reviewReasons = [
    (policy.policyVersion ?? policy.version) === RIGHTS_CLEARANCE_POLICY_VERSION ? null : `policyVersion:${RIGHTS_CLEARANCE_POLICY_VERSION}`,
    missingLegalBases.length ? `allowedLegalBases:${missingLegalBases.join(",")}` : null,
    missingEvidenceKeys.length ? `requiredEvidenceByLegalBasis:${missingEvidenceKeys.join(";")}` : null,
    stableJsonKey(releaseScopeStandards) === stableJsonKey(REQUIRED_RIGHTS_SCOPE_STANDARDS) ? null : "releaseScopeStandards",
    missingScopeStandards.length ? `releaseScopeStandards:${missingScopeStandards.join(",")}` : null,
    policy.takedownOrRemovalSlaDays === REQUIRED_RIGHTS_TAKEDOWN_SLA_DAYS ? null : "takedownOrRemovalSlaDays",
    policyMentions(policy.publicReleaseRule, ["public", "training", "evidence", "removal"]) ? null : "publicReleaseRule",
    policyMentions(policy.hiddenBenchmarkRule, ["hidden", "raw public release", "access control"]) ? null : "hiddenBenchmarkRule",
    policyMentions(policy.reviewerIndependenceRule, ["independent"]) ? null : "reviewerIndependenceRule",
    requiredPromptFieldReason("frozenAt", policy.frozenAt),
  ].filter(Boolean);
  return {
    id,
    rowSource,
    policyVersion: policy.policyVersion ?? policy.version ?? null,
    allowedLegalBases,
    requiredEvidenceByLegalBasis,
    releaseScopeStandards,
    takedownOrRemovalSlaDays: policy.takedownOrRemovalSlaDays ?? null,
    publicReleaseRule: policy.publicReleaseRule ?? null,
    hiddenBenchmarkRule: policy.hiddenBenchmarkRule ?? null,
    reviewerIndependenceRule: policy.reviewerIndependenceRule ?? null,
    reviewReasons,
    status: reviewReasons.length ? "rights_clearance_policy_review_required" : "rights_clearance_policy_complete",
  };
}

function hasRequiredValue(value) {
  if (Array.isArray(value)) return value.length > 0;
  if (typeof value === "string") return value.trim().length > 0;
  return value !== null && value !== undefined;
}

function normalizeRightsReleaseScopes(record, base = {}) {
  if (Array.isArray(record.releaseScopes) && record.releaseScopes.length) return [...new Set(record.releaseScopes.map(normalizeReleaseScope).filter(Boolean))];
  if (typeof record.releaseScope === "string" && record.releaseScope) {
    const value = record.releaseScope.toLowerCase();
    if (value.includes("hidden") || value.includes("benchmark")) return mergeRightsScopes(base.releaseScopes, ["hidden_benchmark", "internal"]);
    if (value.includes("public")) return mergeRightsScopes(base.releaseScopes, ["public", "internal"]);
    if (value.includes("training")) return mergeRightsScopes(base.releaseScopes, ["training", "internal"]);
    if (value.includes("internal")) return mergeRightsScopes(base.releaseScopes, ["internal"]);
  }
  const status = String(record.rightsStatus ?? "").toLowerCase();
  if (status.includes("hidden") || status.includes("benchmark")) return mergeRightsScopes(base.releaseScopes, ["hidden_benchmark", "internal"]);
  if (status.includes("public")) return mergeRightsScopes(base.releaseScopes, ["public", "internal"]);
  if (status.includes("training")) return mergeRightsScopes(base.releaseScopes, ["training", "internal"]);
  if (status.includes("internal")) return mergeRightsScopes(base.releaseScopes, ["internal"]);
  return base.releaseScopes ?? [];
}

function mergeRightsScopes(baseScopes = [], inferredScopes = []) {
  return [...new Set([...baseScopes, ...inferredScopes].map(normalizeReleaseScope).filter(Boolean))];
}

function normalizeReleaseScope(scope) {
  if (scope === "hidden_benchmark_candidate") return "hidden_benchmark";
  if (scope === "public_export") return "public";
  if (scope === "training_export") return "training";
  if (["public", "training", "internal", "hidden_benchmark"].includes(scope)) return scope;
  return null;
}

function normalizeRightsStatus(status, releaseScopes, baseStatus) {
  if (!status) return baseStatus ?? "rights_status_missing";
  if (status === "public_export_allowed" || status === "training_export_allowed") return "cleared";
  if (status === "hidden_benchmark_export_allowed" || status === "hidden_benchmark_allowed" || status === "restricted_benchmark_export_allowed") {
    return releaseScopes.includes("public") || releaseScopes.includes("training") || baseStatus === "cleared" ? "cleared" : "cleared_restricted_benchmark";
  }
  if (status === "cleared_internal") return "cleared_internal_only";
  if (status === "cleared" && releaseScopes.includes("hidden_benchmark")) return "cleared";
  return status;
}

function buildRightsReviewEvidenceReport(
  releaseId,
  positionList = positions,
  rightsRecords = provenanceRightsRecords,
  rightsReviews = [],
  rightsClearancePolicies = [],
) {
  const positionById = new Map(positionList.map((position) => [position.id, position]));
  const rightsRecordByPosition = new Map(rightsRecords.map((record) => [record.positionId, record]));
  const submittedPolicyRows = rightsClearancePolicies
    .map((policy) => normalizeRightsClearancePolicy(policy, "submitted_workflow_rights_clearance_policy"))
    .filter(Boolean);
  const seedPolicyRows = [normalizeRightsClearancePolicy(defaultRightsClearancePolicy(releaseId), "seed_rights_clearance_policy")];
  const activePolicy = submittedPolicyRows.find((row) => row.reviewReasons.length === 0) ?? seedPolicyRows[0];
  const rows = rightsReviews.map((review) => normalizeRightsReviewEvidenceRow(review, positionById, rightsRecordByPosition, activePolicy)).filter(Boolean);
  const policyReviewRows = submittedPolicyRows.filter((row) => row.reviewReasons.length);
  const reviewRows = rows.filter((row) => row.reviewReasons.length);
  return {
    id: `rights-review-evidence-${releaseId}`,
    releaseId,
    generatedAt: new Date().toISOString(),
    policy: {
      requiredArtifact: "RightsReview",
      releaseRule:
        "Submitted rights reviews must name the reviewed position or item, reviewer, status, and release scope, and must be matched by a current RightsRecord before they count as release evidence.",
      nonOverrideRule: "RightsReview actions do not broaden release scopes unless a matching RightsRecord is also present.",
    },
    rightsClearancePolicyRows: [...seedPolicyRows, ...submittedPolicyRows],
    requiredLegalBases: REQUIRED_RIGHTS_LEGAL_BASES,
    requiredEvidenceByLegalBasis: REQUIRED_RIGHTS_EVIDENCE_BY_LEGAL_BASIS,
    requiredReleaseScopeStandards: REQUIRED_RIGHTS_SCOPE_STANDARDS,
    requiredTakedownOrRemovalSlaDays: REQUIRED_RIGHTS_TAKEDOWN_SLA_DAYS,
    rows,
    counts: {
      submittedRightsClearancePolicyCount: submittedPolicyRows.length,
      submittedReviewCount: rows.length,
      completeReviewCount: rows.length - reviewRows.length,
      reviewRequiredCount: reviewRows.length + policyReviewRows.length,
      matchedRightsRecordCount: rows.filter((row) => row.matchedCurrentRightsRecord).length,
      unmatchedRightsRecordCount: rows.filter((row) => !row.matchedCurrentRightsRecord).length,
      releaseScopeCoveredCount: rows.filter((row) => row.releaseScopeCovered).length,
      rightsStatusCompatibleCount: rows.filter((row) => row.rightsStatusCompatible).length,
    },
    byReviewStatus: countBy(rows, "status"),
    byNormalizedRightsStatus: countBy(rows, "normalizedRightsStatus"),
    reviewRows: [
      ...policyReviewRows.map((row) => ({ artifactType: "rights_clearance_policy", artifactId: row.id, reviewReasons: row.reviewReasons })),
      ...reviewRows,
    ],
    releaseUseStatus: !rows.length
      ? "no_submitted_rights_reviews"
      : reviewRows.length || policyReviewRows.length
        ? "rights_review_evidence_review_required"
        : "submitted_rights_review_evidence_complete",
  };
}

function normalizeRightsReviewEvidenceRow(review, positionById, rightsRecordByPosition, activeRightsPolicy) {
  if (!review || typeof review !== "object") return null;
  const activePolicyId = activeRightsPolicy?.id ?? null;
  const artifactId = review.artifactId ?? review.itemId ?? null;
  const positionId =
    review.positionId ??
    parsePositionIdFromItemId(artifactId) ??
    (typeof artifactId === "string" && positionById.has(artifactId) ? artifactId : null);
  const rightsRecord = rightsRecordByPosition.get(positionId);
  const releaseScopes = normalizeRightsReleaseScopes(review, rightsRecord ?? {});
  const normalizedRightsStatus = normalizeRightsStatus(review.rightsStatus, releaseScopes, rightsRecord?.rightsStatus);
  const reviewerId = review.reviewerId ?? review.reviewedBy ?? review.createdBy ?? null;
  const releaseScopeCovered = Boolean(rightsRecord && releaseScopes.length && releaseScopes.every((scope) => rightsRecord.releaseScopes?.includes(scope)));
  const rightsStatusCompatible = Boolean(rightsRecord && releaseScopes.length && releaseScopes.every((scope) => isRightsStatusAllowed(scope, rightsRecord.rightsStatus)));
  const reviewReasons = [
    review.rightsClearancePolicyId === activePolicyId ? null : "rightsClearancePolicyId",
    positionId ? null : "positionId_or_itemId",
    positionId && !positionById.has(positionId) ? "position_not_in_current_corpus" : null,
    reviewerId ? null : "reviewerId",
    review.rightsStatus ? null : "rightsStatus",
    releaseScopes.length ? null : "releaseScope",
    rightsRecord ? null : "matching_rights_record",
    rightsRecord && rightsRecord.rightsClearancePolicyId !== activePolicyId ? "rightsRecordClearancePolicyId" : null,
    rightsRecord && !releaseScopeCovered ? "release_scope_not_covered_by_rights_record" : null,
    rightsRecord && !rightsStatusCompatible ? "rights_status_not_compatible_with_requested_scope" : null,
  ].filter(Boolean);
  return {
    id: review.id,
    rowSource: "submitted_workflow_rights_review",
    rightsClearancePolicyId: review.rightsClearancePolicyId ?? null,
    artifactId,
    positionId,
    itemId: review.itemId ?? null,
    reviewerId,
    rightsStatus: review.rightsStatus ?? null,
    normalizedRightsStatus,
    releaseScopes,
    rightsRecordId: rightsRecord?.id ?? null,
    rightsRecordClearancePolicyId: rightsRecord?.rightsClearancePolicyId ?? null,
    matchedCurrentRightsRecord: Boolean(rightsRecord),
    releaseScopeCovered,
    rightsStatusCompatible,
    reviewedAt: review.reviewedAt ?? review.createdAt ?? review.timestamp ?? null,
    reviewReasons,
    status: reviewReasons.length ? "rights_review_evidence_review_required" : "rights_review_evidence_complete",
  };
}

function buildAssignmentFlagEvidenceReport(releaseId, assignmentFlags = [], assignmentList = assignments) {
  const assignmentById = new Map(assignmentList.map((assignment) => [assignment.id, assignment]));
  const rows = assignmentFlags.map((flag) => normalizeAssignmentFlagEvidenceRow(flag, assignmentById)).filter(Boolean);
  const reviewRows = rows.filter((row) => row.reviewReasons.length);
  return {
    id: `assignment-flag-evidence-${releaseId}`,
    releaseId,
    generatedAt: new Date().toISOString(),
    policy: {
      requiredArtifact: "AssignmentFlag",
      releaseRule:
        "Assignment flags are blind-safe routing and review artifacts; they never count as ratings and must be linked to a current assignment with an accepted reason code.",
      allowedReasonCodes: ASSIGNMENT_FLAG_REASON_CODES,
    },
    rows,
    counts: {
      submittedFlagCount: rows.length,
      completeFlagCount: rows.length - reviewRows.length,
      reviewRequiredCount: reviewRows.length,
      knownAssignmentCount: rows.filter((row) => row.assignmentKnown).length,
      topicFitFlagCount: rows.filter((row) => row.reasonCode === "insufficient_topic_expertise").length,
      conflictOrExposureFlagCount: rows.filter((row) => ["conflict_or_prior_exposure", "source_recognition_or_prior_exposure"].includes(row.reasonCode)).length,
    },
    byReasonCode: countBy(rows, "reasonCode"),
    byQueueType: countBy(rows, "queueType"),
    reviewRows,
    releaseUseStatus: !rows.length
      ? "no_submitted_assignment_flags"
      : reviewRows.length
        ? "assignment_flag_evidence_review_required"
        : "submitted_assignment_flag_evidence_complete",
  };
}

function normalizeAssignmentFlagEvidenceRow(flag, assignmentById) {
  if (!flag || typeof flag !== "object") return null;
  const assignmentId = flag.assignmentId ?? flag.assignment_id ?? null;
  const assignment = assignmentById.get(assignmentId);
  const reasonCode = flag.reasonCode ?? flag.reason_code ?? null;
  const reviewReasons = [
    flag.id ? null : "id",
    assignmentId ? null : "assignmentId",
    assignmentId && !assignment ? "assignment_not_found" : null,
    flag.raterId ? null : "raterId",
    reasonCode ? null : "reasonCode",
    reasonCode && !ASSIGNMENT_FLAG_REASON_CODES.includes(reasonCode) ? "reasonCode:unsupported" : null,
    flag.positionId && assignment && flag.positionId !== assignment.positionId ? "positionId:assignment_mismatch" : null,
    flag.critiqueId && assignment && flag.critiqueId !== assignment.critiqueId ? "critiqueId:assignment_mismatch" : null,
  ].filter(Boolean);
  return {
    id: flag.id ?? null,
    rowSource: "submitted_workflow_assignment_flag",
    assignmentId,
    assignmentKnown: Boolean(assignment),
    positionId: flag.positionId ?? assignment?.positionId ?? null,
    critiqueId: flag.critiqueId ?? assignment?.critiqueId ?? null,
    raterId: flag.raterId ?? null,
    reasonCode,
    queueType: assignment?.queueType ?? null,
    assignmentExposure: assignment?.exposure ?? null,
    notesPresent: typeof flag.notes === "string" && flag.notes.trim().length > 0,
    blindSafeRoutingOnly: true,
    excludedFromRatingDenominator: true,
    reviewReasons,
    status: reviewReasons.length ? "assignment_flag_evidence_review_required" : "assignment_flag_evidence_complete",
  };
}

function buildAssignmentWorkflowEvidenceReport(releaseId, options = {}) {
  const linkedEvidence = {
    raterSessionById: new Map((options.raterSessions ?? []).map((session) => [session.id, session])),
    ratingContextSnapshotById: new Map((options.ratingContextSnapshots ?? []).map((snapshot) => [snapshot.id, snapshot])),
    workflowProfileById: new Map((options.ratingWorkflowProfiles ?? []).map((profile) => [profile.id, profile])),
    scoreInputPolicyById: new Map((options.scoreInputPolicies ?? []).map((policy) => [policy.id, policy])),
    assignmentDeclineByAssignmentId: new Map((options.assignmentDeclines ?? []).map((decline) => [decline.assignmentId, decline])),
  };
  const rows = (options.workflowAssignments ?? [])
    .map((assignment) => normalizeAssignmentWorkflowEvidenceRow(assignment, linkedEvidence))
    .filter(Boolean);
  const reviewRows = rows.filter((row) => row.reviewReasons.length);
  const reviewSections = rows.flatMap((row) =>
    row.reviewReasons.map((reason) => ({ artifactType: "assignment_workflow", artifactId: row.assignmentId, reason })),
  );
  return {
    id: `assignment-workflow-evidence-${releaseId}`,
    releaseId,
    generatedAt: new Date().toISOString(),
    evidenceRules: {
      eligibilityRule:
        "Submitted release-critical assignments must pass pre-rating self-screen, conflict, exposure-aware independent-blind eligibility, and safe-decline routing before serving.",
      blindingRule:
        "Source tags, validation membership, protected split state, model/peer/gold labels, and later same-position siblings must remain hidden before initial lock.",
      orderRule: "Same-position queues must record counterbalanced or randomized order, counterbalance bucket, order index, and prior/later sibling exposure state.",
      pacingRule: "Assignments must carry session workload metadata, current draft dependency state, and rater-session pacing evidence before supporting release claims.",
    },
    rows,
    reviewRows,
    reviewSections,
    byAssignmentType: countBy(rows, "assignmentType"),
    bySamePositionOrderPolicy: countBy(rows, "samePositionOrderPolicy"),
    bySessionPacingState: countBy(rows, "sessionPacingState"),
    counts: {
      submittedAssignmentCount: rows.length,
      completeAssignmentCount: rows.length - reviewRows.length,
      reviewRequiredAssignmentCount: reviewRows.length,
      linkedRaterSessionCount: rows.filter((row) => row.linkedRaterSessionStatus === "linked_rater_session_complete").length,
      linkedRatingContextSnapshotCount: rows.filter((row) => row.linkedRatingContextSnapshotStatus === "linked_rating_context_snapshot_complete").length,
      counterbalancedOrRandomizedOrderCount: rows.filter((row) => row.samePositionOrderStatus === "same_position_order_declared").length,
      blindInitialEligibleCount: rows.filter((row) => row.blindingEligibilityStatus === "blind_initial_eligibility_complete").length,
      currentDraftDependencyCount: rows.filter((row) => row.draftDependencyStaleStatus === "current").length,
    },
    releaseUseStatus: !rows.length
      ? "assignment_workflow_not_submitted"
      : reviewRows.length
        ? "assignment_workflow_evidence_review_required"
        : "submitted_assignment_workflow_evidence_complete",
  };
}

function normalizeAssignmentWorkflowEvidenceRow(assignment, linkedEvidence) {
  if (!assignment || typeof assignment !== "object") return null;
  const assignmentId = assignment.id ?? assignment.assignmentId ?? assignment.assignment_id;
  if (!assignmentId) return null;
  const raterSessionId = assignment.raterSessionId ?? assignment.rater_session_id ?? null;
  const ratingContextSnapshotId = assignment.ratingContextSnapshotId ?? assignment.rating_context_snapshot_id ?? null;
  const workflowProfileId = assignment.workflowProfileId ?? assignment.workflow_profile_id ?? null;
  const scoreInputPolicyId = assignment.scoreInputPolicyId ?? assignment.score_input_policy_id ?? null;
  const requiredUiPanelSet = normalizeStringArray(assignment.requiredUiPanelSet ?? assignment.required_ui_panel_set);
  const optionalUiPanelSet = normalizeStringArray(assignment.optionalUiPanelSet ?? assignment.optional_ui_panel_set);
  const siblingCritiquesSeenPriorIds = normalizeStringArray(assignment.siblingCritiquesSeenPriorIds ?? assignment.sibling_critiques_seen_prior_ids);
  const samePositionOrderPolicy = assignment.samePositionOrderPolicy ?? assignment.same_position_order_policy ?? null;
  const draftDependencyStaleStatus = assignment.draftDependencyStaleStatus ?? assignment.draft_dependency_stale_status ?? null;
  const sessionPacingState = assignment.sessionPacingState ?? assignment.session_pacing_state ?? null;
  const fatigueWarningState = assignment.fatigueWarningState ?? assignment.fatigue_warning_state ?? null;
  const linkedRaterSession = raterSessionId ? linkedEvidence.raterSessionById.get(raterSessionId) : null;
  const linkedRatingContextSnapshot = ratingContextSnapshotId ? linkedEvidence.ratingContextSnapshotById.get(ratingContextSnapshotId) : null;
  const linkedWorkflowProfile = workflowProfileId ? linkedEvidence.workflowProfileById.get(workflowProfileId) : null;
  const linkedScoreInputPolicy = scoreInputPolicyId ? linkedEvidence.scoreInputPolicyById.get(scoreInputPolicyId) : null;
  const linkedDecline = linkedEvidence.assignmentDeclineByAssignmentId.get(assignmentId) ?? null;
  const activeTimeSeconds = Number(assignment.activeTimeSeconds ?? assignment.active_time_seconds);
  const interruptionCount = Number(assignment.interruptionCount ?? assignment.interruption_count);
  const resumeCount = Number(assignment.resumeCount ?? assignment.resume_count);
  const positionOrderIndex = Number(assignment.positionOrderIndex ?? assignment.position_order_index);
  const siblingCritiquesSeenPriorCount = Number(assignment.siblingCritiquesSeenPriorCount ?? assignment.sibling_critiques_seen_prior_count);
  const reviewReasons = [
    requiredPromptFieldReason("raterId", assignment.raterId ?? assignment.rater_id),
    requiredPromptFieldReason("raterSessionId", raterSessionId),
    raterSessionId && !linkedRaterSession ? "raterSessionId:not_found" : null,
    requiredPromptFieldReason("positionId", assignment.positionId ?? assignment.position_id),
    requiredPromptFieldReason("critiqueId", assignment.critiqueId ?? assignment.critique_id),
    requiredPromptFieldReason("assignmentType", assignment.assignmentType ?? assignment.assignment_type),
    requiredPromptFieldReason("workflowProfileId", workflowProfileId),
    workflowProfileId && !linkedWorkflowProfile ? "workflowProfileId:not_found" : null,
    requiredPromptFieldReason("workflowProfileVersion", assignment.workflowProfileVersion ?? assignment.workflow_profile_version),
    requiredPromptFieldReason("scoreInputPolicyId", scoreInputPolicyId),
    scoreInputPolicyId && !linkedScoreInputPolicy ? "scoreInputPolicyId:not_found" : null,
    requiredUiPanelSet.length ? null : "requiredUiPanelSet",
    requiredUiPanelSet.includes("score_fields") ? null : "requiredUiPanelSet:score_fields",
    requiredUiPanelSet.includes("safe_decline") ? null : "requiredUiPanelSet:safe_decline",
    requiredUiPanelSet.includes("source_recognition") ? null : "requiredUiPanelSet:source_recognition",
    Array.isArray(assignment.optionalUiPanelSet ?? assignment.optional_ui_panel_set) ? null : "optionalUiPanelSet",
    assignment.preRatingSelfScreenStatus === "passed" ? null : "preRatingSelfScreenStatus",
    assignment.raterItemConflictCheckStatus === "no_conflict" ? null : "raterItemConflictCheckStatus",
    assignment.independentBlindEligibilityStatus === "eligible" ? null : "independentBlindEligibilityStatus",
    requiredPromptFieldReason("declineOrReassignmentStatus", assignment.declineOrReassignmentStatus ?? assignment.decline_or_reassignment_status),
    assignment.blindState === "blind_initial" ? null : "blindState",
    assignment.sourceTagVisibilityState === "hidden_before_initial_lock" ? null : "sourceTagVisibilityState",
    requiredPromptFieldReason("topicRoutingBasisAdminOnly", assignment.topicRoutingBasisAdminOnly ?? assignment.topic_routing_basis_admin_only),
    assignment.validationMembershipBlindToRater === true ? null : "validationMembershipBlindToRater",
    requiredPromptFieldReason("ratingContextSnapshotId", ratingContextSnapshotId),
    ratingContextSnapshotId && !linkedRatingContextSnapshot ? "ratingContextSnapshotId:not_found" : null,
    requiredPromptFieldReason("samePositionSessionId", assignment.samePositionSessionId ?? assignment.same_position_session_id),
    policyMentionsAny(samePositionOrderPolicy, ["counterbalanced", "randomized", "random"]) ? null : "samePositionOrderPolicy",
    requiredPromptFieldReason("orderCounterbalanceBucket", assignment.orderCounterbalanceBucket ?? assignment.order_counterbalance_bucket),
    Number.isFinite(positionOrderIndex) && positionOrderIndex >= 0 ? null : "positionOrderIndex",
    Number.isFinite(siblingCritiquesSeenPriorCount) && siblingCritiquesSeenPriorCount >= 0 ? null : "siblingCritiquesSeenPriorCount",
    Array.isArray(assignment.siblingCritiquesSeenPriorIds ?? assignment.sibling_critiques_seen_prior_ids) ? null : "siblingCritiquesSeenPriorIds",
    assignment.laterSiblingCritiquesAbsentAtSubmission === true ? null : "laterSiblingCritiquesAbsentAtSubmission",
    requiredPromptFieldReason("positionLengthBand", assignment.positionLengthBand ?? assignment.position_length_band),
    requiredPromptFieldReason("critiqueLengthBand", assignment.critiqueLengthBand ?? assignment.critique_length_band),
    requiredPromptFieldReason("expectedEffortBand", assignment.expectedEffortBand ?? assignment.expected_effort_band),
    requiredPromptFieldReason("startedAt", assignment.startedAt ?? assignment.started_at),
    Number.isFinite(activeTimeSeconds) && activeTimeSeconds >= 0 ? null : "activeTimeSeconds",
    requiredPromptFieldReason("idleGapSummary", assignment.idleGapSummary ?? assignment.idle_gap_summary),
    Number.isFinite(interruptionCount) && interruptionCount >= 0 ? null : "interruptionCount",
    requiredPromptFieldReason("draftAutosaveStatus", assignment.draftAutosaveStatus ?? assignment.draft_autosave_status),
    requiredPromptFieldReason("lastAutosavedAt", assignment.lastAutosavedAt ?? assignment.last_autosaved_at),
    draftDependencyStaleStatus === "current" ? null : "draftDependencyStaleStatus",
    Number.isFinite(resumeCount) && resumeCount >= 0 ? null : "resumeCount",
    requiredPromptFieldReason("sessionPacingState", sessionPacingState),
    requiredPromptFieldReason("fatigueWarningState", fatigueWarningState),
    linkedRaterSession && linkedRaterSession.raterId !== (assignment.raterId ?? assignment.rater_id) ? "raterSessionId:rater_mismatch" : null,
    requiredPromptFieldReason("uiMode", assignment.uiMode ?? assignment.ui_mode),
    requiredPromptFieldReason("rubricAnchorPanelVersion", assignment.rubricAnchorPanelVersion ?? assignment.rubric_anchor_panel_version),
    requiredPromptFieldReason("preSubmitLintPolicyVersion", assignment.preSubmitLintPolicyVersion ?? assignment.pre_submit_lint_policy_version),
  ].filter(Boolean);
  return {
    assignmentId,
    rowSource: "submitted_workflow_assignment",
    raterId: assignment.raterId ?? assignment.rater_id ?? null,
    raterSessionId,
    linkedRaterSessionStatus: linkedRaterSession ? "linked_rater_session_complete" : "linked_rater_session_missing",
    positionId: assignment.positionId ?? assignment.position_id ?? null,
    critiqueId: assignment.critiqueId ?? assignment.critique_id ?? null,
    assignmentType: assignment.assignmentType ?? assignment.assignment_type ?? null,
    workflowProfileId,
    linkedWorkflowProfileStatus: linkedWorkflowProfile ? "linked_workflow_profile_complete" : "linked_workflow_profile_missing",
    scoreInputPolicyId,
    linkedScoreInputPolicyStatus: linkedScoreInputPolicy ? "linked_score_input_policy_complete" : "linked_score_input_policy_missing",
    requiredUiPanelSet,
    optionalUiPanelSet,
    preRatingSelfScreenStatus: assignment.preRatingSelfScreenStatus ?? assignment.pre_rating_self_screen_status ?? null,
    raterItemConflictCheckStatus: assignment.raterItemConflictCheckStatus ?? assignment.rater_item_conflict_check_status ?? null,
    independentBlindEligibilityStatus: assignment.independentBlindEligibilityStatus ?? assignment.independent_blind_eligibility_status ?? null,
    declineOrReassignmentStatus: assignment.declineOrReassignmentStatus ?? assignment.decline_or_reassignment_status ?? null,
    linkedAssignmentDeclineId: linkedDecline?.id ?? null,
    blindState: assignment.blindState ?? assignment.blind_state ?? null,
    sourceTagVisibilityState: assignment.sourceTagVisibilityState ?? assignment.source_tag_visibility_state ?? null,
    validationMembershipBlindToRater: assignment.validationMembershipBlindToRater === true,
    blindingEligibilityStatus:
      assignment.blindState === "blind_initial" &&
      assignment.sourceTagVisibilityState === "hidden_before_initial_lock" &&
      assignment.validationMembershipBlindToRater === true &&
      assignment.independentBlindEligibilityStatus === "eligible"
        ? "blind_initial_eligibility_complete"
        : "blind_initial_eligibility_review_required",
    ratingContextSnapshotId,
    linkedRatingContextSnapshotStatus: linkedRatingContextSnapshot ? "linked_rating_context_snapshot_complete" : "linked_rating_context_snapshot_missing",
    samePositionSessionId: assignment.samePositionSessionId ?? assignment.same_position_session_id ?? null,
    samePositionOrderPolicy,
    samePositionOrderStatus: policyMentionsAny(samePositionOrderPolicy, ["counterbalanced", "randomized", "random"])
      ? "same_position_order_declared"
      : "same_position_order_review_required",
    orderCounterbalanceBucket: assignment.orderCounterbalanceBucket ?? assignment.order_counterbalance_bucket ?? null,
    positionOrderIndex: Number.isFinite(positionOrderIndex) ? positionOrderIndex : null,
    siblingCritiquesSeenPriorCount: Number.isFinite(siblingCritiquesSeenPriorCount) ? siblingCritiquesSeenPriorCount : null,
    siblingCritiquesSeenPriorIds,
    laterSiblingCritiquesAbsentAtSubmission: assignment.laterSiblingCritiquesAbsentAtSubmission === true,
    positionLengthBand: assignment.positionLengthBand ?? assignment.position_length_band ?? null,
    critiqueLengthBand: assignment.critiqueLengthBand ?? assignment.critique_length_band ?? null,
    expectedEffortBand: assignment.expectedEffortBand ?? assignment.expected_effort_band ?? null,
    activeTimeSeconds: Number.isFinite(activeTimeSeconds) ? activeTimeSeconds : null,
    interruptionCount: Number.isFinite(interruptionCount) ? interruptionCount : null,
    resumeCount: Number.isFinite(resumeCount) ? resumeCount : null,
    draftAutosaveStatus: assignment.draftAutosaveStatus ?? assignment.draft_autosave_status ?? null,
    draftDependencyStaleStatus,
    sessionPacingState,
    fatigueWarningState,
    uiMode: assignment.uiMode ?? assignment.ui_mode ?? null,
    reviewReasons,
    status: reviewReasons.length ? "assignment_workflow_evidence_review_required" : "assignment_workflow_evidence_complete",
  };
}

const REQUIRED_ACTIVE_LEARNING_SELECTION_AUDIT_FIELDS = [
  "id",
  "candidateBatchId",
  "positionId",
  "activeLearningSelectionPolicyId",
  "generatedOrIngestedCount",
  "judgedCount",
  "disagreementSelectedCount",
  "highRatedSelectedCount",
  "suspectedJudgeFalsePositiveCount",
  "humanSelectedForDiversityCount",
  "humanSelectedForSuitabilityCount",
  "humanSelectedForInterestingnessCount",
  "selectionThresholds",
  "rejectedCountByReason",
  "promotedToRatingCount",
];
const REQUIRED_ACTIVE_LEARNING_SELECTION_AUDIT_NUMBER_FIELDS = [
  "generatedOrIngestedCount",
  "judgedCount",
  "disagreementSelectedCount",
  "highRatedSelectedCount",
  "suspectedJudgeFalsePositiveCount",
  "humanSelectedForDiversityCount",
  "humanSelectedForSuitabilityCount",
  "humanSelectedForInterestingnessCount",
  "promotedToRatingCount",
];
export const ACTIVE_LEARNING_SELECTION_POLICY_VERSION = "active-learning-selection-rlhf90-v1";
export const REQUIRED_ACTIVE_LEARNING_SELECTION_THRESHOLDS = {
  judgeDisagreementDeltaMin: 0.25,
  highRatedOverallScoreMin: 0.7,
  suspectedJudgeFalsePositiveOverallMax: 0.35,
  modelJudgeCoverageShareMin: 0.2,
  promotedToRatingShareMax: 0.25,
  nearDuplicateRejectionShareReviewMin: 0.3,
  rightsUnclearRejectionShareReviewMin: 0.05,
  lowMarginalInformativenessRejectionShareReviewMin: 0.25,
};
export const REQUIRED_ACTIVE_LEARNING_HAND_SELECTION_QUOTAS = {
  diversitySelectedMin: 1,
  suitabilitySelectedMin: 1,
  interestingnessSelectedMin: 1,
  promotedPerBatchMin: 1,
};
export const REQUIRED_ACTIVE_LEARNING_SELECTION_REASON_CODES = [
  "judge_disagreement",
  "high_rated",
  "suspected_judge_false_positive",
  "human_diversity_selection",
  "human_suitability_selection",
  "human_interestingness_selection",
];
export const REQUIRED_ACTIVE_LEARNING_REJECTION_REASON_CODES = ["near_duplicate", "rights_unclear", "low_marginal_informativeness"];

function defaultActiveLearningSelectionPolicy(releaseId = "october-2026-demo") {
  return {
    id: `active-learning-selection-policy-${releaseId}`,
    policyVersion: ACTIVE_LEARNING_SELECTION_POLICY_VERSION,
    thresholds: REQUIRED_ACTIVE_LEARNING_SELECTION_THRESHOLDS,
    handSelectionQuotas: REQUIRED_ACTIVE_LEARNING_HAND_SELECTION_QUOTAS,
    selectionReasonCodes: REQUIRED_ACTIVE_LEARNING_SELECTION_REASON_CODES,
    rejectionReasonCodes: REQUIRED_ACTIVE_LEARNING_REJECTION_REASON_CODES,
    thresholdRule:
      "Judge-disagreement, high-rated, and suspected-false-positive selections use the frozen numeric thresholds before human hand-selection.",
    handSelectionQuotaRule:
      "Each active-learning batch needs at least one diversity, suitability, and interestingness hand-selection path before promoted-to-rating claims.",
    raterVisibilityRule:
      "Selection policy ids, judge thresholds, reason codes, and model-judge scores remain admin-only before initial rating lock.",
    lmcaSourceBoundary:
      "Project default active-learning thresholds and hand-selection quotas are frozen here; LMCA motivates active-learning denominator audits but does not state these exact platform values.",
    frozenAt: "2026-10-01T00:00:00.000Z",
  };
}

function activeLearningSelectionThresholdValues(policy) {
  const thresholds = policy?.thresholds && typeof policy.thresholds === "object" && !Array.isArray(policy.thresholds) ? policy.thresholds : {};
  return { ...REQUIRED_ACTIVE_LEARNING_SELECTION_THRESHOLDS, ...thresholds };
}

function normalizeActiveLearningSelectionPolicy(policy, rowSource) {
  const id = policy?.id ?? policy?.activeLearningSelectionPolicyId;
  if (!id) return null;
  const thresholds = policy.thresholds && typeof policy.thresholds === "object" && !Array.isArray(policy.thresholds) ? policy.thresholds : {};
  const handSelectionQuotas =
    policy.handSelectionQuotas && typeof policy.handSelectionQuotas === "object" && !Array.isArray(policy.handSelectionQuotas)
      ? policy.handSelectionQuotas
      : {};
  const selectionReasonCodes = normalizeStringArray(policy.selectionReasonCodes);
  const rejectionReasonCodes = normalizeStringArray(policy.rejectionReasonCodes);
  const missingThresholdKeys = Object.keys(REQUIRED_ACTIVE_LEARNING_SELECTION_THRESHOLDS).filter((key) => !Object.hasOwn(thresholds, key));
  const missingQuotaKeys = Object.keys(REQUIRED_ACTIVE_LEARNING_HAND_SELECTION_QUOTAS).filter((key) => !Object.hasOwn(handSelectionQuotas, key));
  const missingSelectionReasonCodes = REQUIRED_ACTIVE_LEARNING_SELECTION_REASON_CODES.filter((code) => !selectionReasonCodes.includes(code));
  const missingRejectionReasonCodes = REQUIRED_ACTIVE_LEARNING_REJECTION_REASON_CODES.filter((code) => !rejectionReasonCodes.includes(code));
  const reviewReasons = [
    (policy.policyVersion ?? policy.version) === ACTIVE_LEARNING_SELECTION_POLICY_VERSION
      ? null
      : `policyVersion:${ACTIVE_LEARNING_SELECTION_POLICY_VERSION}`,
    missingThresholdKeys.length ? `thresholds:${missingThresholdKeys.join(",")}` : null,
    stableJsonKey(thresholds) === stableJsonKey(REQUIRED_ACTIVE_LEARNING_SELECTION_THRESHOLDS) ? null : "thresholds",
    missingQuotaKeys.length ? `handSelectionQuotas:${missingQuotaKeys.join(",")}` : null,
    stableJsonKey(handSelectionQuotas) === stableJsonKey(REQUIRED_ACTIVE_LEARNING_HAND_SELECTION_QUOTAS) ? null : "handSelectionQuotas",
    missingSelectionReasonCodes.length ? `selectionReasonCodes:${missingSelectionReasonCodes.join(",")}` : null,
    missingRejectionReasonCodes.length ? `rejectionReasonCodes:${missingRejectionReasonCodes.join(",")}` : null,
    policyMentions(policy.thresholdRule, ["judge", "threshold"]) ? null : "thresholdRule",
    policyMentions(policy.handSelectionQuotaRule, ["diversity", "suitability", "interestingness"]) ? null : "handSelectionQuotaRule",
    policyMentions(policy.raterVisibilityRule, ["admin-only", "initial rating lock"]) ? null : "raterVisibilityRule",
    policyMentions(policy.lmcaSourceBoundary, ["project", "lmca"]) ? null : "lmcaSourceBoundary",
    requiredPromptFieldReason("frozenAt", policy.frozenAt),
  ].filter(Boolean);
  return {
    id,
    rowSource,
    policyVersion: policy.policyVersion ?? policy.version ?? null,
    thresholds,
    handSelectionQuotas,
    selectionReasonCodes,
    rejectionReasonCodes,
    thresholdRule: policy.thresholdRule ?? null,
    handSelectionQuotaRule: policy.handSelectionQuotaRule ?? null,
    raterVisibilityRule: policy.raterVisibilityRule ?? null,
    lmcaSourceBoundary: policy.lmcaSourceBoundary ?? null,
    frozenAt: policy.frozenAt ?? null,
    reviewReasons,
    status: reviewReasons.length ? "active_learning_selection_policy_review_required" : "active_learning_selection_policy_complete",
  };
}

function buildActiveLearningSelectionPolicyEvidenceReport(releaseId, submittedPolicies = []) {
  const submittedRows = submittedPolicies
    .map((policy) => normalizeActiveLearningSelectionPolicy(policy, "submitted_workflow_active_learning_selection_policy"))
    .filter(Boolean);
  const seedRows = [normalizeActiveLearningSelectionPolicy(defaultActiveLearningSelectionPolicy(releaseId), "seed_active_learning_selection_policy")];
  const activePolicy = submittedRows.find((row) => row.reviewReasons.length === 0) ?? seedRows[0];
  const reviewRows = submittedRows.filter((row) => row.reviewReasons.length);
  return {
    id: `active-learning-selection-policy-evidence-${releaseId}`,
    releaseId,
    requiredThresholds: REQUIRED_ACTIVE_LEARNING_SELECTION_THRESHOLDS,
    requiredHandSelectionQuotas: REQUIRED_ACTIVE_LEARNING_HAND_SELECTION_QUOTAS,
    requiredSelectionReasonCodes: REQUIRED_ACTIVE_LEARNING_SELECTION_REASON_CODES,
    requiredRejectionReasonCodes: REQUIRED_ACTIVE_LEARNING_REJECTION_REASON_CODES,
    policyRows: [...seedRows, ...submittedRows],
    activePolicy,
    activePolicyId: activePolicy?.id ?? null,
    reviewRows,
    counts: {
      submittedPolicyCount: submittedRows.length,
      reviewRequiredPolicyCount: reviewRows.length,
    },
    releaseUseStatus: !submittedRows.length
      ? "seed_active_learning_selection_policy_active"
      : reviewRows.length
        ? "submitted_active_learning_selection_policy_review_required"
        : "submitted_active_learning_selection_policy_active",
  };
}

export function buildActiveLearningAudit(batches = activeLearningBatches, submittedSelectionAudits = [], workflowArtifacts = {}) {
  const releaseId = workflowArtifacts.releaseId ?? "october-2026-demo";
  const selectionPolicyEvidence = buildActiveLearningSelectionPolicyEvidenceReport(releaseId, workflowArtifacts.activeLearningSelectionPolicies ?? []);
  const activeSelectionPolicy = selectionPolicyEvidence.activePolicy;
  const candidateWorkflowEvidence = buildCandidateWorkflowEvidence(workflowArtifacts, activeSelectionPolicy, selectionPolicyEvidence);
  const submittedBatches = submittedSelectionAudits
    .map((audit) => normalizeSubmittedActiveLearningSelectionAudit(audit, candidateWorkflowEvidence, activeSelectionPolicy, selectionPolicyEvidence))
    .filter(Boolean);
  const submittedSelectionAuditContractViolationRows = submittedBatches.filter((batch) => batch.selectionAuditContractViolations.length);
  const auditedBatchIds = new Set(submittedBatches.map((batch) => batch.id).filter(Boolean));
  const candidateWorkflowBatches = buildCandidateWorkflowActiveLearningBatches(candidateWorkflowEvidence, auditedBatchIds);
  const allBatches = [...batches, ...submittedBatches, ...candidateWorkflowBatches];
  const totals = ["generated", "ingested", "judged", "disagreementSelected", "highRated", "suspectedJudgeFalsePositive", "handSelected", "rejected", "promoted"].reduce(
    (acc, field) => {
      acc[field] = allBatches.reduce((sum, batch) => sum + batch[field], 0);
      return acc;
    },
    {},
  );
  const selectionReasonCounts = mergeCountMaps(allBatches.map((batch) => batch.selectionReasonCounts ?? {}));
  const rejectionReasonCounts = mergeCountMaps(allBatches.map((batch) => batch.rejectedCountByReason ?? {}));
  return {
    id: "active-learning-selection-denominator-audit",
    totals,
    submittedSelectionAuditCount: submittedBatches.length,
    submittedSelectionAuditIds: submittedBatches.map((batch) => batch.selectionAuditId),
    submittedSelectionAuditContractViolationCount: submittedSelectionAuditContractViolationRows.length,
    submittedSelectionAuditContractViolationRows,
    selectionPolicyEvidence,
    activeLearningSelectionPolicyId: selectionPolicyEvidence.activePolicyId,
    activeLearningSelectionPolicyReleaseUseStatus: selectionPolicyEvidence.releaseUseStatus,
    requiredSelectionThresholds: REQUIRED_ACTIVE_LEARNING_SELECTION_THRESHOLDS,
    requiredHandSelectionQuotas: REQUIRED_ACTIVE_LEARNING_HAND_SELECTION_QUOTAS,
    requiredSelectionReasonCodes: REQUIRED_ACTIVE_LEARNING_SELECTION_REASON_CODES,
    requiredRejectionReasonCodes: REQUIRED_ACTIVE_LEARNING_REJECTION_REASON_CODES,
    candidateWorkflowEvidence,
    candidateWorkflowContractViolationCount: candidateWorkflowEvidence.candidateWorkflowContractViolationCount ?? 0,
    derivedCandidateWorkflowBatchCount: candidateWorkflowBatches.length,
    acceptedCritiqueIds: [...new Set(allBatches.flatMap((batch) => batch.acceptedCritiqueIds))],
    blindingPass:
      candidateWorkflowEvidence.hiddenMetadataViolationCount === 0 &&
      allBatches.every((batch) => !batch.modelJudgeScoresVisibleToInitialRaters && batch.selectionReasonHiddenFromInitialRaters),
    selectionReasonCounts,
    rejectionReasonCounts,
    batches: allBatches.map((batch) => ({
      id: batch.id,
      selectionAuditId: batch.selectionAuditId ?? null,
      batchSource: batch.batchSource ?? "seed_active_learning_batch",
      generated: batch.generated,
      ingested: batch.ingested,
      judged: batch.judged,
      disagreementSelected: batch.disagreementSelected,
      highRated: batch.highRated,
      suspectedJudgeFalsePositive: batch.suspectedJudgeFalsePositive,
      handSelected: batch.handSelected,
      humanSelectedForDiversity: batch.humanSelectedForDiversity ?? null,
      humanSelectedForSuitability: batch.humanSelectedForSuitability ?? null,
      humanSelectedForInterestingness: batch.humanSelectedForInterestingness ?? null,
      rejected: batch.rejected,
      promoted: batch.promoted,
      activeLearningSelectionPolicyId: batch.activeLearningSelectionPolicyId ?? null,
      submittedActiveLearningSelectionPolicyId: batch.submittedActiveLearningSelectionPolicyId ?? null,
      selectionPolicyReleaseUseStatus: batch.selectionPolicyReleaseUseStatus ?? null,
      selectionThresholdsApplied: batch.selectionThresholdsApplied ?? REQUIRED_ACTIVE_LEARNING_SELECTION_THRESHOLDS,
      submittedSelectionThresholds: batch.submittedSelectionThresholds ?? null,
      handSelectionQuotasApplied: batch.handSelectionQuotasApplied ?? REQUIRED_ACTIVE_LEARNING_HAND_SELECTION_QUOTAS,
      selectionReasonCounts: batch.selectionReasonCounts ?? {},
      rejectedCountByReason: batch.rejectedCountByReason ?? {},
      selectionRates: {
        promotedFromGenerated: batch.generated ? round(batch.promoted / batch.generated) : null,
        handSelectedFromJudged: batch.judged ? round(batch.handSelected / batch.judged) : null,
      },
      selectionAuditContractStatus: batch.selectionAuditContractViolations?.length
        ? "selection_audit_contract_review_required"
        : batch.batchSource === "submitted_workflow_selection_audit"
          ? "selection_audit_contract_complete"
          : "not_submitted_selection_audit",
      selectionAuditContractViolations: batch.selectionAuditContractViolations ?? [],
    })),
    releaseUseStatus:
      submittedSelectionAuditContractViolationRows.length
        ? "active_learning_selection_audit_review_required"
        : candidateWorkflowEvidence.candidateWorkflowContractViolationCount
          ? "candidate_workflow_evidence_review_required"
          : submittedBatches.length || batches.length
            ? "active_learning_selection_denominators_audited"
            : "active_learning_selection_denominators_missing",
  };
}

function normalizeSubmittedActiveLearningSelectionAudit(
  audit,
  candidateWorkflowEvidence = {},
  activeSelectionPolicy = normalizeActiveLearningSelectionPolicy(defaultActiveLearningSelectionPolicy("october-2026-demo"), "seed_active_learning_selection_policy"),
  selectionPolicyEvidence = null,
) {
  if (!audit || typeof audit !== "object") return null;
  const rejectedCountByReason = audit.rejectedCountByReason ?? audit.rejectionReasonCounts ?? {};
  const selectionReasonCounts = {
    ...(audit.selectionReasonCounts ?? audit.humanSelectionReasonCounts ?? {}),
  };
  if (audit.disagreementSelectedCount !== undefined) selectionReasonCounts.judge_disagreement = numberOrDefault(audit.disagreementSelectedCount, 0);
  if (audit.highRatedSelectedCount !== undefined) selectionReasonCounts.high_rated = numberOrDefault(audit.highRatedSelectedCount, 0);
  if (audit.suspectedJudgeFalsePositiveCount !== undefined) {
    selectionReasonCounts.suspected_judge_false_positive = numberOrDefault(audit.suspectedJudgeFalsePositiveCount, 0);
  }
  if (audit.humanSelectedForDiversityCount !== undefined) {
    selectionReasonCounts.human_diversity_selection = numberOrDefault(audit.humanSelectedForDiversityCount, 0);
  }
  if (audit.humanSelectedForSuitabilityCount !== undefined) {
    selectionReasonCounts.human_suitability_selection = numberOrDefault(audit.humanSelectedForSuitabilityCount, 0);
  }
  if (audit.humanSelectedForInterestingnessCount !== undefined) {
    selectionReasonCounts.human_interestingness_selection = numberOrDefault(audit.humanSelectedForInterestingnessCount, 0);
  }
  const batchId = audit.candidateBatchId ?? audit.batchId ?? audit.id;
  const workflowRow = (candidateWorkflowEvidence.rows ?? []).find((row) => row.candidateBatchId === batchId);
  const selectionThresholds =
    audit.selectionThresholds && typeof audit.selectionThresholds === "object" && !Array.isArray(audit.selectionThresholds)
      ? audit.selectionThresholds
      : {};
  const activeThresholds = activeLearningSelectionThresholdValues(activeSelectionPolicy);
  const selectionAuditContractChecks = submittedActiveLearningSelectionAuditContractChecks(audit, activeSelectionPolicy);
  const selectionAuditContractViolations = selectionAuditContractChecks.filter((check) => check.status !== "pass");
  const humanSelectedForDiversity = numberOrDefault(audit.humanSelectedForDiversityCount, 0);
  const humanSelectedForSuitability = numberOrDefault(audit.humanSelectedForSuitabilityCount, 0);
  const humanSelectedForInterestingness = numberOrDefault(audit.humanSelectedForInterestingnessCount, 0);
  return {
    id: batchId,
    selectionAuditId: audit.id ?? null,
    positionId: audit.positionId ?? workflowRow?.positionId ?? null,
    batchSource: "submitted_workflow_selection_audit",
    activeLearningSelectionPolicyId: activeSelectionPolicy?.id ?? null,
    submittedActiveLearningSelectionPolicyId: audit.activeLearningSelectionPolicyId ?? audit.selectionPolicyId ?? null,
    selectionPolicyReleaseUseStatus: selectionPolicyEvidence?.releaseUseStatus ?? null,
    selectionThresholdsApplied: activeThresholds,
    submittedSelectionThresholds: selectionThresholds,
    handSelectionQuotasApplied: activeSelectionPolicy?.handSelectionQuotas ?? REQUIRED_ACTIVE_LEARNING_HAND_SELECTION_QUOTAS,
    generated: numberOrDefault(audit.generatedOrIngestedCount ?? audit.generatedOrIngestedCandidateCount ?? audit.generatedCount, 0),
    ingested: numberOrDefault(audit.ingestedCount, 0),
    judged: numberOrDefault(audit.judgedCount ?? audit.judgedCandidateCount, 0),
    disagreementSelected: numberOrDefault(audit.disagreementSelectedCount, 0),
    highRated: numberOrDefault(audit.highRatedSelectedCount ?? audit.highRatedCount, 0),
    suspectedJudgeFalsePositive: numberOrDefault(audit.suspectedJudgeFalsePositiveCount, 0),
    humanSelectedForDiversity,
    humanSelectedForSuitability,
    humanSelectedForInterestingness,
    handSelected: numberOrDefault(
      audit.handSelectedCount ?? audit.humanHandSelectedCount,
      humanSelectedForDiversity + humanSelectedForSuitability + humanSelectedForInterestingness,
    ),
    rejected: numberOrDefault(audit.rejectedCount, sumCountMap(rejectedCountByReason)),
    promoted: numberOrDefault(audit.promotedToRatingCount ?? audit.promotedCount, 0),
    acceptedCritiqueIds: uniqueStrings([...(audit.acceptedCritiqueIds ?? audit.promotedCritiqueIds ?? []), ...(workflowRow?.acceptedCritiqueIds ?? [])]),
    modelJudgeScoresVisibleToInitialRaters: audit.modelJudgeScoresVisibleToInitialRaters === true || workflowRow?.modelJudgeScoresVisibleToInitialRaters === true,
    selectionReasonHiddenFromInitialRaters: audit.selectionReasonHiddenFromInitialRaters !== false && workflowRow?.selectionReasonHiddenFromInitialRaters !== false,
    selectionReasonCounts,
    rejectedCountByReason,
    selectionAuditContractChecks,
    selectionAuditContractViolations,
  };
}

function submittedActiveLearningSelectionAuditContractChecks(audit, activeSelectionPolicy = null) {
  const requiredFieldChecks = REQUIRED_ACTIVE_LEARNING_SELECTION_AUDIT_FIELDS.map((field) => ({
    field,
    expected: "present",
    observed: audit?.[field] ?? null,
    status: hasRequiredValue(audit?.[field]) ? "pass" : "missing_required_field",
  }));
  const finiteNumberChecks = REQUIRED_ACTIVE_LEARNING_SELECTION_AUDIT_NUMBER_FIELDS.map((field) => ({
    field,
    expected: "finite_number",
    observed: audit?.[field] ?? null,
    status: Number.isFinite(Number(audit?.[field])) ? "pass" : "invalid_number",
  }));
  const rejectedCountByReasonCheck = {
    field: "rejectedCountByReason",
    expected: "object",
    observed: audit?.rejectedCountByReason ?? null,
    status: audit?.rejectedCountByReason && typeof audit.rejectedCountByReason === "object" && !Array.isArray(audit.rejectedCountByReason)
      ? "pass"
      : "invalid_object",
  };
  const selectionThresholds = audit?.selectionThresholds;
  const activeThresholds = activeLearningSelectionThresholdValues(activeSelectionPolicy);
  const thresholdPolicyCheck = {
    field: "activeLearningSelectionPolicyId",
    expected: activeSelectionPolicy?.id ?? null,
    observed: audit?.activeLearningSelectionPolicyId ?? audit?.selectionPolicyId ?? null,
    status:
      audit?.activeLearningSelectionPolicyId && activeSelectionPolicy?.id && audit.activeLearningSelectionPolicyId === activeSelectionPolicy.id
        ? "pass"
        : "selection_policy_mismatch",
  };
  const selectionThresholdCheck = {
    field: "selectionThresholds",
    expected: activeThresholds,
    observed: selectionThresholds ?? null,
    status:
      selectionThresholds && typeof selectionThresholds === "object" && !Array.isArray(selectionThresholds) && stableJsonKey(selectionThresholds) === stableJsonKey(activeThresholds)
        ? "pass"
        : "selection_thresholds_mismatch",
  };
  const rejectedReasonChecks = REQUIRED_ACTIVE_LEARNING_REJECTION_REASON_CODES.map((reason) => ({
    field: `rejectedCountByReason.${reason}`,
    expected: "present",
    observed: audit?.rejectedCountByReason?.[reason] ?? null,
    status: Number.isFinite(Number(audit?.rejectedCountByReason?.[reason])) ? "pass" : "missing_required_reason_count",
  }));
  return [...requiredFieldChecks, ...finiteNumberChecks, rejectedCountByReasonCheck, thresholdPolicyCheck, selectionThresholdCheck, ...rejectedReasonChecks];
}

const REQUIRED_CANDIDATE_BATCH_FIELDS = [
  "id",
  "positionId",
  "generatorSourceDescription",
  "promptTemplateVersion",
  "judgeModelSet",
  "generatedOrIngestedCandidateCount",
  "judgedCandidateCount",
  "candidatePoolDenominatorPolicy",
  "selectionPolicyVersion",
  "batchStatus",
  "createdAt",
];
const REQUIRED_CANDIDATE_CRITIQUE_FIELDS = [
  "id",
  "candidateBatchId",
  "positionId",
  "text",
  "sourceType",
  "generationRoute",
  "rightsStatus",
  "selectionReason",
  "nearDuplicateClusterId",
  "marginalInformativenessRationale",
  "reviewStatus",
];
const REQUIRED_MODEL_JUDGE_SCORE_FIELDS = [
  "id",
  "candidateId",
  "candidateBatchId",
  "judgeRequestedModelAlias",
  "judgeProvider",
  "judgeResolvedModelSnapshot",
  "promptVersion",
  "modelParameters",
  "aliasStabilityStatus",
  "rawOutput",
  "parseStatus",
  "overallScore",
  "disagreementStatistics",
  "timestamp",
];
const REQUIRED_MODEL_JUDGE_SCORE_SUBMISSION_FIELDS = ["id", "submittedScoreIds", "batchCoveragePolicy", "judgedCandidateCount", "submittedAt"];

function buildCandidateWorkflowEvidence({
  candidateBatches = [],
  candidateCritiques = [],
  modelJudgeScores = [],
  candidateBatchModelJudgeScoreSubmissions = [],
  candidateReviews = [],
  candidatePromotions = [],
} = {}, activeSelectionPolicy = null, selectionPolicyEvidence = null) {
  const activeThresholds = activeLearningSelectionThresholdValues(activeSelectionPolicy);
  const critiqueById = new Map(candidateCritiques.map((critique) => [critique.id, critique]));
  const batchRows = candidateBatches.map((batch) => {
    const batchId = batch.id;
    const candidateBatchContractChecks = submittedCandidateBatchContractChecks(batch);
    const candidateBatchContractViolations = candidateBatchContractChecks.filter((check) => check.status !== "pass");
    const batchCritiques = candidateCritiques.filter((critique) => critique.candidateBatchId === batchId || critique.batchId === batchId);
    const batchCandidateIds = new Set(batchCritiques.map((critique) => critique.id));
    const batchScores = modelJudgeScores.filter(
      (score) => score.candidateBatchId === batchId || score.batchId === batchId || batchCandidateIds.has(score.candidateId),
    );
    const scoreSubmissions = candidateBatchModelJudgeScoreSubmissions.filter((submission) => submission.candidateBatchId === batchId || submission.batchId === batchId);
    const candidateCritiqueContractViolationRows = batchCritiques
      .map((critique) => ({
        id: critique.id,
        contractViolations: submittedCandidateCritiqueContractChecks(critique).filter((check) => check.status !== "pass"),
      }))
      .filter((row) => row.contractViolations.length);
    const modelJudgeScoreContractViolationRows = batchScores
      .map((score) => ({
        id: score.id,
        candidateId: score.candidateId ?? null,
        contractViolations: submittedModelJudgeScoreContractChecks(score).filter((check) => check.status !== "pass"),
      }))
      .filter((row) => row.contractViolations.length);
    const scoreSubmissionContractViolationRows = scoreSubmissions
      .map((submission) => ({
        id: submission.id,
        contractViolations: submittedModelJudgeScoreSubmissionContractChecks(submission).filter((check) => check.status !== "pass"),
      }))
      .filter((row) => row.contractViolations.length);
    const reviews = candidateReviews.filter((review) => {
      const candidateId = review.candidateId ?? review.id;
      return batchCandidateIds.has(candidateId) || critiqueById.get(candidateId)?.candidateBatchId === batchId;
    });
    const promotions = candidatePromotions.filter((promotion) => {
      const candidateId = promotion.candidateId ?? promotion.generatedCritiqueId ?? promotion.id;
      return batchCandidateIds.has(candidateId) || critiqueById.get(candidateId)?.candidateBatchId === batchId;
    });
    const selectionReasonCounts = candidateSelectionReasonCounts(batchCritiques, reviews, batchScores);
    const acceptedCritiqueIds = uniqueStrings(promotions.map((promotion) => promotion.acceptedCritiqueId ?? promotion.promotedCritiqueId).filter(Boolean));
    const modelJudgeScoresVisibleToInitialRaters =
      batch.modelJudgeScoresVisibleToInitialRaters === true ||
      batchScores.some((score) => score.hiddenFromRatersBeforeInitialLock === false || score.modelJudgeScoresVisibleToInitialRaters === true) ||
      scoreSubmissions.some((submission) => submission.hiddenFromRatersBeforeInitialLock === false || submission.modelJudgeScoresVisibleToInitialRaters === true);
    const selectionReasonHiddenFromInitialRaters =
      batch.selectionReasonHiddenFromInitialRaters !== false &&
      batchCritiques.every((critique) => critique.selectionReasonVisibleToRatersBeforeInitialLock !== true) &&
      reviews.every((review) => review.selectionReasonHiddenFromInitialRaters !== false) &&
      promotions.every((promotion) => promotion.sourceMetadataHiddenFromRaters !== false);
    return {
      candidateBatchId: batchId,
      positionId: batch.positionId ?? null,
      candidateBatchStatus: batch.batchStatus ?? null,
      batchSource: "submitted_workflow_candidate_batch",
      activeLearningSelectionPolicyId: activeSelectionPolicy?.id ?? null,
      selectionPolicyReleaseUseStatus: selectionPolicyEvidence?.releaseUseStatus ?? null,
      selectionThresholdsApplied: activeThresholds,
      handSelectionQuotasApplied: activeSelectionPolicy?.handSelectionQuotas ?? REQUIRED_ACTIVE_LEARNING_HAND_SELECTION_QUOTAS,
      generated: numberOrDefault(batch.generatedOrIngestedCandidateCount ?? batch.generatedOrIngestedCount ?? batch.generatedCount, batchCritiques.length),
      ingested: numberOrDefault(batch.ingestedCount, 0),
      judged: numberOrDefault(
        batch.judgedCandidateCount ?? batch.judgedCount ?? firstDefined(scoreSubmissions.map((submission) => submission.judgedCandidateCount)) ?? batchScores.length,
        0,
      ),
      disagreementSelected: selectionReasonCounts.judge_disagreement ?? 0,
      highRated: batchScores.filter((score) => numberOrDefault(score.overallScore ?? score.score, 0) >= activeThresholds.highRatedOverallScoreMin).length,
      suspectedJudgeFalsePositive: selectionReasonCounts.suspected_judge_false_positive ?? 0,
      handSelected: reviews.filter((review) => /approved|selected|include/.test(String(review.reviewStatus ?? review.inclusionReason ?? ""))).length,
      rejected: reviews.filter((review) => /reject|exclude/.test(String(review.reviewStatus ?? ""))).length,
      promoted: promotions.length,
      acceptedCritiqueIds,
      modelJudgeScoresVisibleToInitialRaters,
      selectionReasonHiddenFromInitialRaters,
      selectionReasonCounts,
      rejectedCountByReason: {},
      candidateCritiqueCount: batchCritiques.length,
      modelJudgeScoreCount: batchScores.length,
      scoreSubmissionCount: scoreSubmissions.length,
      reviewCount: reviews.length,
      promotionCount: promotions.length,
      candidateBatchContractChecks,
      candidateBatchContractViolations,
      candidateBatchContractStatus: candidateBatchContractViolations.length
        ? "candidate_batch_contract_review_required"
        : "candidate_batch_contract_complete",
      candidateCritiqueContractViolationCount: candidateCritiqueContractViolationRows.length,
      candidateCritiqueContractViolationRows,
      modelJudgeScoreContractViolationCount: modelJudgeScoreContractViolationRows.length,
      modelJudgeScoreContractViolationRows,
      scoreSubmissionContractViolationCount: scoreSubmissionContractViolationRows.length,
      scoreSubmissionContractViolationRows,
      candidateWorkflowContractStatus:
        candidateBatchContractViolations.length ||
        candidateCritiqueContractViolationRows.length ||
        modelJudgeScoreContractViolationRows.length ||
        scoreSubmissionContractViolationRows.length
          ? "candidate_workflow_contract_review_required"
          : "candidate_workflow_contract_complete",
      hiddenMetadataStatus:
        !modelJudgeScoresVisibleToInitialRaters && selectionReasonHiddenFromInitialRaters
          ? "candidate_intake_metadata_hidden_before_initial_lock"
          : "candidate_intake_metadata_visibility_review_required",
    };
  });
  const hiddenMetadataViolationRows = batchRows.filter((row) => row.hiddenMetadataStatus === "candidate_intake_metadata_visibility_review_required");
  const candidateBatchContractViolationRows = batchRows.filter((row) => row.candidateBatchContractViolations.length);
  const candidateWorkflowContractViolationRows = batchRows.filter((row) => row.candidateWorkflowContractStatus === "candidate_workflow_contract_review_required");
  return {
    candidateBatchCount: candidateBatches.length,
    candidateCritiqueCount: candidateCritiques.length,
    modelJudgeScoreCount: modelJudgeScores.length,
    scoreSubmissionCount: candidateBatchModelJudgeScoreSubmissions.length,
    reviewCount: candidateReviews.length,
    promotionCount: candidatePromotions.length,
    candidateBatchContractViolationCount: candidateBatchContractViolationRows.length,
    candidateBatchContractViolationRows,
    candidateWorkflowContractViolationCount: candidateWorkflowContractViolationRows.length,
    candidateWorkflowContractViolationRows,
    hiddenMetadataViolationCount: hiddenMetadataViolationRows.length,
    hiddenMetadataViolationRows,
    rows: batchRows,
  };
}

function submittedCandidateBatchContractChecks(batch) {
  const fieldChecks = REQUIRED_CANDIDATE_BATCH_FIELDS.map((field) => ({
    field,
    expected: "present",
    observed: batch?.[field] ?? null,
    status: hasRequiredValue(batch?.[field]) ? "pass" : "missing_required_field",
  }));
  const judgeModelSetCheck = {
    field: "judgeModelSet",
    expected: "non_empty_array",
    observed: batch?.judgeModelSet ?? null,
    status: Array.isArray(batch?.judgeModelSet) && batch.judgeModelSet.length ? "pass" : "missing_required_array_values",
  };
  const generatedCountCheck = {
    field: "generatedOrIngestedCandidateCount",
    expected: "finite_number",
    observed: batch?.generatedOrIngestedCandidateCount ?? null,
    status: Number.isFinite(Number(batch?.generatedOrIngestedCandidateCount)) ? "pass" : "invalid_number",
  };
  const judgedCountCheck = {
    field: "judgedCandidateCount",
    expected: "finite_number",
    observed: batch?.judgedCandidateCount ?? null,
    status: Number.isFinite(Number(batch?.judgedCandidateCount)) ? "pass" : "invalid_number",
  };
  const selectionReasonHiddenCheck = {
    field: "selectionReasonHiddenFromInitialRaters",
    expected: true,
    observed: batch?.selectionReasonHiddenFromInitialRaters ?? null,
    status: batch?.selectionReasonHiddenFromInitialRaters === true ? "pass" : "must_equal_true",
  };
  const modelJudgeHiddenCheck = {
    field: "modelJudgeScoresVisibleToInitialRaters",
    expected: false,
    observed: batch?.modelJudgeScoresVisibleToInitialRaters ?? null,
    status: batch?.modelJudgeScoresVisibleToInitialRaters === false ? "pass" : "must_equal_false",
  };
  return [...fieldChecks, judgeModelSetCheck, generatedCountCheck, judgedCountCheck, selectionReasonHiddenCheck, modelJudgeHiddenCheck];
}

function submittedCandidateCritiqueContractChecks(critique) {
  const fieldChecks = REQUIRED_CANDIDATE_CRITIQUE_FIELDS.map((field) => ({
    field,
    expected: "present",
    observed: critique?.[field] ?? null,
    status: hasRequiredValue(critique?.[field]) ? "pass" : "missing_required_field",
  }));
  const selectionReasonHiddenCheck = {
    field: "selectionReasonVisibleToRatersBeforeInitialLock",
    expected: false,
    observed: critique?.selectionReasonVisibleToRatersBeforeInitialLock ?? null,
    status: critique?.selectionReasonVisibleToRatersBeforeInitialLock === false ? "pass" : "must_equal_false",
  };
  return [...fieldChecks, selectionReasonHiddenCheck];
}

function submittedModelJudgeScoreContractChecks(score) {
  const fieldChecks = REQUIRED_MODEL_JUDGE_SCORE_FIELDS.map((field) => ({
    field,
    expected: "present",
    observed: score?.[field] ?? null,
    status: hasRequiredValue(score?.[field]) ? "pass" : "missing_required_field",
  }));
  const modelParametersCheck = {
    field: "modelParameters",
    expected: "object",
    observed: score?.modelParameters ?? null,
    status: score?.modelParameters && typeof score.modelParameters === "object" && !Array.isArray(score.modelParameters) ? "pass" : "invalid_object",
  };
  const disagreementStatisticsCheck = {
    field: "disagreementStatistics",
    expected: "object",
    observed: score?.disagreementStatistics ?? null,
    status: score?.disagreementStatistics && typeof score.disagreementStatistics === "object" && !Array.isArray(score.disagreementStatistics) ? "pass" : "invalid_object",
  };
  const overallScoreCheck = {
    field: "overallScore",
    expected: "finite_number",
    observed: score?.overallScore ?? null,
    status: Number.isFinite(Number(score?.overallScore)) ? "pass" : "invalid_number",
  };
  const hiddenCheck = {
    field: "hiddenFromRatersBeforeInitialLock",
    expected: true,
    observed: score?.hiddenFromRatersBeforeInitialLock ?? null,
    status: score?.hiddenFromRatersBeforeInitialLock === true ? "pass" : "must_equal_true",
  };
  return [...fieldChecks, modelParametersCheck, disagreementStatisticsCheck, overallScoreCheck, hiddenCheck];
}

function submittedModelJudgeScoreSubmissionContractChecks(submission) {
  const fieldChecks = REQUIRED_MODEL_JUDGE_SCORE_SUBMISSION_FIELDS.map((field) => ({
    field,
    expected: "present",
    observed: submission?.[field] ?? null,
    status: hasRequiredValue(submission?.[field]) ? "pass" : "missing_required_field",
  }));
  const submittedScoreIdsCheck = {
    field: "submittedScoreIds",
    expected: "non_empty_array",
    observed: submission?.submittedScoreIds ?? null,
    status: Array.isArray(submission?.submittedScoreIds) && submission.submittedScoreIds.length ? "pass" : "missing_required_array_values",
  };
  const judgedCountCheck = {
    field: "judgedCandidateCount",
    expected: "finite_number",
    observed: submission?.judgedCandidateCount ?? null,
    status: Number.isFinite(Number(submission?.judgedCandidateCount)) ? "pass" : "invalid_number",
  };
  const hiddenCheck = {
    field: "hiddenFromRatersBeforeInitialLock",
    expected: true,
    observed: submission?.hiddenFromRatersBeforeInitialLock ?? null,
    status: submission?.hiddenFromRatersBeforeInitialLock === true ? "pass" : "must_equal_true",
  };
  return [...fieldChecks, submittedScoreIdsCheck, judgedCountCheck, hiddenCheck];
}

function buildCandidateWorkflowActiveLearningBatches(candidateWorkflowEvidence, auditedBatchIds = new Set()) {
  return (candidateWorkflowEvidence.rows ?? [])
    .filter((row) => !auditedBatchIds.has(row.candidateBatchId))
    .map((row) => ({
      id: row.candidateBatchId,
      batchSource: "submitted_workflow_candidate_batch",
      activeLearningSelectionPolicyId: row.activeLearningSelectionPolicyId ?? null,
      selectionPolicyReleaseUseStatus: row.selectionPolicyReleaseUseStatus ?? null,
      selectionThresholdsApplied: row.selectionThresholdsApplied ?? REQUIRED_ACTIVE_LEARNING_SELECTION_THRESHOLDS,
      handSelectionQuotasApplied: row.handSelectionQuotasApplied ?? REQUIRED_ACTIVE_LEARNING_HAND_SELECTION_QUOTAS,
      generated: row.generated,
      ingested: row.ingested,
      judged: row.judged,
      disagreementSelected: row.disagreementSelected,
      highRated: row.highRated,
      suspectedJudgeFalsePositive: row.suspectedJudgeFalsePositive,
      handSelected: row.handSelected,
      rejected: row.rejected,
      promoted: row.promoted,
      acceptedCritiqueIds: row.acceptedCritiqueIds,
      modelJudgeScoresVisibleToInitialRaters: row.modelJudgeScoresVisibleToInitialRaters,
      selectionReasonHiddenFromInitialRaters: row.selectionReasonHiddenFromInitialRaters,
      selectionReasonCounts: row.selectionReasonCounts,
      rejectedCountByReason: row.rejectedCountByReason,
    }));
}

function candidateSelectionReasonCounts(critiques, reviews, scores) {
  const counts = {};
  const reasonsByCandidate = new Map();
  const addReasons = (candidateId, reason) => {
    if (!candidateId || !reason) return;
    const reasonSet = reasonsByCandidate.get(candidateId) ?? new Set();
    normalizedSelectionReasons(reason).forEach((key) => reasonSet.add(key));
    reasonsByCandidate.set(candidateId, reasonSet);
  };
  critiques.forEach((critique) => addReasons(critique.id, critique.selectionReason));
  reviews.forEach((review) => addReasons(review.candidateId, review.inclusionReason));
  scores.forEach((score) => {
    if (numberOrDefault(score.disagreementStatistics?.judgePairSpread, 0) > 0) addReasons(score.candidateId, "judge_disagreement");
  });
  reasonsByCandidate.forEach((reasonSet) => {
    reasonSet.forEach((key) => {
      counts[key] = (counts[key] ?? 0) + 1;
    });
  });
  return counts;
}

function normalizedSelectionReasons(reason) {
  const value = String(reason);
  const reasons = [];
  if (value.includes("judge_disagreement")) reasons.push("judge_disagreement");
  if (value.includes("high_rated")) reasons.push("high_rated");
  if (value.includes("false_positive")) reasons.push("suspected_judge_false_positive");
  if (value.includes("diversity")) reasons.push("human_diversity_selection");
  if (value.includes("suitability")) reasons.push("human_suitability_selection");
  if (value.includes("interesting")) reasons.push("human_interestingness_selection");
  if (value.includes("new_objection")) reasons.push("new_objection_type");
  return reasons.length ? reasons : [value];
}

function firstDefined(values) {
  return values.find((value) => value !== undefined && value !== null);
}

function mergeCountMaps(maps) {
  return maps.reduce((acc, map) => {
    Object.entries(map ?? {}).forEach(([key, value]) => {
      acc[key] = (acc[key] ?? 0) + numberOrDefault(value, 0);
    });
    return acc;
  }, {});
}

function sumCountMap(map) {
  return Object.values(map ?? {}).reduce((sum, value) => sum + numberOrDefault(value, 0), 0);
}

export function buildCandidateIntakeQualityAudit(
  releaseId,
  critiqueList = critiques,
  positionList = positions,
  generationRuns = critiqueGenerationRuns,
  batches = activeLearningBatches,
) {
  const positionById = new Map(positionList.map((position) => [position.id, position]));
  const acceptedCritiqueIds = new Set(batches.flatMap((batch) => batch.acceptedCritiqueIds));
  const generatedOutputs = generationRuns.flatMap((run) =>
    run.outputs.map((output) => ({
      ...output,
      generationRunId: run.id,
      requestedModelAlias: run.requestedModelAlias,
      resolvedModelSnapshot: run.resolvedModelSnapshot,
    })),
  );
  const duplicateOutputRows = generatedOutputs
    .filter((output) => output.status === "duplicate_filtered" || output.duplicateOfOutputId)
    .map((output) => ({
      generationRunId: output.generationRunId,
      outputId: output.id,
      positionId: output.positionId,
      duplicateOfOutputId: output.duplicateOfOutputId ?? null,
      status: output.status,
      selectionReasons: output.selectionReasons ?? [],
    }));
  const critiqueRows = critiqueList.map((critique) => {
    const position = positionById.get(critique.positionId);
    const redundancyRisk = redundancyRiskForCritique(critique);
    return {
      itemId: makeItemId(critique.positionId, critique.id),
      critiqueId: critique.id,
      positionId: critique.positionId,
      split: position?.split ?? "unknown",
      topicFamily: position?.topicFamily ?? "unknown",
      sourceType: critique.sourceType,
      authorshipType: critique.authorshipType,
      styleBand: critique.styleBand,
      marginalInformativeness: critique.marginalInformativeness ?? "unknown",
      redundancyRisk,
      activeLearningAccepted: acceptedCritiqueIds.has(critique.id),
      countsTowardUnqualifiedScaleClaim: redundancyRisk === "pass",
      scaleClaimPolicy:
        redundancyRisk === "pass"
          ? "eligible_for_unqualified_critique_count_subject_to_release_metric_gates"
          : "disclosed_as_artifact_control_or_low_marginal_information_not_used_to_inflate_quality_claims",
    };
  });
  const positionRows = Object.entries(
    critiqueRows.reduce((acc, row) => {
      acc[row.positionId] ??= [];
      acc[row.positionId].push(row);
      return acc;
    }, {}),
  )
    .map(([positionId, rows]) => ({
      positionId,
      critiqueCount: rows.length,
      unqualifiedScaleEligibleCritiqueCount: rows.filter((row) => row.countsTowardUnqualifiedScaleClaim).length,
      lowInformationOrArtifactControlCount: rows.filter((row) => !row.countsTowardUnqualifiedScaleClaim).length,
      marginalInformativenessCounts: countBy(rows, "marginalInformativeness"),
      status: rows.some((row) => !row.countsTowardUnqualifiedScaleClaim) ? "mixed_information_quality_disclosed" : "pass",
    }))
    .sort((left, right) => right.lowInformationOrArtifactControlCount - left.lowInformationOrArtifactControlCount || left.positionId.localeCompare(right.positionId));
  const lowInformationRows = critiqueRows.filter((row) => !row.countsTowardUnqualifiedScaleClaim);
  const acceptedRows = critiqueRows.filter((row) => row.activeLearningAccepted);
  return {
    id: `candidate-intake-quality-${releaseId}`,
    releaseId,
    generatedAt: new Date().toISOString(),
    policy: {
      auditScope: "candidate_and_benchmark_intake_marginal_informativeness_redundancy",
      unqualifiedScaleRule:
        "Critique counts used for quality or benchmark breadth claims must disclose artifact-control, duplicate-filtered, and low-marginal-information rows separately.",
      duplicatePolicy: "Near-duplicate generated outputs count as generation outcomes but not additional promoted critique quality evidence.",
      benchmarkPolicy:
        "Hidden-benchmark and validation candidates keep marginal-information and redundancy fields so protected critique counts are not inflated by trivially weak variants.",
    },
    counts: {
      totalCritiques: critiqueRows.length,
      unqualifiedScaleEligibleCritiques: critiqueRows.filter((row) => row.countsTowardUnqualifiedScaleClaim).length,
      lowInformationOrArtifactControlCritiques: lowInformationRows.length,
      activeLearningAcceptedCritiques: acceptedRows.length,
      acceptedLowInformationOrArtifactControlCritiques: acceptedRows.filter((row) => !row.countsTowardUnqualifiedScaleClaim).length,
      duplicateGeneratedOutputs: duplicateOutputRows.length,
    },
    marginalInformativenessCounts: countBy(critiqueRows, "marginalInformativeness"),
    redundancyRiskCounts: countBy(critiqueRows, "redundancyRisk"),
    generatedOutputStatusCounts: countBy(generatedOutputs, "status"),
    duplicateOutputRows,
    lowInformationRows,
    activeLearningAcceptedRows: acceptedRows,
    positionRows,
    critiqueRows,
    releaseUseStatus:
      lowInformationRows.length || duplicateOutputRows.length
        ? "marginal_informativeness_audit_disclosed_low_redundancy_controls"
        : "marginal_informativeness_audit_pass",
  };
}

export function buildCandidateGenerationIntakeChecklistReport(
  releaseId,
  {
    positionIntakeReadiness,
    activeLearning,
    candidateIntakeQualityAudit,
    critiqueGenerationEvaluation,
    corpusManifest,
    hiddenBenchmarkFreeze,
  } = {},
) {
  const activeTotals = activeLearning?.totals ?? {};
  const qualityCounts = candidateIntakeQualityAudit?.counts ?? {};
  const generationCounts = critiqueGenerationEvaluation?.aggregateCounts ?? {};
  const generationSeparation = critiqueGenerationEvaluation?.generationVsJudgingSeparation ?? {};
  const hiddenArtifactBalance = hiddenBenchmarkFreeze?.artifactBalance ?? {};
  const hiddenCounterbalanceStatus = hiddenArtifactBalance.counterbalanceStatus ?? "not_evaluated";

  const rows = [
    candidateGenerationChecklistRow({
      id: "position_scope_context_screen",
      label: "Position scope and context screen",
      evidenceIds: [positionIntakeReadiness?.id].filter(Boolean),
      sourceStatuses: [positionIntakeReadiness?.releaseUseStatus].filter(Boolean),
      complete:
        hasRequiredValue(positionIntakeReadiness?.releaseUseStatus) &&
        positionIntakeReadiness.releaseUseStatus !== "position_intake_screening_review_required" &&
        (positionIntakeReadiness.counts?.incompleteScreeningCount ?? 0) === 0,
      reviewReasons: [
        !positionIntakeReadiness ? "positionIntakeReadiness:missing" : null,
        positionIntakeReadiness?.releaseUseStatus === "position_intake_screening_review_required"
          ? "positionIntakeReadiness.review_required"
          : null,
        (positionIntakeReadiness?.counts?.incompleteScreeningCount ?? 0) > 0
          ? "positionIntakeReadiness.incompleteScreeningCount"
          : null,
      ],
      requirement:
        "Conceptual-scope, ground-truth, position-clarity, and context-sufficiency screens run before candidate critique generation or assignment.",
    }),
    candidateGenerationChecklistRow({
      id: "candidate_generation_denominator_audit",
      label: "Candidate generation denominator audit",
      evidenceIds: [activeLearning?.id].filter(Boolean),
      sourceStatuses: [activeLearning?.releaseUseStatus, activeLearning?.activeLearningSelectionPolicyReleaseUseStatus].filter(Boolean),
      complete:
        activeLearning?.releaseUseStatus === "active_learning_selection_denominators_audited" &&
        (activeTotals.generated ?? 0) + (activeTotals.ingested ?? 0) > 0 &&
        (activeLearning?.candidateWorkflowContractViolationCount ?? 0) === 0 &&
        (activeLearning?.submittedSelectionAuditContractViolationCount ?? 0) === 0,
      reviewReasons: [
        !activeLearning ? "activeLearning:missing" : null,
        activeLearning?.releaseUseStatus !== "active_learning_selection_denominators_audited"
          ? "activeLearning.releaseUseStatus"
          : null,
        (activeTotals.generated ?? 0) + (activeTotals.ingested ?? 0) <= 0 ? "activeLearning.generated_or_ingested" : null,
        (activeLearning?.candidateWorkflowContractViolationCount ?? 0) > 0
          ? "activeLearning.candidateWorkflowContractViolationCount"
          : null,
        (activeLearning?.submittedSelectionAuditContractViolationCount ?? 0) > 0
          ? "activeLearning.submittedSelectionAuditContractViolationCount"
          : null,
      ],
      requirement:
        "CandidateBatch and ActiveLearningSelectionAudit evidence records generated/ingested, judged, selected, rejected, and promoted denominators.",
    }),
    candidateGenerationChecklistRow({
      id: "selection_targets_human_curation",
      label: "Selection targets and human curation",
      evidenceIds: [activeLearning?.id].filter(Boolean),
      sourceStatuses: [activeLearning?.releaseUseStatus].filter(Boolean),
      complete:
        (activeTotals.disagreementSelected ?? 0) > 0 &&
        (activeTotals.highRated ?? 0) > 0 &&
        (activeTotals.suspectedJudgeFalsePositive ?? 0) > 0 &&
        (activeTotals.handSelected ?? 0) > 0 &&
        (activeTotals.promoted ?? 0) > 0,
      reviewReasons: [
        (activeTotals.disagreementSelected ?? 0) <= 0 ? "activeLearning.disagreementSelected" : null,
        (activeTotals.highRated ?? 0) <= 0 ? "activeLearning.highRated" : null,
        (activeTotals.suspectedJudgeFalsePositive ?? 0) <= 0 ? "activeLearning.suspectedJudgeFalsePositive" : null,
        (activeTotals.handSelected ?? 0) <= 0 ? "activeLearning.handSelected" : null,
        (activeTotals.promoted ?? 0) <= 0 ? "activeLearning.promoted" : null,
      ],
      requirement:
        "Selection includes judge disagreement, high-rated candidates, suspected false positives, and trained human curation before rating intake.",
    }),
    candidateGenerationChecklistRow({
      id: "model_judge_screening_admin_only",
      label: "Model-judge screening stays admin-only",
      evidenceIds: [activeLearning?.id].filter(Boolean),
      sourceStatuses: [activeLearning?.releaseUseStatus].filter(Boolean),
      complete:
        (activeTotals.judged ?? 0) > 0 &&
        activeLearning?.blindingPass === true &&
        (activeLearning?.candidateWorkflowEvidence?.hiddenMetadataViolationCount ?? 0) === 0,
      reviewReasons: [
        (activeTotals.judged ?? 0) <= 0 ? "activeLearning.judged" : null,
        activeLearning?.blindingPass === true ? null : "activeLearning.blindingPass",
        (activeLearning?.candidateWorkflowEvidence?.hiddenMetadataViolationCount ?? 0) > 0
          ? "activeLearning.hiddenMetadataViolationCount"
          : null,
      ],
      requirement:
        "Model-judge scores, selection reasons, and active-learning flags remain hidden from ordinary and validation raters before initial lock.",
    }),
    candidateGenerationChecklistRow({
      id: "marginal_informativeness_redundancy_controls",
      label: "Marginal informativeness and redundancy controls",
      evidenceIds: [candidateIntakeQualityAudit?.id].filter(Boolean),
      sourceStatuses: [candidateIntakeQualityAudit?.releaseUseStatus].filter(Boolean),
      complete:
        candidateIntakeQualityAudit?.releaseUseStatus === "marginal_informativeness_audit_pass" ||
        candidateIntakeQualityAudit?.releaseUseStatus === "marginal_informativeness_audit_disclosed_low_redundancy_controls",
      reviewReasons: [
        !candidateIntakeQualityAudit ? "candidateIntakeQualityAudit:missing" : null,
        candidateIntakeQualityAudit?.releaseUseStatus &&
        ![
          "marginal_informativeness_audit_pass",
          "marginal_informativeness_audit_disclosed_low_redundancy_controls",
        ].includes(candidateIntakeQualityAudit.releaseUseStatus)
          ? "candidateIntakeQualityAudit.releaseUseStatus"
          : null,
      ],
      requirement:
        "Accepted critique counts disclose low-information, artifact-control, near-duplicate, and low-marginal-information rows separately.",
    }),
    candidateGenerationChecklistRow({
      id: "critique_generation_evaluation_provenance",
      label: "Critique-generation evaluation provenance",
      evidenceIds: [critiqueGenerationEvaluation?.id].filter(Boolean),
      sourceStatuses: [
        critiqueGenerationEvaluation?.releaseUseStatus,
        critiqueGenerationEvaluation?.providerPolicyEvidence?.releaseUseStatus,
        critiqueGenerationEvaluation?.submittedWorkflowContractEvidence?.releaseUseStatus,
      ].filter(Boolean),
      complete:
        critiqueGenerationEvaluation?.releaseUseStatus === "generation_evaluation_separate_with_blind_rating_coverage" &&
        (generationCounts.generatedOutputs ?? 0) > 0 &&
        (generationCounts.promotedToRating ?? 0) === (generationCounts.blindHumanRatedPromoted ?? -1) &&
        critiqueGenerationEvaluation?.providerPolicyEvidence?.releaseUseStatus === "critique_generation_provider_policies_approved" &&
        critiqueGenerationEvaluation?.submittedWorkflowContractEvidence?.releaseUseStatus === "critique_generation_workflow_contract_complete",
      reviewReasons: [
        !critiqueGenerationEvaluation ? "critiqueGenerationEvaluation:missing" : null,
        critiqueGenerationEvaluation?.releaseUseStatus !== "generation_evaluation_separate_with_blind_rating_coverage"
          ? "critiqueGenerationEvaluation.releaseUseStatus"
          : null,
        (generationCounts.generatedOutputs ?? 0) <= 0 ? "critiqueGenerationEvaluation.generatedOutputs" : null,
        (generationCounts.promotedToRating ?? 0) !== (generationCounts.blindHumanRatedPromoted ?? -1)
          ? "critiqueGenerationEvaluation.blindHumanRatedPromoted"
          : null,
        critiqueGenerationEvaluation?.providerPolicyEvidence?.releaseUseStatus !== "critique_generation_provider_policies_approved"
          ? "critiqueGenerationEvaluation.providerPolicyEvidence"
          : null,
        critiqueGenerationEvaluation?.submittedWorkflowContractEvidence?.releaseUseStatus !== "critique_generation_workflow_contract_complete"
          ? "critiqueGenerationEvaluation.submittedWorkflowContractEvidence"
          : null,
      ],
      requirement:
        "GeneratedCritiqueSubmission and generation reports preserve generator provenance, uncurated denominators, provider policy bindings, and blind human rating coverage.",
    }),
    candidateGenerationChecklistRow({
      id: "model_judges_not_gold_role_separation",
      label: "Model judges are not gold labels",
      evidenceIds: [critiqueGenerationEvaluation?.id].filter(Boolean),
      sourceStatuses: [
        critiqueGenerationEvaluation?.releaseUseStatus,
        critiqueGenerationEvaluation?.generatorEvaluatorOverlap?.releaseUseStatus,
      ].filter(Boolean),
      complete:
        generationSeparation.generatedCritiquesRequireBlindHumanRatingBeforeQualityClaim === true &&
        generationSeparation.modelJudgeScoresDiagnosticOnly === true &&
        generationSeparation.modelJudgeScoresAcceptedAsGoldLabels === false &&
        generationSeparation.modelJudgeScoresVisibleToInitialRaters === false &&
        hasRequiredValue(critiqueGenerationEvaluation?.generatorEvaluatorOverlap?.releaseUseStatus),
      reviewReasons: [
        generationSeparation.generatedCritiquesRequireBlindHumanRatingBeforeQualityClaim === true
          ? null
          : "generationVsJudgingSeparation.generatedCritiquesRequireBlindHumanRatingBeforeQualityClaim",
        generationSeparation.modelJudgeScoresDiagnosticOnly === true
          ? null
          : "generationVsJudgingSeparation.modelJudgeScoresDiagnosticOnly",
        generationSeparation.modelJudgeScoresAcceptedAsGoldLabels === false
          ? null
          : "generationVsJudgingSeparation.modelJudgeScoresAcceptedAsGoldLabels",
        generationSeparation.modelJudgeScoresVisibleToInitialRaters === false
          ? null
          : "generationVsJudgingSeparation.modelJudgeScoresVisibleToInitialRaters",
        hasRequiredValue(critiqueGenerationEvaluation?.generatorEvaluatorOverlap?.releaseUseStatus)
          ? null
          : "generatorEvaluatorOverlap.releaseUseStatus",
      ],
      requirement:
        "Model judges remain diagnostic discovery tools; gold, benchmark, and evaluation labels require human rating or adjudication, with generator/judge overlap disclosed.",
    }),
    candidateGenerationChecklistRow({
      id: "source_topic_artifact_controls",
      label: "Source, topic, and artifact controls",
      evidenceIds: [corpusManifest?.id, hiddenBenchmarkFreeze?.id].filter(Boolean),
      sourceStatuses: [hiddenCounterbalanceStatus, hiddenBenchmarkFreeze?.freezeStatus].filter(Boolean),
      complete:
        hasRequiredValue(corpusManifest?.sourceDetailCoverage?.status ?? corpusManifest?.sourceDetailCoverage) &&
        Object.keys(corpusManifest?.positionSourceCategory ?? {}).length > 0 &&
        Object.keys(corpusManifest?.critiqueSourceType ?? {}).length > 0 &&
        hasRequiredValue(hiddenCounterbalanceStatus) &&
        hiddenCounterbalanceStatus !== "quality_source_style_confound_review_required",
      reviewReasons: [
        !corpusManifest ? "corpusManifest:missing" : null,
        Object.keys(corpusManifest?.positionSourceCategory ?? {}).length === 0 ? "corpusManifest.positionSourceCategory" : null,
        Object.keys(corpusManifest?.critiqueSourceType ?? {}).length === 0 ? "corpusManifest.critiqueSourceType" : null,
        !hasRequiredValue(hiddenCounterbalanceStatus) ? "hiddenBenchmarkFreeze.artifactBalance.counterbalanceStatus" : null,
        hiddenCounterbalanceStatus === "quality_source_style_confound_review_required"
          ? "hiddenBenchmarkFreeze.artifactBalance.quality_source_style_confound_review_required"
          : null,
      ],
      requirement:
        "Corpus and hidden-benchmark manifests expose source, topic, authorship, length/style, expected-quality, and source-quality counterbalancing controls.",
    }),
  ];

  return {
    id: `candidate-generation-intake-checklist-${releaseId}`,
    releaseId,
    generatedAt: new Date().toISOString(),
    policy: {
      scope:
        "RLHF91 candidate generation and active-learning intake evidence checklist over existing Position, Critique, CandidateBatch, CandidateCritique, GeneratedCritiqueSubmission, and ModelJudgeScore surfaces.",
      duplicationBoundary:
        "This checklist does not create CandidateItem, CandidateBatchMembership, live queue, gold label, benchmark label, or alternate candidate architecture.",
      labelBoundary:
        "Model-judge and generator signals are discovery and diagnostic metadata only; blind human ratings or adjudications remain the label source.",
    },
    counts: {
      checklistRows: rows.length,
      completeRows: rows.filter((row) => row.status === "complete").length,
      reviewRequiredRows: rows.filter((row) => row.status === "review_required").length,
      generatedOrIngestedCandidates: (activeTotals.generated ?? 0) + (activeTotals.ingested ?? 0),
      judgedCandidates: activeTotals.judged ?? 0,
      promotedCandidates: activeTotals.promoted ?? 0,
      lowInformationOrArtifactControlCritiques: qualityCounts.lowInformationOrArtifactControlCritiques ?? 0,
      duplicateGeneratedOutputs: qualityCounts.duplicateGeneratedOutputs ?? 0,
      generatedCritiqueOutputs: generationCounts.generatedOutputs ?? 0,
      blindHumanRatedPromotedOutputs: generationCounts.blindHumanRatedPromoted ?? 0,
    },
    rows,
    reviewSections: rows.flatMap((row) =>
      row.reviewReasons.map((reason) => ({
        artifactType: "candidate_generation_intake_checklist",
        artifactId: row.id,
        reason,
      })),
    ),
    releaseUseStatus: rows.every((row) => row.status === "complete")
      ? "candidate_generation_intake_requirements_evidenced"
      : "candidate_generation_intake_review_required",
  };
}

function candidateGenerationChecklistRow({ id, label, requirement, evidenceIds = [], sourceStatuses = [], complete, reviewReasons = [] }) {
  const filteredReasons = reviewReasons.filter(Boolean);
  return {
    id,
    label,
    requirement,
    evidenceIds,
    sourceStatuses,
    status: complete && filteredReasons.length === 0 ? "complete" : "review_required",
    reviewReasons: filteredReasons,
  };
}

export function buildLabelAggregationReliabilityChecklistReport(
  releaseId,
  {
    labelSnapshotReliability,
    raterReliabilityWeightModelEvidence,
    ratingRevisionAudit,
    postDiscussionDisagreement,
    adjudicationMemoAudit,
    disagreementThresholdPolicyEvidence,
    metricDirectionalityConfig,
    modelAssistedLabelOverlap,
  } = {},
) {
  const reliability = labelSnapshotReliability ?? {};
  const weightModel = reliability.reliabilityWeightModel ?? {};
  const fitData = weightModel.fitDataProvenance ?? {};
  const effectiveContribution = weightModel.effectiveContribution ?? {};
  const aggregationSensitivity = reliability.aggregationSensitivity ?? weightModel.sensitivitySummary ?? {};
  const includedRatingProvenance = reliability.includedRatingProvenance ?? weightModel.includedRatingProvenance ?? {};
  const raterWeightEvidence = raterReliabilityWeightModelEvidence ?? reliability.raterReliabilityWeightModelEvidence ?? {};
  const revisionCounts = ratingRevisionAudit?.counts ?? {};
  const disagreementCounts = postDiscussionDisagreement?.counts ?? {};
  const adjudicationCounts = adjudicationMemoAudit?.counts ?? {};
  const metricCounts = metricDirectionalityConfig?.counts ?? {};

  const submittedWeightModelStatusOk = [
    "default_uniform_weight_model_used_no_submitted_model",
    "active_submitted_weight_model_provenance_complete",
  ].includes(raterWeightEvidence.releaseUseStatus);
  const disagreementPolicyStatusOk = [
    "seed_disagreement_threshold_policy_active",
    "submitted_disagreement_threshold_policy_active",
  ].includes(disagreementThresholdPolicyEvidence?.releaseUseStatus);
  const adjudicationStatusOk = ["adjudication_limitations_preserved", "adjudication_memos_complete"].includes(
    adjudicationMemoAudit?.releaseUseStatus,
  );
  const modelAssistedStatusOk =
    hasRequiredValue(modelAssistedLabelOverlap?.releaseUseStatus) &&
    !String(modelAssistedLabelOverlap.releaseUseStatus).includes("review_required");

  const rows = [
    labelAggregationChecklistRow({
      id: "immutable_label_snapshot_and_denominators",
      label: "Immutable label snapshot and denominator separation",
      evidenceIds: [reliability.labelSnapshotId, ratingRevisionAudit?.id].filter(Boolean),
      sourceStatuses: [ratingRevisionAudit?.releaseUseStatus].filter(Boolean),
      complete:
        hasRequiredValue(reliability.labelSnapshotId) &&
        ratingRevisionAudit?.releaseUseStatus === "revision_and_check_denominators_separated" &&
        (includedRatingProvenance.includedRatingCount ?? 0) > 0 &&
        (revisionCounts.blindInitialRows ?? 0) > 0,
      reviewReasons: [
        !hasRequiredValue(reliability.labelSnapshotId) ? "labelSnapshotReliability.labelSnapshotId" : null,
        ratingRevisionAudit?.releaseUseStatus !== "revision_and_check_denominators_separated"
          ? "ratingRevisionAudit.releaseUseStatus"
          : null,
        (includedRatingProvenance.includedRatingCount ?? 0) <= 0 ? "labelSnapshotReliability.includedRatingCount" : null,
        (revisionCounts.blindInitialRows ?? 0) <= 0 ? "ratingRevisionAudit.blindInitialRows" : null,
      ],
      requirement:
        "Released labels come from immutable LabelSnapshot evidence, while blind initials, revisions, checks, model-assisted checks, and adjudication rows remain separately counted.",
    }),
    labelAggregationChecklistRow({
      id: "frozen_reliability_weight_model",
      label: "Frozen reliability-weight model provenance",
      evidenceIds: [weightModel.id, raterWeightEvidence.id].filter(Boolean),
      sourceStatuses: [weightModel.releaseUseStatus, raterWeightEvidence.releaseUseStatus].filter(Boolean),
      complete:
        weightModel.frozenBeforeAggregation === true &&
        hasRequiredValue(weightModel.reliabilityWeightModelId) &&
        weightModel.releaseUseStatus === "uniform_weights_frozen_with_sensitivity_report" &&
        submittedWeightModelStatusOk &&
        (raterWeightEvidence.reviewRows?.length ?? 0) === 0,
      reviewReasons: [
        weightModel.frozenBeforeAggregation === true ? null : "reliabilityWeightModel.frozenBeforeAggregation",
        hasRequiredValue(weightModel.reliabilityWeightModelId) ? null : "reliabilityWeightModel.reliabilityWeightModelId",
        weightModel.releaseUseStatus !== "uniform_weights_frozen_with_sensitivity_report"
          ? "reliabilityWeightModel.releaseUseStatus"
          : null,
        submittedWeightModelStatusOk ? null : "raterReliabilityWeightModelEvidence.releaseUseStatus",
        (raterWeightEvidence.reviewRows?.length ?? 0) > 0 ? "raterReliabilityWeightModelEvidence.reviewRows" : null,
      ],
      requirement:
        "Any rater-reliability weight model used for release labels is frozen before aggregation, versioned, and matched to submitted provenance when such workflow records exist.",
    }),
    labelAggregationChecklistRow({
      id: "protected_fit_exclusion",
      label: "Protected fit-data exclusion",
      evidenceIds: [weightModel.id, raterWeightEvidence.id].filter(Boolean),
      sourceStatuses: [raterWeightEvidence.releaseUseStatus].filter(Boolean),
      complete:
        fitData.protectedRatingsUsedForFit === 0 &&
        (fitData.protectedExcludedSplits ?? []).includes("hidden_benchmark") &&
        (fitData.protectedExcludedSplits ?? []).includes("internal_validation") &&
        submittedWeightModelStatusOk,
      reviewReasons: [
        fitData.protectedRatingsUsedForFit === 0 ? null : "fitDataProvenance.protectedRatingsUsedForFit",
        (fitData.protectedExcludedSplits ?? []).includes("hidden_benchmark") ? null : "fitDataProvenance.hiddenBenchmarkExcluded",
        (fitData.protectedExcludedSplits ?? []).includes("internal_validation") ? null : "fitDataProvenance.internalValidationExcluded",
        submittedWeightModelStatusOk ? null : "raterReliabilityWeightModelEvidence.releaseUseStatus",
      ],
      requirement:
        "Reliability weights are not fit or tuned on hidden benchmark or protected-validation rows; submitted weight-model evidence must preserve that exclusion.",
    }),
    labelAggregationChecklistRow({
      id: "unweighted_median_sensitivity",
      label: "Unweighted and median sensitivity",
      evidenceIds: [weightModel.id].filter(Boolean),
      sourceStatuses: [weightModel.releaseUseStatus].filter(Boolean),
      complete:
        aggregationSensitivity.unweightedMeanMatchesHeadline === true &&
        aggregationSensitivity.medianSensitivityAvailable === true &&
        Object.keys(aggregationSensitivity.meanAbsMeanMedianDeltaByDimension ?? {}).length > 0,
      reviewReasons: [
        aggregationSensitivity.unweightedMeanMatchesHeadline === true ? null : "aggregationSensitivity.unweightedMeanMatchesHeadline",
        aggregationSensitivity.medianSensitivityAvailable === true ? null : "aggregationSensitivity.medianSensitivityAvailable",
        Object.keys(aggregationSensitivity.meanAbsMeanMedianDeltaByDimension ?? {}).length > 0
          ? null
          : "aggregationSensitivity.meanAbsMeanMedianDeltaByDimension",
      ],
      requirement:
        "Release-critical snapshots disclose unweighted headline behavior plus median sensitivity rather than hiding aggregation choice behind opaque weighting.",
    }),
    labelAggregationChecklistRow({
      id: "rater_dominance_disclosed",
      label: "Rater dominance disclosed",
      evidenceIds: [weightModel.id].filter(Boolean),
      sourceStatuses: [effectiveContribution.dominanceReviewStatus].filter(Boolean),
      complete:
        Number.isFinite(effectiveContribution.maxSingleRaterContributionShare) &&
        (effectiveContribution.itemRows?.length ?? 0) > 0 &&
        hasRequiredValue(effectiveContribution.dominanceReviewStatus) &&
        Array.isArray(effectiveContribution.independentExpertReviewRequiredItemIds),
      reviewReasons: [
        Number.isFinite(effectiveContribution.maxSingleRaterContributionShare)
          ? null
          : "effectiveContribution.maxSingleRaterContributionShare",
        (effectiveContribution.itemRows?.length ?? 0) > 0 ? null : "effectiveContribution.itemRows",
        hasRequiredValue(effectiveContribution.dominanceReviewStatus) ? null : "effectiveContribution.dominanceReviewStatus",
        Array.isArray(effectiveContribution.independentExpertReviewRequiredItemIds)
          ? null
          : "effectiveContribution.independentExpertReviewRequiredItemIds",
      ],
      requirement:
        "Label snapshots report largest single-rater contribution share and identify rows that need independent expert review before strong claims.",
    }),
    labelAggregationChecklistRow({
      id: "disagreement_policy_and_post_discussion",
      label: "Disagreement thresholds and post-discussion residuals",
      evidenceIds: [disagreementThresholdPolicyEvidence?.id, postDiscussionDisagreement?.id].filter(Boolean),
      sourceStatuses: [
        disagreementThresholdPolicyEvidence?.releaseUseStatus,
        postDiscussionDisagreement?.releaseUseStatus,
      ].filter(Boolean),
      complete:
        disagreementPolicyStatusOk &&
        hasRequiredValue(postDiscussionDisagreement?.releaseUseStatus) &&
        !String(postDiscussionDisagreement?.releaseUseStatus ?? "").includes("review_required") &&
        (disagreementCounts.missingMemoHighSpreadItemCount ?? 0) === 0,
      reviewReasons: [
        disagreementPolicyStatusOk ? null : "disagreementThresholdPolicyEvidence.releaseUseStatus",
        hasRequiredValue(postDiscussionDisagreement?.releaseUseStatus) ? null : "postDiscussionDisagreement.releaseUseStatus",
        String(postDiscussionDisagreement?.releaseUseStatus ?? "").includes("review_required")
          ? "postDiscussionDisagreement.review_required"
          : null,
        (disagreementCounts.missingMemoHighSpreadItemCount ?? 0) > 0
          ? "postDiscussionDisagreement.missingMemoHighSpreadItemCount"
          : null,
      ],
      requirement:
        "Residual high-spread release-critical items are classified under frozen disagreement thresholds and are not forced into silent consensus.",
    }),
    labelAggregationChecklistRow({
      id: "adjudication_memos_and_minority_rationales",
      label: "Adjudication memos and minority rationales",
      evidenceIds: [adjudicationMemoAudit?.id].filter(Boolean),
      sourceStatuses: [adjudicationMemoAudit?.releaseUseStatus].filter(Boolean),
      complete:
        adjudicationStatusOk &&
        (adjudicationCounts.memoCount ?? 0) > 0 &&
        (adjudicationCounts.incompleteReleaseCriticalAmbiguityMemoCount ?? 0) === 0,
      reviewReasons: [
        adjudicationStatusOk ? null : "adjudicationMemoAudit.releaseUseStatus",
        (adjudicationCounts.memoCount ?? 0) > 0 ? null : "adjudicationMemoAudit.memoCount",
        (adjudicationCounts.incompleteReleaseCriticalAmbiguityMemoCount ?? 0) > 0
          ? "adjudicationMemoAudit.incompleteReleaseCriticalAmbiguityMemoCount"
          : null,
      ],
      requirement:
        "Release-critical adjudication records preserve ambiguity decisions, bottom-line dependence, imprecision flags, obfuscation risks, and minority rationales.",
    }),
    labelAggregationChecklistRow({
      id: "metric_directionality_and_low_clarity",
      label: "Metric directionality and low-clarity policy",
      evidenceIds: [metricDirectionalityConfig?.id].filter(Boolean),
      sourceStatuses: [metricDirectionalityConfig?.releaseUseStatus].filter(Boolean),
      complete:
        metricDirectionalityConfig?.releaseUseStatus === "metric_config_and_directionality_declared" &&
        hasRequiredValue(metricDirectionalityConfig?.effectiveMetricConfig?.lowClarityPolicy) &&
        (metricCounts.directionalityRows ?? 0) > 0 &&
        (metricCounts.configViolationCount ?? 0) === 0 &&
        (metricCounts.directionalityViolationCount ?? 0) === 0,
      reviewReasons: [
        metricDirectionalityConfig?.releaseUseStatus !== "metric_config_and_directionality_declared"
          ? "metricDirectionalityConfig.releaseUseStatus"
          : null,
        hasRequiredValue(metricDirectionalityConfig?.effectiveMetricConfig?.lowClarityPolicy)
          ? null
          : "metricDirectionalityConfig.lowClarityPolicy",
        (metricCounts.directionalityRows ?? 0) > 0 ? null : "metricDirectionalityConfig.directionalityRows",
        (metricCounts.configViolationCount ?? 0) > 0 ? "metricDirectionalityConfig.configViolationCount" : null,
        (metricCounts.directionalityViolationCount ?? 0) > 0 ? "metricDirectionalityConfig.directionalityViolationCount" : null,
      ],
      requirement:
        "Custom-loss and pairwise reports declare target-vs-prediction directionality, tie policies, and low-clarity branch behavior before leaderboard or ceiling claims.",
    }),
    labelAggregationChecklistRow({
      id: "model_assisted_overlap_disclosed",
      label: "Model-assisted overlap disclosed",
      evidenceIds: [modelAssistedLabelOverlap?.id].filter(Boolean),
      sourceStatuses: [modelAssistedLabelOverlap?.releaseUseStatus].filter(Boolean),
      complete:
        modelAssistedStatusOk &&
        hasRequiredValue(modelAssistedLabelOverlap?.humanOnlyPreAssistanceTarget?.status ?? modelAssistedLabelOverlap?.releaseUseStatus),
      reviewReasons: [
        modelAssistedLabelOverlap ? null : "modelAssistedLabelOverlap:missing",
        modelAssistedStatusOk ? null : "modelAssistedLabelOverlap.releaseUseStatus",
        hasRequiredValue(modelAssistedLabelOverlap?.humanOnlyPreAssistanceTarget?.status ?? modelAssistedLabelOverlap?.releaseUseStatus)
          ? null
          : "modelAssistedLabelOverlap.humanOnlyPreAssistanceTarget",
      ],
      requirement:
        "Model-assisted checks and evaluator-family overlap are disclosed, and clean model comparisons require a human-only or pre-assistance target when overlap is sensitive.",
    }),
  ];

  return {
    id: `label-aggregation-reliability-checklist-${releaseId}`,
    releaseId,
    generatedAt: new Date().toISOString(),
    policy: {
      scope:
        "RLHF91 label aggregation and reliability checklist over existing LabelSnapshot, Rating, RevisionRecord, AdjudicationMemo, disagreement-policy, metric-config, and model-assisted-overlap evidence.",
      duplicationBoundary:
        "This checklist does not create a new label snapshot, rating table, rater-weighting algorithm, adjudication object, or candidate architecture; it only binds existing release-report evidence.",
      releaseClaimBoundary:
        "Limitations such as thin final-rater overlap, single-rater dominance, and model-assisted overlap remain disclosed rather than converted into stronger consensus or clean-baseline claims.",
    },
    counts: {
      checklistRows: rows.length,
      completeRows: rows.filter((row) => row.status === "complete").length,
      reviewRequiredRows: rows.filter((row) => row.status === "review_required").length,
      includedRatingCount: includedRatingProvenance.includedRatingCount ?? 0,
      blindInitialRows: revisionCounts.blindInitialRows ?? 0,
      revisionRows: revisionCounts.revisionRows ?? 0,
      checkRows:
        (revisionCounts.selfCheckRows ?? 0) +
        (revisionCounts.expertCheckRows ?? 0) +
        (revisionCounts.modelAssistedCheckRows ?? 0),
      maxSingleRaterContributionShare: effectiveContribution.maxSingleRaterContributionShare ?? null,
      singleRaterDominatedItems: effectiveContribution.singleRaterDominatedItemIds?.length ?? 0,
      highSpreadItems: disagreementCounts.highSpreadItemCount ?? 0,
      missingMemoHighSpreadItems: disagreementCounts.missingMemoHighSpreadItemCount ?? 0,
      adjudicationMemos: adjudicationCounts.memoCount ?? 0,
      modelAssistedRatingCheckRows: modelAssistedLabelOverlap?.counts?.submittedModelAssistedRatingCheckRows ?? 0,
    },
    rows,
    reviewSections: rows.flatMap((row) =>
      row.reviewReasons.map((reason) => ({
        artifactType: "label_aggregation_reliability_checklist",
        artifactId: row.id,
        reason,
      })),
    ),
    releaseUseStatus: rows.every((row) => row.status === "complete")
      ? "label_aggregation_reliability_requirements_evidenced"
      : "label_aggregation_reliability_review_required",
  };
}

function labelAggregationChecklistRow({ id, label, requirement, evidenceIds = [], sourceStatuses = [], complete, reviewReasons = [] }) {
  const filteredReasons = reviewReasons.filter(Boolean);
  return {
    id,
    label,
    requirement,
    evidenceIds,
    sourceStatuses,
    status: complete && filteredReasons.length === 0 ? "complete" : "review_required",
    reviewReasons: filteredReasons,
  };
}

export function buildModelEvaluationReproducibilityChecklistReport(
  releaseId,
  {
    itemTextViewParity,
    samePositionContext,
    leaderboardReport,
    modelEvaluationArtifactEvidence,
    promptParserProvenance,
    promptTrackSeparation,
    metricDirectionalityConfig,
    modelAssistedLabelOverlap,
    modelFailureAudits = [],
    auxiliaryWorkflowEvidence,
  } = {},
) {
  const leaderboard = leaderboardReport ?? {};
  const modelRunProvenance = leaderboard.modelRunProvenance ?? {};
  const parserPromptIntegrity = leaderboard.parserPromptIntegrity ?? {};
  const modelRunPolicyEvidence =
    auxiliaryWorkflowEvidence?.modelRunReproducibilityPolicyEvidence ??
    modelRunProvenance.modelRunReproducibilityPolicyEvidence ??
    null;
  const artifactEvidence = modelEvaluationArtifactEvidence ?? {};
  const predictionCounts = artifactEvidence.predictionEvidence?.counts ?? {};
  const uncertaintyPolicy = leaderboard.uncertaintyPolicy ?? {};
  const modelAssistedStatusOk =
    hasRequiredValue(modelAssistedLabelOverlap?.releaseUseStatus) &&
    !String(modelAssistedLabelOverlap.releaseUseStatus).includes("review_required");
  const failureAudits = Array.isArray(modelFailureAudits) ? modelFailureAudits : [];
  const failureDiagnosticsOk =
    failureAudits.length > 0 &&
    failureAudits.every(
      (audit) =>
        audit?.diagnosticOnly === true &&
        audit?.cannotReplaceAggregateMetrics === true &&
        hasRequiredValue(audit?.claimGatedDiagnostics?.releaseUseStatus) &&
        !String(audit.claimGatedDiagnostics.releaseUseStatus).includes("review_required"),
    );
  const modelRunPolicyStatusOk = [
    "seed_model_run_reproducibility_policy_active",
    "submitted_model_run_reproducibility_policy_active",
  ].includes(modelRunPolicyEvidence?.releaseUseStatus);
  const leaderboardModelRunStatusOk = [
    "common_model_run_provenance_declared",
    "mixed_model_run_provenance_sensitivity_declared",
  ].includes(modelRunProvenance.releaseUseStatus);
  const promptParserStatusOk = ["seed_prompt_parser_provenance_complete", "submitted_prompt_parser_provenance_complete"].includes(
    promptParserProvenance?.releaseUseStatus,
  );
  const promptTrackStatusOk = promptTrackSeparation?.releaseUseStatus === "appendix_g_baseline_separated_from_project_prompt_tracks";
  const parserPromptStatusOk =
    hasRequiredValue(parserPromptIntegrity.releaseUseStatus) &&
    !String(parserPromptIntegrity.releaseUseStatus).includes("review_required");
  const leaderboardStatusOk =
    hasRequiredValue(leaderboard.releaseUseStatus) && !String(leaderboard.releaseUseStatus).includes("review_required");

  const rows = [
    modelEvaluationChecklistRow({
      id: "submitted_evaluation_artifacts_bound_to_release",
      label: "Submitted evaluation artifacts bound to release",
      evidenceIds: [artifactEvidence.id].filter(Boolean),
      sourceStatuses: [artifactEvidence.releaseUseStatus].filter(Boolean),
      complete: artifactEvidence.releaseUseStatus === "submitted_model_evaluation_artifacts_release_evidence_complete",
      reviewReasons: [
        !artifactEvidence.id ? "modelEvaluationArtifactEvidence:missing" : null,
        artifactEvidence.releaseUseStatus !== "submitted_model_evaluation_artifacts_release_evidence_complete"
          ? "modelEvaluationArtifactEvidence.releaseUseStatus"
          : null,
        (artifactEvidence.reviewSections?.length ?? 0) > 0 ? "modelEvaluationArtifactEvidence.reviewSections" : null,
      ],
      requirement:
        "Submitted evaluation runs, predictions, calibration, leaderboards, failure audits, provider policies, and run provenance match the current release target.",
    }),
    modelEvaluationChecklistRow({
      id: "item_text_and_context_parity",
      label: "Item text and rating-context parity",
      evidenceIds: [itemTextViewParity?.id, samePositionContext?.id].filter(Boolean),
      sourceStatuses: [itemTextViewParity?.releaseUseStatus, samePositionContext?.releaseUseStatus].filter(Boolean),
      complete:
        itemTextViewParity?.releaseUseStatus === "item_text_versions_frozen_with_human_model_view_parity" &&
        samePositionContext?.releaseUseStatus === "same_position_context_parity_preserved",
      reviewReasons: [
        itemTextViewParity?.releaseUseStatus !== "item_text_versions_frozen_with_human_model_view_parity"
          ? "itemTextViewParity.releaseUseStatus"
          : null,
        samePositionContext?.releaseUseStatus !== "same_position_context_parity_preserved"
          ? "samePositionContext.releaseUseStatus"
          : null,
      ],
      requirement:
        "Human ratings and model predictions bind to frozen item-text hashes and same-position context snapshots before clean model-comparison claims.",
    }),
    modelEvaluationChecklistRow({
      id: "prompt_parser_and_injection_controls",
      label: "Prompt, parser, and prompt-injection controls",
      evidenceIds: [promptParserProvenance?.id, promptTrackSeparation?.id, leaderboard.id].filter(Boolean),
      sourceStatuses: [
        promptParserProvenance?.releaseUseStatus,
        promptTrackSeparation?.releaseUseStatus,
        parserPromptIntegrity.releaseUseStatus,
      ].filter(Boolean),
      complete: promptParserStatusOk && promptTrackStatusOk && parserPromptStatusOk,
      reviewReasons: [
        promptParserStatusOk ? null : "promptParserProvenance.releaseUseStatus",
        promptTrackStatusOk ? null : "promptTrackSeparation.releaseUseStatus",
        parserPromptStatusOk ? null : "leaderboardReport.parserPromptIntegrity.releaseUseStatus",
        (parserPromptIntegrity.reviewSections?.length ?? 0) > 0 ? "leaderboardReport.parserPromptIntegrity.reviewSections" : null,
      ],
      requirement:
        "Prompt templates, parser configs, Appendix-G-vs-project prompt tracks, schema retry behavior, and item-text-as-data controls are versioned and comparable.",
    }),
    modelEvaluationChecklistRow({
      id: "leaderboard_model_run_provenance",
      label: "Leaderboard model-run provenance",
      evidenceIds: [leaderboard.id, ...modelRunProvenance.perModelRows?.map((row) => row.modelInferenceConfigId).filter(Boolean) ?? []].filter(Boolean),
      sourceStatuses: [modelRunProvenance.releaseUseStatus, modelRunProvenance.commonSettingStatus].filter(Boolean),
      complete:
        leaderboardModelRunStatusOk &&
        (modelRunProvenance.perModelRows?.length ?? 0) > 0 &&
        (modelRunProvenance.reviewSections?.length ?? 0) === 0,
      reviewReasons: [
        leaderboardModelRunStatusOk ? null : "leaderboardReport.modelRunProvenance.releaseUseStatus",
        (modelRunProvenance.perModelRows?.length ?? 0) > 0 ? null : "leaderboardReport.modelRunProvenance.perModelRows",
        (modelRunProvenance.reviewSections?.length ?? 0) > 0 ? "leaderboardReport.modelRunProvenance.reviewSections" : null,
      ],
      requirement:
        "Every leaderboard evaluation run has resolved model snapshot, inference config, deterministic settings, environment metadata, and parser/extractor version links.",
    }),
    modelEvaluationChecklistRow({
      id: "submitted_run_inference_environment_provenance",
      label: "Submitted run inference and environment provenance",
      evidenceIds: [
        artifactEvidence.modelRunProvenanceEvidence?.modelInferenceConfigId,
        artifactEvidence.modelRunProvenanceEvidence?.modelRunEnvironmentId,
      ].filter(Boolean),
      sourceStatuses: [
        artifactEvidence.modelRunProvenanceEvidence?.status,
        artifactEvidence.modelRunProvenanceEvidence?.modelRunReproducibilityPolicyReleaseUseStatus,
      ].filter(Boolean),
      complete: artifactEvidence.modelRunProvenanceEvidence?.status === "submitted_model_run_provenance_preserves_inference_and_environment",
      reviewReasons: [
        artifactEvidence.modelRunProvenanceEvidence?.status !== "submitted_model_run_provenance_preserves_inference_and_environment"
          ? "modelEvaluationArtifactEvidence.modelRunProvenanceEvidence.status"
          : null,
      ],
      requirement:
        "Submitted model-evaluation artifacts preserve model inference config and model-run environment evidence for their evaluated run.",
    }),
    modelEvaluationChecklistRow({
      id: "model_run_reproducibility_policy_active",
      label: "Model-run reproducibility policy active",
      evidenceIds: [modelRunPolicyEvidence?.id, modelRunPolicyEvidence?.activePolicyId].filter(Boolean),
      sourceStatuses: [modelRunPolicyEvidence?.releaseUseStatus].filter(Boolean),
      complete: modelRunPolicyStatusOk && (modelRunPolicyEvidence?.reviewRows?.length ?? 0) === 0,
      reviewReasons: [
        modelRunPolicyStatusOk ? null : "modelRunReproducibilityPolicyEvidence.releaseUseStatus",
        (modelRunPolicyEvidence?.reviewRows?.length ?? 0) > 0 ? "modelRunReproducibilityPolicyEvidence.reviewRows" : null,
      ],
      requirement:
        "A frozen reproducibility policy declares required inference-config fields, run-environment fields, parser/prompt linkage, and clean-comparison boundaries.",
    }),
    modelEvaluationChecklistRow({
      id: "metric_uncertainty_and_directionality",
      label: "Metric uncertainty and directionality",
      evidenceIds: [metricDirectionalityConfig?.id, leaderboard.id].filter(Boolean),
      sourceStatuses: [metricDirectionalityConfig?.releaseUseStatus, leaderboard.releaseUseStatus].filter(Boolean),
      complete:
        metricDirectionalityConfig?.releaseUseStatus === "metric_config_and_directionality_declared" &&
        leaderboardStatusOk &&
        hasRequiredValue(uncertaintyPolicy.intervalType) &&
        hasRequiredValue(uncertaintyPolicy.nominalLevel) &&
        hasRequiredValue(uncertaintyPolicy.constructionMethod) &&
        hasRequiredValue(uncertaintyPolicy.resamplingUnit),
      reviewReasons: [
        metricDirectionalityConfig?.releaseUseStatus !== "metric_config_and_directionality_declared"
          ? "metricDirectionalityConfig.releaseUseStatus"
          : null,
        leaderboardStatusOk ? null : "leaderboardReport.releaseUseStatus",
        hasRequiredValue(uncertaintyPolicy.intervalType) ? null : "leaderboardReport.uncertaintyPolicy.intervalType",
        hasRequiredValue(uncertaintyPolicy.nominalLevel) ? null : "leaderboardReport.uncertaintyPolicy.nominalLevel",
        hasRequiredValue(uncertaintyPolicy.constructionMethod) ? null : "leaderboardReport.uncertaintyPolicy.constructionMethod",
        hasRequiredValue(uncertaintyPolicy.resamplingUnit) ? null : "leaderboardReport.uncertaintyPolicy.resamplingUnit",
      ],
      requirement:
        "Leaderboards and custom losses declare target/prediction directionality, tie policies, uncertainty interval provenance, and common-subset ranking limits.",
    }),
    modelEvaluationChecklistRow({
      id: "model_assisted_label_overlap_separation",
      label: "Model-assisted label overlap separation",
      evidenceIds: [modelAssistedLabelOverlap?.id].filter(Boolean),
      sourceStatuses: [modelAssistedLabelOverlap?.releaseUseStatus].filter(Boolean),
      complete:
        modelAssistedStatusOk &&
        hasRequiredValue(modelAssistedLabelOverlap?.humanOnlyPreAssistanceTarget?.status ?? modelAssistedLabelOverlap?.releaseUseStatus),
      reviewReasons: [
        modelAssistedLabelOverlap ? null : "modelAssistedLabelOverlap:missing",
        modelAssistedStatusOk ? null : "modelAssistedLabelOverlap.releaseUseStatus",
        hasRequiredValue(modelAssistedLabelOverlap?.humanOnlyPreAssistanceTarget?.status ?? modelAssistedLabelOverlap?.releaseUseStatus)
          ? null
          : "modelAssistedLabelOverlap.humanOnlyPreAssistanceTarget",
      ],
      requirement:
        "Clean model-evaluation claims use human-only or overlap-free targets, while model-assisted checking and provider-family overlap remain disclosed.",
    }),
    modelEvaluationChecklistRow({
      id: "failure_diagnostics_claim_gated",
      label: "Failure diagnostics are claim-gated",
      evidenceIds: failureAudits.map((audit) => audit.id).filter(Boolean),
      sourceStatuses: failureAudits.map((audit) => audit.claimGatedDiagnostics?.releaseUseStatus).filter(Boolean),
      complete: failureDiagnosticsOk,
      reviewReasons: [
        failureAudits.length > 0 ? null : "modelFailureAudits:missing",
        failureDiagnosticsOk ? null : "modelFailureAudits.claimGatedDiagnostics",
      ],
      requirement:
        "Failure audits remain diagnostic-only, cannot replace aggregate metrics, and require claim-gated robustness diagnostics before stronger model-improvement claims.",
    }),
  ];

  return {
    id: `model-evaluation-reproducibility-checklist-${releaseId}`,
    releaseId,
    generatedAt: new Date().toISOString(),
    policy: {
      scope:
        "RLHF91 model-evaluation reproducibility checklist over existing item-text parity, prompt/parser, leaderboard, model-run provenance, metric, provider, overlap, and failure-audit evidence.",
      duplicationBoundary:
        "This checklist does not create a new model-evaluation table, queue path, candidate artifact, source-preparation bridge, or model run; it only binds existing release-report evidence.",
      releaseClaimBoundary:
        "Incomplete submitted artifacts, missing leaderboard model-run provenance, prompt/parser review, or protected-data/provider gaps keep release claims review-required or sensitivity-labeled.",
    },
    counts: {
      checklistRows: rows.length,
      completeRows: rows.filter((row) => row.status === "complete").length,
      reviewRequiredRows: rows.filter((row) => row.status === "review_required").length,
      submittedEvaluationRunCount: artifactEvidence.evaluationRunEvidence?.submittedArtifactId ? 1 : 0,
      submittedPredictionRows: predictionCounts.predictionRows ?? 0,
      leaderboardEvaluationRunCount: modelRunProvenance.perModelRows?.length ?? leaderboard.rows?.length ?? 0,
      leaderboardRunsWithInferenceConfig: modelRunProvenance.perModelRows?.filter((row) => hasRequiredValue(row.modelInferenceConfigId)).length ?? 0,
      leaderboardRunsWithEnvironment: modelRunProvenance.perModelRows?.filter((row) => hasRequiredValue(row.modelRunEnvironmentId)).length ?? 0,
      modelRunProvenanceReviewSections: modelRunProvenance.reviewSections?.length ?? 0,
      promptParserReviewRows:
        (promptParserProvenance?.reviewRows?.submittedPromptReviewRows?.length ?? 0) +
        (promptParserProvenance?.reviewRows?.submittedParserReviewRows?.length ?? 0),
      failureAuditCount: failureAudits.length,
    },
    rows,
    reviewSections: rows.flatMap((row) =>
      row.reviewReasons.map((reason) => ({
        artifactType: "model_evaluation_reproducibility_checklist",
        artifactId: row.id,
        reason,
      })),
    ),
    releaseUseStatus: rows.every((row) => row.status === "complete")
      ? "model_evaluation_reproducibility_requirements_evidenced"
      : "model_evaluation_reproducibility_review_required",
  };
}

function modelEvaluationChecklistRow({ id, label, requirement, evidenceIds = [], sourceStatuses = [], complete, reviewReasons = [] }) {
  const filteredReasons = reviewReasons.filter(Boolean);
  return {
    id,
    label,
    requirement,
    evidenceIds,
    sourceStatuses,
    status: complete && filteredReasons.length === 0 ? "complete" : "review_required",
    reviewReasons: filteredReasons,
  };
}

export function buildHiddenBenchmarkInitialBlindingReport(
  releaseId,
  labelSnapshot,
  ratings = seedRatings,
  positionList = positions,
) {
  const positionById = new Map(positionList.map((position) => [position.id, position]));
  const rows = ratings
    .filter((rating) => positionById.get(rating.positionId)?.split === "hidden_benchmark" && rating.kind === "blind_initial")
    .map((rating) => {
      const visibility = preLockVisibilityFromRating(rating);
      const visibleCueFields = Object.entries(visibility)
        .filter(([, visible]) => visible)
        .map(([field]) => field);
      const exceptionId = blindAggregationExceptionId(rating);
      const exceptionDisclosed = blindAggregationExceptionDisclosed(rating);
      const blindAggregationPolicy = hiddenBenchmarkInitialRatingPolicy(rating, positionList);
      return {
        ratingId: rating.id,
        itemId: makeItemId(rating.positionId, rating.critiqueId),
        raterId: rating.raterId,
        sourceMetadataVisibleBeforeInitialLock: visibility.sourceMetadataVisibleBeforeInitialLock,
        adminTagsVisibleBeforeInitialLock: visibility.adminTagsVisibleBeforeInitialLock,
        topicRoutingTagsVisibleBeforeInitialLock: visibility.topicRoutingTagsVisibleBeforeInitialLock,
        benchmarkStatusVisibleBeforeInitialLock: visibility.benchmarkStatusVisibleBeforeInitialLock,
        visibleCueFields,
        sourceTagVisibleBeforeInitialLock: visibleCueFields.length > 0,
        adjudicatedExceptionId: exceptionId,
        exceptionDisclosed,
        blindAggregationPolicy,
        includedInBlindAggregation: blindAggregationPolicy !== "exclude_source_tag_visible_initial_from_blind_aggregation",
      };
    })
    .sort((left, right) => left.itemId.localeCompare(right.itemId) || left.ratingId.localeCompare(right.ratingId));
  const visibleRows = rows.filter((row) => row.sourceTagVisibleBeforeInitialLock);
  const excludedRows = rows.filter((row) => row.blindAggregationPolicy === "exclude_source_tag_visible_initial_from_blind_aggregation");
  const exceptionRows = rows.filter((row) => row.blindAggregationPolicy === "include_adjudicated_exception_disclosed");
  const snapshotExcludedRows = labelSnapshot?.excludedBlindAggregationRows ?? [];
  const undisclosedIncludedRows = visibleRows.filter((row) => row.includedInBlindAggregation && row.blindAggregationPolicy !== "include_adjudicated_exception_disclosed");
  return {
    id: `hidden-benchmark-initial-blinding-${releaseId}`,
    releaseId,
    labelSnapshotId: labelSnapshot?.id ?? null,
    generatedAt: new Date().toISOString(),
    policy: {
      hiddenInitialRule:
        "Hidden-benchmark blind aggregation can include only source/tag-hidden initial ratings or source/tag-visible initial ratings with a disclosed adjudicated exception.",
      exclusionRule:
        "Source, admin-tag, topic-routing-tag, or benchmark-status visibility before initial lock excludes the row from blind aggregation unless an adjudicated exception is disclosed.",
      snapshotBindingRule:
        "LabelSnapshot.excludedBlindAggregationRows records source/tag-visible hidden-benchmark initial ratings excluded from the target labels.",
    },
    counts: {
      hiddenInitialRatingRows: rows.length,
      sourceTagVisibleInitialRows: visibleRows.length,
      excludedFromBlindAggregationRows: excludedRows.length,
      adjudicatedExceptionRows: exceptionRows.length,
      undisclosedIncludedRows: undisclosedIncludedRows.length,
      snapshotExcludedRows: snapshotExcludedRows.length,
    },
    rows,
    sourceTagVisibleRows: visibleRows,
    excludedRows,
    exceptionRows,
    snapshotExcludedRows,
    releaseUseStatus:
      undisclosedIncludedRows.length > 0
        ? "hidden_benchmark_initial_blinding_violation"
        : visibleRows.length > 0
          ? "source_tag_visible_initial_ratings_excluded_or_exception_disclosed"
          : "hidden_benchmark_initial_rating_blinding_pass",
  };
}

export function buildPositionIntakeReadinessReport(releaseId, positionList = positions) {
  const rows = positionList
    .map((position) => {
      const latestVersion = latestText(position);
      const screening = position.intakeScreening ?? {};
      const originalTextPreserved = screening.originalTextPreserved === true && Boolean(latestVersion?.text);
      const adminNotes = [...(screening.adminOnlyAmbiguityNotes ?? []), ...(screening.adminOnlyIntendedConclusionNotes ?? [])];
      const adminNotesHiddenFromInitialRaters = screening.notesVisibleToInitialRaters === false && adminNotes.length > 0;
      const conceptuallyAdmissible = ["primarily_conceptual", "mixed_conceptual_non_conceptual"].includes(position.conceptualScope);
      const contextSufficientOrNormalized =
        position.contextSufficiency === "sufficient" ||
        ["normalized", "rights_review_normalized", "expert_normalized"].includes(screening.normalizationStatus);
      const ordinaryHeadlineEligible = conceptuallyAdmissible && contextSufficientOrNormalized && screening.ordinaryHeadlineEligibility === "eligible";
      const reviewReasons = positionIntakeReviewReasons(position, screening, {
        latestVersion,
        originalTextPreserved,
        conceptuallyAdmissible,
        contextSufficientOrNormalized,
      });
      return {
        positionId: position.id,
        clusterId: position.clusterId,
        split: position.split,
        topicFamily: position.topicFamily,
        conceptualScope: position.conceptualScope,
        groundTruthAvailability: position.groundTruthAvailability,
        acceptedMethodologyStatus: position.acceptedMethodologyStatus,
        nonConceptualDependencyNotes: position.nonConceptualDependencyNotes,
        contextSufficiency: position.contextSufficiency,
        assumedBackgroundPolicy: position.assumedBackgroundPolicy,
        pricedInContextNotes: position.pricedInContextNotes,
        originalTextPreserved,
        raterVisibleTextVersionId: screening.raterVisibleTextVersionId ?? latestVersion?.id ?? null,
        canonicalHash: latestVersion?.canonicalHash ?? null,
        normalizationStatus: screening.normalizationStatus ?? "missing",
        expertNormalizationRequired: Boolean(screening.expertNormalizationRequired),
        adminOnlyAmbiguityNotes: screening.adminOnlyAmbiguityNotes ?? [],
        adminOnlyIntendedConclusionNotes: screening.adminOnlyIntendedConclusionNotes ?? [],
        adminNotesHiddenFromInitialRaters,
        contextGapFlags: screening.contextGapFlags ?? [],
        ordinaryHeadlineEligibility: screening.ordinaryHeadlineEligibility ?? "missing",
        ordinaryHeadlineEligible,
        reviewReasons,
        hiddenBenchmarkEligible:
          position.split === "hidden_benchmark" &&
          reviewReasons.length === 0 &&
          ordinaryHeadlineEligible &&
          screening.notesVisibleToInitialRaters === false,
      };
    })
    .sort((left, right) => Number(right.expertNormalizationRequired) - Number(left.expertNormalizationRequired) || left.positionId.localeCompare(right.positionId));
  const normalizationRequiredRows = rows.filter((row) => row.expertNormalizationRequired || row.contextSufficiency === "needs_normalization");
  const contextGapRows = rows.filter((row) => row.contextGapFlags.length > 0);
  const nonHeadlineRows = rows.filter((row) => !row.ordinaryHeadlineEligible);
  const incompleteScreeningRows = rows.filter((row) => row.reviewReasons.length > 0);
  const hiddenBenchmarkContextBlockedRows = rows.filter((row) => row.split === "hidden_benchmark" && !row.hiddenBenchmarkEligible);
  const reviewSections = rows.flatMap((row) =>
    row.reviewReasons.map((reason) => ({ artifactType: "position_intake_screening", artifactId: row.positionId, reason })),
  );
  return {
    id: `position-intake-readiness-${releaseId}`,
    releaseId,
    generatedAt: new Date().toISOString(),
    policy: {
      blindRaterBoundary:
        "Original text, normalization notes, intended-conclusion notes, topic-routing tags, and context-gap flags remain admin-only before initial ratings lock.",
      headlineEligibilityRule:
        "Ordinary hidden-benchmark/headline use requires conceptual admissibility plus sufficient or completed expert-normalized rater-visible context.",
      preservationRule:
        "Every position keeps an original/canonical text version and a rater-visible text version id for content-addressed comparison.",
    },
    counts: {
      positionsScreened: rows.length,
      originalTextPreservedCount: rows.filter((row) => row.originalTextPreserved).length,
      adminNotesHiddenCount: rows.filter((row) => row.adminNotesHiddenFromInitialRaters).length,
      normalizationRequiredCount: normalizationRequiredRows.length,
      contextGapFlaggedPositionCount: contextGapRows.length,
      incompleteScreeningCount: incompleteScreeningRows.length,
      ordinaryHeadlineEligibleCount: rows.filter((row) => row.ordinaryHeadlineEligible).length,
      nonHeadlinePositionCount: nonHeadlineRows.length,
      hiddenBenchmarkContextBlockedCount: hiddenBenchmarkContextBlockedRows.length,
    },
    byConceptualScope: countBy(rows, "conceptualScope"),
    byGroundTruthAvailability: countBy(rows, "groundTruthAvailability"),
    byContextSufficiency: countBy(rows, "contextSufficiency"),
    rows,
    normalizationRequiredRows,
    contextGapRows,
    nonHeadlineRows,
    incompleteScreeningRows,
    hiddenBenchmarkContextBlockedRows,
    reviewSections,
    releaseUseStatus:
      incompleteScreeningRows.length > 0
        ? "position_intake_screening_review_required"
        : hiddenBenchmarkContextBlockedRows.length > 0
        ? "position_intake_blocks_hidden_benchmark_claims"
        : normalizationRequiredRows.length || contextGapRows.length || nonHeadlineRows.length
          ? "position_intake_limitations_disclosed"
          : "position_intake_ready",
  };
}

function positionIntakeReviewReasons(position, screening, evidence) {
  const reasons = [
    REQUIRED_POSITION_CONCEPTUAL_SCOPE_STATUSES.includes(position.conceptualScope) ? null : "conceptualScope",
    REQUIRED_POSITION_GROUND_TRUTH_AVAILABILITY_STATUSES.includes(position.groundTruthAvailability) ? null : "groundTruthAvailability",
    REQUIRED_POSITION_ACCEPTED_METHODOLOGY_STATUSES.includes(position.acceptedMethodologyStatus) ? null : "acceptedMethodologyStatus",
    REQUIRED_POSITION_CONTEXT_SUFFICIENCY_STATUSES.includes(position.contextSufficiency) ? null : "contextSufficiency",
    hasRequiredText(position.nonConceptualDependencyNotes) ? null : "nonConceptualDependencyNotes",
    hasRequiredText(position.assumedBackgroundPolicy) ? null : "assumedBackgroundPolicy",
    hasRequiredText(position.pricedInContextNotes) ? null : "pricedInContextNotes",
    evidence.originalTextPreserved ? null : "originalTextPreserved",
    evidence.latestVersion?.canonicalHash ? null : "canonicalHash",
    hasRequiredText(screening.raterVisibleTextVersionId) ? null : "raterVisibleTextVersionId",
    REQUIRED_POSITION_INTAKE_NORMALIZATION_STATUSES.includes(screening.normalizationStatus) ? null : "normalizationStatus",
    screening.notesVisibleToInitialRaters === false ? null : "notesVisibleToInitialRaters",
    REQUIRED_POSITION_HEADLINE_ELIGIBILITY_STATUSES.includes(screening.ordinaryHeadlineEligibility) ? null : "ordinaryHeadlineEligibility",
  ].filter(Boolean);
  if (position.conceptualScope === "mixed_conceptual_non_conceptual") {
    if (!String(position.nonConceptualDependencyNotes ?? "").toLowerCase().includes("separat")) {
      reasons.push("nonConceptualDependencyNotes:separation");
    }
  }
  if (position.conceptualScope === "primarily_non_conceptual" && !policyMentionsAny(screening.ordinaryHeadlineEligibility, ["excluded", "stress", "comparison"])) {
    reasons.push("ordinaryHeadlineEligibility:nonconceptual");
  }
  if (["context_insufficient", "needs_normalization"].includes(position.contextSufficiency) && !evidence.contextSufficientOrNormalized) {
    if (!Array.isArray(screening.contextGapFlags) || screening.contextGapFlags.length === 0) {
      reasons.push("contextGapFlags");
    }
    if (!policyMentionsAny(screening.ordinaryHeadlineEligibility, ["normalization", "validation", "stress", "comparison", "excluded"])) {
      reasons.push("ordinaryHeadlineEligibility:context");
    }
  }
  return reasons;
}

function sourceIntakeRouteSummary() {
  const jsonlImportRoutes = SOURCE_INTAKE_JSONL_IMPORT_ROUTES.map((route) => ({
    route,
    dryRunImportRoute: operatorImportRouteWithQueryFlag(route, "dryRun", "true"),
    validateOnlyImportRoute: operatorImportRouteWithQueryFlag(route, "validateOnly", "true"),
  }));
  return {
    adminWriteRoutes: SOURCE_INTAKE_ADMIN_WRITE_ROUTES,
    jsonlImportRoutes,
    reviewRoutes: SOURCE_INTAKE_REVIEW_ROUTES,
    readbackRoutes: SOURCE_INTAKE_READBACK_ROUTES,
    templateReadbackRoutes: sourceWorkbenchTemplateRoutes([
      "source_card_write",
      "source_span_write",
      "extraction_jsonl_import",
      "argument_extraction_review",
    ]),
    workflowTemplateIds: [
      "source-workbench-template:source-card",
      "source-workbench-template:source-span",
      "source-workbench-template:extraction-jsonl",
      "source-workbench-template:extraction-review",
    ],
  };
}

function sourcePreparationRouteSummary() {
  return {
    adminWriteRoutes: SOURCE_PREPARATION_ADMIN_WRITE_ROUTES,
    readbackRoutes: SOURCE_PREPARATION_READBACK_ROUTES,
    templateReadbackRoutes: sourceWorkbenchTemplateRoutes([
      "prepared_position_draft_create",
      "prepared_critique_draft_create",
      "prepared_draft_review",
      "prepared_draft_promote",
    ]),
    workflowTemplateIds: [
      "source-workbench-template:prepared-position",
      "source-workbench-template:prepared-critique",
      "source-workbench-template:prepared-draft-review",
      "source-workbench-template:prepared-draft-promote",
    ],
  };
}

function sourceWorkbenchTemplateRoutes(templateKinds) {
  return [
    "/api/v1/metaphilosophy/source-workbench-template",
    ...templateKinds.map((templateKind) => operatorTemplateReadbackRoute("/api/v1/metaphilosophy/source-workbench-template", { templateKind })),
  ];
}

function sourceWorkbenchRouteCounts(routeSummary) {
  const routes = [
    ...flattenRouteValues(Object.values(routeSummary)),
    ...(routeSummary.jsonlImportRoutes ?? []).flatMap((item) => [item.route, item.dryRunImportRoute, item.validateOnlyImportRoute]),
    ...SOURCE_WORKBENCH_READBACK_ROUTES,
  ];
  const byRoute = {};
  for (const route of uniqueStrings(routes)) byRoute[route] = (byRoute[route] ?? 0) + 1;
  return {
    adminWriteRoutes: routeSummary.adminWriteRoutes?.length ?? 0,
    jsonlImportRoutes: routeSummary.jsonlImportRoutes?.length ?? 0,
    reviewRoutes: routeSummary.reviewRoutes?.length ?? 0,
    readbackRoutes: routeSummary.readbackRoutes?.length ?? 0,
    templateReadbackRoutes: routeSummary.templateReadbackRoutes?.length ?? 0,
    byRoute,
  };
}

function flattenRouteValues(values) {
  return values.flatMap((value) => {
    if (Array.isArray(value)) return flattenRouteValues(value);
    if (value && typeof value === "object") return flattenRouteValues(Object.values(value));
    return typeof value === "string" && value.startsWith("/api/") ? [value] : [];
  });
}

export function buildSourceIntakeEvidenceReport(releaseId, options = {}) {
  const sourceCards = latestSourceIntakeRows(options.sourceCards ?? []);
  const sourceCardRows = sourceCards
    .map((card, index) => {
      const reviewReasons = sourceCardReviewReasons(card);
      return {
        ...card,
        artifactId: hasRequiredText(card.id) ? card.id : `source-card-${index + 1}`,
        reviewReasons,
      };
    })
    .sort((left, right) => left.artifactId.localeCompare(right.artifactId));
  const validSourceCardIds = new Set(sourceCardRows.filter((row) => row.reviewReasons.length === 0).map((row) => row.id));

  const sourceSpans = latestSourceIntakeRows(options.sourceSpans ?? []);
  const sourceSpanRows = sourceSpans
    .map((span, index) => {
      const reviewReasons = sourceSpanReviewReasons(span, validSourceCardIds);
      return {
        ...span,
        artifactId: hasRequiredText(span.id) ? span.id : `source-span-${index + 1}`,
        reviewReasons,
      };
    })
    .sort((left, right) => left.artifactId.localeCompare(right.artifactId));
  const validSourceSpanById = new Map(sourceSpanRows.filter((row) => row.reviewReasons.length === 0).map((row) => [row.id, row]));

  const extractionBatches = latestSourceIntakeRows(options.extractionBatches ?? []);
  const extractionBatchRows = extractionBatches
    .map((batch, index) => {
      const reviewReasons = extractionBatchReviewReasons(batch, validSourceCardIds);
      return {
        ...batch,
        artifactId: hasRequiredText(batch.id) ? batch.id : `extraction-batch-${index + 1}`,
        reviewReasons,
      };
    })
    .sort((left, right) => left.artifactId.localeCompare(right.artifactId));
  const validExtractionBatchById = new Map(extractionBatchRows.filter((row) => row.reviewReasons.length === 0).map((row) => [row.id, row]));

  const argumentExtractions = latestSourceIntakeRows(options.argumentExtractions ?? []);
  const extractionsByBatchId = countBy(argumentExtractions, "extractionBatchId");
  const argumentExtractionRows = argumentExtractions
    .map((extraction, index) => {
      const reviewReasons = argumentExtractionReviewReasons(extraction, {
        validSourceCardIds,
        validSourceSpanById,
        validExtractionBatchById,
      });
      return {
        ...extraction,
        artifactId: hasRequiredText(extraction.id) ? extraction.id : `argument-extraction-${index + 1}`,
        reviewReasons,
      };
    })
    .sort((left, right) => left.artifactId.localeCompare(right.artifactId));

  for (const batchRow of extractionBatchRows) {
    const observedCount = extractionsByBatchId[batchRow.id] ?? 0;
    if (Number.isFinite(batchRow.extractionCount) && batchRow.extractionCount !== observedCount) {
      batchRow.reviewReasons = [...batchRow.reviewReasons, "extractionCount:jsonl_line_count_mismatch"];
    }
  }

  const reviewSections = [
    ...sourceIntakeReviewSections("source_card", sourceCardRows),
    ...sourceIntakeReviewSections("source_span", sourceSpanRows),
    ...sourceIntakeReviewSections("extraction_batch", extractionBatchRows),
    ...sourceIntakeReviewSections("argument_extraction", argumentExtractionRows),
  ];
  const pendingExtractionRows = argumentExtractionRows.filter((row) => row.reviewStatus === "pending_admin_review");
  const acceptedExtractionRows = argumentExtractionRows.filter((row) => ARGUMENT_EXTRACTION_ACCEPTED_REVIEW_STATUSES.includes(row.reviewStatus));
  const nonAcceptedReviewedExtractionRows = argumentExtractionRows.filter((row) =>
    ["needs_revision", "rejected", "deferred"].includes(row.reviewStatus),
  );
  const totalArtifacts = sourceCardRows.length + sourceSpanRows.length + extractionBatchRows.length + argumentExtractionRows.length;
  const releaseUseStatus = sourceIntakeReleaseUseStatus({
    totalArtifacts,
    reviewSections,
    pendingExtractionRows,
    argumentExtractionRows,
    acceptedExtractionRows,
  });
  const routes = sourceIntakeRouteSummary();

  return {
    id: `source-intake-evidence-${releaseId}`,
    releaseId,
    generatedAt: new Date().toISOString(),
    phase: SOURCE_INTAKE_PHASE,
    policy: {
      scope:
        "Phase 1 stores admin-only source cards, selected spans, JSONL extraction batches, and manually reviewed argument extractions.",
      raterVisibilityRule:
        "Source cards, raw source spans, and extraction provenance remain admin-only and are not rater-visible before any later preparation workflow.",
      downstreamBoundary:
        "Phase 1 does not create PreparedDraft, ReviewSignal, WorkflowGate, WorkflowPolicy, GateDecision, CandidateItem, CandidateBatch, PromotionRecord, candidate membership, AI extraction, or live queue artifacts.",
      importRule:
        "JSONL import records externally prepared argument extractions only; the platform does not execute AI extraction in this phase.",
    },
    counts: {
      sourceCards: sourceCardRows.length,
      sourceSpans: sourceSpanRows.length,
      extractionBatches: extractionBatchRows.length,
      argumentExtractions: argumentExtractionRows.length,
      pendingReviewExtractions: pendingExtractionRows.length,
      acceptedForSourcePreparationExtractions: acceptedExtractionRows.length,
      acceptedForPositionIntakeExtractions: argumentExtractionRows.filter((row) => row.reviewStatus === "accepted_for_position_intake").length,
      acceptedForCritiqueIntakeExtractions: argumentExtractionRows.filter((row) => row.reviewStatus === "accepted_for_critique_intake").length,
      acceptedForGeneralSourcePreparationExtractions: argumentExtractionRows.filter((row) => row.reviewStatus === "accepted_for_source_preparation").length,
      nonAcceptedReviewedExtractions: nonAcceptedReviewedExtractionRows.length,
      reviewRequiredArtifacts: new Set(reviewSections.map((section) => `${section.artifactType}:${section.artifactId}`)).size,
    },
    bySourceType: countBy(sourceCardRows, "sourceType"),
    bySpanKind: countBy(sourceSpanRows, "spanKind"),
    byArgumentRole: countBy(argumentExtractionRows, "argumentRole"),
    byExtractionReviewStatus: countBy(argumentExtractionRows, "reviewStatus"),
    routes,
    routeCounts: sourceWorkbenchRouteCounts(routes),
    sourceCardRows,
    sourceSpanRows,
    extractionBatchRows,
    argumentExtractionRows,
    pendingExtractionRows,
    acceptedExtractionRows,
    nonAcceptedReviewedExtractionRows,
    reviewSections,
    releaseUseStatus,
  };
}

export function buildSourcePreparationEvidenceReport(releaseId, options = {}) {
  const routes = sourcePreparationRouteSummary();
  const workflowPolicy = sourcePreparationWorkflowPolicyDefinition();
  const argumentExtractions = latestSourceIntakeRows(options.argumentExtractions ?? []);
  const extractionById = new Map(argumentExtractions.filter((row) => hasRequiredText(row.id)).map((row) => [row.id, row]));
  const sourcePreparedDraftRows = latestSourceIntakeRows(options.preparedDrafts ?? [])
    .filter((draft) => hasRequiredText(draft.sourceArgumentExtractionId))
    .map((draft, index) => {
      const extraction = extractionById.get(draft.sourceArgumentExtractionId);
      const gateSummary = gatesSatisfiedForPolicy("prepared_draft_readiness", draft.id, options.gateDecisions ?? []);
      const reviewReasons = sourcePreparedDraftReviewReasons(draft, extraction);
      return {
        ...draft,
        artifactId: hasRequiredText(draft.id) ? draft.id : `source-prepared-draft-${index + 1}`,
        sourceExtractionReviewStatus: extraction?.reviewStatus ?? null,
        requiredGateSummary: {
          policyId: workflowPolicy.policyId,
          status: gateSummary.ok ? "satisfied" : "blocked_or_pending",
          requiredGateIds: workflowPolicy.requiredGateIds,
          requiredGates: workflowPolicy.requiredGates,
          missingGateIds: gateSummary.missingGateIds,
          blockingGateIds: gateSummary.blockingGateIds,
        },
        reviewReasons,
      };
    })
    .sort((left, right) => left.artifactId.localeCompare(right.artifactId));

  const sourcePreparedDraftIds = new Set(sourcePreparedDraftRows.map((draft) => draft.id).filter(Boolean));
  const sourceCandidateItemRows = latestSourceIntakeRows(options.candidateItems ?? [])
    .filter((item) => item.sourceArgumentExtractionId || sourcePreparedDraftIds.has(item.sourcePreparedDraftId))
    .map((item, index) => ({
      ...item,
      artifactId: hasRequiredText(item.id) ? item.id : `source-candidate-item-${index + 1}`,
      reviewReasons: sourceCandidateItemReviewReasons(item, sourcePreparedDraftIds),
    }))
    .sort((left, right) => left.artifactId.localeCompare(right.artifactId));
  const sourcePromotionRecordRows = latestSourceIntakeRows(options.promotionRecords ?? [])
    .filter((record) => record.auditTrail?.argumentExtractionId || sourcePreparedDraftIds.has(record.sourcePreparedDraftId))
    .map((record, index) => ({
      ...record,
      artifactId: hasRequiredText(record.id) ? record.id : `source-promotion-record-${index + 1}`,
      reviewReasons: sourcePromotionRecordReviewReasons(record, sourcePreparedDraftIds),
    }))
    .sort((left, right) => left.artifactId.localeCompare(right.artifactId));
  const sourceCandidateItemIds = new Set(sourceCandidateItemRows.map((item) => item.id).filter(Boolean));
  const sourceArgumentExtractionIds = new Set(sourcePreparedDraftRows.map((draft) => draft.sourceArgumentExtractionId).filter(Boolean));
  const sourceExtractionBatchIds = new Set(sourcePreparedDraftRows.map((draft) => draft.sourceExtractionBatchId).filter(Boolean));
  const sourceCardIds = new Set(sourcePreparedDraftRows.map((draft) => draft.sourceCardId).filter(Boolean));
  const sourceSpanIds = new Set(sourcePreparedDraftRows.flatMap((draft) => (Array.isArray(draft.sourceSpanIds) ? draft.sourceSpanIds : [])).filter(Boolean));
  const sourceReviewSignalRows = latestSourceIntakeRows(options.reviewSignals ?? [])
    .filter((signal) =>
      sourcePreparationReviewSignalTargetsSourceLineage(signal, {
        sourcePreparedDraftIds,
        sourceCandidateItemIds,
        sourceArgumentExtractionIds,
        sourceExtractionBatchIds,
        sourceCardIds,
        sourceSpanIds,
      }),
    )
    .map((signal, index) => ({
      ...signal,
      artifactId: hasRequiredText(signal.id) ? signal.id : `source-review-signal-${index + 1}`,
      reviewReasons: sourceReviewSignalReviewReasons(signal),
    }))
    .sort((left, right) => left.artifactId.localeCompare(right.artifactId));
  const sourceGateDecisionRows = latestSourceIntakeRows(options.gateDecisions ?? [])
    .filter((decision) => decision.workflowPolicyId === "prepared_draft_readiness" && sourcePreparedDraftIds.has(decision.objectId))
    .map((decision, index) => ({
      ...decision,
      artifactId: hasRequiredText(decision.id) ? decision.id : `source-gate-decision-${index + 1}`,
      reviewReasons: sourceGateDecisionReviewReasons(decision, sourcePreparedDraftIds, new Set(sourceReviewSignalRows.map((signal) => signal.id).filter(Boolean))),
    }))
    .sort((left, right) => String(left.id ?? "").localeCompare(String(right.id ?? "")));

  const reviewSections = [
    ...sourcePreparationReviewSections("source_prepared_draft", sourcePreparedDraftRows),
    ...sourcePreparationReviewSections("source_review_signal", sourceReviewSignalRows),
    ...sourcePreparationReviewSections("source_gate_decision", sourceGateDecisionRows),
    ...sourcePreparationReviewSections("source_candidate_item", sourceCandidateItemRows),
    ...sourcePreparationReviewSections("source_promotion_record", sourcePromotionRecordRows),
  ];

  return {
    id: `source-preparation-evidence-${releaseId}`,
    releaseId,
    generatedAt: new Date().toISOString(),
    phase: "phase2_source_preparation",
    policy: {
      scope:
        "Source preparation creates reviewer-visible PreparedDraft records from accepted ArgumentExtraction records, then reuses the existing PreparedDraft review gates and CandidateItem promotion layer.",
      intakeBoundary:
        "JSONL import and extraction review remain Phase 1 source-intake actions and do not create prepared drafts or candidate artifacts by themselves.",
      promotionBoundary:
        "PreparedDraft promotion creates CandidateItem and PromotionRecord artifacts only; it does not create live Position, live Critique, CandidateBatch, candidate-batch membership, AI extraction jobs, or live queue work.",
      raterVisibilityRule:
        "SourceCard, SourceSpan, extraction provenance, source locator, raw source text, review signals, and gate decisions remain admin-only before any later rater-visible workflow.",
    },
    workflowPolicy,
    counts: {
      preparedDrafts: sourcePreparedDraftRows.length,
      candidateItems: sourceCandidateItemRows.length,
      promotionRecords: sourcePromotionRecordRows.length,
      reviewSignals: sourceReviewSignalRows.length,
      gateDecisions: sourceGateDecisionRows.length,
      reviewRequiredArtifacts: new Set(reviewSections.map((section) => `${section.artifactType}:${section.artifactId}`)).size,
    },
    byDraftType: countBy(sourcePreparedDraftRows, "draftType"),
    byPreparedDraftStatus: countBy(sourcePreparedDraftRows, "preparedDraftStatus"),
    byCandidateItemType: countBy(sourceCandidateItemRows, "itemType"),
    routes,
    routeCounts: sourceWorkbenchRouteCounts(routes),
    preparedDraftRows: sourcePreparedDraftRows,
    reviewSignalRows: sourceReviewSignalRows,
    candidateItemRows: sourceCandidateItemRows,
    promotionRecordRows: sourcePromotionRecordRows,
    gateDecisionRows: sourceGateDecisionRows,
    reviewSections,
    releaseUseStatus: sourcePreparationReleaseUseStatus({
      sourcePreparedDraftRows,
      sourceCandidateItemRows,
      sourcePromotionRecordRows,
      reviewSections,
    }),
  };
}

function sourcePreparationWorkflowPolicyDefinition() {
  const workflowPolicy = WORKFLOW_POLICIES.prepared_draft_readiness ?? {};
  const requiredGateIds = requiredGateIdsForPolicy("prepared_draft_readiness");
  const gateDefinitionRoute = "/api/v1/admin/workflow-gates?workflowPolicyId=prepared_draft_readiness";
  const gateDecisionRoute = "/api/v1/admin/gate-decisions";
  const requiredGates = requiredGateIds
    .map((gateId) => WORKFLOW_GATES[gateId])
    .filter(Boolean)
    .map((gate) => ({
      ...gate,
      readbackRoute: `/api/v1/admin/workflow-gates/${encodeURIComponent(gate.gateId)}?workflowPolicyId=prepared_draft_readiness`,
      definitionCollectionRoute: gateDefinitionRoute,
      decisionRoute: gateDecisionRoute,
      readbackSource: "static_workflow_gate_definition",
    }));
  return {
    policyId: "prepared_draft_readiness",
    appliesTo: Array.isArray(workflowPolicy.appliesTo) ? workflowPolicy.appliesTo : [],
    requiredGateIds,
    requiredGates,
    gateDefinitionRoute,
    gateDecisionRoute,
    readbackSource: "static_workflow_policy_definition",
    nonMutationBoundary:
      "This policy summary and its gate-definition routes are read-only release-report metadata; only submitted GateDecision rows are source-preparation evidence.",
  };
}

function latestSourceIntakeRows(rows) {
  const keyedRows = new Map();
  const unkeyedRows = [];
  for (const row of rows) {
    if (!row || typeof row !== "object" || Array.isArray(row)) continue;
    const clone = structuredClone(row);
    if (hasRequiredText(clone.id)) keyedRows.set(clone.id, clone);
    else unkeyedRows.push(clone);
  }
  return [...unkeyedRows, ...keyedRows.values()];
}

function sourcePreparedDraftReviewReasons(draft, extraction) {
  return [
    ...missingSourceIntakeFields(draft, [
      "id",
      "sourceArgumentExtractionId",
      "draftType",
      "preparedText",
      "candidateRaterVisibleText",
      "blindingReviewStatus",
      "sourceLeakageReviewStatus",
      "gateReadinessStatus",
      "candidateItemReadiness",
      "preparedDraftStatus",
      "createdBy",
      "createdAt",
    ]),
    ["prepared_position_draft", "prepared_critique_draft"].includes(draft.draftType) ? null : "draftType",
    extraction ? null : "sourceArgumentExtractionId:not_found",
    ARGUMENT_EXTRACTION_ACCEPTED_REVIEW_STATUSES.includes(extraction?.reviewStatus) ? null : "sourceArgumentExtractionId:not_accepted",
    hasRequiredText(draft.preparedText) ? null : "preparedText",
    hasRequiredText(draft.candidateRaterVisibleText) ? null : "candidateRaterVisibleText",
    draft.sourcePreparationPhase === "phase2_source_preparation" ? null : "sourcePreparationPhase",
    draft.sourcePreparationReviewStatus === "prepared_from_accepted_extraction" ? null : "sourcePreparationReviewStatus",
    draft.visibilityClasses?.preparedText === "reviewer_visible" ? null : "visibilityClasses.preparedText",
    draft.visibilityClasses?.candidateRaterVisibleText === "reviewer_visible" ? null : "visibilityClasses.candidateRaterVisibleText",
    draft.visibilityClasses?.sourceArgumentExtractionId === "admin_only" ? null : "visibilityClasses.sourceArgumentExtractionId",
    draft.draftType !== "prepared_critique_draft" ||
    hasRequiredText(draft.targetPreparedDraftId) ||
    hasRequiredText(draft.targetCandidateItemId) ||
    hasRequiredText(draft.targetPositionId)
      ? null
      : "critiqueTargetLink",
  ].filter(Boolean);
}

function sourceCandidateItemReviewReasons(item, sourcePreparedDraftIds) {
  return [
    ...missingSourceIntakeFields(item, [
      "id",
      "itemType",
      "sourcePreparedDraftId",
      "sourceArgumentExtractionId",
      "candidateItemStatus",
      "downstreamPromotionStatus",
      "createdAt",
    ]),
    ["candidate_position", "candidate_critique"].includes(item.itemType) ? null : "itemType",
    sourcePreparedDraftIds.has(item.sourcePreparedDraftId) ? null : "sourcePreparedDraftId:not_source_prepared_draft",
    hasRequiredText(item.candidateRaterVisibleText) ? null : "candidateRaterVisibleText",
    item.downstreamPromotionStatus === "not_promoted_to_live" ? null : "downstreamPromotionStatus",
    item.visibilityClasses?.candidateRaterVisibleText === "rater_visible_after_promotion" ? null : "visibilityClasses.candidateRaterVisibleText",
    item.visibilityClasses?.sourceArgumentExtractionId === "admin_only" ? null : "visibilityClasses.sourceArgumentExtractionId",
  ].filter(Boolean);
}

function sourcePromotionRecordReviewReasons(record, sourcePreparedDraftIds) {
  return [
    ...missingSourceIntakeFields(record, ["id", "sourcePreparedDraftId", "targetCandidateItemId", "targetType", "promotedBy", "promotedAt"]),
    sourcePreparedDraftIds.has(record.sourcePreparedDraftId) ? null : "sourcePreparedDraftId:not_source_prepared_draft",
    record.createdLiveRecord === false ? null : "createdLiveRecord",
    record.createdCandidateBatch === false ? null : "createdCandidateBatch",
    record.auditTrail?.sourceType === "argument_extraction" ? null : "auditTrail.sourceType",
  ].filter(Boolean);
}

function sourcePreparationReviewSignalTargetsSourceLineage(signal, lineage) {
  if (!signal || typeof signal !== "object" || Array.isArray(signal)) return false;
  if (signal.affectedObjectType === "PreparedDraft") return lineage.sourcePreparedDraftIds.has(signal.affectedObjectId);
  if (signal.affectedObjectType === "CandidateItem") return lineage.sourceCandidateItemIds.has(signal.affectedObjectId);
  if (signal.affectedObjectType === "ArgumentExtraction") return lineage.sourceArgumentExtractionIds.has(signal.affectedObjectId);
  if (signal.affectedObjectType === "ExtractionBatch") return lineage.sourceExtractionBatchIds.has(signal.affectedObjectId);
  if (signal.affectedObjectType === "SourceCard") return lineage.sourceCardIds.has(signal.affectedObjectId);
  if (signal.affectedObjectType === "SourceSpan") return lineage.sourceSpanIds.has(signal.affectedObjectId);
  return false;
}

function sourceReviewSignalReviewReasons(signal) {
  return [
    ...missingSourceIntakeFields(signal, ["id", "signalType", "source", "explanation", "affectedObjectType", "affectedObjectId", "visibilityClass", "createdAt"]),
    REVIEW_SIGNAL_SOURCES.includes(signal.source) ? null : "source",
    REVIEW_SIGNAL_RATER_HIDDEN_VISIBILITY_CLASSES.includes(signal.visibilityClass) ? null : "visibilityClass",
    signal.confidence === null ||
    signal.confidence === undefined ||
    (Number.isFinite(Number(signal.confidence)) && Number(signal.confidence) >= 0 && Number(signal.confidence) <= 1)
      ? null
      : "confidence",
  ].filter(Boolean);
}

function sourceGateDecisionReviewReasons(decision, sourcePreparedDraftIds, sourceReviewSignalIds) {
  const citedReviewSignalIds = Array.isArray(decision.citedReviewSignalIds) ? decision.citedReviewSignalIds : [];
  const requiredGateIds = requiredGateIdsForPolicy("prepared_draft_readiness");
  return [
    ...missingSourceIntakeFields(decision, ["id", "gateId", "workflowPolicyId", "objectType", "objectId", "gateStatus", "decisionSource", "decisionNote", "reviewerId", "timestamp", "visibilityClass"]),
    decision.workflowPolicyId === "prepared_draft_readiness" ? null : "workflowPolicyId",
    requiredGateIds.includes(decision.gateId) ? null : "gateId:not_required_for_policy",
    decision.objectType === "PreparedDraft" ? null : "objectType",
    sourcePreparedDraftIds.has(decision.objectId) ? null : "objectId:not_source_prepared_draft",
    GATE_DECISION_STATUSES.includes(decision.gateStatus) ? null : "gateStatus",
    decision.gateStatus !== "waived_with_reason" || hasRequiredText(decision.waiverReason) ? null : "waiverReason",
    decision.decisionSource !== "automated_prescreen" ? null : "decisionSource",
    hasRequiredText(decision.decisionNote) ? null : "decisionNote",
    REVIEW_SIGNAL_RATER_HIDDEN_VISIBILITY_CLASSES.includes(decision.visibilityClass) ? null : "visibilityClass",
    citedReviewSignalIds.length ? null : "citedReviewSignalIds",
    ...citedReviewSignalIds
      .filter((signalId) => !sourceReviewSignalIds.has(signalId))
      .map((signalId) => `citedReviewSignalIds:not_found:${signalId}`),
  ].filter(Boolean);
}

function sourcePreparationReviewSections(artifactType, rows) {
  return rows.flatMap((row) => row.reviewReasons.map((reason) => ({ artifactType, artifactId: row.artifactId, reason })));
}

function sourcePreparationReleaseUseStatus({ sourcePreparedDraftRows, sourceCandidateItemRows, sourcePromotionRecordRows, reviewSections }) {
  if (sourcePreparedDraftRows.length === 0 && sourceCandidateItemRows.length === 0 && sourcePromotionRecordRows.length === 0) return "source_preparation_not_started";
  if (reviewSections.length > 0) return "source_preparation_review_required";
  if (sourcePromotionRecordRows.length > 0) return "source_preparation_candidate_layer_ready_no_live_records";
  return "source_preparation_prepared_drafts_recorded";
}

function sourceCardReviewReasons(card) {
  return [
    ...missingSourceIntakeFields(card, [
      "id",
      "title",
      "sourceAuthor",
      "sourceWork",
      "sourcePublisherOrSite",
      "publicationYear",
      "sourceType",
      "sourceLocator",
      "sourceProvenanceSummary",
      "rightsStatus",
      "sourceLanguage",
      "translationStatus",
      "translationRoute",
      "taskFormat",
      "sourceDatasetName",
      "sourceSubsource",
      "sourceDomainSuitability",
      "sourceDomainConcentration",
      "lsatDerived",
      "adminNotes",
      "sourceAccessPolicy",
      "releasePolicy",
      "sourceVisibility",
      "createdBy",
      "createdAt",
    ]),
    SOURCE_CARD_TYPES.includes(card.sourceType) ? null : "sourceType",
    SOURCE_CARD_TRANSLATION_STATUSES.includes(card.translationStatus) ? null : "translationStatus",
    SOURCE_CARD_TASK_FORMATS.includes(card.taskFormat) ? null : "taskFormat",
    SOURCE_CARD_DOMAIN_SUITABILITY_STATUSES.includes(card.sourceDomainSuitability) ? null : "sourceDomainSuitability",
    typeof card.lsatDerived === "boolean" ? null : "lsatDerived",
    SOURCE_CARD_ACCESS_POLICIES.includes(card.sourceAccessPolicy) ? null : "sourceAccessPolicy",
    SOURCE_CARD_RELEASE_POLICIES.includes(card.releasePolicy) ? null : "releasePolicy",
    card.sourceVisibility === SOURCE_INTAKE_VISIBILITY ? null : "sourceVisibility",
    ...sourceIntakeForbiddenDownstreamFieldReasons(card),
  ].filter(Boolean);
}

function sourceSpanReviewReasons(span, validSourceCardIds) {
  return [
    ...missingSourceIntakeFields(span, [
      "id",
      "sourceCardId",
      "spanLocator",
      "boundedLocator",
      "spanKind",
      "textHash",
      "excerptStoragePolicy",
      "segmentationStatus",
      "extractionStatus",
      "adminSelectionNotes",
      "sourceVisibility",
      "createdBy",
      "createdAt",
    ]),
    SOURCE_SPAN_KINDS.includes(span.spanKind) ? null : "spanKind",
    SOURCE_SPAN_SEGMENTATION_STATUSES.includes(span.segmentationStatus) ? null : "segmentationStatus",
    SOURCE_SPAN_EXTRACTION_STATUSES.includes(span.extractionStatus) ? null : "extractionStatus",
    String(span.textHash ?? "").startsWith("sha256:") ? null : "textHash",
    span.sourceVisibility === SOURCE_INTAKE_VISIBILITY ? null : "sourceVisibility",
    validSourceCardIds.has(span.sourceCardId) ? null : "sourceCardId:not_found",
    ...sourceIntakeForbiddenDownstreamFieldReasons(span),
  ].filter(Boolean);
}

function extractionBatchReviewReasons(batch, validSourceCardIds) {
  return [
    ...missingSourceIntakeFields(batch, [
      "id",
      "sourceCardId",
      "importFormat",
      "importedBy",
      "importedAt",
      "extractionCount",
      "parserVersion",
      "importRoute",
      "extractionExecutionMode",
      "downstreamIntegrationStatus",
    ]),
    batch.importFormat === "jsonl" ? null : "importFormat",
    validSourceCardIds.has(batch.sourceCardId) ? null : "sourceCardId:not_found",
    Number.isInteger(batch.extractionCount) && batch.extractionCount >= 0 ? null : "extractionCount",
    batch.downstreamIntegrationStatus === SOURCE_INTAKE_DOWNSTREAM_INTEGRATION_STATUS ? null : "downstreamIntegrationStatus",
    sourceIntakeNoPlatformAiExecution(batch.extractionExecutionMode) ? null : "extractionExecutionMode",
    ...sourceIntakeFalseFlagReasons(batch),
    ...sourceIntakeForbiddenDownstreamFieldReasons(batch),
  ].filter(Boolean);
}

function argumentExtractionReviewReasons(extraction, context) {
  const sourceSpanIds = Array.isArray(extraction.sourceSpanIds) ? extraction.sourceSpanIds : [];
  const batch = context.validExtractionBatchById.get(extraction.extractionBatchId);
  const missingSpanIds = sourceSpanIds.filter((spanId) => !context.validSourceSpanById.has(spanId));
  const mismatchedSpanIds = sourceSpanIds.filter((spanId) => {
    const span = context.validSourceSpanById.get(spanId);
    return span && span.sourceCardId !== extraction.sourceCardId;
  });
  return [
    ...missingSourceIntakeFields(extraction, [
      "id",
      "extractionBatchId",
      "sourceCardId",
      "sourceSpanIds",
      "argumentRole",
      "intendedConclusion",
      "argumentSummary",
      "implicitAssumptions",
      "contextNeeded",
      "conceptualScopeNotes",
      "suitabilityNotes",
      "extractionRationale",
      "extractionMethod",
      "reviewStatus",
      "downstreamIntegrationStatus",
      "sourceVisibility",
      "importedAt",
    ]),
    sourceSpanIds.length ? null : "sourceSpanIds",
    Array.isArray(extraction.keyPremises) && extraction.keyPremises.length ? null : "keyPremises",
    Array.isArray(extraction.implicitAssumptions) && extraction.implicitAssumptions.length ? null : "implicitAssumptions",
    ARGUMENT_EXTRACTION_ROLES.includes(extraction.argumentRole) ? null : "argumentRole",
    argumentExtractionHasPreparedText(extraction) ? null : "possiblePreparedText",
    argumentExtractionRequiresCritiqueTarget(extraction) && !hasRequiredText(extraction.critiqueTarget) ? "critiqueTarget" : null,
    argumentExtractionRequiresPositionText(extraction) && !argumentExtractionHasPositionText(extraction) ? "possiblePreparedPositionText" : null,
    argumentExtractionRequiresCritiqueText(extraction) && !argumentExtractionHasCritiqueText(extraction) ? "possiblePreparedCritiqueText" : null,
    ARGUMENT_EXTRACTION_METHODS.includes(extraction.extractionMethod) ? null : "extractionMethod",
    ARGUMENT_EXTRACTION_REVIEW_STATUSES.includes(extraction.reviewStatus) ? null : "reviewStatus",
    extraction.downstreamIntegrationStatus === SOURCE_INTAKE_DOWNSTREAM_INTEGRATION_STATUS ? null : "downstreamIntegrationStatus",
    extraction.sourceVisibility === SOURCE_INTAKE_VISIBILITY ? null : "sourceVisibility",
    ...argumentExtractionAiProvenanceReviewReasons(extraction),
    context.validSourceCardIds.has(extraction.sourceCardId) ? null : "sourceCardId:not_found",
    batch ? null : "extractionBatchId:not_found",
    !batch || batch.sourceCardId === extraction.sourceCardId ? null : "extractionBatchId:sourceCardId_mismatch",
    missingSpanIds.length ? `sourceSpanIds:not_found:${missingSpanIds.join(",")}` : null,
    mismatchedSpanIds.length ? `sourceSpanIds:sourceCardId_mismatch:${mismatchedSpanIds.join(",")}` : null,
    ...sourceIntakeFalseFlagReasons(extraction),
    ...sourceIntakeForbiddenDownstreamFieldReasons(extraction),
  ].filter(Boolean);
}

function argumentExtractionAiProvenanceReviewReasons(extraction) {
  if (extraction.extractionMethod !== "external_ai_assisted_jsonl_import_no_platform_ai_execution") return [];
  const provenance = extraction.modelPromptProvenance;
  if (!provenance || typeof provenance !== "object" || Array.isArray(provenance)) {
    return ["modelPromptProvenance"];
  }
  return [
    hasRequiredText(provenance.requestedModel) ? null : "modelPromptProvenance.requestedModel",
    hasRequiredText(provenance.resolvedModelVersion) ? null : "modelPromptProvenance.resolvedModelVersion",
    hasRequiredText(provenance.promptVersion) ? null : "modelPromptProvenance.promptVersion",
  ].filter(Boolean);
}

function argumentExtractionHasPreparedText(extraction) {
  return argumentExtractionHasPositionText(extraction) || argumentExtractionHasCritiqueText(extraction);
}

function argumentExtractionHasPositionText(extraction) {
  return hasRequiredText(extraction.possiblePreparedPositionText) || hasRequiredText(extraction.extractedPositionText);
}

function argumentExtractionHasCritiqueText(extraction) {
  return hasRequiredText(extraction.possiblePreparedCritiqueText);
}

function argumentExtractionRequiresCritiqueTarget(extraction) {
  return ["critique_argument", "mixed_position_and_critique"].includes(extraction.argumentRole) || argumentExtractionHasCritiqueText(extraction);
}

function argumentExtractionRequiresPositionText(extraction) {
  return ["position_argument", "mixed_position_and_critique"].includes(extraction.argumentRole);
}

function argumentExtractionRequiresCritiqueText(extraction) {
  return ["critique_argument", "mixed_position_and_critique"].includes(extraction.argumentRole);
}

function missingSourceIntakeFields(resource, fieldPaths) {
  return fieldPaths.filter((fieldPath) => {
    const value = sourceIntakeFieldValue(resource, fieldPath);
    if (Array.isArray(value)) return value.length === 0;
    return value === undefined || value === null || value === "";
  });
}

function sourceIntakeFieldValue(resource, fieldPath) {
  return String(fieldPath)
    .split(".")
    .reduce((current, segment) => (current && typeof current === "object" ? current[segment] : undefined), resource);
}

function sourceIntakeFalseFlagReasons(resource) {
  const flags = ["createsPreparedDraft", "createsCandidateItem", "createsCandidateBatch", "liveQueueIntegration", "aiExtractionExecuted"];
  return flags.map((field) => (resource[field] === false ? null : field)).filter(Boolean);
}

function sourceIntakeForbiddenDownstreamFieldReasons(resource) {
  return sourceIntakeForbiddenDownstreamFieldPaths(resource).map((fieldPath) => `forbidden_downstream_field:${fieldPath}`);
}

function sourceIntakeForbiddenDownstreamFieldPaths(resource, path = "") {
  if (!resource || typeof resource !== "object") return [];
  if (Array.isArray(resource)) {
    return resource.flatMap((item, index) => sourceIntakeForbiddenDownstreamFieldPaths(item, `${path}[${index}]`));
  }
  return Object.entries(resource).flatMap(([key, value]) => {
    const fieldPath = path ? `${path}.${key}` : key;
    const ownReason = SOURCE_INTAKE_FORBIDDEN_DOWNSTREAM_FIELDS.includes(key) ? [fieldPath] : [];
    return ownReason.concat(sourceIntakeForbiddenDownstreamFieldPaths(value, fieldPath));
  });
}

function sourceIntakeNoPlatformAiExecution(value) {
  const normalized = String(value ?? "").toLowerCase().replace(/[^a-z0-9]/g, "_");
  return normalized.includes("no_platform_ai") || normalized.includes("no_ai_extraction");
}

function sourceIntakeReviewSections(artifactType, rows) {
  return rows.flatMap((row) => row.reviewReasons.map((reason) => ({ artifactType, artifactId: row.artifactId, reason })));
}

function sourceIntakeReleaseUseStatus({ totalArtifacts, reviewSections, pendingExtractionRows, argumentExtractionRows, acceptedExtractionRows }) {
  if (totalArtifacts === 0) return "phase1_source_intake_not_started";
  if (reviewSections.length > 0) return "phase1_source_intake_review_required";
  if (pendingExtractionRows.length > 0) return "phase1_source_intake_pending_review";
  if (argumentExtractionRows.length === 0) return "phase1_source_intake_sources_recorded_extraction_not_started";
  if (acceptedExtractionRows.length === 0) return "phase1_source_intake_reviewed_no_accepted_extractions";
  return "phase1_source_intake_ready_for_future_source_preparation";
}

export function buildMetaphilosophyGreenfieldArchitectureReport(releaseId, options = {}) {
  const submittedLayers =
    Array.isArray(options.architectureLayers) && options.architectureLayers.length
      ? options.architectureLayers
      : Array.isArray(options.greenfieldArchitectureLayers) && options.greenfieldArchitectureLayers.length
        ? options.greenfieldArchitectureLayers
        : METAPHILOSOPHY_GREENFIELD_ARCHITECTURE_LAYERS;
  const layerRows = submittedLayers
    .filter((layer) => layer && typeof layer === "object" && !Array.isArray(layer))
    .map((layer, index) => {
      const clone = structuredClone(layer);
      const reviewReasons = metaphilosophyArchitectureLayerReviewReasons(clone);
      return {
        ...clone,
        artifactId: hasRequiredText(clone.id) ? clone.id : `metaphilosophy-architecture-layer-${index + 1}`,
        reviewReasons,
      };
    })
    .sort((left, right) => left.artifactId.localeCompare(right.artifactId));
  const validLayerIds = new Set(layerRows.filter((row) => row.reviewReasons.length === 0).map((row) => row.id));
  const missingRequiredLayerIds = METAPHILOSOPHY_REQUIRED_ARCHITECTURE_LAYER_IDS.filter((layerId) => !validLayerIds.has(layerId));
  const reviewSections = [
    ...layerRows.flatMap((row) => row.reviewReasons.map((reason) => ({ artifactType: "metaphilosophy_architecture_layer", artifactId: row.artifactId, reason }))),
    ...missingRequiredLayerIds.map((layerId) => ({ artifactType: "metaphilosophy_architecture_layer", artifactId: layerId, reason: "required_layer_missing" })),
  ];

  return {
    id: `metaphilosophy-greenfield-architecture-${releaseId}`,
    releaseId,
    generatedAt: new Date().toISOString(),
    policy: {
      preservationRule:
        "The platform must preserve the distinction between research spine, intake spine, evaluation spine, and operating shell so safeguards do not redefine LMCA labels or merge experimental tasks into release claims.",
      operatingShellRule:
        "A feature belongs in the operating shell only if it protects the research spine, improves rater reliability, improves release reproducibility, or enables a declared evaluation or training use.",
      duplicationBoundary:
        "Greenfield architecture framing must reuse existing Position, Critique, CandidateBatch, CandidateCritique, release-report, and policy-gate surfaces instead of creating parallel candidate or label systems.",
    },
    requiredLayerIds: METAPHILOSOPHY_REQUIRED_ARCHITECTURE_LAYER_IDS,
    missingRequiredLayerIds,
    layerRows,
    counts: {
      layers: layerRows.length,
      requiredLayers: METAPHILOSOPHY_REQUIRED_ARCHITECTURE_LAYER_IDS.length,
      validRequiredLayers: METAPHILOSOPHY_REQUIRED_ARCHITECTURE_LAYER_IDS.length - missingRequiredLayerIds.length,
      reviewRequiredLayers: new Set(reviewSections.map((section) => section.artifactId)).size,
    },
    byReleaseClaimRole: countBy(layerRows, "releaseClaimRole"),
    reviewSections,
    releaseUseStatus: reviewSections.length
      ? "metaphilosophy_greenfield_architecture_review_required"
      : "metaphilosophy_greenfield_architecture_declared",
  };
}

function metaphilosophyArchitectureLayerReviewReasons(layer) {
  return [
    hasRequiredText(layer.id) ? null : "id",
    hasRequiredText(layer.label) ? null : "label",
    hasRequiredText(layer.role) ? null : "role",
    Array.isArray(layer.artifactFamilies) && layer.artifactFamilies.length ? null : "artifactFamilies",
    hasRequiredText(layer.boundaryRule) ? null : "boundaryRule",
    hasRequiredText(layer.releaseClaimRole) ? null : "releaseClaimRole",
  ].filter(Boolean);
}

export function buildMetaphilosophyTaskTrackTaxonomyReport(releaseId, options = {}) {
  const submittedTracks = Array.isArray(options.taskTracks) && options.taskTracks.length ? options.taskTracks : METAPHILOSOPHY_TASK_TRACKS;
  const taskTrackRows = submittedTracks
    .filter((track) => track && typeof track === "object" && !Array.isArray(track))
    .map((track, index) => {
      const clone = structuredClone(track);
      const reviewReasons = metaphilosophyTaskTrackReviewReasons(clone);
      return {
        ...clone,
        artifactId: hasRequiredText(clone.id) ? clone.id : `metaphilosophy-task-track-${index + 1}`,
        reviewReasons,
      };
    })
    .sort((left, right) => left.artifactId.localeCompare(right.artifactId));
  const validTrackIds = new Set(taskTrackRows.filter((row) => row.reviewReasons.length === 0).map((row) => row.id));
  const missingRequiredTrackIds = METAPHILOSOPHY_REQUIRED_TASK_TRACK_IDS.filter((trackId) => !validTrackIds.has(trackId));
  const reviewSections = [
    ...taskTrackRows.flatMap((row) => row.reviewReasons.map((reason) => ({ artifactType: "metaphilosophy_task_track", artifactId: row.artifactId, reason }))),
    ...missingRequiredTrackIds.map((trackId) => ({ artifactType: "metaphilosophy_task_track", artifactId: trackId, reason: "required_track_missing" })),
  ];

  return {
    id: `metaphilosophy-task-track-taxonomy-${releaseId}`,
    releaseId,
    generatedAt: new Date().toISOString(),
    policy: {
      corpusProductionWorkflow:
        "SourceCard, SourceSpan, and ArgumentExtraction are corpus-production intake artifacts; later PreparedDraft and candidate promotion remain behind manual review gates.",
      benchmarkModelWorkflow:
        "Task-track definition, split freeze, model run, parser, metric calculation, leaderboard/report, and training export are benchmark/model workflow artifacts.",
      separationRule:
        "Critique rating, critique ranking, critique generation, critique revision, position/reply revision, and adjudication explanation must be declared as separate tracks before release claims expand beyond critique rating.",
      sourceIntakeBoundary:
        "Source-derived material cannot enter benchmark/model workflows until human review and normal candidate intake governance approve it.",
    },
    requiredTrackIds: METAPHILOSOPHY_REQUIRED_TASK_TRACK_IDS,
    missingRequiredTrackIds,
    taskTrackRows,
    byLmcaRelationship: countBy(taskTrackRows, "lmcaRelationship"),
    counts: {
      taskTracks: taskTrackRows.length,
      requiredTracks: METAPHILOSOPHY_REQUIRED_TASK_TRACK_IDS.length,
      validRequiredTracks: METAPHILOSOPHY_REQUIRED_TASK_TRACK_IDS.length - missingRequiredTrackIds.length,
      reviewRequiredTracks: new Set(reviewSections.map((section) => section.artifactId)).size,
    },
    reviewSections,
    releaseUseStatus: reviewSections.length
      ? "metaphilosophy_task_track_taxonomy_review_required"
      : "metaphilosophy_task_track_taxonomy_declared",
  };
}

function metaphilosophyTaskTrackReviewReasons(track) {
  return [
    hasRequiredText(track.id) ? null : "id",
    hasRequiredText(track.label) ? null : "label",
    hasRequiredText(track.lmcaRelationship) ? null : "lmcaRelationship",
    METAPHILOSOPHY_TASK_TRACK_LMCA_RELATIONSHIPS.includes(track.lmcaRelationship) ? null : "lmcaRelationship:unsupported",
    hasRequiredText(track.modelInput?.summary) ? null : "modelInput.summary",
    Array.isArray(track.modelInput?.fields) && track.modelInput.fields.length ? null : "modelInput.fields",
    hasRequiredText(track.modelOutput?.summary) ? null : "modelOutput.summary",
    Array.isArray(track.modelOutput?.fields) && track.modelOutput.fields.length ? null : "modelOutput.fields",
    hasRequiredText(track.humanExpertTarget) ? null : "humanExpertTarget",
    Array.isArray(track.primaryMetricFamilies) && track.primaryMetricFamilies.length ? null : "primaryMetricFamilies",
    hasRequiredText(track.labelTiming) ? null : "labelTiming",
    hasRequiredText(track.blindToModelPolicy) ? null : "blindToModelPolicy",
    policyMentionsAny(track.blindToModelPolicy, ["blind", "hidden", "cannot see", "cannot use"])
      ? null
      : "blindToModelPolicy:must_state_blinding",
    hasRequiredText(track.splitPolicy) ? null : "splitPolicy",
    policyMentions(track.splitPolicy, ["split"]) ? null : "splitPolicy:must_state_split_policy",
    hasRequiredText(track.trainingExportPolicy) ? null : "trainingExportPolicy",
    policyMentions(track.trainingExportPolicy, ["export"]) ? null : "trainingExportPolicy:must_state_export_boundary",
  ].filter(Boolean);
}

export function buildMetaphilosophyResearchBacklogReport(releaseId, options = {}) {
  const submittedItems =
    Array.isArray(options.backlogItems) && options.backlogItems.length
      ? options.backlogItems
      : Array.isArray(options.researchBacklogItems) && options.researchBacklogItems.length
        ? options.researchBacklogItems
        : METAPHILOSOPHY_RD_BACKLOG_ITEMS;
  const rows = submittedItems
    .filter((item) => item && typeof item === "object" && !Array.isArray(item))
    .map((item, index) => {
      const clone = structuredClone(item);
      const reviewReasons = metaphilosophyBacklogItemReviewReasons(clone);
      return {
        ...clone,
        artifactId: hasRequiredText(clone.id) ? clone.id : `metaphilosophy-rd-backlog-${index + 1}`,
        reviewReasons,
      };
    })
    .sort((left, right) => left.artifactId.localeCompare(right.artifactId));
  const reviewSections = rows.flatMap((row) =>
    row.reviewReasons.map((reason) => ({ artifactType: "metaphilosophy_rd_backlog_item", artifactId: row.artifactId, reason })),
  );

  return {
    id: `metaphilosophy-research-backlog-${releaseId}`,
    releaseId,
    generatedAt: new Date().toISOString(),
    policy: {
      backlogBoundary:
        "R&D ideas are non-binding experiments; they do not become release requirements, hidden-benchmark claims, or training-export permissions without pilot evidence and a later governed policy decision.",
      releaseGateRule:
        "Speculative tracks remain outside release gates until task-specific labels, metrics, blinding rules, and split policies are approved.",
      pilotEvidenceRule:
        "Each backlog row must state whether the pilot is meant to improve measurement validity, rater reliability, or model-evaluation usefulness before any governed promotion.",
      promotionGovernanceRule:
        "Backlog rows cannot become release gates through report text alone; they need a later governed policy decision before release-gate, hidden-benchmark, or training-export use.",
    },
    rows,
    counts: {
      backlogItems: rows.length,
      nonBindingItems: rows.filter((row) => row.directRequirement === false).length,
      pilotEvidenceBoundItems: rows.filter((row) => !row.reviewReasons.some((reason) => reason.startsWith("pilotEvidenceRequirement"))).length,
      promotionGovernanceBoundItems: rows.filter((row) => !row.reviewReasons.some((reason) => reason.startsWith("promotionGovernance"))).length,
      reviewRequiredItems: new Set(reviewSections.map((section) => section.artifactId)).size,
    },
    byExperimentType: countBy(rows, "experimentType"),
    reviewSections,
    releaseUseStatus: reviewSections.length
      ? "metaphilosophy_research_backlog_review_required"
      : "metaphilosophy_research_backlog_separated_from_release_gates",
  };
}

function metaphilosophyBacklogItemReviewReasons(item) {
  const normalizedGateStatus = String(item.releaseGateStatus ?? "").toLowerCase();
  return [
    hasRequiredText(item.id) ? null : "id",
    hasRequiredText(item.title) ? null : "title",
    hasRequiredText(item.experimentType) ? null : "experimentType",
    hasRequiredText(item.releaseGateStatus) ? null : "releaseGateStatus",
    normalizedGateStatus.includes("not_release_gate") ? null : "releaseGateStatus:must_not_be_release_gate",
    item.directRequirement === false ? null : "directRequirement:must_be_false",
    hasRequiredText(item.pilotEvidenceRequirement) ? null : "pilotEvidenceRequirement",
    policyMentionsAny(item.pilotEvidenceRequirement, ["measurement validity", "rater reliability", "model-evaluation usefulness"])
      ? null
      : "pilotEvidenceRequirement:evidence_goal",
    hasRequiredText(item.promotionGovernance) ? null : "promotionGovernance",
    policyMentions(item.promotionGovernance, ["governed", "policy", "decision", "release", "gate"])
      ? null
      : "promotionGovernance:governed_policy_decision",
    hasRequiredText(item.governanceBoundary) ? null : "governanceBoundary",
  ].filter(Boolean);
}

export function buildMetaphilosophyDecisionLogReport(releaseId, options = {}) {
  const submittedEntries =
    Array.isArray(options.decisionLogEntries) && options.decisionLogEntries.length
      ? options.decisionLogEntries
      : Array.isArray(options.metaphilosophyDecisionLogEntries) && options.metaphilosophyDecisionLogEntries.length
        ? options.metaphilosophyDecisionLogEntries
        : METAPHILOSOPHY_DECISION_LOG_ENTRIES;
  const entries = submittedEntries
    .filter((entry) => entry && typeof entry === "object" && !Array.isArray(entry))
    .map((entry, index) => {
      const clone = structuredClone(entry);
      const reviewReasons = metaphilosophyDecisionLogEntryReviewReasons(clone);
      return {
        ...clone,
        artifactId: hasRequiredText(clone.id) ? clone.id : `metaphilosophy-decision-log-entry-${index + 1}`,
        sourceFile: clone.preservedIn ?? METAPHILOSOPHY_DECISION_LOG_SOURCE_FILE,
        status: reviewReasons.length ? "review_required" : "complete",
        reviewReasons,
      };
    })
    .sort((left, right) => left.artifactId.localeCompare(right.artifactId));
  const coveredDecisionTypes = uniqueStrings(
    entries.filter((entry) => entry.reviewReasons.length === 0).map((entry) => entry.decisionType),
  );
  const missingDecisionTypes = METAPHILOSOPHY_REQUIRED_DECISION_LOG_TYPES.filter((decisionType) => !coveredDecisionTypes.includes(decisionType));
  const reviewSections = [
    ...entries.flatMap((entry) =>
      entry.reviewReasons.map((reason) => ({ artifactType: "metaphilosophy_decision_log_entry", artifactId: entry.artifactId, reason })),
    ),
    ...missingDecisionTypes.map((decisionType) => ({
      artifactType: "metaphilosophy_decision_log_entry",
      artifactId: decisionType,
      reason: "required_decision_type_missing",
    })),
  ];

  return {
    id: `metaphilosophy-decision-log-${releaseId}`,
    releaseId,
    generatedAt: new Date().toISOString(),
    sourceFile: METAPHILOSOPHY_DECISION_LOG_SOURCE_FILE,
    policy: {
      mainSpecFocusRule:
        "RLHF93 keeps the main specification focused on current build, release, measurement, governance, and UX requirements.",
      auditabilityRule:
        "The decision log must preserve accepted edits, rejected ideas, pruning decisions, credences, and rationale after historical detail is pruned from the main spec.",
      releaseGateBoundary:
        "Decision-log preservation is audit evidence only; it does not waive release gates, promote source-derived material, or create candidate, queue, label, benchmark, or training-export records.",
    },
    requiredDecisionTypes: METAPHILOSOPHY_REQUIRED_DECISION_LOG_TYPES,
    coveredDecisionTypes,
    missingDecisionTypes,
    entries,
    counts: {
      decisionEntries: entries.length,
      requiredDecisionTypes: METAPHILOSOPHY_REQUIRED_DECISION_LOG_TYPES.length,
      coveredDecisionTypes: coveredDecisionTypes.length,
      missingDecisionTypes: missingDecisionTypes.length,
      acceptedEntries: entries.filter((entry) => entry.decisionType === "accepted_edit").length,
      rejectedEntries: entries.filter((entry) => entry.decisionType === "rejected_idea").length,
      prunedEntries: entries.filter((entry) => entry.decisionType === "pruning_decision").length,
      reviewRequiredEntries: entries.filter((entry) => entry.reviewReasons.length > 0).length,
    },
    byDecisionType: countBy(entries, "decisionType"),
    byDecisionStatus: countBy(entries, "decisionStatus"),
    bySourceVersion: countBy(entries, "sourceVersion"),
    reviewSections,
    releaseUseStatus: reviewSections.length ? "metaphilosophy_decision_log_review_required" : "metaphilosophy_decision_log_preserved",
  };
}

function metaphilosophyDecisionLogEntryReviewReasons(entry) {
  const expectedStatusByType = {
    accepted_edit: "accepted",
    rejected_idea: "rejected",
    pruning_decision: "pruned",
  };
  const credence = Number(entry.credence);
  const expectedStatus = expectedStatusByType[entry.decisionType];
  const normalizedGateImpact = String(entry.releaseGateImpact ?? "").toLowerCase();
  return [
    hasRequiredText(entry.id) ? null : "id",
    hasRequiredText(entry.title) ? null : "title",
    hasRequiredText(entry.decisionType) ? null : "decisionType",
    METAPHILOSOPHY_REQUIRED_DECISION_LOG_TYPES.includes(entry.decisionType) ? null : "decisionType:unsupported",
    hasRequiredText(entry.decisionStatus) ? null : "decisionStatus",
    expectedStatus && entry.decisionStatus === expectedStatus ? null : "decisionStatus:must_match_decision_type",
    hasRequiredText(entry.sourceVersion) ? null : "sourceVersion",
    /^RLHF\d+$/.test(String(entry.sourceVersion ?? "")) ? null : "sourceVersion:must_be_rlhf_version",
    Number.isFinite(credence) && credence >= 0 && credence <= 1 ? null : "credence:must_be_0_to_1",
    hasRequiredText(entry.currentSpecDisposition) ? null : "currentSpecDisposition",
    hasRequiredText(entry.releaseGateImpact) ? null : "releaseGateImpact",
    normalizedGateImpact.includes("no_release_gate") || normalizedGateImpact.includes("audit_only")
      ? null
      : "releaseGateImpact:must_be_audit_only",
    String(entry.preservedIn ?? "") === METAPHILOSOPHY_DECISION_LOG_SOURCE_FILE ? null : "preservedIn:must_point_to_decision_log",
    hasRequiredText(entry.rationale) ? null : "rationale",
  ].filter(Boolean);
}

export function buildMetaphilosophyDeliverableChecklistReport(
  releaseId,
  {
    greenfieldArchitecture,
    sourceIntakeEvidence,
    sourcePreparationEvidence,
    taskTrackTaxonomy,
    researchBacklog,
    metaphilosophyDecisionLog,
    operationalControlEvidence,
  } = {},
) {
  const sourceWorkbenchPhaseGate = metaphilosophySourceWorkbenchPhaseGate(operationalControlEvidence);
  const decisionLogEvidence = metaphilosophyDecisionLog ?? buildMetaphilosophyDecisionLogReport(releaseId);
  const rows = [
    metaphilosophyChecklistRow({
      id: "greenfield_task_track_taxonomy",
      deliverable:
        "Greenfield task-track taxonomy declares critique rating, critique ranking, critique generation, critique revision, position/reply revision, and adjudication explanation as separate tracks with separate inputs, outputs, metrics, and split policies.",
      completionRule: "Required before any release claims more than critique-rating coverage.",
      evidenceIds: [taskTrackTaxonomy?.id].filter(Boolean),
      sourceStatuses: [taskTrackTaxonomy?.releaseUseStatus].filter(Boolean),
      status:
        taskTrackTaxonomy?.releaseUseStatus === "metaphilosophy_task_track_taxonomy_declared" &&
        (taskTrackTaxonomy?.missingRequiredTrackIds?.length ?? 1) === 0
          ? "complete"
          : "review_required",
      reviewReasons: [
        taskTrackTaxonomy?.releaseUseStatus === "metaphilosophy_task_track_taxonomy_declared" ? null : "taskTrackTaxonomy.releaseUseStatus",
        (taskTrackTaxonomy?.missingRequiredTrackIds?.length ?? 0)
          ? `missingRequiredTrackIds:${taskTrackTaxonomy.missingRequiredTrackIds.join(",")}`
          : null,
      ],
    }),
    metaphilosophyChecklistRow({
      id: "admin_source_extraction_workbench",
      deliverable:
        "Admin-only source-to-position/source-to-critique workbench records source cards, source spans, JSONL extraction batches, manual extraction review, and source-derived PreparedDraft promotion through existing candidate gates.",
      completionRule: "Required when source-derived items are used in the release.",
      evidenceIds: [sourceIntakeEvidence?.id, sourcePreparationEvidence?.id].filter(Boolean),
      sourceStatuses: [
        sourceIntakeEvidence?.releaseUseStatus,
        sourcePreparationEvidence?.releaseUseStatus,
        sourceWorkbenchPhaseGate.status,
      ].filter(Boolean),
      phaseGate: sourceWorkbenchPhaseGate,
      status: metaphilosophySourceWorkbenchChecklistStatus(sourceIntakeEvidence, sourcePreparationEvidence, sourceWorkbenchPhaseGate),
      reviewReasons: [
        sourceIntakeEvidence?.releaseUseStatus === "phase1_source_intake_review_required" ? "sourceIntakeEvidence.review_required" : null,
        metaphilosophySourceIntakeNotReadyForSourcePreparation(sourceIntakeEvidence)
          ? "sourceIntakeEvidence:not_ready_for_source_preparation"
          : null,
        sourcePreparationEvidence?.releaseUseStatus === "source_preparation_review_required" ? "sourcePreparationEvidence.review_required" : null,
        metaphilosophySourceWorkbenchUsesSourceDerivedItems(sourceIntakeEvidence, sourcePreparationEvidence) &&
        sourceWorkbenchPhaseGate.status !== "workbench_route_lane_available"
          ? `sourceWorkbenchPhaseGate:${sourceWorkbenchPhaseGate.status}`
          : null,
      ],
    }),
    metaphilosophyChecklistRow({
      id: "rd_backlog_experiments_separated",
      deliverable:
        "R&D Backlog / Experiments section is maintained separately from release gates so speculative ideas do not become requirements without pilot evidence.",
      completionRule: "Required for every RLHF91 release report.",
      evidenceIds: [researchBacklog?.id].filter(Boolean),
      sourceStatuses: [researchBacklog?.releaseUseStatus].filter(Boolean),
      status:
        researchBacklog?.releaseUseStatus === "metaphilosophy_research_backlog_separated_from_release_gates" &&
        (researchBacklog?.counts?.reviewRequiredItems ?? 1) === 0
          ? "complete"
          : "review_required",
      reviewReasons: [
        researchBacklog?.releaseUseStatus === "metaphilosophy_research_backlog_separated_from_release_gates"
          ? null
          : "researchBacklog.releaseUseStatus",
        (researchBacklog?.counts?.reviewRequiredItems ?? 0) ? "researchBacklog.reviewRequiredItems" : null,
      ],
    }),
    metaphilosophyChecklistRow({
      id: "decision_log_preserved",
      deliverable:
        "Metaphilosophy_Decision_Log.md preserves accepted/rejected/pruned design decisions and credences, so the main specification can remain focused on current build and release requirements.",
      completionRule: "Required for RLHF93 and later specs so pruning does not erase decision rationale or credence evidence.",
      evidenceIds: [decisionLogEvidence?.id].filter(Boolean),
      sourceStatuses: [decisionLogEvidence?.releaseUseStatus].filter(Boolean),
      status:
        decisionLogEvidence?.releaseUseStatus === "metaphilosophy_decision_log_preserved" &&
        (decisionLogEvidence?.counts?.missingDecisionTypes ?? 1) === 0 &&
        (decisionLogEvidence?.counts?.reviewRequiredEntries ?? 1) === 0
          ? "complete"
          : "review_required",
      reviewReasons: [
        decisionLogEvidence?.releaseUseStatus === "metaphilosophy_decision_log_preserved"
          ? null
          : "metaphilosophyDecisionLog.releaseUseStatus",
        (decisionLogEvidence?.counts?.missingDecisionTypes ?? 0)
          ? `missingDecisionTypes:${decisionLogEvidence.missingDecisionTypes.join(",")}`
          : null,
        (decisionLogEvidence?.counts?.reviewRequiredEntries ?? 0) ? "metaphilosophyDecisionLog.reviewRequiredEntries" : null,
      ],
    }),
    metaphilosophyChecklistRow({
      id: "greenfield_architecture_frame",
      deliverable:
        "Greenfield comparison and research-spine / operating-shell framing preserve the research spine, intake spine, evaluation spine, and operating shell without duplicating the existing candidate architecture.",
      completionRule: "Required before using RLHF91 greenfield architecture claims in release review.",
      evidenceIds: [greenfieldArchitecture?.id].filter(Boolean),
      sourceStatuses: [greenfieldArchitecture?.releaseUseStatus].filter(Boolean),
      status: greenfieldArchitecture?.releaseUseStatus === "metaphilosophy_greenfield_architecture_declared" ? "complete" : "review_required",
      reviewReasons: [
        greenfieldArchitecture?.releaseUseStatus === "metaphilosophy_greenfield_architecture_declared"
          ? null
          : "greenfieldArchitecture.releaseUseStatus",
        (greenfieldArchitecture?.missingRequiredLayerIds?.length ?? 0)
          ? `missingRequiredLayerIds:${greenfieldArchitecture.missingRequiredLayerIds.join(",")}`
          : null,
      ],
    }),
  ];
  const reviewSections = rows.flatMap((row) =>
    row.reviewReasons.map((reason) => ({ artifactType: "metaphilosophy_deliverable", artifactId: row.id, reason })),
  );

  return {
    id: `metaphilosophy-deliverable-checklist-${releaseId}`,
    releaseId,
    generatedAt: new Date().toISOString(),
    policy: {
      checklistScope:
        "This checklist binds RLHF91's new Metaphilosophy deliverables to existing release-report evidence; it does not create a parallel candidate, label, or queue architecture.",
      completionRule:
        "Rows may support release claims only when the referenced evidence sections are complete or explicitly not applicable under the source-derived-item rule.",
      sourceDerivedItemRule:
        "The source workbench row is not applicable when no source-derived items are used. Source-intake import/review must remain admin-only and non-promotional; source-preparation may create PreparedDraft and CandidateItem artifacts only through the existing gates.",
      sourceWorkbenchPhaseGateRule:
        "Source-derived items require the implementation phase route lane to be enabled or staff_only; otherwise the source workbench is treated as disabled and cannot support source-derived release claims.",
      decisionLogRule:
        "RLHF93 historical pruning is complete only when the decision log preserves accepted edits, rejected ideas, pruning decisions, credences, and rationale without turning logged decisions into release gates.",
    },
    rows,
    reviewSections,
    counts: {
      deliverables: rows.length,
      complete: rows.filter((row) => row.status === "complete").length,
      notApplicable: rows.filter((row) => row.status === "not_applicable_without_source_derived_items").length,
      reviewRequired: rows.filter((row) => row.status === "review_required").length,
    },
    releaseUseStatus: reviewSections.length ? "metaphilosophy_deliverable_checklist_review_required" : "metaphilosophy_deliverable_checklist_complete",
  };
}

function metaphilosophyChecklistRow({ id, deliverable, completionRule, evidenceIds, sourceStatuses, phaseGate, status, reviewReasons }) {
  return {
    id,
    deliverable,
    completionRule,
    evidenceIds,
    sourceStatuses,
    ...(phaseGate ? { phaseGate } : {}),
    status,
    reviewReasons: reviewReasons.filter(Boolean),
  };
}

function metaphilosophySourceWorkbenchUsesSourceDerivedItems(sourceIntakeEvidence, sourcePreparationEvidence) {
  const sourcePreparationCount =
    (sourcePreparationEvidence?.counts?.preparedDrafts ?? 0) +
    (sourcePreparationEvidence?.counts?.candidateItems ?? 0) +
    (sourcePreparationEvidence?.counts?.promotionRecords ?? 0);
  return metaphilosophySourceIntakeArtifactCount(sourceIntakeEvidence) > 0 || sourcePreparationCount > 0;
}

function metaphilosophySourceIntakeArtifactCount(sourceIntakeEvidence) {
  return (
    (sourceIntakeEvidence?.counts?.sourceCards ?? 0) +
    (sourceIntakeEvidence?.counts?.sourceSpans ?? 0) +
    (sourceIntakeEvidence?.counts?.extractionBatches ?? 0) +
    (sourceIntakeEvidence?.counts?.argumentExtractions ?? 0)
  );
}

function metaphilosophySourceIntakeNotReadyForSourcePreparation(sourceIntakeEvidence) {
  if (metaphilosophySourceIntakeArtifactCount(sourceIntakeEvidence) === 0) {
    return false;
  }
  if (sourceIntakeEvidence?.releaseUseStatus === "phase1_source_intake_review_required") {
    return false;
  }
  return sourceIntakeEvidence?.releaseUseStatus !== "phase1_source_intake_ready_for_future_source_preparation";
}

function metaphilosophySourceWorkbenchChecklistStatus(sourceIntakeEvidence, sourcePreparationEvidence, sourceWorkbenchPhaseGate) {
  if (!metaphilosophySourceWorkbenchUsesSourceDerivedItems(sourceIntakeEvidence, sourcePreparationEvidence)) {
    return "not_applicable_without_source_derived_items";
  }
  if (sourceIntakeEvidence?.releaseUseStatus === "phase1_source_intake_review_required") {
    return "review_required";
  }
  if (metaphilosophySourceIntakeNotReadyForSourcePreparation(sourceIntakeEvidence)) {
    return "review_required";
  }
  if (sourcePreparationEvidence?.releaseUseStatus === "source_preparation_review_required") {
    return "review_required";
  }
  if (sourceWorkbenchPhaseGate?.status !== "workbench_route_lane_available") {
    return "review_required";
  }
  return "complete";
}

function metaphilosophySourceWorkbenchPhaseGate(operationalControlEvidence) {
  const routeLane =
    (operationalControlEvidence?.phaseLaneRows ?? []).find((row) => row.laneKind === "route") ??
    null;
  if (!routeLane) {
    return {
      laneKind: "route",
      phaseState: null,
      bundleId: null,
      operationalControlEvidenceId: operationalControlEvidence?.id ?? null,
      status: operationalControlEvidence ? "workbench_route_lane_missing" : "workbench_route_lane_evidence_missing",
    };
  }
  const laneComplete = routeLane.status === "implementation_phase_lane_complete";
  const laneAvailable = laneComplete && ["enabled", "staff_only"].includes(routeLane.phaseState);
  return {
    laneKind: "route",
    phaseState: routeLane.phaseState ?? null,
    bundleId: routeLane.bundleId ?? null,
    operationalControlEvidenceId: operationalControlEvidence?.id ?? null,
    status: laneAvailable
      ? "workbench_route_lane_available"
      : laneComplete
        ? "workbench_route_lane_safely_disabled"
        : "workbench_route_lane_review_required",
  };
}

function hasRequiredText(value) {
  return typeof value === "string" && value.trim().length > 0;
}

export function buildItemTextViewParityReport(
  releaseId,
  ratings = seedRatings,
  evaluationRuns = [fullRubricEvaluationRun, overallOnlyEvaluationRun],
  positionList = positions,
  critiqueList = critiques,
) {
  const positionById = new Map(positionList.map((position) => [position.id, position]));
  const critiqueById = new Map(critiqueList.map((critique) => [critique.id, critique]));
  const textVersionFor = (item, versionId) => item?.textVersions?.find((version) => version.id === versionId) ?? null;
  const ratingRows = ratings.map((rating) => {
    const position = positionById.get(rating.positionId);
    const critique = critiqueById.get(rating.critiqueId);
    const positionVersion = textVersionFor(position, rating.positionTextVersionId);
    const critiqueVersion = textVersionFor(critique, rating.critiqueTextVersionId);
    const versionBound = Boolean(positionVersion && critiqueVersion);
    return {
      ratingId: rating.id,
      itemId: makeItemId(rating.positionId, rating.critiqueId),
      kind: rating.kind,
      split: position?.split ?? "unknown",
      positionTextVersionId: rating.positionTextVersionId ?? null,
      critiqueTextVersionId: rating.critiqueTextVersionId ?? null,
      positionCanonicalHash: positionVersion?.canonicalHash ?? null,
      critiqueCanonicalHash: critiqueVersion?.canonicalHash ?? null,
      raterVisiblePositionRenderedHash: positionVersion?.renderedHash ?? null,
      raterVisibleCritiqueRenderedHash: critiqueVersion?.renderedHash ?? null,
      status: versionBound ? "frozen_item_text_version_bound" : "missing_or_unknown_item_text_version",
    };
  });
  const evaluationRows = evaluationRuns.flatMap((run) =>
    run.predictions.map((prediction) => {
      const position = positionById.get(prediction.positionId);
      const critique = critiqueById.get(prediction.critiqueId);
      const positionVersion = textVersionFor(position, prediction.positionTextVersionId);
      const critiqueVersion = textVersionFor(critique, prediction.critiqueTextVersionId);
      const versionBound = Boolean(positionVersion && critiqueVersion);
      const positionHashMatches = prediction.modelVisiblePositionRenderedHash === positionVersion?.renderedHash;
      const critiqueHashMatches = prediction.modelVisibleCritiqueRenderedHash === critiqueVersion?.renderedHash;
      const parityStatus =
        versionBound && positionHashMatches && critiqueHashMatches
          ? "human_model_text_view_match"
          : versionBound
            ? "text_view_sensitive_hash_mismatch"
            : "missing_or_unknown_item_text_version";
      return {
        evaluationRunId: run.id,
        predictionId: prediction.id,
        itemId: makeItemId(prediction.positionId, prediction.critiqueId),
        promptScope: run.promptScope,
        positionTextVersionId: prediction.positionTextVersionId ?? null,
        critiqueTextVersionId: prediction.critiqueTextVersionId ?? null,
        positionCanonicalHash: positionVersion?.canonicalHash ?? null,
        critiqueCanonicalHash: critiqueVersion?.canonicalHash ?? null,
        modelVisiblePositionRenderedHash: prediction.modelVisiblePositionRenderedHash ?? null,
        modelVisibleCritiqueRenderedHash: prediction.modelVisibleCritiqueRenderedHash ?? null,
        targetRaterVisiblePositionRenderedHash: positionVersion?.renderedHash ?? null,
        targetRaterVisibleCritiqueRenderedHash: critiqueVersion?.renderedHash ?? null,
        positionHashMatches,
        critiqueHashMatches,
        humanModelItemViewParityStatus: prediction.humanModelItemViewParityStatus ?? "missing_prediction_parity_status",
        parityStatus,
      };
    }),
  );
  const textViewSensitiveRows = evaluationRows.filter((row) => row.parityStatus !== "human_model_text_view_match");
  const missingRatingVersionRows = ratingRows.filter((row) => row.status !== "frozen_item_text_version_bound");
  return {
    id: `item-text-view-parity-${releaseId}`,
    releaseId,
    generatedAt: new Date().toISOString(),
    policy: {
      requiredArtifact: "ItemTextVersion",
      ratingRule:
        "Every rating must bind to frozen position and critique text-version ids with canonical and rater-visible rendered hashes.",
      modelViewRule:
        "Every model prediction must declare the target item text-version ids and model-visible rendered hashes; mismatches are text-view-sensitive, not clean LMCA comparisons.",
    },
    counts: {
      ratingRows: ratingRows.length,
      frozenRatingTextVersionRows: ratingRows.filter((row) => row.status === "frozen_item_text_version_bound").length,
      evaluationPredictionRows: evaluationRows.length,
      evaluationRowsWithViewParity: evaluationRows.filter((row) => row.parityStatus === "human_model_text_view_match").length,
      textViewSensitiveRows: textViewSensitiveRows.length,
      missingRatingVersionRows: missingRatingVersionRows.length,
    },
    byRatingStatus: countBy(ratingRows, "status"),
    byEvaluationParityStatus: countBy(evaluationRows, "parityStatus"),
    ratingRows,
    evaluationRows,
    textViewSensitiveRows,
    missingRatingVersionRows,
    releaseUseStatus:
      missingRatingVersionRows.length || textViewSensitiveRows.length
        ? "item_text_view_parity_review_required"
        : "item_text_versions_frozen_with_human_model_view_parity",
  };
}

export function buildRubricQaCoverageReport(
  releaseId,
  fixtures = rubricQaFixtures,
  requiredFamilies = RUBRIC_QA_REQUIRED_FAMILIES,
) {
  const fixtureRows = fixtures
    .map((fixture) => ({
      fixtureId: fixture.id,
      title: fixture.title,
      invariant: fixture.invariant,
      coveredFamilies: fixture.coveredFamilies ?? [],
      coveredFamilyCount: (fixture.coveredFamilies ?? []).length,
      targetDimensions: fixture.targetDimensions ?? [],
      exemplarTypes: fixture.exemplarTypes ?? [],
      source: fixture.source,
      rubricVersion: fixture.rubricVersion ?? "lmca-app-f-2026-10",
      exposurePolicy: fixture.exposurePolicy ?? "public_training_qa_only",
      protectedEvaluationEligible: fixture.protectedEvaluationEligible ?? false,
      promptRegressionEligible: fixture.promptRegressionEligible ?? true,
    }))
    .sort((left, right) => left.fixtureId.localeCompare(right.fixtureId));
  const coveredFamilies = uniqueStrings(fixtureRows.flatMap((row) => row.coveredFamilies)).sort();
  const missingFamilies = requiredFamilies.filter((family) => !coveredFamilies.includes(family)).sort();
  const coveredExemplarTypes = uniqueStrings(fixtureRows.flatMap((row) => row.exemplarTypes)).sort();
  const missingExemplarTypes = REQUIRED_RUBRIC_QA_EXEMPLAR_TYPES.filter((type) => !coveredExemplarTypes.includes(type));
  const protectedExposureRows = fixtureRows.filter((row) => row.protectedEvaluationEligible || row.exposurePolicy !== "public_training_qa_only");
  const dimensionCoverage = Object.fromEntries(
    RUBRIC_DIMENSIONS.map((dimension) => [dimension, fixtureRows.filter((row) => row.targetDimensions.includes(dimension)).length]),
  );
  const curriculumRows = REQUIRED_RUBRIC_CERTIFICATION_CURRICULUM_MODULES.map((module) => {
    const missingModuleFamilies = module.requiredFamilies.filter((family) => !coveredFamilies.includes(family));
    const fixtureIds = fixtureRows
      .filter((row) => row.coveredFamilies.some((family) => module.requiredFamilies.includes(family)))
      .map((row) => row.fixtureId);
    return {
      moduleId: module.id,
      requiredFamilies: module.requiredFamilies,
      fixtureIds,
      missingFamilies: missingModuleFamilies,
      status: missingModuleFamilies.length ? "curriculum_module_missing_fixture_family" : "curriculum_module_frozen",
    };
  });
  const missingCurriculumRows = curriculumRows.filter((row) => row.status !== "curriculum_module_frozen");
  return {
    id: `rubric-qa-coverage-${releaseId}`,
    releaseId,
    generatedAt: new Date().toISOString(),
    rubricVersion: "lmca-app-f-2026-10",
    policy: {
      source: "Appendix-F operational rubric pack plus public LMCA calibration examples.",
      protectionBoundary:
        "Rubric QA fixtures are public training and certification exposure; they are excluded from protected validation, hidden benchmark, label snapshots, and clean model-score claims.",
      coverageRule:
        "Each RLHF77 Appendix-F edge-case family must have at least one versioned fixture before claiming the rubric pack is frozen for release.",
      exemplarRule:
        "The frozen pack must include worked examples, counterexamples, adversarial-interpretation guidance, and priced-in exemplars.",
      certificationCurriculumRule:
        "Certification and recertification training must map interpretation, vague-critique, priced-in, ambiguity, dead-weight, and strength-centrality modules to frozen public fixtures.",
    },
    counts: {
      requiredFamilyCount: requiredFamilies.length,
      coveredFamilyCount: coveredFamilies.length,
      missingFamilyCount: missingFamilies.length,
      requiredExemplarTypeCount: REQUIRED_RUBRIC_QA_EXEMPLAR_TYPES.length,
      coveredExemplarTypeCount: coveredExemplarTypes.length,
      missingExemplarTypeCount: missingExemplarTypes.length,
      requiredCurriculumModuleCount: REQUIRED_RUBRIC_CERTIFICATION_CURRICULUM_MODULES.length,
      coveredCurriculumModuleCount: curriculumRows.length - missingCurriculumRows.length,
      missingCurriculumModuleCount: missingCurriculumRows.length,
      fixtureCount: fixtureRows.length,
      protectedExposureViolationCount: protectedExposureRows.length,
    },
    requiredFamilies,
    coveredFamilies,
    missingFamilies,
    requiredExemplarTypes: REQUIRED_RUBRIC_QA_EXEMPLAR_TYPES,
    coveredExemplarTypes,
    missingExemplarTypes,
    fixtureRows,
    dimensionCoverage,
    curriculumRows,
    missingCurriculumRows,
    familyCoverageRows: requiredFamilies
      .map((family) => ({
        family,
        fixtureIds: fixtureRows.filter((row) => row.coveredFamilies.includes(family)).map((row) => row.fixtureId),
        status: coveredFamilies.includes(family) ? "covered" : "missing",
      }))
      .sort((left, right) => left.status.localeCompare(right.status) || left.family.localeCompare(right.family)),
    protectedExposureRows,
    releaseUseStatus:
      missingFamilies.length > 0
        ? "rubric_qa_required_families_missing"
        : missingExemplarTypes.length > 0
          ? "rubric_qa_required_exemplar_types_missing"
          : missingCurriculumRows.length > 0
            ? "rubric_certification_curriculum_modules_missing"
            : protectedExposureRows.length > 0
              ? "rubric_qa_protected_exposure_review_required"
              : "rubric_qa_pack_frozen_public_only",
  };
}

const REQUIRED_SOURCE_ANCHOR_ALLOWED_USES = ["training", "certification", "prompt_regression"];

export function buildLmcaSourceExampleAnchorReport(
  releaseId,
  anchors = lmcaSourceExampleAnchors,
  options = {},
) {
  const requiredFamilies = options.requiredFamilies ?? ["is_ought_gap", "approval_voting_midrange", "table4_model_failure"];
  const protectedSplits = new Set(options.protectedSplits ?? ["internal_validation", "hidden_benchmark"]);
  const submittedAnchors = (options.sourceAnchorExamples ?? []).map((anchor) => normalizeSubmittedSourceAnchorExample(anchor, releaseId)).filter(Boolean);
  const allAnchors = [...anchors, ...submittedAnchors];
  const anchorRows = allAnchors
    .map((anchor) => {
      const anchorSource = anchor.anchorSource ?? "seed_lmca_public_source_anchor";
      const submittedAnchor = anchorSource === "submitted_workflow_source_anchor_example";
      const rawAllowedUse = uniqueStrings(normalizeStringArray(anchor.allowedUse ?? anchor.allowedUses));
      const allowedUse = rawAllowedUse.length ? rawAllowedUse : submittedAnchor ? [] : REQUIRED_SOURCE_ANCHOR_ALLOWED_USES;
      const targetDimensions = uniqueStrings(normalizeStringArray(anchor.targetDimensions));
      const promptRegressionEligible = anchor.promptRegressionEligible === true;
      const certificationExposureEligible = anchor.certificationExposureEligible === true;
      const excludedFromProtectedEvaluation =
        anchor.excludedFromProtectedEvaluation === true ||
        anchor.protectedEvaluationExclusion === true ||
        anchor.protectedSplitExclusionStatus === true ||
        (!submittedAnchor &&
          anchor.protectedValidationEligible !== true &&
          anchor.hiddenBenchmarkEligible !== true &&
          anchor.humanCeilingEligible !== true);
      const missingAllowedUse = submittedAnchor
        ? REQUIRED_SOURCE_ANCHOR_ALLOWED_USES.filter((use) => !allowedUse.includes(use))
        : [];
      const submittedUsePolicyViolation =
        submittedAnchor &&
        (missingAllowedUse.length > 0 ||
          !excludedFromProtectedEvaluation ||
          !promptRegressionEligible ||
          !certificationExposureEligible ||
          !targetDimensions.length ||
          !anchor.expectedLabelSummary);
      return {
        anchorId: anchor.id,
        anchorSource,
        submittedAnchorId: anchor.submittedAnchorId ?? null,
        suiteVersion: anchor.suiteVersion,
        sourceExampleFamily: anchor.sourceExampleFamily,
        publicSourceReference: anchor.publicSourceReference,
        itemId: anchor.itemId,
        positionClusterId: anchor.positionClusterId,
        split: anchor.split,
        rubricVersion: anchor.rubricVersion,
        exposurePolicy: anchor.exposurePolicy,
        allowedUse,
        missingAllowedUse,
        excludedFromProtectedEvaluation,
        protectedValidationEligible: anchor.protectedValidationEligible === true,
        hiddenBenchmarkEligible: anchor.hiddenBenchmarkEligible === true,
        humanCeilingEligible: anchor.humanCeilingEligible === true,
        promptRegressionEligible,
        certificationExposureEligible,
        expectedLabelSummary: anchor.expectedLabelSummary,
        targetDimensions,
        submittedUsePolicyViolation,
        protectedSplitLeakage:
          protectedSplits.has(anchor.split) ||
          anchor.protectedValidationEligible === true ||
          anchor.hiddenBenchmarkEligible === true ||
          anchor.humanCeilingEligible === true,
        requiredIdsPresent:
          Boolean(anchor.id) &&
          Boolean(anchor.itemId) &&
          Boolean(anchor.positionClusterId) &&
          Boolean(anchor.split) &&
          Boolean(anchor.suiteVersion),
      };
    })
    .sort((left, right) => left.anchorId.localeCompare(right.anchorId));
  const coveredFamilies = uniqueStrings(anchorRows.map((row) => row.sourceExampleFamily)).sort();
  const missingFamilies = requiredFamilies.filter((family) => !coveredFamilies.includes(family)).sort();
  const exposureViolationRows = anchorRows.filter(
    (row) => row.exposurePolicy !== "public_training_qa_only" || row.protectedSplitLeakage,
  );
  const missingRequiredIdRows = anchorRows.filter((row) => !row.requiredIdsPresent);
  const submittedUsePolicyViolationRows = anchorRows.filter((row) => row.submittedUsePolicyViolation);
  const suiteVersions = uniqueStrings(anchorRows.map((row) => row.suiteVersion)).sort();
  return {
    id: `lmca-source-example-anchors-${releaseId}`,
    releaseId,
    generatedAt: new Date().toISOString(),
    policy: {
      sourceAnchorRule:
        "LMCA public source examples are versioned public training, certification, and prompt-regression anchors; they are not hidden-benchmark, protected-validation, or human-ceiling rows.",
      requiredFamiliesRule:
        "The suite must include is/ought near-zero and near-perfect anchors, approval-voting mid-range strength/centrality calibration, and the Table 4 over-crediting model-failure anchor.",
      denominatorExclusionRule:
        "Anchor item ids and position clusters are excluded from protected validation, hidden benchmark, human-ceiling, and clean leaderboard denominators.",
      submittedUsePolicyRule:
        "Submitted source-anchor examples must declare training, certification, and prompt-regression allowed uses, prompt/certification eligibility, protected-evaluation exclusion, expected-label summary, and target dimensions before release use.",
    },
    suiteVersions,
    coveredFamilies,
    missingFamilies,
    counts: {
      anchorCount: anchorRows.length,
      submittedAnchorCount: anchorRows.filter((row) => row.anchorSource === "submitted_workflow_source_anchor_example").length,
      suiteVersionCount: suiteVersions.length,
      coveredFamilyCount: coveredFamilies.length,
      requiredFamilyCount: requiredFamilies.length,
      missingFamilyCount: missingFamilies.length,
      exposureViolationCount: exposureViolationRows.length,
      submittedExposureViolationCount: exposureViolationRows.filter((row) => row.anchorSource === "submitted_workflow_source_anchor_example").length,
      submittedUsePolicyViolationCount: submittedUsePolicyViolationRows.length,
      missingRequiredIdCount: missingRequiredIdRows.length,
      humanCeilingEligibleCount: anchorRows.filter((row) => row.humanCeilingEligible).length,
      promptRegressionEligibleCount: anchorRows.filter((row) => row.promptRegressionEligible).length,
      certificationExposureEligibleCount: anchorRows.filter((row) => row.certificationExposureEligible).length,
    },
    anchorRows,
    exposureViolationRows,
    missingRequiredIdRows,
    submittedUsePolicyViolationRows,
    byFamily: countBy(anchorRows, "sourceExampleFamily"),
    releaseUseStatus:
      exposureViolationRows.length || missingRequiredIdRows.length || submittedUsePolicyViolationRows.length
        ? "source_anchor_protection_review_required"
        : missingFamilies.length
          ? "source_anchor_required_family_missing"
          : "source_anchor_suite_public_training_only",
  };
}

function normalizeSubmittedSourceAnchorExample(anchor, releaseId) {
  const id = anchor?.id ?? anchor?.sourceAnchorId ?? anchor?.source_anchor_id;
  if (!id) return null;
  const allowedUses = uniqueStrings(normalizeStringArray(anchor.allowedUse ?? anchor.allowedUses));
  const protectedSplitExplicitlyIncluded =
    anchor.protectedSplitExclusionStatus === false ||
    anchor.excludedFromProtectedEvaluation === false ||
    anchor.protectedEvaluationExclusion === false;
  return {
    id,
    submittedAnchorId: id,
    anchorSource: "submitted_workflow_source_anchor_example",
    suiteVersion: anchor.suiteVersion ?? anchor.version ?? `submitted-source-anchors-${releaseId}`,
    sourceExampleFamily: anchor.sourceExampleFamily ?? anchor.intendedLesson ?? anchor.anchorKind ?? "declared_custom",
    publicSourceReference: anchor.publicSourceReference ?? anchor.lmcaTableReference ?? anchor.sourceReference ?? anchor.anchorKind ?? id,
    itemId: anchor.itemId ?? `submitted-source-anchor::${id}`,
    positionClusterId: anchor.positionClusterId ?? anchor.clusterId ?? `submitted-source-anchor-${id}`,
    split: anchor.split ?? "public_training_qa_anchor",
    rubricVersion: anchor.rubricVersion ?? anchor.rubricVersionMapping ?? CURRENT_RUBRIC_VERSION,
    exposurePolicy: anchor.exposurePolicy ?? "public_training_qa_only",
    allowedUse: allowedUses,
    excludedFromProtectedEvaluation:
      anchor.excludedFromProtectedEvaluation === true ||
      anchor.protectedEvaluationExclusion === true ||
      anchor.protectedSplitExclusionStatus === true,
    protectedValidationEligible: anchor.protectedValidationEligible === true || protectedSplitExplicitlyIncluded,
    hiddenBenchmarkEligible: anchor.hiddenBenchmarkEligible === true,
    humanCeilingEligible: anchor.humanCeilingEligible === true,
    promptRegressionEligible: anchor.promptRegressionEligible ?? (allowedUses.length ? allowedUses.includes("prompt_regression") : true),
    certificationExposureEligible: anchor.certificationExposureEligible ?? (allowedUses.length ? allowedUses.includes("certification") : true),
    expectedLabelSummary: anchor.expectedLabelSummary ?? anchor.sourceStatedRaterScores ?? anchor.intendedLesson ?? "submitted_source_anchor_expected_label_summary",
    targetDimensions: anchor.targetDimensions ?? anchor.rubricDimensions ?? [],
  };
}

export function buildRaterCompositionConflictReport(
  releaseId,
  labelSnapshot,
  ratings = seedRatings,
  positionList = positions,
  profiles = raterProfiles,
  options = {},
) {
  const snapshotItemIds = new Set(Object.keys(labelSnapshot.itemLabels));
  const positionById = new Map(positionList.map((position) => [position.id, position]));
  const critiqueById = new Map((options.critiqueList ?? critiques).map((critique) => [critique.id, critique]));
  const profileById = new Map(profiles.map((profile) => [profile.id, profile]));
  const topicSpecialistQualificationSource =
    Array.isArray(options.raterQualificationRecords) && options.raterQualificationRecords.length
      ? options.raterQualificationRecords
      : defaultRaterQualificationRecords(releaseId);
  const topicSpecialistQualificationRows = topicSpecialistQualificationSource
    .map((record) => normalizeRaterQualificationRecord(record, "rater_composition_topic_specialist_qualification_record"))
    .filter((record) =>
      raterQualificationRecordIsCurrent(record, {
        qualificationScope: "topic_specialist",
        approvedRole: "expert",
        requiredEligibility: "release_critical",
      }),
    );
  const topicSpecialistQualificationByRater = new Map(topicSpecialistQualificationRows.map((record) => [record.raterId, record]));
  const includedRatings = ratings.filter((rating) => snapshotItemIds.has(makeItemId(rating.positionId, rating.critiqueId)));
  const releaseCriticalRatings = includedRatings.filter((rating) => isReleaseCriticalSplit(positionById.get(rating.positionId)?.split));
  const requiredReleaseCriticalTierDiversityMin = Math.max(1, Number(options.requiredReleaseCriticalTierDiversityMin ?? 2));
  const raterRows = Object.values(
    includedRatings.reduce((acc, rating) => {
      const position = positionById.get(rating.positionId);
      const profile = profileById.get(rating.raterId) ?? fallbackRaterProfile(rating);
      acc[rating.raterId] ??= {
        raterId: rating.raterId,
        tier: profile.tier ?? rating.raterTier,
        certificationStatus: profile.certificationStatus ?? "unknown",
        reliabilityProfile: profile.reliabilityProfile ?? "unknown",
        topicExpertise: profile.topicExpertise ?? [],
        conflictDisclosures: profile.conflictDisclosures ?? [],
        itemIds: new Set(),
        releaseCriticalItemIds: new Set(),
        ratingKinds: {},
        topicFamiliesRated: new Set(),
        releaseCriticalTopicFamiliesRated: new Set(),
        topicExpertiseMatchedItemIds: new Set(),
      };
      const row = acc[rating.raterId];
      const itemId = makeItemId(rating.positionId, rating.critiqueId);
      row.itemIds.add(itemId);
      row.ratingKinds[rating.kind] = (row.ratingKinds[rating.kind] ?? 0) + 1;
      if (position?.topicFamily) row.topicFamiliesRated.add(position.topicFamily);
      if (isReleaseCriticalSplit(position?.split)) {
        row.releaseCriticalItemIds.add(itemId);
        if (position?.topicFamily) row.releaseCriticalTopicFamiliesRated.add(position.topicFamily);
      }
      if (
        position?.topicFamily &&
        (profile.topicExpertise ?? []).includes(position.topicFamily) &&
        raterHasTopicSpecialistQualificationForFamily(topicSpecialistQualificationByRater.get(rating.raterId), position.topicFamily)
      ) {
        row.topicExpertiseMatchedItemIds.add(itemId);
      }
      return acc;
    }, {}),
  )
    .map((row) => ({
      raterId: row.raterId,
      tier: row.tier,
      certificationStatus: row.certificationStatus,
      reliabilityProfile: row.reliabilityProfile,
      topicExpertise: [...row.topicExpertise].sort(),
      conflictDisclosures: row.conflictDisclosures,
      includedItemCount: row.itemIds.size,
      releaseCriticalItemCount: row.releaseCriticalItemIds.size,
      ratingKinds: row.ratingKinds,
      topicFamiliesRated: [...row.topicFamiliesRated].sort(),
      releaseCriticalTopicFamiliesRated: [...row.releaseCriticalTopicFamiliesRated].sort(),
      topicExpertiseMatchedItemCount: row.topicExpertiseMatchedItemIds.size,
      topicExpertiseCoverageShare: row.itemIds.size ? round(row.topicExpertiseMatchedItemIds.size / row.itemIds.size) : 0,
    }))
    .sort((left, right) => right.includedItemCount - left.includedItemCount || left.raterId.localeCompare(right.raterId));
  const itemRows = Object.entries(labelSnapshot.itemLabels)
    .map(([itemId, label]) => {
      const [positionId, critiqueId] = itemId.split("::");
      const position = positionById.get(positionId);
      const critique = critiqueById.get(critiqueId);
      const itemRatings = includedRatings.filter((rating) => rating.positionId === positionId && rating.critiqueId === critiqueId);
      const itemRaterIds = uniqueStrings(itemRatings.map((rating) => rating.raterId)).sort();
      const itemRaterTierDiversity = uniqueStrings(
        itemRatings.map((rating) => profileById.get(rating.raterId)?.tier ?? rating.raterTier).filter(Boolean),
      ).sort();
      const expertRaterIds = uniqueStrings(itemRatings.filter((rating) => ["graduate", "phd", "expert", "admin"].includes(rating.raterTier)).map((rating) => rating.raterId)).sort();
      const profileTopicExpertRaterIds = itemRaterIds.filter((raterId) => (profileById.get(raterId)?.topicExpertise ?? []).includes(position?.topicFamily));
      const topicExpertRaterIds = profileTopicExpertRaterIds.filter((raterId) =>
        raterHasTopicSpecialistQualificationForFamily(topicSpecialistQualificationByRater.get(raterId), position?.topicFamily),
      );
      const releaseCritical = isReleaseCriticalSplit(position?.split);
      const tierDiversityTargetMet = !releaseCritical || itemRaterTierDiversity.length >= requiredReleaseCriticalTierDiversityMin;
      return {
        itemId,
        split: position?.split ?? "unknown",
        topicFamily: position?.topicFamily ?? "unknown",
        releaseCritical,
        raterIds: itemRaterIds,
        raterCount: itemRaterIds.length,
        raterTierDiversity: itemRaterTierDiversity,
        raterTierDiversityCount: itemRaterTierDiversity.length,
        requiredRaterTierDiversityMin: releaseCritical ? requiredReleaseCriticalTierDiversityMin : 0,
        tierDiversityTargetMet,
        expertRaterIds,
        profileTopicExpertRaterIds,
        topicExpertRaterIds,
        topicSpecialistQualificationRecordIds: uniqueStrings(
          topicExpertRaterIds.map((raterId) => topicSpecialistQualificationByRater.get(raterId)?.id).filter(Boolean),
        ),
        topicExpertCoverage: topicExpertRaterIds.length > 0,
        largestSingleRaterContributionShare: label.largestSingleRaterContributionShare,
        singleRaterDominated: label.largestSingleRaterContributionShare > 0.5,
        independentExpertReviewRequired: releaseCritical && label.largestSingleRaterContributionShare > 0.5,
        conflictRows: itemRatings.flatMap((rating) => conflictRowsForRating(rating, position, profileById.get(rating.raterId), critique)),
      };
    })
    .sort((left, right) => Number(right.releaseCritical) - Number(left.releaseCritical) || right.largestSingleRaterContributionShare - left.largestSingleRaterContributionShare || left.itemId.localeCompare(right.itemId));
  const conflictRows = itemRows.flatMap((row) => row.conflictRows);
  const releaseCriticalItemRows = itemRows.filter((row) => row.releaseCritical);
  const singleRaterDominatedReleaseCriticalRows = releaseCriticalItemRows.filter((row) => row.singleRaterDominated);
  const topicExpertiseMissingRows = releaseCriticalItemRows.filter((row) => !row.topicExpertCoverage);
  const tierDiversityMissingRows = releaseCriticalItemRows.filter((row) => !row.tierDiversityTargetMet);
  return {
    id: `rater-composition-conflicts-${releaseId}-${labelSnapshot.id}`,
    releaseId,
    labelSnapshotId: labelSnapshot.id,
    targetLabelVersion: labelSnapshot.targetLabelVersion,
    generatedAt: new Date().toISOString(),
    policy: {
      releaseCriticalSplits: ["internal_validation", "hidden_benchmark"],
      conflictRule:
        "Ratings are flagged when a rater authored, selected, adapted, or previously discussed the item unless an admin exception is explicitly recorded.",
      topicExpertiseRule:
        "Release-critical items disclose whether at least one included rater has profile topic expertise and current topic_specialist qualification for the position family.",
      raterTierDiversityRule:
        "Release-critical items require at least two distinct rater tiers where feasible; thinner tier mixes are disclosed before headline use rather than hidden inside aggregate rater counts.",
      requiredReleaseCriticalTierDiversityMin,
      dominanceRule:
        "Protected validation and hidden-benchmark items with a single-rater majority are disclosed and require independent expert-review before strong headline claims.",
    },
    counts: {
      includedRatingRows: includedRatings.length,
      includedRaterCount: raterRows.length,
      releaseCriticalRatingRows: releaseCriticalRatings.length,
      releaseCriticalItemCount: releaseCriticalItemRows.length,
      conflictFlagCount: conflictRows.length,
      topicExpertiseMissingItemCount: topicExpertiseMissingRows.length,
      raterTierDiversityMissingItemCount: tierDiversityMissingRows.length,
      currentTopicSpecialistQualificationCount: topicSpecialistQualificationRows.length,
      singleRaterDominatedReleaseCriticalItemCount: singleRaterDominatedReleaseCriticalRows.length,
    },
    raterTierDistribution: countBy(raterRows, "tier"),
    releaseCriticalRaterTierDistribution: countBy(
      raterRows.filter((row) => row.releaseCriticalItemCount > 0),
      "tier",
    ),
    raterRows,
    itemRows,
    conflictRows,
    topicSpecialistQualificationRows,
    topicExpertiseMissingRows,
    tierDiversityMissingRows,
    singleRaterDominatedReleaseCriticalRows,
    releaseUseStatus:
      conflictRows.length > 0
        ? "rater_conflict_review_required"
        : singleRaterDominatedReleaseCriticalRows.length > 0 || topicExpertiseMissingRows.length > 0 || tierDiversityMissingRows.length > 0
          ? "rater_composition_limitations_disclosed"
          : "rater_composition_conflict_pass",
  };
}

function buildEffectiveRaterProfiles(submittedRaters = [], baseProfiles = raterProfiles) {
  const normalizedSubmittedProfiles = submittedRaters.map(normalizeSubmittedRaterProfile).filter(Boolean);
  return mergeByArtifactId(baseProfiles, normalizedSubmittedProfiles);
}

function normalizeSubmittedRaterProfile(profile) {
  const id = profile?.id ?? profile?.raterId;
  if (!id) return null;
  const activeReliabilityWeightModelId =
    profile.activeReliabilityWeightModelId ?? profile.reliabilityWeightModelId ?? profile.reliabilityProfile ?? null;
  return {
    ...profile,
    id,
    profileSource: "submitted_workflow_rater",
    tier: profile.tier ?? profile.raterTier ?? null,
    topicExpertise: normalizeRaterTopicExpertise(profile.topicExpertise ?? profile.topicExpertiseByFamily),
    certificationStatus: profile.certificationStatus ?? profile.certification_status ?? null,
    reliabilityProfile: activeReliabilityWeightModelId ?? profile.reliabilityProfile ?? null,
    activeReliabilityWeightModelId,
    conflictDisclosures: normalizeStringArray(profile.conflictDisclosures ?? profile.conflict_disclosures),
    priorExposure: normalizeRaterPriorExposure(profile.priorExposure ?? profile.prior_exposure),
  };
}

function buildRaterProfileEvidenceReport(
  releaseId,
  labelSnapshot,
  ratings = seedRatings,
  profiles = raterProfiles,
  options = {},
) {
  const snapshotItemIds = new Set(Object.keys(labelSnapshot.itemLabels));
  const positionById = new Map((options.positionList ?? positions).map((position) => [position.id, position]));
  const includedRatings = ratings.filter((rating) => snapshotItemIds.has(makeItemId(rating.positionId, rating.critiqueId)));
  const submittedProfiles = (options.raters ?? []).map(normalizeSubmittedRaterProfile).filter(Boolean);
  const submittedProfileById = new Map(submittedProfiles.map((profile) => [profile.id, profile]));
  const profileById = new Map(profiles.map((profile) => [profile.id, profile]));
  const qualificationRows = (options.raterQualificationRecords ?? [])
    .map((record) => normalizeRaterQualificationRecord(record, "submitted_workflow_rater_qualification_record"))
    .filter(Boolean);
  const packById = new Map(certificationPacks.map((pack) => [pack.id, pack]));
  const itemById = new Map(buildReleaseGoldLibraryItems(options.goldItems ?? [], options.positionList ?? positions).map((item) => [item.id, item]));
  const submittedThresholdPolicyRows = (options.certificationThresholdPolicies ?? [])
    .map((policy) => normalizeCertificationThresholdPolicy(policy, "submitted_workflow_certification_threshold_policy"))
    .filter(Boolean);
  const seedThresholdPolicy = normalizeCertificationThresholdPolicy(defaultCertificationThresholdPolicy(releaseId), "seed_certification_threshold_policy");
  const activeThresholdPolicy = submittedThresholdPolicyRows.find((row) => row.reviewReasons.length === 0) ?? seedThresholdPolicy;
  const certificationRows = (options.certificationRecords ?? [])
    .map((record) => normalizeSubmittedCertificationRecord(record, packById, itemById, activeThresholdPolicy))
    .filter(Boolean);
  const consentRows = [...(options.raterDataConsents ?? []), ...(options.volunteerDataConsentProfiles ?? [])]
    .map((consent) => normalizeRaterDataConsent(consent, "submitted_workflow_rater_data_consent"))
    .filter(Boolean);
  const withdrawalRows = (options.volunteerDataWithdrawalRequests ?? [])
    .map((request) => normalizeVolunteerDataWithdrawalRequest(request, "submitted_workflow_volunteer_data_withdrawal_request"))
    .filter(Boolean);
  const reliabilityModelRefs = new Set(
    (options.raterReliabilityWeightModels ?? []).flatMap((model) =>
      [model.id, model.reliabilityWeightModelId, model.modelId, model.weightModelId].filter((value) => typeof value === "string" && value),
    ),
  );
  const auditedRaterIds = uniqueStrings([
    ...includedRatings.map((rating) => rating.raterId),
    ...submittedProfiles.map((profile) => profile.id),
  ]).sort();
  const rows = auditedRaterIds.map((raterId) =>
    raterProfileEvidenceRow(raterId, {
      profile: profileById.get(raterId),
      submittedProfile: submittedProfileById.get(raterId),
      ratingsForRater: includedRatings.filter((rating) => rating.raterId === raterId),
      positionById,
      qualificationRows: qualificationRows.filter((row) => row.raterId === raterId),
      certificationRows: certificationRows.filter((row) => row.raterId === raterId),
      consentRows: consentRows.filter((row) => row.raterId === raterId),
      withdrawalRows: withdrawalRows.filter((row) => row.raterId === raterId),
      reliabilityModelRefs,
    }),
  );
  const reviewRows = rows.filter((row) => row.reviewReasons.length);
  const releaseUsedSubmittedRows = rows.filter((row) => row.releaseUsed && row.profileSource === "submitted_workflow_rater");
  return {
    id: `rater-profile-evidence-${releaseId}-${labelSnapshot.id}`,
    releaseId,
    labelSnapshotId: labelSnapshot.id,
    generatedAt: new Date().toISOString(),
    policy: {
      profileEvidenceRule:
        "Submitted raters that contribute release-used ratings must have a profile, role evidence from qualification or certification records, and a current data-consent artifact.",
      expertRoleRule:
        "Expert-denominator, adjudicator, topic-specialist, hidden-benchmark, and primary-anchor claims require evidence-backed qualification, certification, prior-rating evidence, or an approved exception rather than self-attestation alone.",
      reliabilityModelRule:
        "Submitted active reliability-weight model references must resolve to a submitted frozen rater-reliability weight model before release reports can treat them as provenance-backed.",
    },
    counts: {
      includedRatingRows: includedRatings.length,
      auditedRaterCount: rows.length,
      submittedRaterProfileCount: submittedProfiles.length,
      releaseUsedSubmittedRaterProfileCount: releaseUsedSubmittedRows.length,
      completeReleaseUsedSubmittedRaterProfileCount: releaseUsedSubmittedRows.filter((row) => !row.reviewReasons.length).length,
      submittedQualificationRecordCount: qualificationRows.length,
      submittedCertificationRecordCount: certificationRows.length,
      submittedConsentRecordCount: consentRows.length,
      submittedWithdrawalRecordCount: withdrawalRows.length,
      reviewRowCount: reviewRows.length,
    },
    rows,
    reviewRows,
    releaseUseStatus: reviewRows.length
      ? "rater_profile_evidence_review_required"
      : submittedProfiles.length
        ? "submitted_rater_profile_evidence_complete"
        : "seed_or_fallback_rater_profile_evidence_complete",
  };
}

function raterProfileEvidenceRow(raterId, context) {
  const {
    profile,
    submittedProfile,
    ratingsForRater,
    positionById,
    qualificationRows,
    certificationRows,
    consentRows,
    withdrawalRows,
    reliabilityModelRefs,
  } = context;
  const effectiveProfile = profile ?? submittedProfile ?? null;
  const profileMissing = !effectiveProfile || effectiveProfile.certificationStatus === "unknown_unprofiled_persisted_rater";
  const releaseUsed = ratingsForRater.length > 0;
  const releaseCriticalRatings = ratingsForRater.filter((rating) => isReleaseCriticalSplit(positionById.get(rating.positionId)?.split));
  const topicFamiliesRated = uniqueStrings(ratingsForRater.map((rating) => positionById.get(rating.positionId)?.topicFamily)).sort();
  const releaseCriticalTopicFamilies = uniqueStrings(releaseCriticalRatings.map((rating) => positionById.get(rating.positionId)?.topicFamily)).sort();
  const topicExpertise = normalizeRaterTopicExpertise(effectiveProfile?.topicExpertise);
  const topicExpertiseMissingFamilies = releaseCriticalTopicFamilies.filter((family) => !topicExpertise.includes(family));
  const completeQualificationRows = qualificationRows.filter((row) => row.status === "rater_qualification_complete");
  const completeCertificationRows = certificationRows.filter((row) => row.recordStatus === "certified_or_tier_unlocked");
  const completeConsentRows = consentRows.filter((row) => row.status === "rater_data_consent_notice_complete");
  const submitted = Boolean(submittedProfile);
  const requiresSubmittedReleaseEvidence = releaseUsed && (submitted || profileMissing);
  const activeReliabilityWeightModelId = effectiveProfile?.activeReliabilityWeightModelId ?? effectiveProfile?.reliabilityWeightModelId ?? null;
  const reviewReasons = [
    profileMissing ? "raterProfile" : null,
    submitted && !effectiveProfile?.tier ? "tier" : null,
    submitted && !RATER_PROFILE_TIERS.includes(effectiveProfile?.tier) ? "tierAllowedValue" : null,
    submitted && !topicExpertise.length ? "topicExpertise" : null,
    submitted && !effectiveProfile?.certificationStatus ? "certificationStatus" : null,
    submitted && !activeReliabilityWeightModelId ? "activeReliabilityWeightModelId" : null,
    submitted && !normalizeStringArray(effectiveProfile?.conflictDisclosures).length ? "conflictDisclosures" : null,
    requiresSubmittedReleaseEvidence && !completeQualificationRows.length && !completeCertificationRows.length ? "qualificationOrCertificationEvidence" : null,
    requiresSubmittedReleaseEvidence && !completeConsentRows.length ? "raterDataConsent" : null,
    requiresSubmittedReleaseEvidence && releaseCriticalTopicFamilies.length && topicExpertiseMissingFamilies.length
      ? `releaseCriticalTopicExpertise:${topicExpertiseMissingFamilies.join(",")}`
      : null,
    submitted && activeReliabilityWeightModelId && !reliabilityModelRefs.has(activeReliabilityWeightModelId) ? "activeReliabilityWeightModelId:submittedModelMissing" : null,
  ].filter(Boolean);
  return {
    raterId,
    profileSource: submitted ? "submitted_workflow_rater" : effectiveProfile ? "seed_rater_profile_registry" : "missing_rater_profile",
    releaseUsed,
    includedRatingCount: ratingsForRater.length,
    releaseCriticalRatingCount: releaseCriticalRatings.length,
    tier: effectiveProfile?.tier ?? null,
    certificationStatus: effectiveProfile?.certificationStatus ?? null,
    reliabilityProfile: effectiveProfile?.reliabilityProfile ?? null,
    activeReliabilityWeightModelId,
    topicExpertise,
    topicFamiliesRated,
    releaseCriticalTopicFamilies,
    topicExpertiseMissingFamilies,
    conflictDisclosures: normalizeStringArray(effectiveProfile?.conflictDisclosures),
    qualificationRecordIds: qualificationRows.map((row) => row.id),
    completeQualificationRecordIds: completeQualificationRows.map((row) => row.id),
    certificationRecordIds: certificationRows.map((row) => row.recordId),
    completeCertificationRecordIds: completeCertificationRows.map((row) => row.recordId),
    consentRecordIds: consentRows.map((row) => row.id),
    completeConsentRecordIds: completeConsentRows.map((row) => row.id),
    withdrawalRequestIds: withdrawalRows.map((row) => row.id),
    roleEvidenceStatus:
      completeQualificationRows.length || completeCertificationRows.length
        ? "role_evidence_backed"
        : requiresSubmittedReleaseEvidence
          ? "role_evidence_missing"
          : "seed_or_not_required",
    dataConsentStatus:
      completeConsentRows.length
        ? "rater_data_consent_complete"
        : requiresSubmittedReleaseEvidence
          ? "rater_data_consent_missing"
          : "seed_or_not_required",
    reliabilityModelStatus:
      activeReliabilityWeightModelId && reliabilityModelRefs.has(activeReliabilityWeightModelId)
        ? "submitted_reliability_model_reference_resolved"
        : activeReliabilityWeightModelId
          ? "submitted_reliability_model_reference_missing"
          : "not_declared",
    reviewReasons,
    status: reviewReasons.length
      ? "rater_profile_evidence_review_required"
      : releaseUsed
        ? "rater_profile_release_evidence_complete"
        : "rater_profile_registry_evidence_complete",
  };
}

function normalizeRaterTopicExpertise(value) {
  if (Array.isArray(value) || typeof value === "string") return normalizeStringArray(value).sort();
  if (value && typeof value === "object") {
    return Object.entries(value)
      .filter(([, level]) => level !== false && level !== null && level !== undefined && level !== "none" && level !== "not_applicable")
      .map(([topic]) => topic)
      .filter((topic) => typeof topic === "string" && topic)
      .sort();
  }
  return [];
}

function normalizeRaterPriorExposure(value = {}) {
  return {
    authoredPositionIds: normalizeStringArray(value.authoredPositionIds ?? value.authored_position_ids),
    authoredCritiqueIds: normalizeStringArray(value.authoredCritiqueIds ?? value.authored_critique_ids),
    selectedCritiqueIds: normalizeStringArray(value.selectedCritiqueIds ?? value.selected_critique_ids),
    selectedPositionIds: normalizeStringArray(value.selectedPositionIds ?? value.selected_position_ids),
    selectedItemIds: normalizeStringArray(value.selectedItemIds ?? value.selected_item_ids),
    adaptedPositionIds: normalizeStringArray(value.adaptedPositionIds ?? value.adapted_position_ids),
    submittedSourceIds: normalizeStringArray(value.submittedSourceIds ?? value.submitted_source_ids),
    generatedCritiqueIds: normalizeStringArray(value.generatedCritiqueIds ?? value.generated_critique_ids),
    editedItemIds: normalizeStringArray(value.editedItemIds ?? value.edited_item_ids),
    adaptationClusterIds: normalizeStringArray(value.adaptationClusterIds ?? value.adaptation_cluster_ids ?? value.adaptationFamilyIds ?? value.adaptation_family_ids),
    sourceFamilyIds: normalizeStringArray(value.sourceFamilyIds ?? value.source_family_ids),
    nearDuplicateClusterIds: normalizeStringArray(value.nearDuplicateClusterIds ?? value.near_duplicate_cluster_ids),
    publicExampleIds: normalizeStringArray(
      value.publicExampleIds ??
        value.public_example_ids ??
        value.publicSourceAnchorExampleIds ??
        value.public_source_anchor_example_ids,
    ),
    previouslyDiscussedPositionIds: normalizeStringArray(value.previouslyDiscussedPositionIds ?? value.previously_discussed_position_ids),
    priorPositionClusterIds: normalizeStringArray(value.priorPositionClusterIds ?? value.prior_position_cluster_ids),
  };
}

export function buildCritiqueGenerationEvaluationReport(
  releaseId,
  labelSnapshot,
  generationRuns = critiqueGenerationRuns,
  ratings = seedRatings,
  positionList = positions,
  critiqueList = critiques,
  memos = adjudicationMemos,
  options = {},
) {
  const positionById = new Map(positionList.map((position) => [position.id, position]));
  const critiqueById = new Map(critiqueList.map((critique) => [critique.id, critique]));
  const adjudicatedCritiqueIds = new Set(memos.map((memo) => memo.critiqueId));
  const modelProviderPolicyRows = (options.modelProviderDataHandlingPolicies?.length
    ? options.modelProviderDataHandlingPolicies
    : defaultModelProviderDataHandlingPolicies(releaseId)
  )
    .map((policy) => normalizeModelProviderDataHandlingPolicy(policy, "critique_generation_provider_policy"))
    .filter(Boolean);
  const runRows = generationRuns.map((run) => {
    const outputRows = run.outputs.map((output) => {
      const position = positionById.get(output.positionId);
      const promotedCritique = output.promotedCritiqueId ? critiqueById.get(output.promotedCritiqueId) : null;
      const itemId = promotedCritique ? makeItemId(promotedCritique.positionId, promotedCritique.id) : null;
      const blindRatings = promotedCritique
        ? ratings.filter((rating) => rating.kind === "blind_initial" && rating.positionId === promotedCritique.positionId && rating.critiqueId === promotedCritique.id)
        : [];
      const label = itemId ? labelSnapshot.itemLabels[itemId] : null;
      return {
        outputId: output.id,
        positionId: output.positionId,
        positionSplit: position?.split ?? "unknown",
        status: normalizeGenerationOutputStatus(output.status),
        promotedCritiqueId: output.promotedCritiqueId ?? null,
        itemId,
        duplicateOfOutputId: output.duplicateOfOutputId ?? null,
        selectionReasons: output.selectionReasons ?? [],
        modelJudgeScore: output.modelJudgeScore ?? null,
        modelJudgeDiagnosticOnly: true,
        blindInitialRatingCount: blindRatings.length,
        blindHumanRated: blindRatings.length > 0,
        adjudicated: promotedCritique ? adjudicatedCritiqueIds.has(promotedCritique.id) : false,
        targetOverall: label?.weightedMeanScores?.overall ?? null,
        targetQualityBand: qualityBand(label?.weightedMeanScores?.overall),
      };
    });
    const promotedRows = outputRows.filter((row) => row.status === "promoted_to_rating");
    const blindRatedRows = promotedRows.filter((row) => row.blindHumanRated);
    const passThreshold = run.metricDefinitions.passThresholdOverall;
    return {
      id: run.id,
      runSource: run.runSource ?? "seed_critique_generation_run",
      submittedGenerationEvaluationReportIds: run.submittedGenerationEvaluationReportIds ?? [],
      requestedModelAlias: run.requestedModelAlias,
      resolvedModelSnapshot: run.resolvedModelSnapshot,
      providerRoute: run.providerRoute,
      inferenceDate: run.inferenceDate,
      promptTemplateId: run.promptTemplateId,
      promptFamily: run.promptFamily,
      promptArtifact: run.promptArtifact,
      promptBody: run.promptBody,
      renderedPromptChecksum: run.renderedPromptChecksum,
      promptPolicyComparabilityStatus: run.promptPolicyComparabilityStatus,
      protectedPromptExampleCheck: run.protectedPromptExampleCheck,
      sourcePositionSplitPolicy: run.sourcePositionSplitPolicy,
      sourcePositionIds: run.sourcePositionIds,
      generationBudgetPerPosition: run.generationBudgetPerPosition,
      sampledOutputCount: run.sampledOutputCount,
      generationSettings: run.generationSettings,
      filteringPolicy: run.filteringPolicy,
      modelJudgeScreening: run.modelJudgeScreening,
      modelProviderPolicyBinding: critiqueGenerationProviderPolicyBinding(run, modelProviderPolicyRows),
      generationRunContractStatus: run.generationRunContractStatus ?? "seed_critique_generation_run_contract_not_required",
      generationRunContractChecks: run.generationRunContractChecks ?? [],
      generationRunContractViolations: run.generationRunContractViolations ?? [],
      generatedSubmissionContractViolationCount: run.generatedSubmissionContractViolationCount ?? 0,
      generatedSubmissionContractViolationRows: run.generatedSubmissionContractViolationRows ?? [],
      generatedPromotionContractViolationCount: run.generatedPromotionContractViolationCount ?? 0,
      generatedPromotionContractViolationRows: run.generatedPromotionContractViolationRows ?? [],
      generationEvaluationReportContractViolationCount: run.generationEvaluationReportContractViolationCount ?? 0,
      generationEvaluationReportContractViolationRows: run.generationEvaluationReportContractViolationRows ?? [],
      generationWorkflowContractViolationCount: run.generationWorkflowContractViolationCount ?? 0,
      metricDefinitions: run.metricDefinitions,
      submittedWorkflowOutputCount: run.submittedWorkflowOutputCount ?? 0,
      outputStatusCounts: countBy(outputRows, "status"),
      counts: {
        generatedOutputs: outputRows.length,
        emptyOrRefusal: outputRows.filter((row) => row.status === "empty_or_refusal").length,
        duplicatesFiltered: outputRows.filter((row) => row.status === "duplicate_filtered").length,
        filteredBeforeRating: outputRows.filter((row) => row.status === "filtered_before_rating").length,
        humanRejected: outputRows.filter((row) => row.status === "human_rejected").length,
        promotedToRating: promotedRows.length,
        blindHumanRatedPromoted: blindRatedRows.length,
        adjudicatedPromoted: promotedRows.filter((row) => row.adjudicated).length,
      },
      blindRatingCoverage: {
        promotedCoverageNumerator: blindRatedRows.length,
        promotedCoverageDenominator: promotedRows.length,
        promotedCoverageShare: promotedRows.length ? round(blindRatedRows.length / promotedRows.length) : null,
        noBlindRatingOutputIds: promotedRows.filter((row) => !row.blindHumanRated).map((row) => row.outputId),
      },
      qualityMetrics: {
        ratedPromotedOverall: summarizeValues(blindRatedRows.map((row) => row.targetOverall).filter(isValidScore)),
        passThresholdOverall: passThreshold,
        passAtThresholdCount: blindRatedRows.filter((row) => isValidScore(row.targetOverall) && row.targetOverall >= passThreshold).length,
        passAtThresholdRate: blindRatedRows.length
          ? round(blindRatedRows.filter((row) => isValidScore(row.targetOverall) && row.targetOverall >= passThreshold).length / blindRatedRows.length)
          : null,
        bestOfNByPosition: buildGenerationBestOfNRows(run, outputRows),
      },
      outputRows,
    };
  });
  const providerPolicyReviewSections = runRows.flatMap((row) =>
    row.modelProviderPolicyBinding.reviewReasons.map((reason) => ({ artifactType: "critique_generation_provider_policy", artifactId: row.id, reason })),
  );
  const contractReviewSections = runRows.flatMap((row) => [
    ...row.generationRunContractViolations.map((check) => ({
      artifactType: "critique_generation_run",
      artifactId: row.id,
      reason: `generationRun.${check.field}:${check.status}`,
    })),
    ...row.generatedSubmissionContractViolationRows.flatMap((violationRow) =>
      violationRow.contractViolations.map((check) => ({
        artifactType: "generated_critique_submission",
        artifactId: violationRow.outputId,
        reason: `${check.field}:${check.status}`,
      })),
    ),
    ...row.generatedPromotionContractViolationRows.flatMap((violationRow) =>
      violationRow.contractViolations.map((check) => ({
        artifactType: "generated_critique_promotion",
        artifactId: violationRow.outputId,
        reason: `${check.field}:${check.status}`,
      })),
    ),
    ...row.generationEvaluationReportContractViolationRows.flatMap((violationRow) =>
      violationRow.contractViolations.map((check) => ({
        artifactType: "generation_evaluation_report",
        artifactId: violationRow.id,
        reason: `${check.field}:${check.status}`,
      })),
    ),
  ]);
  const generatorEvaluatorOverlap = buildGenerationEvaluatorOverlapReport(
    runRows,
    options.evaluationRuns ?? [fullRubricEvaluationRun, overallOnlyEvaluationRun],
  );
  const coverageAndBlindingPass = runRows.every(
    (row) => !row.modelJudgeScreening.scoresVisibleToInitialRaters && row.blindRatingCoverage.noBlindRatingOutputIds.length === 0,
  );
  return {
    id: `critique-generation-evaluation-${releaseId}`,
    releaseId,
    targetLabelSnapshotId: labelSnapshot.id,
    targetLabelVersion: labelSnapshot.targetLabelVersion,
    generatedAt: new Date().toISOString(),
    reportScope: "critique_generation_not_critique_rating_or_model_judging",
    generationVsJudgingSeparation: {
      generatedCritiquesRequireBlindHumanRatingBeforeQualityClaim: true,
      modelJudgeScoresDiagnosticOnly: true,
      modelJudgeScoresAcceptedAsGoldLabels: false,
      modelJudgeScoresVisibleToInitialRaters: generationRuns.some((run) => run.modelJudgeScreening.scoresVisibleToInitialRaters),
    },
    generatorEvaluatorOverlap,
    aggregateCounts: aggregateGenerationCounts(runRows),
    providerPolicyEvidence: {
      runRows: runRows.map((row) => row.modelProviderPolicyBinding),
      reviewSections: providerPolicyReviewSections,
      releaseUseStatus: providerPolicyReviewSections.length
        ? "critique_generation_provider_policy_review_required"
        : "critique_generation_provider_policies_approved",
    },
    submittedWorkflowContractEvidence: {
      runRows: runRows
        .filter((row) => row.runSource === "submitted_workflow_critique_generation_run")
        .map((row) => ({
          generationRunId: row.id,
          generationRunContractStatus: row.generationRunContractStatus,
          generationRunContractViolationCount: row.generationRunContractViolations.length,
          generatedSubmissionContractViolationCount: row.generatedSubmissionContractViolationCount,
          generatedPromotionContractViolationCount: row.generatedPromotionContractViolationCount,
          generationEvaluationReportContractViolationCount: row.generationEvaluationReportContractViolationCount,
          generationWorkflowContractViolationCount: row.generationWorkflowContractViolationCount,
        })),
      reviewSections: contractReviewSections,
      releaseUseStatus: contractReviewSections.length
        ? "critique_generation_workflow_contract_review_required"
        : "critique_generation_workflow_contract_complete",
    },
    runRows,
    releaseUseStatus:
      coverageAndBlindingPass && providerPolicyReviewSections.length === 0 && contractReviewSections.length === 0
        ? "generation_evaluation_separate_with_blind_rating_coverage"
        : "generation_evaluation_requires_blinding_rating_coverage_provider_policy_or_contract_review",
  };
}

function buildGenerationEvaluatorOverlapReport(runRows = [], evaluationRuns = []) {
  const evaluatorRows = evaluationRuns.map((run) => ({
    evaluationRunId: run.id,
    requestedModelAlias: run.requestedModelAlias ?? null,
    resolvedModelSnapshot: run.resolvedModelSnapshot ?? null,
    modelFamily: modelIdentityForRun(run).modelFamily,
    identity: modelIdentityForRun(run),
  }));
  const rows = runRows.map((run) => {
    const generatorIdentity = modelIdentityFromValues({
      requestedModelAlias: run.requestedModelAlias,
      resolvedModelSnapshot: run.resolvedModelSnapshot,
      provider: run.providerRoute,
      modelFamily: run.modelFamily,
    });
    const judgeIdentity = modelIdentityFromValues({
      requestedModelAlias: run.modelJudgeScreening?.requestedModelAlias,
      resolvedModelSnapshot: run.modelJudgeScreening?.resolvedModelSnapshot,
      provider: run.modelJudgeScreening?.providerRoute,
      modelFamily: run.modelJudgeScreening?.modelFamily,
    });
    const generatorJudgeOverlapBasis =
      judgeIdentity.normalizedAlias || judgeIdentity.normalizedSnapshot || judgeIdentity.modelFamily
        ? modelOverlapBasis(generatorIdentity, judgeIdentity)
        : "not_declared";
    const evaluatorOverlapRows = evaluatorRows
      .map((evaluator) => ({
        evaluationRunId: evaluator.evaluationRunId,
        evaluatorRequestedModelAlias: evaluator.requestedModelAlias,
        evaluatorResolvedModelSnapshot: evaluator.resolvedModelSnapshot,
        evaluatorModelFamily: evaluator.modelFamily,
        overlapBasis: modelOverlapBasis(evaluator.identity, generatorIdentity),
      }))
      .filter((row) => row.overlapBasis !== "none");
    return {
      generationRunId: run.id,
      requestedModelAlias: generatorIdentity.requestedModelAlias,
      resolvedModelSnapshot: generatorIdentity.resolvedModelSnapshot,
      modelFamily: generatorIdentity.modelFamily,
      modelJudgeRequestedModelAlias: judgeIdentity.requestedModelAlias,
      modelJudgeResolvedModelSnapshot: judgeIdentity.resolvedModelSnapshot,
      modelJudgeModelFamily: judgeIdentity.modelFamily,
      generatorJudgeOverlapBasis,
      evaluatorOverlapRows,
      evaluatorOverlapCount: evaluatorOverlapRows.length,
      status:
        evaluatorOverlapRows.length || ["exact_resolved_snapshot", "exact_requested_alias", "close_model_family"].includes(generatorJudgeOverlapBasis)
          ? "generator_overlap_disclosed"
          : "no_generator_overlap_detected",
    };
  });
  const evaluatorOverlapRows = rows.flatMap((row) =>
    row.evaluatorOverlapRows.map((overlap) => ({
      generationRunId: row.generationRunId,
      generatorRequestedModelAlias: row.requestedModelAlias,
      generatorResolvedModelSnapshot: row.resolvedModelSnapshot,
      generatorModelFamily: row.modelFamily,
      ...overlap,
    })),
  );
  const generatorJudgeOverlapRows = rows.filter((row) =>
    ["exact_resolved_snapshot", "exact_requested_alias", "close_model_family"].includes(row.generatorJudgeOverlapBasis),
  );
  return {
    policy: {
      disclosureRule:
        "Release reports disclose when a critique generator shares an exact alias, exact resolved snapshot, or close model family with a model judge or evaluated model.",
      cleanInterpretationRule:
        "Generator/evaluator overlap is diagnostic provenance for source-style familiarity risk; it does not convert model-judge scores into labels or replace blind human rating coverage.",
    },
    counts: {
      generationRunCount: rows.length,
      evaluatedModelCount: evaluatorRows.length,
      evaluatorOverlapCount: evaluatorOverlapRows.length,
      generatorJudgeOverlapCount: generatorJudgeOverlapRows.length,
    },
    rows,
    evaluatorOverlapRows,
    generatorJudgeOverlapRows,
    releaseUseStatus:
      evaluatorOverlapRows.length || generatorJudgeOverlapRows.length
        ? "generator_evaluator_or_judge_overlap_disclosed"
        : "no_generator_evaluator_overlap_detected",
  };
}

