function buildEffectiveCritiqueGenerationRuns({
  critiqueGenerationRuns: submittedRuns = [],
  generatedCritiqueSubmissions = [],
  generatedCritiquePromotions = [],
  generationEvaluationReports = [],
} = {}) {
  if (!submittedRuns.length && !generatedCritiqueSubmissions.length && !generatedCritiquePromotions.length) {
    return critiqueGenerationRuns;
  }
  const submittedRunIds = new Set(submittedRuns.map((run) => run.id).filter(Boolean));
  const runIdsFromSubmissions = uniqueStrings(generatedCritiqueSubmissions.map((submission) => submission.generationRunId ?? submission.critiqueGenerationRunId));
  const stubRuns = runIdsFromSubmissions
    .filter((runId) => runId && !submittedRunIds.has(runId))
    .map((runId) => ({ id: runId, promptTemplateId: "candidate-gen-v3" }));
  const normalizedSubmittedRuns = [...submittedRuns, ...stubRuns].map((run) =>
    normalizeSubmittedCritiqueGenerationRun(run, generatedCritiqueSubmissions, generatedCritiquePromotions, generationEvaluationReports),
  );
  return [...critiqueGenerationRuns, ...normalizedSubmittedRuns];
}

function critiqueGenerationProviderPolicyBinding(run, policyRows = []) {
  const generatorPolicyId = run.modelProviderDataHandlingPolicyId ?? run.generationModelProviderDataHandlingPolicyId ?? null;
  const judgePolicyId = run.modelJudgeScreening?.modelProviderDataHandlingPolicyId ?? run.judgeModelProviderDataHandlingPolicyId ?? null;
  const generator = modelProviderPolicyBindingForRunClass(run, "critique_generation", generatorPolicyId, policyRows);
  const modelJudge = modelProviderPolicyBindingForRunClass(run, "model_judge", judgePolicyId, policyRows);
  return {
    generationRunId: run.id,
    runSource: run.runSource ?? "seed_critique_generation_run",
    generator,
    modelJudge,
    reviewReasons: [...generator.reviewReasons.map((reason) => `generator.${reason}`), ...modelJudge.reviewReasons.map((reason) => `modelJudge.${reason}`)],
    status:
      generator.reviewReasons.length || modelJudge.reviewReasons.length
        ? "critique_generation_provider_policy_review_required"
        : "critique_generation_provider_policy_approved",
  };
}

function modelProviderPolicyBindingForRunClass(run, runClass, explicitPolicyId, policyRows = [], options = {}) {
  const submittedWorkflowRun = options.requireExplicitPolicyId ?? run.runSource === "submitted_workflow_critique_generation_run";
  const policy = explicitPolicyId
    ? policyRows.find((row) => row.id === explicitPolicyId) ?? null
    : submittedWorkflowRun
      ? null
      : policyRows.find((row) => row.coveredRunClass === runClass && row.reviewReasons.length === 0) ?? null;
  const reviewReasons = [
    submittedWorkflowRun && !explicitPolicyId ? "modelProviderDataHandlingPolicyId" : null,
    policy ? null : "policyNotFound",
    policy && policy.coveredRunClass !== runClass ? "coveredRunClass" : null,
    policy && !policy.approvedSplitContentClasses.includes("protected_validation") ? "approvedSplitContentClasses.protected_validation" : null,
    policy && !policy.approvedSplitContentClasses.includes("hidden_benchmark") ? "approvedSplitContentClasses.hidden_benchmark" : null,
    policy && policy.noTrainingOnInputsOutputs !== true ? "noTrainingOnInputsOutputs" : null,
    policy && policy.noPromptOrOutputReuse !== true ? "noPromptOrOutputReuse" : null,
    policy && policy.unnecessaryHumanReviewProhibited !== true ? "unnecessaryHumanReviewProhibited" : null,
    policy && policy.protectedContentEligible !== true ? "protectedContentEligible" : null,
    policy && policy.approvalStatus !== "approved" ? "approvalStatus" : null,
    ...(policy?.reviewReasons ?? []),
  ].filter(Boolean);
  return {
    runClass,
    modelProviderDataHandlingPolicyId: policy?.id ?? explicitPolicyId ?? null,
    providerEndpointClass: policy?.providerEndpointClass ?? null,
    approvedSplitContentClasses: policy?.approvedSplitContentClasses ?? [],
    protectedContentEligible: policy?.protectedContentEligible === true,
    noTrainingOnInputsOutputs: policy?.noTrainingOnInputsOutputs === true,
    noPromptOrOutputReuse: policy?.noPromptOrOutputReuse === true,
    unnecessaryHumanReviewProhibited: policy?.unnecessaryHumanReviewProhibited === true,
    logRetentionWindowDays: policy?.logRetentionWindowDays ?? null,
    approvalStatus: policy?.approvalStatus ?? null,
    reviewReasons,
    status: reviewReasons.length ? "model_provider_policy_review_required" : "model_provider_policy_approved",
  };
}

function normalizeSubmittedCritiqueGenerationRun(run, submissions, promotions, reports) {
  const runId = run.id;
  const runSubmissions = submissions.filter((submission) => (submission.generationRunId ?? submission.critiqueGenerationRunId) === runId);
  const promotionByGeneratedId = new Map(promotions.map((promotion) => [promotion.generatedCritiqueId ?? promotion.outputId, promotion]));
  const generationRunContractChecks = submittedCritiqueGenerationRunContractChecks(run);
  const generationRunContractViolations = generationRunContractChecks.filter((check) => check.status !== "pass");
  const outputRows = runSubmissions.length
    ? runSubmissions.map((submission) => normalizeSubmittedGenerationOutput(submission, promotionByGeneratedId.get(submission.id), true))
    : (run.outputs ?? []).map((output) => normalizeSubmittedGenerationOutput(output, promotionByGeneratedId.get(output.id), false));
  const reportRows = reports.filter((report) => {
    const reportRunIds = report.generationRunIds ?? report.critiqueGenerationRunIds ?? [];
    return report.generationRunId === runId || report.critiqueGenerationRunId === runId || reportRunIds.includes(runId);
  });
  const generationEvaluationReportContractViolationRows = reportRows
    .map((report) => ({
      id: report.id,
      contractViolations: submittedGenerationEvaluationReportContractChecks(report, runId).filter((check) => check.status !== "pass"),
    }))
    .filter((row) => row.contractViolations.length);
  const generatedSubmissionContractViolationRows = outputRows
    .filter((output) => output.generatedSubmissionContractViolations?.length)
    .map((output) => ({
      outputId: output.id,
      positionId: output.positionId,
      contractViolations: output.generatedSubmissionContractViolations,
    }));
  const generatedPromotionContractViolationRows = outputRows
    .filter((output) => output.generatedPromotionContractViolations?.length)
    .map((output) => ({
      outputId: output.id,
      promotedCritiqueId: output.promotedCritiqueId,
      contractViolations: output.generatedPromotionContractViolations,
    }));
  const promptTemplateId = run.promptTemplateId ?? run.promptTemplateVersion ?? "candidate-gen-v3";
  const promptArtifact = promptArtifactForSubmittedWorkflow(
    promptTemplateId,
    run.promptFamily ?? "critique_generation",
    run.promptScope ?? "project_critique_generation",
    run.promptPolicyComparabilityStatus ?? "project_extension_critique_generation_prompt",
    run.renderedPromptChecksum ?? `sha256:${promptTemplateId}:submitted`,
    run.outputFormatPolicy ?? "generated_critique_text",
  );
  const judgePromptTemplateId = run.modelJudgeScreening?.promptTemplateId ?? run.modelJudgePromptTemplateId ?? "candidate-judge-v2";
  const judgePromptArtifact = promptArtifactForSubmittedWorkflow(
    judgePromptTemplateId,
    "model_judge_screening",
    "project_model_judge_diagnostic",
    "project_extension_model_judge_prompt",
    run.modelJudgeScreening?.renderedPromptChecksum ?? run.modelJudgeRenderedPromptChecksum ?? `sha256:${judgePromptTemplateId}:submitted`,
    "json_generation_screening_score",
  );
  const sourcePositionIds = uniqueStrings(run.sourcePositionIds ?? run.positionIds ?? outputRows.map((output) => output.positionId).filter(Boolean));
  const firstReport = reportRows[0] ?? {};
  return {
    id: runId,
    runSource: "submitted_workflow_critique_generation_run",
    submittedGenerationEvaluationReportIds: reportRows.map((report) => report.id).filter(Boolean),
    requestedModelAlias: run.requestedModelAlias ?? run.generatorRequestedModelAlias ?? run.generatorModelAlias ?? "submitted-generator",
    resolvedModelSnapshot: run.resolvedModelSnapshot ?? run.generatorResolvedModelSnapshot ?? run.generatorModelSnapshot ?? "submitted-generator-snapshot",
    providerRoute: run.providerRoute ?? run.provider ?? run.generatorProvider ?? "submitted_workflow",
    modelProviderDataHandlingPolicyId: run.modelProviderDataHandlingPolicyId ?? run.generationModelProviderDataHandlingPolicyId ?? null,
    inferenceDate: run.inferenceDate ?? run.createdAt ?? null,
    promptTemplateId,
    promptFamily: promptArtifact.promptFamily,
    promptArtifact,
    promptBody: run.promptBody ?? promptArtifact.promptBody,
    renderedPromptChecksum: run.renderedPromptChecksum ?? promptArtifact.renderedPromptChecksum,
    promptPolicyComparabilityStatus: run.promptPolicyComparabilityStatus ?? promptArtifact.promptPolicyComparabilityStatus,
    protectedPromptExampleCheck: run.protectedPromptExampleCheck ?? promptArtifact.protectedSplitExclusionCheck,
    sourcePositionSplitPolicy: run.sourcePositionSplitPolicy ?? run.sourceSplit ?? "submitted_workflow_generation_source_split",
    sourcePositionIds,
    generationBudgetPerPosition: run.generationBudgetPerPosition ?? firstReport.generationBudgetPerPosition ?? 1,
    sampledOutputCount: run.sampledOutputCount ?? outputRows.length,
    generationSettings: run.generationSettings ?? run.generationParameters ?? {
      temperature: run.temperature ?? null,
      topP: run.topP ?? null,
      maxOutputTokens: run.maxOutputTokens ?? null,
      reasoningMode: run.reasoningMode ?? "not_declared",
    },
    filteringPolicy: normalizeSubmittedGenerationFilteringPolicy(run),
    modelJudgeScreening: normalizeSubmittedGenerationJudge(run, judgePromptArtifact),
    outputs: outputRows,
    submittedWorkflowOutputCount: outputRows.length,
    generationRunContractChecks,
    generationRunContractViolations,
    generationRunContractStatus: generationRunContractViolations.length
      ? "critique_generation_run_contract_review_required"
      : "critique_generation_run_contract_complete",
    generatedSubmissionContractViolationCount: generatedSubmissionContractViolationRows.length,
    generatedSubmissionContractViolationRows,
    generatedPromotionContractViolationCount: generatedPromotionContractViolationRows.length,
    generatedPromotionContractViolationRows,
    generationEvaluationReportContractViolationCount: generationEvaluationReportContractViolationRows.length,
    generationEvaluationReportContractViolationRows,
    generationWorkflowContractViolationCount:
      Number(generationRunContractViolations.length > 0) +
      generatedSubmissionContractViolationRows.length +
      generatedPromotionContractViolationRows.length +
      generationEvaluationReportContractViolationRows.length,
    metricDefinitions: {
      headlineMetric: run.metricDefinitions?.headlineMetric ?? firstReport.headlineMetric ?? "submitted_generation_evaluation_report",
      uncuratedRandomSampleMetric:
        run.metricDefinitions?.uncuratedRandomSampleMetric ?? firstReport.uncuratedRandomSampleMetric ?? "submitted_all_generated_status_accounting",
      bestOfNPolicy: run.metricDefinitions?.bestOfNPolicy ?? firstReport.bestOfNPolicy ?? "submitted_best_of_n_reported_with_generation_budget",
      topKPolicy: run.metricDefinitions?.topKPolicy ?? firstReport.topKPolicy ?? "submitted_top_k_or_curated_metric_separated",
      passThresholdOverall: run.metricDefinitions?.passThresholdOverall ?? firstReport.passThresholdOverall ?? 0.6,
    },
  };
}

function normalizeSubmittedGenerationOutput(output, promotion, submittedWorkflowOutput = false) {
  const generatedSubmissionContractChecks = submittedWorkflowOutput ? submittedGeneratedCritiqueSubmissionContractChecks(output) : [];
  const generatedSubmissionContractViolations = generatedSubmissionContractChecks.filter((check) => check.status !== "pass");
  const generatedPromotionContractChecks = promotion ? submittedGeneratedCritiquePromotionContractChecks(promotion) : [];
  const generatedPromotionContractViolations = generatedPromotionContractChecks.filter((check) => check.status !== "pass");
  return {
    id: output.id,
    positionId: output.positionId,
    status: promotion?.promotedCritiqueId ? "promoted_to_rating" : normalizeGenerationOutputStatus(output.status ?? output.generationOutputStatus),
    promotedCritiqueId: promotion?.promotedCritiqueId ?? output.promotedCritiqueId ?? null,
    duplicateOfOutputId: output.duplicateOfOutputId ?? null,
    selectionReasons: output.selectionReasons ?? output.selectionReasonCodes ?? (output.selectionReason ? [output.selectionReason] : []),
    modelJudgeScore: output.modelJudgeScore ?? output.screeningScore ?? null,
    generatedSubmissionContractChecks,
    generatedSubmissionContractViolations,
    generatedSubmissionContractStatus: generatedSubmissionContractViolations.length
      ? "generated_critique_submission_contract_review_required"
      : submittedWorkflowOutput
        ? "generated_critique_submission_contract_complete"
        : "not_submitted_generated_critique_submission",
    generatedPromotionContractChecks,
    generatedPromotionContractViolations,
    generatedPromotionContractStatus: generatedPromotionContractViolations.length
      ? "generated_critique_promotion_contract_review_required"
      : promotion
        ? "generated_critique_promotion_contract_complete"
        : "not_promoted_generated_critique",
  };
}

function submittedCritiqueGenerationRunContractChecks(run) {
  const fieldChecks = REQUIRED_CRITIQUE_GENERATION_RUN_FIELDS.map((field) => ({
    field,
    expected: "present",
    observed: run?.[field] ?? null,
    status: hasRequiredValue(run?.[field]) ? "pass" : "missing_required_field",
  }));
  const positionIdsCheck = {
    field: "positionIds",
    expected: "non_empty_array",
    observed: run?.positionIds ?? null,
    status: Array.isArray(run?.positionIds) && run.positionIds.length ? "pass" : "missing_required_array_values",
  };
  const generationParametersCheck = {
    field: "generationParameters",
    expected: "object",
    observed: run?.generationParameters ?? null,
    status: run?.generationParameters && typeof run.generationParameters === "object" && !Array.isArray(run.generationParameters) ? "pass" : "invalid_object",
  };
  const finiteNumberChecks = REQUIRED_CRITIQUE_GENERATION_RUN_NUMBER_FIELDS.map((field) => ({
    field,
    expected: "finite_number",
    observed: run?.[field] ?? null,
    status: Number.isFinite(Number(run?.[field])) ? "pass" : "invalid_number",
  }));
  const blindRatingCheck = {
    field: "blindRatingBeforeScreening",
    expected: true,
    observed: run?.blindRatingBeforeScreening ?? null,
    status: run?.blindRatingBeforeScreening === true ? "pass" : "must_equal_true",
  };
  return [...fieldChecks, positionIdsCheck, generationParametersCheck, ...finiteNumberChecks, blindRatingCheck];
}

function submittedGeneratedCritiqueSubmissionContractChecks(submission) {
  const fieldChecks = REQUIRED_GENERATED_CRITIQUE_SUBMISSION_FIELDS.map((field) => ({
    field,
    expected: "present",
    observed: submission?.[field] ?? null,
    status: hasRequiredValue(submission?.[field]) ? "pass" : "missing_required_field",
  }));
  const generationIndexCheck = {
    field: "generationIndex",
    expected: "finite_number",
    observed: submission?.generationIndex ?? null,
    status: Number.isFinite(Number(submission?.generationIndex)) ? "pass" : "invalid_number",
  };
  const statusCheck = {
    field: "generationOutputStatus",
    expected: GENERATED_CRITIQUE_SUBMISSION_ALLOWED_STATUSES,
    observed: submission?.generationOutputStatus ?? null,
    status: GENERATED_CRITIQUE_SUBMISSION_ALLOWED_STATUSES.includes(submission?.generationOutputStatus) ? "pass" : "unsupported_status",
  };
  const hiddenCheck = {
    field: "generatorMetadataHiddenFromRaters",
    expected: true,
    observed: submission?.generatorMetadataHiddenFromRaters ?? null,
    status: submission?.generatorMetadataHiddenFromRaters === true ? "pass" : "must_equal_true",
  };
  return [...fieldChecks, generationIndexCheck, statusCheck, hiddenCheck];
}

function submittedGeneratedCritiquePromotionContractChecks(promotion) {
  const fieldChecks = REQUIRED_GENERATED_CRITIQUE_PROMOTION_FIELDS.map((field) => ({
    field,
    expected: "present",
    observed: promotion?.[field] ?? null,
    status: hasRequiredValue(promotion?.[field]) ? "pass" : "missing_required_field",
  }));
  const promotionStatusCheck = {
    field: "promotionStatus",
    expected: "promoted_after_human_review",
    observed: promotion?.promotionStatus ?? null,
    status: promotion?.promotionStatus === "promoted_after_human_review" ? "pass" : "unsupported_status",
  };
  const humanReviewStatusCheck = {
    field: "humanReviewStatus",
    expected: "passed_trained_human_review",
    observed: promotion?.humanReviewStatus ?? null,
    status: promotion?.humanReviewStatus === "passed_trained_human_review" ? "pass" : "unsupported_status",
  };
  const hiddenCheck = {
    field: "generatorMetadataHiddenFromRaters",
    expected: true,
    observed: promotion?.generatorMetadataHiddenFromRaters ?? null,
    status: promotion?.generatorMetadataHiddenFromRaters === true ? "pass" : "must_equal_true",
  };
  return [...fieldChecks, promotionStatusCheck, humanReviewStatusCheck, hiddenCheck];
}

function submittedGenerationEvaluationReportContractChecks(report, generationRunId) {
  const fieldChecks = REQUIRED_GENERATION_EVALUATION_REPORT_FIELDS.map((field) => ({
    field,
    expected: "present",
    observed: report?.[field] ?? null,
    status: hasRequiredValue(report?.[field]) ? "pass" : "missing_required_field",
  }));
  const linkedRunCheck = {
    field: "generationRunIds",
    expected: generationRunId,
    observed: report?.generationRunIds ?? report?.critiqueGenerationRunIds ?? [],
    status: normalizeStringArray(report?.generationRunIds ?? report?.critiqueGenerationRunIds).includes(generationRunId) ? "pass" : "missing_linked_generation_run",
  };
  const objectChecks = Object.keys(REQUIRED_GENERATION_EVALUATION_REPORT_METRIC_FIELDS).map((field) => ({
    field,
    expected: "object",
    observed: report?.[field] ?? null,
    status: report?.[field] && typeof report[field] === "object" && !Array.isArray(report[field]) ? "pass" : "invalid_object",
  }));
  const metricFieldChecks = Object.entries(REQUIRED_GENERATION_EVALUATION_REPORT_METRIC_FIELDS).flatMap(([objectField, nestedFields]) =>
    nestedFields.map((nestedField) => ({
      field: `${objectField}.${nestedField}`,
      expected: "finite_number",
      observed: report?.[objectField]?.[nestedField] ?? null,
      status: Number.isFinite(Number(report?.[objectField]?.[nestedField])) ? "pass" : "invalid_number",
    })),
  );
  const definitionChecks = [
    {
      field: "uncuratedRandomSampleMetric",
      expected: "mentions uncurated or random sample",
      observed: report?.uncuratedRandomSampleMetric ?? null,
      status: policyMentionsAny(report?.uncuratedRandomSampleMetric, ["uncurated", "random", "all generated"]) ? "pass" : "missing_metric_definition",
    },
    {
      field: "bestOfNPolicy",
      expected: "mentions best-of-N and generation budget",
      observed: report?.bestOfNPolicy ?? null,
      status: policyMentions(report?.bestOfNPolicy, ["best", "n"]) && policyMentionsAny(report?.bestOfNPolicy, ["budget", "generated", "requested"])
        ? "pass"
        : "missing_metric_definition",
    },
    {
      field: "topKPolicy",
      expected: "mentions top-k or curated view separated from default metric",
      observed: report?.topKPolicy ?? null,
      status:
        policyMentionsAny(report?.topKPolicy, ["top", "curated"]) && policyMentionsAny(report?.topKPolicy, ["separate", "diagnostic", "non-headline"])
          ? "pass"
          : "missing_metric_definition",
    },
  ];
  const passThresholdCheck = {
    field: "passThresholdOverall",
    expected: "finite_number",
    observed: report?.passThresholdOverall ?? null,
    status: Number.isFinite(Number(report?.passThresholdOverall)) ? "pass" : "invalid_number",
  };
  return [...fieldChecks, linkedRunCheck, ...objectChecks, ...metricFieldChecks, ...definitionChecks, passThresholdCheck];
}

function normalizeGenerationOutputStatus(status) {
  if (["promoted_to_rating", "empty_or_refusal", "duplicate_filtered", "filtered_before_rating", "human_rejected"].includes(status)) return status;
  if (status === "promoted" || status === "rated") return "promoted_to_rating";
  if (status === "empty" || status === "refusal") return "empty_or_refusal";
  if (status === "duplicate" || status === "near_duplicate") return "duplicate_filtered";
  if (status === "filtered" || status === "rejected_before_rating") return "filtered_before_rating";
  if (status === "rejected") return "human_rejected";
  return "generated_not_promoted";
}

function normalizeSubmittedGenerationFilteringPolicy(run) {
  return {
    duplicatePolicy: run.filteringPolicy?.duplicatePolicy ?? run.duplicatePolicy ?? "submitted_duplicates_counted_and_reported",
    emptyRefusalPolicy: run.filteringPolicy?.emptyRefusalPolicy ?? run.emptyRefusalPolicy ?? "submitted_empty_refusals_counted",
    humanCurationPolicy: run.filteringPolicy?.humanCurationPolicy ?? run.humanCurationPolicy ?? "submitted_selection_policy_reported_separately",
    protectedSplitUse: run.filteringPolicy?.protectedSplitUse ?? run.protectedSplitUse ?? "submitted_generation_protected_split_policy_reported",
  };
}

function normalizeSubmittedGenerationJudge(run, promptArtifact) {
  const judge = run.modelJudgeScreening ?? {};
  return {
    requestedModelAlias: judge.requestedModelAlias ?? run.judgeRequestedModelAlias ?? null,
    resolvedModelSnapshot: judge.resolvedModelSnapshot ?? run.judgeResolvedModelSnapshot ?? null,
    parserConfigId: judge.parserConfigId ?? run.judgeParserConfigId ?? null,
    acceptedOutputSchema: judge.acceptedOutputSchema ?? null,
    promptTemplateId: promptArtifact.id,
    promptArtifact,
    renderedPromptChecksum: judge.renderedPromptChecksum ?? promptArtifact.renderedPromptChecksum,
    promptPolicyComparabilityStatus: judge.promptPolicyComparabilityStatus ?? promptArtifact.promptPolicyComparabilityStatus,
    parseFailureCount: judge.parseFailureCount ?? 0,
    invalidScoreCount: judge.invalidScoreCount ?? 0,
    retryCount: judge.retryCount ?? 0,
    repairedOutputCount: judge.repairedOutputCount ?? 0,
    scoresVisibleToInitialRaters: judge.scoresVisibleToInitialRaters ?? run.modelJudgeScoresVisibleToInitialRaters ?? false,
    diagnosticOnly: judge.diagnosticOnly ?? run.modelJudgeDiagnosticOnly ?? true,
    modelProviderDataHandlingPolicyId: judge.modelProviderDataHandlingPolicyId ?? run.judgeModelProviderDataHandlingPolicyId ?? null,
  };
}

function promptArtifactForSubmittedWorkflow(id, promptFamily, promptScope, promptPolicyComparabilityStatus, renderedPromptChecksum, outputFormatPolicy) {
  if (id && promptArtifacts[id]) return promptArtifactRef(id);
  return {
    id,
    artifactKind: "prompt_template",
    promptFamily,
    promptScope,
    promptBody: "submitted workflow prompt body stored outside seed prompt registry",
    renderedPromptChecksum,
    promptPolicyComparabilityStatus,
    protectedSplitExclusionCheck: {
      status: "submitted_prompt_examples_exclude_protected_splits",
      hiddenBenchmarkExamplesExcluded: true,
      protectedValidationExamplesExcluded: true,
      exampleItemIds: [],
      examplePositionClusterIds: [],
      exampleSplits: [],
    },
    promptExampleProvenance: [],
    itemRoleTerminology: "position_critique",
    outputFormatPolicy,
  };
}

const BENCHMARK_SPLIT_MEMBER_ALLOWED_SPLITS = ["hidden_benchmark_candidate", "hidden_benchmark"];
const BENCHMARK_SPLIT_MEMBER_LEAK_PREVENTION_FRAGMENTS = ["excluded", "training", "public"];

export function buildHiddenBenchmarkFreezeReport(
  releaseId,
  labelSnapshot,
  positionList = positions,
  critiqueList = critiques,
  rightsRecords = provenanceRightsRecords,
  exposureEvents = seedBenchmarkExposureEvents,
  options = {},
) {
  const hiddenBenchmarkGovernancePolicy = {
    membershipFreezeRule: "hidden_benchmark_membership_frozen_before_scoring_and_redacted_from_ordinary_raters",
    authorizedAccessRoles: ["admin", "expert"],
    exposureLoggingRule: "all_membership_view_export_probe_and_refresh_actions_emit_exposure_log_rows",
    routineRefreshCadenceDays: 180,
    leakageIncidentRefreshCadenceDays: 30,
    saturationTriggeredRefresh: "defer_to_active_benchmark_refresh_policy",
    leakResponseActions: ["quarantine_exposed_items", "reassign_or_replace_items", "record_public_or_internal_erratum", "rerun_freeze_report"],
  };
  const ratings = options.ratings ?? seedRatings;
  const submittedSplitMembership = buildSubmittedBenchmarkSplitMembership(positionList, options.benchmarkSplitMembers ?? []);
  const benchmarkPositionList = submittedSplitMembership.effectivePositionList;
  const hiddenPositions = benchmarkPositionList.filter((position) => position.split === "hidden_benchmark");
  const hiddenPositionIds = hiddenPositions.map((position) => position.id);
  const hiddenPositionIdSet = new Set(hiddenPositionIds);
  const hiddenCritiques = critiqueList.filter((critique) => hiddenPositionIdSet.has(critique.positionId));
  const hiddenCritiqueIds = hiddenCritiques.map((critique) => critique.id);
  const hiddenItemIds = hiddenCritiques.map((critique) => makeItemId(critique.positionId, critique.id));
  const hiddenClusters = new Set(hiddenPositions.map((position) => position.clusterId));
  const overlappingSplitClusters = benchmarkPositionList
    .filter((position) => position.split !== "hidden_benchmark" && hiddenClusters.has(position.clusterId))
    .map((position) => ({
      clusterId: position.clusterId,
      positionId: position.id,
      split: position.split,
    }));
  const rightsStatus = auditProvenanceRights("hidden_benchmark", benchmarkPositionList, rightsRecords);
  const metricEligibility = buildMetricFamilyEligibilityManifest(releaseId, labelSnapshot, hiddenPositions, hiddenCritiques);
  const positionToHumanOveralls = Object.fromEntries(
    hiddenPositions.map((position) => [
      position.id,
      Object.fromEntries(
        hiddenCritiques
          .filter((critique) => critique.positionId === position.id)
          .map((critique) => [critique.id, labelSnapshot.itemLabels[makeItemId(position.id, critique.id)]?.weightedMeanScores.overall])
          .filter(([, score]) => isValidScore(score)),
      ),
    ]),
  );
  const pairwiseSnapshot = buildPairwiseComparisonSnapshot(
    `hidden-benchmark-pairwise-${releaseId}`,
    labelSnapshot.id,
    labelSnapshot.targetLabelVersion,
    positionToHumanOveralls,
  );
  const marginDistribution = pairwiseMarginDistribution(pairwiseSnapshot);
  const artifactBalance = buildHiddenArtifactBalance(hiddenPositions, hiddenCritiques, labelSnapshot);
  const accessAudit = summarizeBenchmarkAccess(exposureEvents);
  const artifactProbeDiagnostics = buildArtifactProbeDiagnostics(exposureEvents, options.artifactProbeRuns ?? [], {
    releaseId,
    labelSnapshot,
  });
  const initialBlinding = buildHiddenBenchmarkInitialBlindingReport(releaseId, labelSnapshot, ratings, benchmarkPositionList);
  const hiddenBenchmarkExpertQualification = buildHiddenBenchmarkExpertQualificationReport(
    hiddenItemIds,
    ratings,
    Array.isArray(options.raterQualificationRecords) && options.raterQualificationRecords.length
      ? options.raterQualificationRecords
      : defaultRaterQualificationRecords(releaseId),
  );
  const freezeChecks = [
    freezeCheck("rights", rightsStatus.status, "Hidden-benchmark positions have restricted benchmark release scopes and adapted-source provenance."),
    freezeCheck(
      "position_cluster_isolation",
      overlappingSplitClusters.length ? "blocked" : "pass",
      "Hidden benchmark positions must not share clusters with public, training, or validation positions.",
    ),
    freezeCheck(
      "context_sufficiency",
      hiddenPositions.every((position) => position.contextSufficiency === "sufficient") ? "pass" : "blocked",
      "Hidden benchmark positions must have enough rater-visible context or a disclosed expert normalization route.",
    ),
    freezeCheck(
      "conceptual_scope",
      hiddenPositions.every((position) => position.conceptualScope === "primarily_conceptual" || position.conceptualScope === "mixed_conceptual_non_conceptual")
        ? "pass"
        : "blocked",
      "Ordinary hidden-benchmark claims exclude primarily non-conceptual items unless declared as stress/comparison cases.",
    ),
    freezeCheck(
      "metric_family_eligibility",
      metricEligibility.pairwiseEligiblePairCount > 0 ? "pass" : metricEligibility.customLossEligibleItems.length > 0 ? "pointwise_only" : "blocked",
      "Pairwise headline subsets require non-tied same-position critique pairs; custom weighted loss can include pointwise-only items when disclosed.",
    ),
    freezeCheck(
      "pairwise_margin_distribution",
      pairwiseSnapshot.nonTiedEdges.length > 0 ? (marginDistribution.lowMarginWeightShare > 0.75 ? "low_margin_sensitive" : "pass") : "pointwise_only",
      "Benchmark-freeze reports must disclose human/adjudicated overall-score gap distributions and low-margin sensitivity.",
    ),
    freezeCheck(
      "artifact_balance",
      artifactBalance.counterbalanceStatus,
      "Position source/adaptation, critique source/authorship, LLM assistance, length, style, and adjudicated quality are counterbalanced before freeze.",
    ),
    freezeCheck(
      "artifact_probe_diagnostics",
      artifactProbeDiagnostics.status,
      "Critique-only and metadata/style-only probes must be run or explicitly documented on authorized data before ordinary headline claims.",
    ),
    freezeCheck(
      "access_audit",
      accessAudit.unauthorizedAccessCount === 0 && accessAudit.totalEvents > 0 ? "pass" : "blocked",
      "Hidden benchmark status and membership are restricted to authorized roles, with accesses logged before and after freeze.",
    ),
    freezeCheck(
      "governance_refresh_policy",
      "pass",
      `Hidden benchmark refresh cadence is frozen at ${hiddenBenchmarkGovernancePolicy.routineRefreshCadenceDays} routine days and ${hiddenBenchmarkGovernancePolicy.leakageIncidentRefreshCadenceDays} days after leakage incidents.`,
    ),
    freezeCheck(
      "initial_rating_blinding",
      initialBlinding.releaseUseStatus === "hidden_benchmark_initial_blinding_violation" ? "blocked" : "pass",
      `${initialBlinding.counts.sourceTagVisibleInitialRows} source/tag-visible hidden-benchmark initial rows; ${initialBlinding.counts.excludedFromBlindAggregationRows} excluded and ${initialBlinding.counts.adjudicatedExceptionRows} disclosed exceptions.`,
    ),
    freezeCheck(
      "hidden_benchmark_expert_qualification",
      hiddenBenchmarkExpertQualification.status === "pass" ? "pass" : "blocked",
      `${hiddenBenchmarkExpertQualification.counts.qualifiedHiddenBenchmarkItemCount}/${hiddenBenchmarkExpertQualification.counts.hiddenBenchmarkItemCount} hidden-benchmark items have current hidden_benchmark_expert qualification evidence.`,
    ),
    freezeCheck(
      "submitted_split_membership_contract",
      submittedSplitMembership.report.contractViolationRows.length ? "blocked" : "pass",
      `${submittedSplitMembership.report.contractViolationRows.length} submitted benchmark split membership rows failed cluster, freeze, eligibility, exposure, or leak-prevention contract checks.`,
    ),
  ];
  return {
    id: `hidden-benchmark-freeze-${releaseId}`,
    releaseId,
    generatedAt: new Date().toISOString(),
    labelSnapshotId: labelSnapshot.id,
    targetLabelVersion: labelSnapshot.targetLabelVersion,
    freezeStatus: summarizeFreezeStatus(freezeChecks),
    frozenAt: summarizeFreezeStatus(freezeChecks) === "frozen" ? new Date().toISOString() : null,
    hiddenPositionCount: hiddenPositions.length,
    hiddenCritiqueCount: hiddenCritiques.length,
    submittedSplitMembership: submittedSplitMembership.report,
    restrictedItemRefs: options.includeRestrictedIds
      ? { hiddenPositionIds, hiddenCritiqueIds, hiddenItemIds }
      : { hiddenPositionIds: [], hiddenCritiqueIds: [], hiddenItemIds: [], redaction: "membership_ids_restricted_to_admin_endpoint" },
    rightsStatus,
    hiddenBenchmarkGovernancePolicy,
    clusterIsolation: {
      status: overlappingSplitClusters.length ? "blocked" : "pass",
      hiddenClusterIds: options.includeRestrictedIds ? [...hiddenClusters] : [],
      overlappingSplitClusters,
    },
    metricEligibility,
    pairwiseComparisonSnapshot: pairwiseSnapshot,
    pairwiseMarginDistribution: marginDistribution,
    artifactBalance,
    artifactProbeDiagnostics,
    accessAudit,
    initialBlinding,
    hiddenBenchmarkExpertQualification,
    freezeChecks,
  };
}

function buildHiddenBenchmarkExpertQualificationReport(hiddenItemIds, ratings, raterQualificationRecords = []) {
  const qualificationRows = (raterQualificationRecords ?? [])
    .map((record) => normalizeRaterQualificationRecord(record, "hidden_benchmark_expert_qualification_record"))
    .filter(Boolean);
  const currentHiddenBenchmarkExpertRecordByRater = new Map(
    qualificationRows
      .filter((record) =>
        raterQualificationRecordIsCurrent(record, {
          qualificationScope: "hidden_benchmark_expert",
          approvedRole: "expert",
          requiredEligibility: "hidden_benchmark",
        }),
      )
      .map((record) => [record.raterId, record]),
  );
  const rows = hiddenItemIds.map((itemId) => {
    const itemRatings = ratings.filter((rating) => makeItemId(rating.positionId, rating.critiqueId) === itemId);
    const qualifiedRows = itemRatings
      .map((rating) => ({
        ratingId: rating.id,
        raterId: rating.raterId,
        raterTier: rating.raterTier,
        ratingKind: rating.kind,
        raterQualificationRecordId: currentHiddenBenchmarkExpertRecordByRater.get(rating.raterId)?.id ?? null,
      }))
      .filter((row) => row.raterQualificationRecordId);
    const expertTierUnqualifiedRows = itemRatings
      .filter((rating) => rating.raterTier === "expert" && !currentHiddenBenchmarkExpertRecordByRater.has(rating.raterId))
      .map((rating) => ({ ratingId: rating.id, raterId: rating.raterId, raterTier: rating.raterTier, ratingKind: rating.kind }));
    return {
      itemId,
      ratingCount: itemRatings.length,
      qualifiedHiddenBenchmarkExpertRaterIds: uniqueStrings(qualifiedRows.map((row) => row.raterId)),
      qualifiedHiddenBenchmarkExpertCount: uniqueStrings(qualifiedRows.map((row) => row.raterId)).length,
      qualifiedRows,
      expertTierUnqualifiedRows,
      status: qualifiedRows.length ? "hidden_benchmark_expert_qualified" : "hidden_benchmark_expert_qualification_missing",
    };
  });
  const missingRows = rows.filter((row) => row.status !== "hidden_benchmark_expert_qualified");
  return {
    requiredQualificationScope: "hidden_benchmark_expert",
    requiredApprovedRole: "expert",
    requiredSplitWorkflowEligibility: "hidden_benchmark",
    rows,
    missingRows,
    counts: {
      hiddenBenchmarkItemCount: rows.length,
      qualifiedHiddenBenchmarkItemCount: rows.filter((row) => row.status === "hidden_benchmark_expert_qualified").length,
      missingHiddenBenchmarkExpertQualificationItemCount: missingRows.length,
      currentHiddenBenchmarkExpertRaterCount: currentHiddenBenchmarkExpertRecordByRater.size,
    },
    status: missingRows.length ? "hidden_benchmark_expert_qualification_required" : "pass",
  };
}

function buildSubmittedBenchmarkSplitMembership(positionList, splitMembers = []) {
  const positionById = new Map(positionList.map((position) => [position.id, position]));
  const rows = splitMembers
    .map((member) => {
      if (!member || typeof member !== "object") return null;
      const positionId = member.positionId ?? parsePositionIdFromItemId(member.itemId);
      const position = positionById.get(positionId);
      const requestedSplit = member.split ?? "unknown";
      const effectiveSplit = requestedSplit === "hidden_benchmark_candidate" ? "hidden_benchmark" : requestedSplit;
      const leakPreventionStatus = member.leakPreventionStatus ?? "not_declared";
      const normalizedLeakPreventionStatus = String(leakPreventionStatus).toLowerCase();
      const missingLeakPreventionFragments = BENCHMARK_SPLIT_MEMBER_LEAK_PREVENTION_FRAGMENTS.filter(
        (fragment) => !normalizedLeakPreventionStatus.includes(fragment),
      );
      const positionClusterId = member.positionClusterId ?? member.clusterId ?? null;
      const contractViolations = [
        member.id ? null : "id",
        member.releaseId ? null : "releaseId",
        member.itemId ? null : "itemId",
        positionClusterId ? null : "positionClusterId",
        position && positionClusterId === position.clusterId ? null : "positionClusterId:position_cluster_mismatch",
        BENCHMARK_SPLIT_MEMBER_ALLOWED_SPLITS.includes(requestedSplit) ? null : "split",
        member.splitUnit === "position_cluster" ? null : "splitUnit",
        member.freezeVersion ? null : "freezeVersion",
        member.artifactBalanceBucket ? null : "artifactBalanceBucket",
        member.crossSplitExceptionReason ? null : "crossSplitExceptionReason",
        member.frozenAt ? null : "frozenAt",
        member.customWeightedLossEligible === true ? null : "customWeightedLossEligible",
        member.pairwiseRankingEligible === true ? null : "pairwiseRankingEligible",
        member.pointwiseOnly === false ? null : "pointwiseOnly",
        member.exposureRestricted === true ? null : "exposureRestricted",
        ...missingLeakPreventionFragments.map((fragment) => `leakPreventionStatus:${fragment}`),
      ].filter(Boolean);
      const contractReady = contractViolations.length === 0;
      return {
        id: member.id,
        itemId: member.itemId ?? null,
        positionId,
        positionClusterId,
        requestedSplit,
        effectiveSplit,
        splitUnit: member.splitUnit ?? null,
        freezeVersion: member.freezeVersion ?? null,
        artifactBalanceBucket: member.artifactBalanceBucket ?? null,
        crossSplitExceptionReason: member.crossSplitExceptionReason ?? null,
        leakPreventionStatus,
        missingLeakPreventionFragments,
        customWeightedLossEligible: member.customWeightedLossEligible === true,
        pairwiseRankingEligible: member.pairwiseRankingEligible === true,
        pointwiseOnly: member.pointwiseOnly === true,
        exposureRestricted: member.exposureRestricted === true,
        frozenAt: member.frozenAt ?? null,
        positionKnown: Boolean(position),
        contractViolations,
        contractReady,
        appliedToFreezeMembership: Boolean(position) && contractReady && effectiveSplit === "hidden_benchmark",
      };
    })
    .filter(Boolean);
  const hiddenOverrideByPosition = new Map(
    rows.filter((row) => row.appliedToFreezeMembership).map((row) => [row.positionId, row]),
  );
  const effectivePositionList = positionList.map((position) => {
    const override = hiddenOverrideByPosition.get(position.id);
    if (!override) return position;
    return {
      ...position,
      split: "hidden_benchmark",
      benchmarkSplitMembershipOverride: {
        id: override.id,
        requestedSplit: override.requestedSplit,
        originalSplit: position.split,
        leakPreventionStatus: override.leakPreventionStatus,
      },
    };
  });
  return {
    effectivePositionList,
    report: {
      rowCount: rows.length,
      appliedHiddenPositionCount: hiddenOverrideByPosition.size,
      unknownPositionRows: rows.filter((row) => !row.positionKnown),
      contractViolationRows: rows.filter((row) => !row.contractReady),
      rows,
      status: rows.some((row) => !row.contractReady)
        ? "submitted_membership_contract_review_required"
        : rows.length
        ? hiddenOverrideByPosition.size
          ? "submitted_hidden_benchmark_membership_applied"
          : "submitted_membership_no_hidden_benchmark_rows"
        : "no_submitted_split_membership",
    },
  };
}

function parsePositionIdFromItemId(itemId) {
  if (typeof itemId !== "string" || !itemId.includes("::")) return null;
  return itemId.split("::")[0];
}

const BENCHMARK_PAIRWISE_ELIGIBILITY_POLICY = {
  minimumScoredCritiquesPerPosition: 3,
  minimumNonTiedPairCount: 1,
  minimumAdjudicatedOverallSpread: 0.2,
  pointwiseOnlyFallback: "custom_weighted_loss_items_remain_pointwise_only_when_pairwise_policy_is_not_met",
};

export function buildMetricFamilyEligibilityManifest(releaseId, labelSnapshot, positionList = positions, critiqueList = critiques, tieTolerance = 0) {
  const pairwiseEligiblePositions = [];
  const pointwiseOnlyItems = [];
  const customLossEligibleItems = [];
  const metricFamilySpecificExclusions = [];
  const qualitySpreadRows = [];

  positionList.forEach((position) => {
    const positionCritiques = critiqueList.filter((critique) => critique.positionId === position.id);
    const scoredCritiques = positionCritiques
      .map((critique) => {
        const itemId = makeItemId(position.id, critique.id);
        const label = labelSnapshot.itemLabels[itemId];
        if (label && isCustomLossEligibleLabel(label.weightedMeanScores)) customLossEligibleItems.push(itemId);
        return { critique, itemId, overall: label?.weightedMeanScores.overall };
      })
      .filter((item) => isValidScore(item.overall));

    let nonTiedPairCount = 0;
    scoredCritiques.forEach((a, index) => {
      scoredCritiques.slice(index + 1).forEach((b) => {
        if (!isTie(a.overall - b.overall, tieTolerance)) nonTiedPairCount += 1;
      });
    });
    const scoredOveralls = scoredCritiques.map((item) => item.overall).filter(isValidScore);
    const adjudicatedOverallSpread = scoredOveralls.length ? round(Math.max(...scoredOveralls) - Math.min(...scoredOveralls)) : null;
    const reviewReasons = [
      scoredCritiques.length >= BENCHMARK_PAIRWISE_ELIGIBILITY_POLICY.minimumScoredCritiquesPerPosition
        ? null
        : "fewer_than_three_labelled_critiques",
      nonTiedPairCount >= BENCHMARK_PAIRWISE_ELIGIBILITY_POLICY.minimumNonTiedPairCount ? null : "no_non_tied_human_pairs",
      adjudicatedOverallSpread !== null &&
      adjudicatedOverallSpread >= BENCHMARK_PAIRWISE_ELIGIBILITY_POLICY.minimumAdjudicatedOverallSpread
        ? null
        : "adjudicated_quality_spread_below_threshold",
    ].filter(Boolean);
    qualitySpreadRows.push({
      positionId: position.id,
      scoredCritiqueCount: scoredCritiques.length,
      nonTiedPairCount,
      adjudicatedOverallSpread,
      minimumAdjudicatedOverallSpread: BENCHMARK_PAIRWISE_ELIGIBILITY_POLICY.minimumAdjudicatedOverallSpread,
      status: reviewReasons.length ? "pairwise_headline_ineligible" : "pairwise_headline_eligible",
      reviewReasons,
    });

    if (!reviewReasons.length) {
      pairwiseEligiblePositions.push({
        positionId: position.id,
        critiqueIds: scoredCritiques.map((item) => item.critique.id),
        scoredCritiqueCount: scoredCritiques.length,
        nonTiedPairCount,
        adjudicatedOverallSpread,
        minimumAdjudicatedOverallSpread: BENCHMARK_PAIRWISE_ELIGIBILITY_POLICY.minimumAdjudicatedOverallSpread,
      });
      return;
    }

    scoredCritiques.forEach((item) => {
      if (customLossEligibleItems.includes(item.itemId)) pointwiseOnlyItems.push(item.itemId);
    });
    metricFamilySpecificExclusions.push({
      positionId: position.id,
      reason: reviewReasons[0],
      reviewReasons,
      scoredCritiqueCount: scoredCritiques.length,
      nonTiedPairCount,
      adjudicatedOverallSpread,
      minimumAdjudicatedOverallSpread: BENCHMARK_PAIRWISE_ELIGIBILITY_POLICY.minimumAdjudicatedOverallSpread,
    });
  });

  return {
    id: `metric-eligibility-${releaseId}`,
    releaseId,
    labelSnapshotId: labelSnapshot.id,
    targetLabelVersion: labelSnapshot.targetLabelVersion,
    pairwiseEligibilityPolicy: BENCHMARK_PAIRWISE_ELIGIBILITY_POLICY,
    pairwiseEligiblePositions,
    pairwiseEligiblePairCount: pairwiseEligiblePositions.reduce((sum, item) => sum + item.nonTiedPairCount, 0),
    pairwiseSpreadEligiblePositionCount: qualitySpreadRows.filter((row) => row.status === "pairwise_headline_eligible").length,
    customLossEligibleItems,
    pointwiseOnlyItems,
    metricFamilySpecificExclusions,
    qualitySpreadRows,
    notes: [
      "Pairwise headline subsets require at least three scored same-position critiques, a non-tied pair, and the frozen adjudicated-spread threshold.",
      "Custom weighted loss remains pointwise and may include pointwise-only items.",
    ],
  };
}

export function buildHumanScoreDistributionReport(releaseId, labelSnapshot, positionList = positions, critiqueList = critiques) {
  const rows = buildLabelRows(labelSnapshot, positionList, critiqueList);
  return {
    id: `human-score-distribution-${releaseId}`,
    releaseId,
    labelSnapshotId: labelSnapshot.id,
    targetLabelVersion: labelSnapshot.targetLabelVersion,
    createdAt: new Date().toISOString(),
    histogramBins: ["0-0.2", "0.2-0.4", "0.4-0.6", "0.6-0.8", "0.8-1.0"],
    overall: summarizeLabelRows(rows),
    bySplit: summarizeRowsBy(rows, "split"),
    bySourceCategory: summarizeRowsBy(rows, "sourceCategory"),
    byTopicFamily: summarizeRowsBy(rows, "topicFamily"),
    byCritiqueLengthBand: summarizeRowsBy(rows, "critiqueLengthBand"),
    byCritiqueAuthorshipType: summarizeRowsBy(rows, "critiqueAuthorshipType"),
    notes: [
      "Distributions make prior-only and constant-score baselines interpretable.",
      "Split/source/topic/length strata are reported separately so artifact and calibration confounds remain visible.",
    ],
  };
}

export function buildRatingEffortQualityReport(
  releaseId,
  ratings = seedRatings,
  positionList = positions,
  critiqueList = critiques,
  assignmentList = assignments,
  options = {},
) {
  const positionById = new Map(positionList.map((position) => [position.id, position]));
  const critiqueById = new Map(critiqueList.map((critique) => [critique.id, critique]));
  const assignmentById = new Map(assignmentList.map((assignment) => [assignment.id, assignment]));
  const baseRows = ratings.map((rating) => {
    const position = positionById.get(rating.positionId);
    const critique = critiqueById.get(rating.critiqueId);
    const assignment = assignmentById.get(rating.assignmentId);
    const positionLengthBand = position ? textLengthBand(latestText(position).text) : "unknown";
    const critiqueLengthBand = critique?.lengthBand ?? "unknown";
    const expectation = effortExpectation(positionLengthBand, critiqueLengthBand);
    const telemetry = {
      activeSeconds: rating.activeSeconds,
      idleGapSeconds: rating.idleGapSeconds,
      interruptionCount: rating.interruptionCount,
    };
    const routeReasons = effortRouteReasons(telemetry, expectation);
    const split = position?.split ?? "unknown";
    const assignmentQueueType = assignment?.queueType ?? assignment?.assignmentType ?? "unknown";
    const protectedUseBlocks = protectedEffortUseBlocks(routeReasons, split, assignmentQueueType);
    return {
      ratingId: rating.id,
      ratingHash: `sha256:${rating.id}:effort`,
      itemHash: `sha256:${makeItemId(rating.positionId, rating.critiqueId)}:effort`,
      split,
      queueType: assignmentQueueType,
      kind: rating.kind,
      raterTier: rating.raterTier,
      positionLengthBand,
      critiqueLengthBand,
      expectedEffortBand: expectation.band,
      expectedActiveSecondsMin: expectation.minActiveSeconds,
      activeSeconds: telemetry.activeSeconds ?? null,
      idleGapSeconds: telemetry.idleGapSeconds ?? null,
      interruptionCount: telemetry.interruptionCount ?? null,
      routeReasons,
      qaStatus: routeReasons.length ? "qa_review_required_before_sensitive_use" : "effort_telemetry_pass",
      protectedUseBlocks,
    };
  });
  const reviewRows = (options.ratingEffortQaReviews ?? []).map((review) =>
    normalizeRatingEffortQaReview(review, baseRows, "submitted_rating_effort_qa_review")
  );
  const completeReviewsByRatingId = new Map(
    [...reviewRows]
      .filter((row) => row.reviewStatus === "rating_effort_qa_review_complete")
      .sort((left, right) => String(left.timestamp).localeCompare(String(right.timestamp)) || String(left.id).localeCompare(String(right.id)))
      .map((row) => [row.ratingId, row]),
  );
  const rows = baseRows.map((row) => {
    if (!row.routeReasons.length) return row;
    const qaReview = completeReviewsByRatingId.get(row.ratingId) ?? null;
    if (!qaReview) {
      return {
        ...row,
        ratingEffortQaReviewId: null,
        qaReviewDecision: null,
        sensitiveUseDisposition: "pending_qa_review",
      };
    }
    if (qaReview.reviewDecision === "cleared_for_sensitive_use") {
      return {
        ...row,
        ratingEffortQaReviewId: qaReview.id,
        qaReviewDecision: qaReview.reviewDecision,
        qaStatus: "qa_review_cleared_for_sensitive_use",
        sensitiveUseDisposition: "cleared_for_sensitive_use",
        protectedUseBlocks: [],
      };
    }
    if (qaReview.reviewDecision === "exclude_from_sensitive_denominators") {
      return {
        ...row,
        ratingEffortQaReviewId: qaReview.id,
        qaReviewDecision: qaReview.reviewDecision,
        qaStatus: "qa_review_excluded_from_sensitive_denominators",
        sensitiveUseDisposition: "excluded_from_sensitive_denominators",
        protectedUseBlocks: [],
      };
    }
    return {
      ...row,
      ratingEffortQaReviewId: qaReview.id,
      qaReviewDecision: qaReview.reviewDecision,
      qaStatus: "qa_review_rerate_required",
      sensitiveUseDisposition: "rerate_required",
    };
  });
  const qaRoutedRatings = rows.filter((row) => row.routeReasons.length);
  const unresolvedQaRoutedRatings = qaRoutedRatings.filter((row) => row.protectedUseBlocks.length);
  const invalidReviewRows = reviewRows.filter((row) => row.reviewStatus !== "rating_effort_qa_review_complete");
  return {
    id: `rating-effort-quality-${releaseId}`,
    releaseId,
    policy: {
      requiredTelemetryFields: ["activeSeconds", "idleGapSeconds", "interruptionCount"],
      lengthAdjustedExpectations: EFFORT_EXPECTATIONS,
      idleGapPolicy: "idle gaps above 50% of active time or the band maximum route to QA",
      interruptionPolicy: "interrupted ratings route to QA before certification, validation, or hidden-benchmark use",
      protectedUsePolicy: "QA-routed rows are blocked from certification, validation, and hidden-benchmark denominators until reviewed or rerated.",
    },
    telemetryCoverage: {
      totalRows: rows.length,
      completeTelemetryRows: rows.filter(hasCompleteEffortTelemetry).length,
      missingTelemetryRows: rows.filter((row) => !hasCompleteEffortTelemetry(row)).length,
    },
    byExpectedEffortBand: countBy(rows, "expectedEffortBand"),
    bySplit: countBy(rows, "split"),
    ratingEffortQaReviewRows: reviewRows,
    qaRoutedRatings,
    unresolvedQaRoutedRatings,
    byQaStatus: countBy(rows, "qaStatus"),
    counts: {
      qaRoutedRatingCount: qaRoutedRatings.length,
      unresolvedQaRoutedRatingCount: unresolvedQaRoutedRatings.length,
      submittedQaReviewCount: reviewRows.length,
      completeQaReviewCount: reviewRows.length - invalidReviewRows.length,
      invalidQaReviewCount: invalidReviewRows.length,
      qaReviewClearedCount: qaRoutedRatings.filter((row) => row.qaStatus === "qa_review_cleared_for_sensitive_use").length,
      qaReviewExcludedCount: qaRoutedRatings.filter((row) => row.qaStatus === "qa_review_excluded_from_sensitive_denominators").length,
      qaReviewRerateCount: qaRoutedRatings.filter((row) => row.qaStatus === "qa_review_rerate_required").length,
      qaReviewMissingCount: qaRoutedRatings.filter((row) => row.qaStatus === "qa_review_required_before_sensitive_use").length,
    },
    protectedUseBlockSummary: {
      certificationBlockedCount: unresolvedQaRoutedRatings.filter((row) => row.protectedUseBlocks.includes("certification")).length,
      validationBlockedCount: unresolvedQaRoutedRatings.filter((row) => row.protectedUseBlocks.includes("validation")).length,
      hiddenBenchmarkBlockedCount: unresolvedQaRoutedRatings.filter((row) => row.protectedUseBlocks.includes("hidden_benchmark")).length,
    },
    reviewSections: invalidReviewRows.length
      ? [{ section: "rating_effort_qa_reviews", reviewReasons: invalidReviewRows.flatMap((row) => row.reviewReasons) }]
      : [],
    releaseUseStatus: invalidReviewRows.length || unresolvedQaRoutedRatings.length
      ? "qa_routing_required_before_sensitive_use"
      : qaRoutedRatings.length
        ? "rating_effort_qa_review_complete"
        : "pass",
  };
}

export function buildPostLockSourceStyleAuditReport(
  releaseId,
  audits = postLockSourceStyleAudits,
  ratings = seedRatings,
  positionList = positions,
  critiqueList = critiques,
  labelSnapshot = null,
) {
  const ratingById = new Map(ratings.map((rating) => [rating.id, rating]));
  const positionById = new Map(positionList.map((position) => [position.id, position]));
  const critiqueById = new Map(critiqueList.map((critique) => [critique.id, critique]));
  const rows = audits.map((audit) => {
    const rating = ratingById.get(audit.ratingId);
    const position = positionById.get(audit.positionId);
    const critique = critiqueById.get(audit.critiqueId);
    const itemId = makeItemId(audit.positionId, audit.critiqueId);
    const label = labelSnapshot?.itemLabels?.[itemId];
    const collectedAtMs = timestampMs(audit.collectedAt);
    const lockedAtMs = timestampMs(rating?.lockedAt ?? audit.ratingLockedAt);
    const collectedAfterLock = collectedAtMs !== null && lockedAtMs !== null && collectedAtMs >= lockedAtMs;
    const shownBeforeInitialLock = audit.shownBeforeInitialLock === true;
    const usedForScoring = audit.usedForScoring === true;
    const actualSourceType = critique?.sourceType ?? "unknown";
    const actualAuthorshipType = critique?.authorshipType ?? "unknown";
    const actualStyleBand = critique?.styleBand ?? "unknown";
    return {
      auditId: audit.id,
      ratingHash: `sha256:${audit.ratingId}:source-style-audit`,
      itemHash: `sha256:${itemId}:source-style-audit`,
      split: position?.split ?? "unknown",
      collectionStatus: collectedAfterLock && !shownBeforeInitialLock ? "post_lock" : "policy_violation",
      collectedAfterLock,
      shownBeforeInitialLock,
      usedForScoring,
      sourceGuess: audit.sourceGuess ?? "unknown",
      authorshipGuess: audit.authorshipGuess ?? "unknown",
      styleGuess: audit.styleGuess ?? "unknown",
      styleGuessConfidence: typeof audit.styleGuessConfidence === "number" ? round(audit.styleGuessConfidence) : null,
      actualSourceType,
      actualAuthorshipType,
      actualStyleBand,
      sourceGuessMatches: actualSourceType !== "unknown" && audit.sourceGuess !== "unknown" ? audit.sourceGuess === actualSourceType : null,
      authorshipGuessMatches: actualAuthorshipType !== "unknown" && audit.authorshipGuess !== "unknown" ? audit.authorshipGuess === actualAuthorshipType : null,
      styleGuessMatches: actualStyleBand !== "unknown" && audit.styleGuess !== "unknown" ? audit.styleGuess === actualStyleBand : null,
      targetOverall: label?.weightedMeanScores?.overall ?? null,
      targetQualityBand: qualityBand(label?.weightedMeanScores?.overall),
    };
  });
  const preLockViolations = rows.filter((row) => !row.collectedAfterLock || row.shownBeforeInitialLock);
  const scoringUseViolations = rows.filter((row) => row.usedForScoring);
  const highConfidenceRows = rows.filter((row) => typeof row.styleGuessConfidence === "number" && row.styleGuessConfidence >= 0.75);
  const sourceAccuracy = matchRate(rows, "sourceGuessMatches");
  const authorshipAccuracy = matchRate(rows, "authorshipGuessMatches");
  const styleAccuracy = matchRate(rows, "styleGuessMatches");
  const highConfidenceSourceAccuracy = matchRate(highConfidenceRows, "sourceGuessMatches");
  const meanOverallByGuessedSource = summarizeNumericBy(rows, "sourceGuess", "targetOverall");
  const qualityMeanRange = meanRange(meanOverallByGuessedSource);
  const qualityAssociationStatus =
    Object.keys(meanOverallByGuessedSource).length < 2
      ? "insufficient_labelled_guess_groups"
      : qualityMeanRange >= 0.25
        ? "source_guess_quality_association_observed"
        : "no_large_source_guess_quality_association_observed";
  const residualUnblindingRisk = sourceStyleResidualRisk(preLockViolations, scoringUseViolations, highConfidenceRows, highConfidenceSourceAccuracy, qualityMeanRange);
  return {
    id: `post-lock-source-style-audit-${releaseId}`,
    releaseId,
    generatedAt: new Date().toISOString(),
    policy: {
      collectionPhase: "post_initial_lock_only",
      displayBeforeInitialLockAllowed: false,
      ordinaryRatingOrAdjudicationFeedbackAllowed: false,
      scoringUseAllowed: false,
      reportUse: "diagnose residual source/style artifacts and rater overreliance on source cues",
    },
    counts: {
      totalAudits: rows.length,
      postLockAudits: rows.filter((row) => row.collectionStatus === "post_lock").length,
      preLockViolationCount: preLockViolations.length,
      scoringUseViolationCount: scoringUseViolations.length,
      highConfidenceAuditCount: highConfidenceRows.length,
    },
    accuracySummary: {
      sourceGuess: sourceAccuracy,
      authorshipGuess: authorshipAccuracy,
      styleGuess: styleAccuracy,
      highConfidenceSourceGuess: highConfidenceSourceAccuracy,
    },
    bySplit: countBy(rows, "split"),
    byActualSourceType: countBy(rows, "actualSourceType"),
    byGuessedSource: countBy(rows, "sourceGuess"),
    byStyleGuess: countBy(rows, "styleGuess"),
    qualityCorrelationDiagnostic: {
      meanOverallByGuessedSource,
      meanOverallRange: qualityMeanRange,
      status: qualityAssociationStatus,
      caveat: "Associations are small-sample diagnostics, not evidence for label quality by source.",
    },
    residualUnblindingRisk,
    auditRows: rows,
    diagnosticOnly: true,
    releaseUseStatus:
      preLockViolations.length || scoringUseViolations.length
        ? "source_style_audit_policy_violation"
        : residualUnblindingRisk.status === "residual_unblinding_risk_disclose_counterbalance_or_carve_out"
          ? "residual_unblinding_disclosure_required"
          : "pass",
  };
}

export function buildCorrectnessVerificationReport(
  releaseId,
  ratings = seedRatings,
  positionList = positions,
  critiqueList = critiques,
  records = verificationRecords,
  evidenceArtifacts = buildEffectiveVerificationEvidenceArtifacts([], records),
) {
  const positionById = new Map(positionList.map((position) => [position.id, position]));
  const recordsByItem = records.reduce((acc, record) => {
    const itemId = makeItemId(record.positionId, record.critiqueId);
    acc[itemId] ??= [];
    acc[itemId].push(record);
    return acc;
  }, {});
  const evidenceArtifactsByItem = evidenceArtifacts.reduce((acc, artifact) => {
    const itemId = artifact.itemId ?? makeItemId(artifact.positionId, artifact.critiqueId);
    acc[itemId] ??= [];
    acc[itemId].push(artifact);
    return acc;
  }, {});
  const rows = critiqueList.map((critique) => {
    const position = positionById.get(critique.positionId);
    const itemId = makeItemId(critique.positionId, critique.id);
    const itemRatings = ratings.filter((rating) => rating.positionId === critique.positionId && rating.critiqueId === critique.id);
    const correctnessSpread = spread(itemRatings, "correctness");
    const requirementReasons = [];
    if (itemRatings.some((rating) => rating.flags?.needsVerification)) requirementReasons.push("rater_needs_verification_flag");
    if (correctnessSpread !== null && correctnessSpread > 0.35) requirementReasons.push("correctness_spread_above_0_35");
    const itemRecords = recordsByItem[itemId] ?? [];
    const latestRecord = latestVerificationRecord(itemRecords);
    const itemEvidenceArtifacts = evidenceArtifactsByItem[itemId] ?? [];
    const explicitEvidenceArtifactIds = new Set(latestRecord?.evidenceArtifactIds ?? []);
    const linkedEvidenceArtifacts = itemEvidenceArtifacts.filter((artifact) => {
      if (!latestRecord) return !artifact.verificationRecordId;
      if (explicitEvidenceArtifactIds.size) return explicitEvidenceArtifactIds.has(artifact.id);
      return artifact.verificationRecordId ? artifact.verificationRecordId === latestRecord.id : true;
    });
    const completeEvidenceArtifacts = linkedEvidenceArtifacts.filter((artifact) => artifact.reviewReasons.length === 0);
    const latestRecordNeedsEvidence = latestRecord && ["verified", "adjudication_resolved"].includes(latestRecord.verificationStatus);
    const evidenceProvenanceStatus =
      !latestRecord
        ? "not_applicable"
        : linkedEvidenceArtifacts.some((artifact) => artifact.reviewReasons.length)
          ? "verification_evidence_artifact_review_required"
          : latestRecordNeedsEvidence && !completeEvidenceArtifacts.length
            ? "verification_evidence_artifact_missing"
            : completeEvidenceArtifacts.length
              ? "verification_evidence_artifact_complete"
              : "not_applicable";
    const verificationStatus = latestRecord?.verificationStatus ?? (requirementReasons.length ? "missing" : "not_needed");
    const notPracticableResolved = verificationStatus === "not_practicable" && ["expert", "admin"].includes(latestRecord?.verifierRole);
    const resolved = !requirementReasons.length || ["verified", "not_needed"].includes(verificationStatus) || notPracticableResolved;
    const releaseCritical = ["public_train", "public_dev", "internal_validation", "hidden_benchmark"].includes(position?.split);
    const evidenceReleaseBlocking =
      releaseCritical &&
      latestRecordNeedsEvidence &&
      evidenceProvenanceStatus !== "verification_evidence_artifact_complete";
    return {
      itemHash: `sha256:${itemId}:verification`,
      itemId,
      split: position?.split ?? "unknown",
      positionId: critique.positionId,
      critiqueId: critique.id,
      verificationRequired: requirementReasons.length > 0,
      requirementReasons,
      correctnessSpread: correctnessSpread ?? null,
      linkedRecordCount: itemRecords.length,
      latestRecordHash: latestRecord ? `sha256:${latestRecord.id}:verification-record` : null,
      latestRecordId: latestRecord?.id ?? null,
      latestRecordSource: latestRecord?.recordSource ?? (latestRecord ? "seed_verification_record" : null),
      verificationStatus,
      verificationType: latestRecord?.verificationType ?? "not_applicable",
      verificationMaterials: latestRecord?.verificationMaterials ?? [],
      linkedEvidenceArtifactCount: linkedEvidenceArtifacts.length,
      completeEvidenceArtifactCount: completeEvidenceArtifacts.length,
      verificationEvidenceArtifactIds: linkedEvidenceArtifacts.map((artifact) => artifact.id),
      verificationEvidenceTypes: uniqueStrings(linkedEvidenceArtifacts.map((artifact) => artifact.evidenceType).filter(Boolean)),
      verificationEvidenceProvenanceStatus: evidenceProvenanceStatus,
      nonblindEvidenceFlag: linkedEvidenceArtifacts.some((artifact) => artifact.nonblindEvidenceFlag),
      sourceAssistedEvidenceFlag: linkedEvidenceArtifacts.some((artifact) => artifact.sourceAssistedFlag),
      protectedContentEvidenceFlag: linkedEvidenceArtifacts.some((artifact) => artifact.protectedContentFlag),
      modelAssistedEvidenceFlag: linkedEvidenceArtifacts.some((artifact) => artifact.modelAssistanceStatus && artifact.modelAssistanceStatus !== "none"),
      evidenceShownToOriginalRaterFlag: linkedEvidenceArtifacts.some((artifact) => artifact.shownToOriginalRater),
      evidenceShownToCheckerFlag: linkedEvidenceArtifacts.some((artifact) => artifact.shownToChecker),
      evidenceShownToAdjudicatorFlag: linkedEvidenceArtifacts.some((artifact) => artifact.shownToAdjudicator),
      confidence: latestRecord?.confidence ?? null,
      verifierRole: latestRecord?.verifierRole ?? null,
      exposureStatus: latestRecord?.exposureStatus ?? "not_applicable",
      timestamp: latestRecord?.timestamp ?? latestRecord?.createdAt ?? null,
      releaseBlocking: (requirementReasons.length > 0 && !resolved && releaseCritical) || evidenceReleaseBlocking,
      resultSummary: latestRecord?.verificationResult ?? (requirementReasons.length ? "Verification required but no linked VerificationRecord is resolved." : "No correctness-sensitive verification required."),
    };
  });
  const requiredRows = rows.filter((row) => row.verificationRequired);
  const releaseBlockingRows = rows.filter((row) => row.releaseBlocking);
  const evidenceReviewSections = evidenceArtifacts
    .filter((artifact) => artifact.reviewReasons.length)
    .flatMap((artifact) => artifact.reviewReasons.map((reason) => ({ artifactType: "verification_evidence_artifact", artifactId: artifact.id, reason })));
  const verificationEvidenceProvenanceSummary = buildVerificationEvidenceProvenanceSummary(evidenceArtifacts, evidenceReviewSections);
  return {
    id: `correctness-verification-${releaseId}`,
    releaseId,
    generatedAt: new Date().toISOString(),
    policy: {
      validStatuses: ["not_needed", "verified", "not_practicable", "unresolved"],
      requiredWhen: ["rater_needs_verification_flag", "correctness_spread_above_0_35"],
      releaseRule: "Correctness-sensitive benchmark, validation, or public-release items must be verified or explicitly marked not_practicable by an expert/admin adjudicator.",
      ratingPreservation: "Verification materials are linked records and do not overwrite blind initial ratings.",
      evidenceArtifactRule:
        "VerificationEvidenceArtifact rows preserve evidence type, citation/snapshot, retrieval time, source/protected/model-assistance exposure status, audience exposure, and nonblind/source-assisted flags.",
    },
    requiredItemCount: requiredRows.length,
    linkedRecordCount: records.length,
    linkedEvidenceArtifactCount: evidenceArtifacts.length,
    submittedEvidenceArtifactCount: evidenceArtifacts.filter((artifact) => artifact.rowSource === "submitted_workflow_verification_evidence_artifact").length,
    evidenceReviewSections,
    verificationEvidenceProvenanceSummary,
    unresolvedRequiredItems: requiredRows.filter((row) => ["missing", "unresolved"].includes(row.verificationStatus)),
    releaseBlockingItems: releaseBlockingRows,
    byVerificationStatus: countBy(rows, "verificationStatus"),
    byVerificationType: countBy(rows, "verificationType"),
    byExposureStatus: countBy(rows, "exposureStatus"),
    byEvidenceProvenanceStatus: countBy(rows, "verificationEvidenceProvenanceStatus"),
    verificationEvidenceArtifactRows: evidenceArtifacts,
    verificationRows: rows,
    releaseUseStatus: releaseBlockingRows.length || evidenceReviewSections.length ? "verification_review_required_before_benchmark_or_public_release" : "pass",
  };
}

export function buildHumanCeilingAndSaturationReport(
  releaseId,
  labelSnapshot,
  ratings = seedRatings,
  positionList = positions,
  critiqueList = critiques,
  runs = [fullRubricEvaluationRun],
  options = {},
) {
  const validationPositions = positionList.filter((position) => position.split === "internal_validation");
  const validationPositionIds = new Set(validationPositions.map((position) => position.id));
  const validationCritiques = critiqueList.filter((critique) => validationPositionIds.has(critique.positionId));
  const validationItemIds = validationCritiques.map((critique) => makeItemId(critique.positionId, critique.id)).sort();
  const validationRatings = ratings.filter((rating) => validationPositionIds.has(rating.positionId));
  const raterCoverageRows = buildRaterItemCoverageRows(validationRatings, validationItemIds);
  const commonOverlapItemIds = validationItemIds.filter(
    (itemId) => new Set(validationRatings.filter((rating) => makeItemId(rating.positionId, rating.critiqueId) === itemId).map((rating) => rating.raterId)).size >= 2,
  );
  const comparisonRows = ["blind_initial", "self_check", "expert_check", "model_assisted_check"].map((kind) =>
    humanCeilingComparisonRow(kind, validationRatings, labelSnapshot, validationItemIds),
  );
  const modelProximityRows = runs.map((run) => modelValidationProximityRow(run, labelSnapshot, validationItemIds));
  const validationDesign = buildValidationDesignReport(ratings, positionList, critiqueList, { humanCeilingRuns: options.humanCeilingRuns ?? [] });
  const thinValidation = validationDesign.status !== "appendix_c_scale";
  const submittedHumanCeilingUncertainty = buildSubmittedHumanCeilingUncertaintyEvidence(options.humanCeilingRuns ?? [], labelSnapshot);
  const activeSubmittedUncertaintyPolicy = submittedHumanCeilingUncertainty.activeRun?.uncertaintyPolicy ?? null;
  const benchmarkRefreshPolicyEvidence = buildBenchmarkRefreshPolicyEvidence(releaseId, options.benchmarkRefreshPolicies ?? []);
  const activeBenchmarkRefreshPolicy = benchmarkRefreshPolicyEvidence.activePolicy;
  const bestHumanMeanAbsOverallDiff = minValid(comparisonRows.map((row) => row.meanAbsOverallDiff));
  const closestModelMeanAbsOverallDiff = minValid(modelProximityRows.map((row) => row.meanAbsOverallDiff));
  const modelWithinHumanBand =
    bestHumanMeanAbsOverallDiff !== null &&
    closestModelMeanAbsOverallDiff !== null &&
    closestModelMeanAbsOverallDiff <= bestHumanMeanAbsOverallDiff + 0.02;
  const saturationStatus = thinValidation
    ? "not_assessable_thin_validation"
    : modelWithinHumanBand
      ? "saturation_risk_refresh_required"
      : "no_saturation_signal_current_release";
  const refreshCadenceDays = activeBenchmarkRefreshPolicy?.cadenceDaysBySaturationStatus?.[saturationStatus] ?? null;
  const refreshQueue = buildSaturationRefreshQueue(labelSnapshot, positionList, critiqueList).map((row) => ({
    ...row,
    benchmarkRefreshPolicyId: activeBenchmarkRefreshPolicy?.id ?? null,
    refreshCadenceDays,
    requiredQueueFields: activeBenchmarkRefreshPolicy?.requiredQueueFields ?? [],
  }));
  return {
    id: `human-ceiling-saturation-${releaseId}`,
    releaseId,
    targetLabelSnapshotId: labelSnapshot.id,
    targetLabelVersion: labelSnapshot.targetLabelVersion,
    validationScope: {
      split: "internal_validation",
      validationPositionCount: validationPositions.length,
      validationCritiqueCount: validationCritiques.length,
      validationItemIds,
      appendixCScaleStatus: validationDesign.status,
      submittedValidationEvidence: validationDesign.submittedValidationEvidence,
    },
    finalAverageApproximationPolicy:
      "Final-average labels are an approximation target for validation diagnostics, not literal ground truth or a substitute for blind initial ratings.",
    appendixCNumericBaselineComparison: {
      source: "LMCA Appendix C validation and human-ceiling numeric baselines",
      currentValidationStatus: validationDesign.status,
      appendixCScaleMet: validationDesign.status === "appendix_c_scale",
      baselineFamilies: Object.keys(LMCA_BASELINES.appendixCNumericBaselines),
      numericBaselines: LMCA_BASELINES.appendixCNumericBaselines,
      releaseUseStatus:
        validationDesign.status === "appendix_c_scale"
          ? "appendix_c_numeric_baselines_attached_to_human_ceiling_report"
          : "appendix_c_numeric_baselines_attached_thin_validation_disclosed",
      policy:
        "Human-ceiling and validation claims must interpret current rater/model distances against LMCA Appendix C numeric anchors while preserving thinner-than-Appendix-C labeling when the validation floor is missed.",
    },
    raterItemCoverage: {
      rows: raterCoverageRows,
      commonOverlapItemIds,
      fullCoverageRaterIds: raterCoverageRows.filter((row) => row.coveredItemCount === validationItemIds.length && validationItemIds.length > 0).map((row) => row.raterId),
      partialCoverageRaterIds: raterCoverageRows.filter((row) => row.coveredItemCount > 0 && row.coveredItemCount < validationItemIds.length).map((row) => row.raterId),
    },
    comparisonRows,
    checkSeparation: {
      selfCheckRows: comparisonRows.find((row) => row.ratingKind === "self_check")?.rowCount ?? 0,
      expertCheckRows: comparisonRows.find((row) => row.ratingKind === "expert_check")?.rowCount ?? 0,
      modelAssistedCheckRows: comparisonRows.find((row) => row.ratingKind === "model_assisted_check")?.rowCount ?? 0,
      modelAssistedTreatedAsIndependentHuman: false,
      incrementalModelAssistanceStatus:
        (comparisonRows.find((row) => row.ratingKind === "model_assisted_check")?.rowCount ?? 0) > 0
          ? "model_assisted_delta_report_required"
          : "no_model_assisted_checks_in_seed",
    },
    modelProximityRows,
    submittedHumanCeilingRuns: options.humanCeilingRuns ?? [],
    submittedHumanCeilingUncertainty,
    benchmarkRefreshPolicyEvidence,
    uncertaintyPolicy:
      activeSubmittedUncertaintyPolicy ?? {
        intervalType: "descriptive_seed_no_interval",
        nominalLevel: null,
        constructionMethod: "not_computed_until_appendix_c_scale_or_bootstrap_sample_available",
        resamplingUnit: "item",
        resampleCountOrDegreesOfFreedom: 0,
        randomSeedOrArtifact: "not_applicable_seed_demo",
        intervalComparisonScope: "not_applicable_seed_demo",
      },
    saturationRisk: {
      bestHumanMeanAbsOverallDiff,
      closestModelMeanAbsOverallDiff,
      modelWithinHumanBand,
      status: saturationStatus,
      benchmarkRefreshPolicyId: activeBenchmarkRefreshPolicy?.id ?? null,
      refreshCadenceDays,
      requiredRefreshActions: activeBenchmarkRefreshPolicy?.requiredRefreshActions ?? [],
      releaseUsePolicy:
        "Do not make human-ceiling or saturation claims unless the validation design is Appendix-C-scale or explicitly labeled thinner with reduced claim strength.",
    },
    refreshQueue,
    releaseUseStatus: benchmarkRefreshPolicyEvidence.reviewRows.length
      ? "benchmark_refresh_policy_review_required"
      : thinValidation
      ? "human_ceiling_claims_blocked_thinner_than_appendix_c"
      : submittedHumanCeilingUncertainty.activeRun
        ? "human_ceiling_claims_allowed_with_declared_uncertainty"
        : "human_ceiling_uncertainty_provenance_required",
  };
}

function buildSubmittedHumanCeilingUncertaintyEvidence(humanCeilingRuns = [], labelSnapshot) {
  const rows = humanCeilingRuns.map((run) => normalizeSubmittedHumanCeilingUncertaintyRow(run, labelSnapshot)).filter(Boolean);
  const completeRows = rows.filter((row) => row.status === "human_ceiling_uncertainty_provenance_complete");
  const activeRun = completeRows[0] ?? null;
  return {
    rows,
    activeRun,
    activeRunId: activeRun?.id ?? null,
    rowCount: rows.length,
    completeRunCount: completeRows.length,
    reviewRequiredCount: rows.length - completeRows.length,
    status: activeRun
      ? "submitted_human_ceiling_uncertainty_complete"
      : rows.length
        ? "submitted_human_ceiling_uncertainty_review_required"
        : "no_submitted_human_ceiling_uncertainty",
  };
}

export const BENCHMARK_REFRESH_POLICY_VERSION = "benchmark-refresh-cadence-rlhf90-v1";
export const REQUIRED_BENCHMARK_REFRESH_CADENCE_DAYS_BY_STATUS = {
  saturation_risk_refresh_required: 30,
  not_assessable_thin_validation: 90,
  no_saturation_signal_current_release: 180,
};
export const REQUIRED_BENCHMARK_REFRESH_ACTIONS = [
  "double_rate",
  "expert_double_check",
  "adjudicate_or_preserve_disagreement",
  "harder_or_obfuscated_item",
];
export const REQUIRED_BENCHMARK_REFRESH_QUEUE_FIELDS = [
  "itemId",
  "split",
  "topicFamily",
  "priorityScore",
  "refreshActions",
];
export const REQUIRED_BENCHMARK_REFRESH_POLICY_RULES = {
  saturationCadence:
    "Saturation-risk releases require a governed benchmark refresh plan within 30 days before stronger hidden-benchmark progress claims continue.",
  thinValidationCadence:
    "Thin validation requires a 90-day refresh or validation-floor remediation review before human-ceiling or saturation claims are strengthened.",
  maintenanceCadence:
    "No-saturation releases still receive a 180-day benchmark maintenance review so hidden benchmark freeze is not treated as permanent.",
  refreshActionMinimum:
    "Refresh queues must prioritize double rating, expert double-checking, adjudication or preserved disagreement, and harder or obfuscated item replenishment.",
  protectedSplitGovernance:
    "Protected validation and hidden-benchmark refresh candidates require split-governed review before any item is deprotected, replaced, or added to headline denominators.",
  claimSuppression:
    "Unsupported saturation, human-ceiling, or progress claims remain suppressed until the active benchmark refresh policy is satisfied or a diagnostic deferral records the weaker claim.",
};

function defaultBenchmarkRefreshPolicy(releaseId = "october-2026-demo") {
  return {
    id: `benchmark-refresh-policy-${releaseId}`,
    policyVersion: BENCHMARK_REFRESH_POLICY_VERSION,
    cadenceDaysBySaturationStatus: REQUIRED_BENCHMARK_REFRESH_CADENCE_DAYS_BY_STATUS,
    requiredRefreshActions: REQUIRED_BENCHMARK_REFRESH_ACTIONS,
    requiredQueueFields: REQUIRED_BENCHMARK_REFRESH_QUEUE_FIELDS,
    policyRules: REQUIRED_BENCHMARK_REFRESH_POLICY_RULES,
    saturationCadenceRule: REQUIRED_BENCHMARK_REFRESH_POLICY_RULES.saturationCadence,
    thinValidationCadenceRule: REQUIRED_BENCHMARK_REFRESH_POLICY_RULES.thinValidationCadence,
    maintenanceCadenceRule: REQUIRED_BENCHMARK_REFRESH_POLICY_RULES.maintenanceCadence,
    refreshActionMinimumRule: REQUIRED_BENCHMARK_REFRESH_POLICY_RULES.refreshActionMinimum,
    protectedSplitGovernanceRule: REQUIRED_BENCHMARK_REFRESH_POLICY_RULES.protectedSplitGovernance,
    claimSuppressionRule: REQUIRED_BENCHMARK_REFRESH_POLICY_RULES.claimSuppression,
    sourceBoundary:
      "Project default benchmark-refresh cadence is frozen here; LMCA motivates saturation response but does not state exact refresh timing.",
    frozenAt: "2026-10-01T00:00:00.000Z",
  };
}

function normalizeBenchmarkRefreshPolicy(policy, rowSource) {
  const id = policy?.id ?? policy?.benchmarkRefreshPolicyId ?? policy?.benchmark_refresh_policy_id;
  if (!id) return null;
  const cadenceDaysBySaturationStatus =
    policy.cadenceDaysBySaturationStatus && typeof policy.cadenceDaysBySaturationStatus === "object" && !Array.isArray(policy.cadenceDaysBySaturationStatus)
      ? policy.cadenceDaysBySaturationStatus
      : {};
  const requiredRefreshActions = uniqueStrings(normalizeStringArray(policy.requiredRefreshActions ?? policy.refreshActions));
  const requiredQueueFields = uniqueStrings(normalizeStringArray(policy.requiredQueueFields ?? policy.queueFields));
  const policyRules =
    policy.policyRules && typeof policy.policyRules === "object" && !Array.isArray(policy.policyRules) ? policy.policyRules : {};
  const missingCadenceStatuses = Object.keys(REQUIRED_BENCHMARK_REFRESH_CADENCE_DAYS_BY_STATUS).filter(
    (status) => !Object.hasOwn(cadenceDaysBySaturationStatus, status),
  );
  const missingRefreshActions = REQUIRED_BENCHMARK_REFRESH_ACTIONS.filter((action) => !requiredRefreshActions.includes(action));
  const missingQueueFields = REQUIRED_BENCHMARK_REFRESH_QUEUE_FIELDS.filter((field) => !requiredQueueFields.includes(field));
  const missingRuleKeys = Object.keys(REQUIRED_BENCHMARK_REFRESH_POLICY_RULES).filter((key) => !Object.hasOwn(policyRules, key));
  const reviewReasons = [
    (policy.policyVersion ?? policy.version) === BENCHMARK_REFRESH_POLICY_VERSION
      ? null
      : `policyVersion:${BENCHMARK_REFRESH_POLICY_VERSION}`,
    missingCadenceStatuses.length ? `cadenceDaysBySaturationStatus:${missingCadenceStatuses.join(",")}` : null,
    stableJsonKey(cadenceDaysBySaturationStatus) === stableJsonKey(REQUIRED_BENCHMARK_REFRESH_CADENCE_DAYS_BY_STATUS)
      ? null
      : "cadenceDaysBySaturationStatus",
    missingRefreshActions.length ? `requiredRefreshActions:${missingRefreshActions.join(",")}` : null,
    stableJsonKey(requiredRefreshActions) === stableJsonKey(REQUIRED_BENCHMARK_REFRESH_ACTIONS) ? null : "requiredRefreshActions",
    missingQueueFields.length ? `requiredQueueFields:${missingQueueFields.join(",")}` : null,
    stableJsonKey(requiredQueueFields) === stableJsonKey(REQUIRED_BENCHMARK_REFRESH_QUEUE_FIELDS) ? null : "requiredQueueFields",
    missingRuleKeys.length ? `policyRules:${missingRuleKeys.join(",")}` : null,
    stableJsonKey(policyRules) === stableJsonKey(REQUIRED_BENCHMARK_REFRESH_POLICY_RULES) ? null : "policyRules",
    policyMentions(policy.saturationCadenceRule ?? policyRules.saturationCadence, ["saturation-risk", "30 days", "benchmark refresh"])
      ? null
      : "saturationCadenceRule",
    policyMentions(policy.thinValidationCadenceRule ?? policyRules.thinValidationCadence, ["thin validation", "90-day", "human-ceiling"])
      ? null
      : "thinValidationCadenceRule",
    policyMentions(policy.maintenanceCadenceRule ?? policyRules.maintenanceCadence, ["no-saturation", "180-day", "maintenance"])
      ? null
      : "maintenanceCadenceRule",
    policyMentions(policy.refreshActionMinimumRule ?? policyRules.refreshActionMinimum, ["double rating", "expert double-checking", "harder"])
      ? null
      : "refreshActionMinimumRule",
    policyMentions(policy.protectedSplitGovernanceRule ?? policyRules.protectedSplitGovernance, ["protected validation", "hidden-benchmark", "governed"])
      ? null
      : "protectedSplitGovernanceRule",
    policyMentions(policy.claimSuppressionRule ?? policyRules.claimSuppression, ["claims", "suppressed", "diagnostic deferral"])
      ? null
      : "claimSuppressionRule",
    policyMentions(policy.sourceBoundary, ["project default", "lmca", "does not state"]) ? null : "sourceBoundary",
    requiredPromptFieldReason("frozenAt", policy.frozenAt),
  ].filter(Boolean);
  return {
    id,
    rowSource,
    policyVersion: policy.policyVersion ?? policy.version ?? null,
    cadenceDaysBySaturationStatus,
    requiredRefreshActions,
    requiredQueueFields,
    policyRules,
    saturationCadenceRule: policy.saturationCadenceRule ?? policyRules.saturationCadence ?? null,
    thinValidationCadenceRule: policy.thinValidationCadenceRule ?? policyRules.thinValidationCadence ?? null,
    maintenanceCadenceRule: policy.maintenanceCadenceRule ?? policyRules.maintenanceCadence ?? null,
    refreshActionMinimumRule: policy.refreshActionMinimumRule ?? policyRules.refreshActionMinimum ?? null,
    protectedSplitGovernanceRule: policy.protectedSplitGovernanceRule ?? policyRules.protectedSplitGovernance ?? null,
    claimSuppressionRule: policy.claimSuppressionRule ?? policyRules.claimSuppression ?? null,
    sourceBoundary: policy.sourceBoundary ?? null,
    frozenAt: policy.frozenAt ?? null,
    reviewReasons,
    status: reviewReasons.length ? "benchmark_refresh_policy_review_required" : "benchmark_refresh_policy_complete",
  };
}

function buildBenchmarkRefreshPolicyEvidence(releaseId, submittedPolicies = []) {
  const submittedRows = submittedPolicies
    .map((policy) => normalizeBenchmarkRefreshPolicy(policy, "submitted_workflow_benchmark_refresh_policy"))
    .filter(Boolean);
  const seedRows = [normalizeBenchmarkRefreshPolicy(defaultBenchmarkRefreshPolicy(releaseId), "seed_benchmark_refresh_policy")];
  const activePolicy = submittedRows.find((row) => row.reviewReasons.length === 0) ?? seedRows[0];
  const reviewRows = submittedRows.filter((row) => row.reviewReasons.length);
  return {
    id: `benchmark-refresh-policy-evidence-${releaseId}`,
    releaseId,
    requiredCadenceDaysBySaturationStatus: REQUIRED_BENCHMARK_REFRESH_CADENCE_DAYS_BY_STATUS,
    requiredRefreshActions: REQUIRED_BENCHMARK_REFRESH_ACTIONS,
    requiredQueueFields: REQUIRED_BENCHMARK_REFRESH_QUEUE_FIELDS,
    requiredPolicyRules: REQUIRED_BENCHMARK_REFRESH_POLICY_RULES,
    policyRows: [...seedRows, ...submittedRows],
    activePolicy,
    activePolicyId: activePolicy?.id ?? null,
    reviewRows,
    counts: {
      submittedPolicyCount: submittedRows.length,
      reviewRequiredPolicyCount: reviewRows.length,
    },
    releaseUseStatus: !submittedRows.length
      ? "seed_benchmark_refresh_policy_active"
      : reviewRows.length
        ? "submitted_benchmark_refresh_policy_review_required"
        : "submitted_benchmark_refresh_policy_active",
  };
}

function normalizeSubmittedHumanCeilingUncertaintyRow(run, labelSnapshot) {
  const id = run?.id ?? run?.humanCeilingRunId ?? run?.human_ceiling_run_id;
  if (!id) return null;
  const policySource = run.uncertaintyPolicy ?? run.uncertainty ?? {};
  const intervalLevel = Number(
    run.intervalLevel ??
      run.nominalLevel ??
      run.confidenceLevel ??
      run.confidenceOrCredibleIntervalLevel ??
      policySource.intervalLevel ??
      policySource.nominalLevel ??
      policySource.confidenceLevel ??
      policySource.confidenceOrCredibleIntervalLevel,
  );
  const resampleCountOrDegreesOfFreedom = Number(
    run.resampleCountOrDegreesOfFreedom ??
      run.resampleCount ??
      run.analyticDegreesOfFreedom ??
      policySource.resampleCountOrDegreesOfFreedom ??
      policySource.resampleCount ??
      policySource.analyticDegreesOfFreedom,
  );
  const uncertaintyPolicy = {
    uncertaintyMethod: run.uncertaintyMethod ?? policySource.uncertaintyMethod ?? policySource.method ?? null,
    intervalType: run.intervalType ?? run.uncertaintyIntervalType ?? policySource.intervalType ?? policySource.uncertaintyIntervalType ?? null,
    nominalLevel: Number.isFinite(intervalLevel) ? intervalLevel : null,
    constructionMethod: run.intervalConstructionMethod ?? run.constructionMethod ?? policySource.intervalConstructionMethod ?? policySource.constructionMethod ?? null,
    resamplingUnit: run.resamplingUnit ?? policySource.resamplingUnit ?? null,
    resampleCountOrDegreesOfFreedom: Number.isFinite(resampleCountOrDegreesOfFreedom) ? resampleCountOrDegreesOfFreedom : null,
    randomSeedOrArtifact:
      run.randomSeedOrArtifact ??
      run.randomSeed ??
      run.randomSeedOrResamplingArtifact ??
      run.reproducibilityArtifact ??
      policySource.randomSeedOrArtifact ??
      policySource.randomSeed ??
      policySource.randomSeedOrResamplingArtifact ??
      policySource.reproducibilityArtifact ??
      null,
    intervalComparisonScope:
      run.intervalComparisonScope ??
      run.pairedVsIndependentIntervalPolicy ??
      policySource.intervalComparisonScope ??
      policySource.pairedVsIndependentIntervalPolicy ??
      null,
  };
  const targetLabelSnapshotId = run.targetLabelSnapshotId ?? run.labelSnapshotId ?? null;
  const reviewReasons = [
    targetLabelSnapshotId === labelSnapshot.id ? null : "targetLabelSnapshotId",
    requiredPromptFieldReason("uncertaintyMethod", uncertaintyPolicy.uncertaintyMethod),
    requiredPromptFieldReason("intervalType", uncertaintyPolicy.intervalType),
    Number.isFinite(uncertaintyPolicy.nominalLevel) && uncertaintyPolicy.nominalLevel > 0 && uncertaintyPolicy.nominalLevel < 1
      ? null
      : "intervalLevel",
    requiredPromptFieldReason("intervalConstructionMethod", uncertaintyPolicy.constructionMethod),
    requiredPromptFieldReason("resamplingUnit", uncertaintyPolicy.resamplingUnit),
    Number.isFinite(uncertaintyPolicy.resampleCountOrDegreesOfFreedom) && uncertaintyPolicy.resampleCountOrDegreesOfFreedom > 0
      ? null
      : "resampleCountOrDegreesOfFreedom",
    requiredPromptFieldReason("randomSeedOrArtifact", uncertaintyPolicy.randomSeedOrArtifact),
    requiredPromptFieldReason("intervalComparisonScope", uncertaintyPolicy.intervalComparisonScope),
  ].filter(Boolean);
  return {
    id,
    targetLabelSnapshotId,
    uncertaintyPolicy,
    reviewReasons,
    status: reviewReasons.length ? "human_ceiling_uncertainty_provenance_review_required" : "human_ceiling_uncertainty_provenance_complete",
  };
}

const SAME_POSITION_CONTEXT_RELEASE_CRITICAL_QUEUE_TYPES = new Set([
  "validation",
  "validation_subset",
  "internal_validation",
  "protected_validation",
  "benchmark_candidate_review",
  "hidden_benchmark",
  "hidden_benchmark_review",
  "gold_certification",
  "release_critical",
  "release_review",
]);

export const MODEL_PROMPT_SIBLING_CONTEXT_POLICY_VERSION = "model-prompt-sibling-context-rlhf90-v1";
export const REQUIRED_MODEL_PROMPT_SIBLING_CONTEXT_MODES = [
  "match_human_frozen_context",
  "target_only_restricted_snapshot",
  "paired_context_sensitivity_run",
];
export const REQUIRED_MODEL_PROMPT_SIBLING_CONTEXT_EVIDENCE_FIELDS = [
  "ratingContextSnapshotId",
  "visibleCritiqueIds",
  "priorSiblingCritiqueIds",
  "laterSiblingCritiqueIdsAbsentAtSubmission",
  "orderIndexByCritiqueId",
  "modelPredictionRatingContextSnapshotId",
];
export const REQUIRED_MODEL_PROMPT_SIBLING_CONTEXT_RULES = {
  sequentialHumanRatings:
    "When human ratings used sequential same-position sibling context, clean model comparisons must bind model predictions to the same frozen RatingContextSnapshot or to a declared target-only restricted snapshot.",
  laterSiblingHandling:
    "Later-added same-position sibling critiques absent from the human RatingContextSnapshot are excluded from the model prompt unless a paired context-sensitivity run is labeled separately.",
  contextSensitiveClaim:
    "Context-sensitive labels require matching model-prompt sibling-context evidence before clean leaderboard claims or must be restricted to a target-only snapshot.",
  targetOnlyRestriction:
    "Target-only model prompts may support clean claims only against target-only or restricted target-label snapshots, not against sibling-context-sensitive labels.",
  sourceBoundary:
    "Project default model-prompt sibling-context rules are frozen here; LMCA motivates same-position context preservation but does not state exact model-prompt sibling policy.",
};

function defaultModelPromptSiblingContextPolicy(releaseId) {
  return {
    id: `model-prompt-sibling-context-policy-${releaseId}`,
    policyVersion: MODEL_PROMPT_SIBLING_CONTEXT_POLICY_VERSION,
    allowedComparisonModes: REQUIRED_MODEL_PROMPT_SIBLING_CONTEXT_MODES,
    requiredEvidenceFields: REQUIRED_MODEL_PROMPT_SIBLING_CONTEXT_EVIDENCE_FIELDS,
    policyRules: REQUIRED_MODEL_PROMPT_SIBLING_CONTEXT_RULES,
    sequentialHumanRatingsRule: REQUIRED_MODEL_PROMPT_SIBLING_CONTEXT_RULES.sequentialHumanRatings,
    laterSiblingHandlingRule: REQUIRED_MODEL_PROMPT_SIBLING_CONTEXT_RULES.laterSiblingHandling,
    contextSensitiveClaimRule: REQUIRED_MODEL_PROMPT_SIBLING_CONTEXT_RULES.contextSensitiveClaim,
    targetOnlyRestrictionRule: REQUIRED_MODEL_PROMPT_SIBLING_CONTEXT_RULES.targetOnlyRestriction,
    sourceBoundary: REQUIRED_MODEL_PROMPT_SIBLING_CONTEXT_RULES.sourceBoundary,
    frozenAt: "2026-10-01T00:00:00.000Z",
  };
}

function normalizeModelPromptSiblingContextPolicy(policy, rowSource) {
  const id = policy?.id ?? policy?.modelPromptSiblingContextPolicyId ?? policy?.model_prompt_sibling_context_policy_id;
  if (!id) return null;
  const policyRules = policy.policyRules && typeof policy.policyRules === "object" && !Array.isArray(policy.policyRules) ? policy.policyRules : {};
  const allowedComparisonModes = normalizeStringArray(policy.allowedComparisonModes);
  const requiredEvidenceFields = normalizeStringArray(policy.requiredEvidenceFields);
  const missingRuleKeys = Object.keys(REQUIRED_MODEL_PROMPT_SIBLING_CONTEXT_RULES).filter((key) => !Object.hasOwn(policyRules, key));
  const reviewReasons = [
    policy.policyVersion === MODEL_PROMPT_SIBLING_CONTEXT_POLICY_VERSION ? null : "policyVersion",
    REQUIRED_MODEL_PROMPT_SIBLING_CONTEXT_MODES.every((mode) => allowedComparisonModes.includes(mode)) ? null : "allowedComparisonModes",
    allowedComparisonModes.every((mode) => REQUIRED_MODEL_PROMPT_SIBLING_CONTEXT_MODES.includes(mode)) ? null : "allowedComparisonModes:unsupported",
    REQUIRED_MODEL_PROMPT_SIBLING_CONTEXT_EVIDENCE_FIELDS.every((field) => requiredEvidenceFields.includes(field)) ? null : "requiredEvidenceFields",
    requiredEvidenceFields.every((field) => REQUIRED_MODEL_PROMPT_SIBLING_CONTEXT_EVIDENCE_FIELDS.includes(field))
      ? null
      : "requiredEvidenceFields:unsupported",
    missingRuleKeys.length ? `policyRules:${missingRuleKeys.join(",")}` : null,
    stableJsonKey(policyRules) === stableJsonKey(REQUIRED_MODEL_PROMPT_SIBLING_CONTEXT_RULES) ? null : "policyRules",
    policyMentions(policy.sequentialHumanRatingsRule, ["same-position", "ratingcontextsnapshot"]) ? null : "sequentialHumanRatingsRule",
    policyMentions(policy.laterSiblingHandlingRule, ["later-added", "absent"]) ? null : "laterSiblingHandlingRule",
    policyMentions(policy.contextSensitiveClaimRule, ["context-sensitive", "model-prompt"]) ? null : "contextSensitiveClaimRule",
    policyMentions(policy.targetOnlyRestrictionRule, ["target-only", "sibling-context-sensitive"]) ? null : "targetOnlyRestrictionRule",
    policyMentions(policy.sourceBoundary, ["project", "lmca"]) ? null : "sourceBoundary",
    requiredPromptFieldReason("frozenAt", policy.frozenAt ?? policy.frozen_at),
  ].filter(Boolean);
  return {
    id,
    rowSource,
    policyVersion: policy.policyVersion ?? policy.policy_version ?? null,
    allowedComparisonModes,
    requiredEvidenceFields,
    policyRules,
    sequentialHumanRatingsRule: policy.sequentialHumanRatingsRule ?? policy.sequential_human_ratings_rule ?? null,
    laterSiblingHandlingRule: policy.laterSiblingHandlingRule ?? policy.later_sibling_handling_rule ?? null,
    contextSensitiveClaimRule: policy.contextSensitiveClaimRule ?? policy.context_sensitive_claim_rule ?? null,
    targetOnlyRestrictionRule: policy.targetOnlyRestrictionRule ?? policy.target_only_restriction_rule ?? null,
    sourceBoundary: policy.sourceBoundary ?? policy.source_boundary ?? null,
    frozenAt: policy.frozenAt ?? policy.frozen_at ?? null,
    reviewReasons,
    status: reviewReasons.length ? "model_prompt_sibling_context_policy_review_required" : "model_prompt_sibling_context_policy_complete",
  };
}

function buildModelPromptSiblingContextPolicyEvidence(releaseId, submittedPolicies = []) {
  const submittedRows = submittedPolicies
    .map((policy) => normalizeModelPromptSiblingContextPolicy(policy, "submitted_workflow_model_prompt_sibling_context_policy"))
    .filter(Boolean);
  const seedRow = normalizeModelPromptSiblingContextPolicy(
    defaultModelPromptSiblingContextPolicy(releaseId),
    "seed_model_prompt_sibling_context_policy",
  );
  const activeSubmittedPolicy = submittedRows.find((row) => row.reviewReasons.length === 0) ?? null;
  const reviewRows = submittedRows.filter((row) => row.reviewReasons.length > 0);
  const activePolicy = activeSubmittedPolicy ?? seedRow;
  return {
    id: `model-prompt-sibling-context-policy-evidence-${releaseId}`,
    releaseId,
    requiredComparisonModes: REQUIRED_MODEL_PROMPT_SIBLING_CONTEXT_MODES,
    requiredEvidenceFields: REQUIRED_MODEL_PROMPT_SIBLING_CONTEXT_EVIDENCE_FIELDS,
    requiredPolicyRules: REQUIRED_MODEL_PROMPT_SIBLING_CONTEXT_RULES,
    policyRows: [seedRow, ...submittedRows],
    activePolicy,
    activePolicyId: activePolicy?.id ?? null,
    reviewRows,
    releaseUseStatus: activeSubmittedPolicy
      ? "submitted_model_prompt_sibling_context_policy_active"
      : reviewRows.length
        ? "submitted_model_prompt_sibling_context_policy_review_required"
        : "seed_model_prompt_sibling_context_policy_active",
  };
}

function isSamePositionContextReleaseCriticalQueue(queueType) {
  return SAME_POSITION_CONTEXT_RELEASE_CRITICAL_QUEUE_TYPES.has(queueType);
}

export function buildSamePositionContextReport(
  releaseId,
  ratings = seedRatings,
  positionList = positions,
  critiqueList = critiques,
  contextSnapshots = ratingContextSnapshots,
  assignmentList = assignments,
  options = {},
) {
  const positionById = new Map(positionList.map((position) => [position.id, position]));
  const assignmentById = new Map(assignmentList.map((assignment) => [assignment.id, assignment]));
  const snapshotById = new Map(contextSnapshots.map((snapshot) => [snapshot.id, snapshot]));
  const modelPromptSiblingContextPolicyEvidence = buildModelPromptSiblingContextPolicyEvidence(
    releaseId,
    options.modelPromptSiblingContextPolicies ?? [],
  );
  const activeModelPromptSiblingContextPolicy = modelPromptSiblingContextPolicyEvidence.activePolicy;
  const predictionRowsByItem = (options.modelEvaluationPredictions ?? []).reduce((acc, prediction) => {
    const itemId = makeItemId(prediction.positionId, prediction.critiqueId);
    acc[itemId] ??= [];
    acc[itemId].push(prediction);
    return acc;
  }, {});
  const critiqueIdsByPosition = critiqueList.reduce((acc, critique) => {
    acc[critique.positionId] ??= [];
    acc[critique.positionId].push(critique.id);
    return acc;
  }, {});
  const rows = ratings.map((rating) => {
    const itemId = makeItemId(rating.positionId, rating.critiqueId);
    const position = positionById.get(rating.positionId);
    const assignment = assignmentById.get(rating.assignmentId);
    const assignmentQueueType = assignment?.queueType ?? assignment?.assignmentType ?? "unknown";
    const snapshot = snapshotById.get(rating.ratingContextSnapshotId);
    const allCritiqueIds = critiqueIdsByPosition[rating.positionId] ?? [];
    const siblingCritiqueIds = allCritiqueIds.filter((id) => id !== rating.critiqueId);
    const visibleCritiqueIds = snapshot?.visibleCritiqueIds ?? [];
    const visibleSet = new Set(visibleCritiqueIds);
    const orderIndex = snapshot?.orderIndexByCritiqueId ?? {};
    const currentOrderIndex = orderIndex[rating.critiqueId];
    const visibleSiblingCritiqueIds = siblingCritiqueIds.filter((id) => visibleSet.has(id));
    const priorSiblingCritiqueIds = Number.isInteger(currentOrderIndex)
      ? visibleSiblingCritiqueIds.filter((id) => Number.isInteger(orderIndex[id]) && orderIndex[id] < currentOrderIndex)
      : snapshot?.priorSiblingCritiqueIds ?? [];
    const laterVisibleSiblingCritiqueIds = Number.isInteger(currentOrderIndex)
      ? visibleSiblingCritiqueIds.filter((id) => Number.isInteger(orderIndex[id]) && orderIndex[id] > currentOrderIndex)
      : [];
    const absentSiblingCritiqueIds = uniqueStrings([
      ...siblingCritiqueIds.filter((id) => !visibleSet.has(id)),
      ...(snapshot?.laterSiblingCritiqueIdsAbsentAtSubmission ?? []),
    ]);
    const releaseCritical = isReleaseCriticalSplit(position?.split) || isSamePositionContextReleaseCriticalQueue(assignmentQueueType);
    const currentCritiqueVisible = visibleSet.has(rating.critiqueId);
    const humanModelParityStatus = snapshot?.humanModelParityStatus ?? "missing_context_snapshot";
    const contextSensitive = visibleSiblingCritiqueIds.length > 0 || humanModelParityStatus.includes("context_sensitive");
    const orderPolicyStatus = !snapshot
      ? "missing_context_snapshot"
      : !releaseCritical
        ? "not_release_critical"
        : snapshot.orderPolicy.includes("counterbalanced")
          ? "counterbalanced"
          : "fixed_or_target_only_order_disclosed";
    const modelContextPredictionIds = (predictionRowsByItem[itemId] ?? [])
      .filter((prediction) => prediction.ratingContextSnapshotId === rating.ratingContextSnapshotId)
      .map((prediction) => prediction.id)
      .filter(Boolean);
    const modelContextParityEvidenceStatus = !contextSensitive
      ? "not_required"
      : modelContextPredictionIds.length
        ? "model_prompt_context_matches_frozen_rating_context"
        : "model_prompt_context_parity_evidence_missing";
    return {
      ratingHash: `sha256:${rating.id}:same-position-context`,
      ratingId: rating.id,
      itemId,
      positionId: rating.positionId,
      critiqueId: rating.critiqueId,
      itemHash: `sha256:${itemId}:same-position-context`,
      split: position?.split ?? "unknown",
      queueType: assignmentQueueType,
      ratingContextSnapshotId: rating.ratingContextSnapshotId,
      contextSnapshotFrozen: Boolean(snapshot?.frozenAt),
      currentCritiqueVisible,
      modelPromptSiblingContextPolicyId: activeModelPromptSiblingContextPolicy?.id ?? null,
      policy: snapshot?.policy ?? "missing_context_snapshot",
      orderPolicy: snapshot?.orderPolicy ?? "missing_context_snapshot",
      orderPolicyStatus,
      siblingExposurePattern: snapshot?.siblingExposurePattern ?? "missing_context_snapshot",
      visibleSiblingCritiqueIds,
      priorSiblingCritiqueIds,
      laterVisibleSiblingCritiqueIds,
      absentSiblingCritiqueIds,
      releaseCritical,
      humanModelParityStatus,
      contextSensitive,
      modelContextPredictionIds,
      modelContextParityEvidenceStatus,
      cleanModelPromptRequirement: contextSensitive
        ? (activeModelPromptSiblingContextPolicy?.contextSensitiveClaimRule ?? REQUIRED_MODEL_PROMPT_SIBLING_CONTEXT_RULES.contextSensitiveClaim)
        : "target_only_context_is_matchable",
    };
  });
  const missingContextRows = rows.filter((row) => row.policy === "missing_context_snapshot");
  const currentCritiqueVisibilityViolations = rows.filter((row) => !row.currentCritiqueVisible);
  const contextSensitiveRows = rows.filter((row) => row.contextSensitive);
  const missingModelContextParityRows = contextSensitiveRows.filter((row) => row.modelContextParityEvidenceStatus !== "model_prompt_context_matches_frozen_rating_context");
  return {
    id: `same-position-context-${releaseId}`,
    releaseId,
    generatedAt: new Date().toISOString(),
    policy: {
      requiredArtifact: "RatingContextSnapshot",
      activeModelPromptSiblingContextPolicyId: activeModelPromptSiblingContextPolicy?.id ?? null,
      releaseRule:
        activeModelPromptSiblingContextPolicy?.sequentialHumanRatingsRule ?? REQUIRED_MODEL_PROMPT_SIBLING_CONTEXT_RULES.sequentialHumanRatings,
      orderRule: "Validation and benchmark-candidate queues must counterbalance order where feasible or disclose fixed target-only order.",
      lateSiblingRule:
        activeModelPromptSiblingContextPolicy?.laterSiblingHandlingRule ?? REQUIRED_MODEL_PROMPT_SIBLING_CONTEXT_RULES.laterSiblingHandling,
      targetOnlyRestrictionRule:
        activeModelPromptSiblingContextPolicy?.targetOnlyRestrictionRule ?? REQUIRED_MODEL_PROMPT_SIBLING_CONTEXT_RULES.targetOnlyRestriction,
    },
    modelPromptSiblingContextPolicyEvidence,
    modelPromptSiblingContextPolicyId: activeModelPromptSiblingContextPolicy?.id ?? null,
    counts: {
      totalRatings: rows.length,
      submittedModelPromptSiblingContextPolicyRows: modelPromptSiblingContextPolicyEvidence.policyRows.filter(
        (row) => row.rowSource === "submitted_workflow_model_prompt_sibling_context_policy",
      ).length,
      modelPromptSiblingContextPolicyReviewRows: modelPromptSiblingContextPolicyEvidence.reviewRows.length,
      ratingsWithFrozenContext: rows.filter((row) => row.contextSnapshotFrozen).length,
      missingContextSnapshotCount: missingContextRows.length,
      currentCritiqueVisibilityViolationCount: currentCritiqueVisibilityViolations.length,
      contextSensitiveRatingCount: contextSensitiveRows.length,
      contextSensitiveModelContextMatchedCount: contextSensitiveRows.length - missingModelContextParityRows.length,
      contextSensitiveModelContextMissingCount: missingModelContextParityRows.length,
      releaseCriticalRatingCount: rows.filter((row) => row.releaseCritical).length,
      counterbalancedReleaseCriticalRatingCount: rows.filter((row) => row.releaseCritical && row.orderPolicyStatus === "counterbalanced").length,
      absentSiblingDisclosureCount: rows.filter((row) => row.absentSiblingCritiqueIds.length > 0).length,
    },
    byPolicy: countBy(rows, "policy"),
    byOrderPolicy: countBy(rows, "orderPolicy"),
    byOrderPolicyStatus: countBy(rows, "orderPolicyStatus"),
    byHumanModelParityStatus: countBy(rows, "humanModelParityStatus"),
    byModelContextParityEvidenceStatus: countBy(rows, "modelContextParityEvidenceStatus"),
    contextSensitiveRows,
    missingModelContextParityRows,
    currentCritiqueVisibilityViolations,
    contextRows: rows,
    releaseUseStatus:
      modelPromptSiblingContextPolicyEvidence.reviewRows.length
        ? "model_prompt_sibling_context_policy_review_required"
        : missingContextRows.length || currentCritiqueVisibilityViolations.length
        ? "rating_context_snapshot_repair_required"
        : missingModelContextParityRows.length
          ? "rating_context_sensitive_model_prompt_matching_required"
          : contextSensitiveRows.length
            ? "same_position_context_parity_preserved"
            : "pass",
  };
}

export function buildSanityBaselineReport(releaseId, labelSnapshot, positionList = positions, critiqueList = critiques, options = {}) {
  const rows = buildLabelRows(labelSnapshot, positionList, critiqueList);
  const fitSplits = options.fitSplits ?? ["public_train", "public_dev"];
  const protectedExcludedSplits = options.protectedExcludedSplits ?? ["internal_validation", "hidden_benchmark"];
  const fitRows = rows.filter((row) => fitSplits.includes(row.split) && isCustomLossEligibleLabel(row.scores));
  const scoredRows = rows.filter((row) => isCustomLossEligibleLabel(row.scores));
  const fitMeanScores = constantScoresFromRows(fitRows, "mean");
  const fitMedianScores = constantScoresFromRows(fitRows, "median");
  const allMeanScores = constantScoresFromRows(scoredRows, "mean");
  const allMedianScores = constantScoresFromRows(scoredRows, "median");
  const pairwiseRows = rows.filter((row) => isValidScore(row.scores.overall));
  const positionToOveralls = groupOverallsByPosition(pairwiseRows);
  const pairwiseSnapshot = buildPairwiseComparisonSnapshot(`sanity-pairwise-${releaseId}`, labelSnapshot.id, labelSnapshot.targetLabelVersion, positionToOveralls);
  const computedBaselines = [
    sanityBaseline("random_pairwise", "weighted_pairwise", "all_scored_splits", {
      loss: pairwiseSnapshot.nonTiedEdges.length ? 0.5 : null,
      coverage: {
        nPairsScored: pairwiseSnapshot.nonTiedEdges.length,
        nPositionsScored: pairwiseSnapshot.positionIds.length - pairwiseSnapshot.excludedNoPairPositions.length,
        nHumanTiePairsExcluded: pairwiseSnapshot.excludedHumanTieEdges,
        nPositionsExcludedNoNonTiedPairs: pairwiseSnapshot.excludedNoPairPositions.length,
      },
    }),
    sanityBaseline("constant_mean", "custom_weighted_loss", "all_scored_labels", constantBaselineLoss(scoredRows, allMeanScores)),
    sanityBaseline("constant_median", "custom_weighted_loss", "all_scored_labels", constantBaselineLoss(scoredRows, allMedianScores)),
    sanityBaseline("prior_only_train_dev", "custom_weighted_loss", fitSplits.join(","), constantBaselineLoss(scoredRows, fitMeanScores)),
  ];
  const submittedBaselineEvidence = buildSubmittedSanityBaselineEvidence(releaseId, labelSnapshot, options.sanityBaselineRuns ?? []);
  const submittedBaselines = normalizeSubmittedSanityBaselines(options.sanityBaselineRuns ?? [], releaseId);
  return {
    id: `sanity-baselines-${releaseId}`,
    releaseId,
    labelSnapshotId: labelSnapshot.id,
    targetLabelVersion: labelSnapshot.targetLabelVersion,
    createdAt: new Date().toISOString(),
    metricVersion: "lmca-demo-sanity-v1",
    protectedSplitPolicy: {
      fitSplits,
      protectedExcludedSplits,
      hiddenBenchmarkFitExcluded: !fitRows.some((row) => row.split === "hidden_benchmark"),
      internalValidationFitExcluded: !fitRows.some((row) => row.split === "internal_validation"),
    },
    baselines: [...computedBaselines, ...submittedBaselines],
    submittedBaselineEvidence,
    fitDistribution: summarizeLabelRows(fitRows),
    scoredDistribution: summarizeLabelRows(scoredRows),
    pairwiseComparisonSnapshot: pairwiseSnapshot,
    pairwiseMarginDistribution: pairwiseMarginDistribution(pairwiseSnapshot),
    notes: [
      "Sanity baselines are reported separately from conceptual-reasoning model runs.",
      "Prior-only fitting excludes protected validation and hidden benchmark splits.",
      "Constant-score baselines test label-prior calibration rather than contextual conceptual judgment.",
    ],
    releaseUseStatus:
      submittedBaselineEvidence.reviewRows.length > 0
        ? "submitted_sanity_baselines_review_required"
        : submittedBaselineEvidence.submittedRunCount > 0
          ? submittedBaselineEvidence.releaseUseStatus
          : "computed_sanity_baselines_only",
  };
}

function buildSubmittedSanityBaselineEvidence(releaseId, labelSnapshot, runs = []) {
  const matchingRuns = runs.filter((run) => !run?.releaseId || run.releaseId === releaseId);
  const rows = matchingRuns.map((run) => {
    const fitSplits = submittedFitSplits(run);
    const protectedFitLeakageCount = fitSplits.filter((split) => ["internal_validation", "hidden_benchmark"].includes(split)).length;
    const checks = [
      requiredManifestCheck("releaseId", releaseId, run.releaseId),
      requiredManifestCheck("targetLabelSnapshotId", labelSnapshot.id, run.targetLabelSnapshotId ?? run.labelSnapshotId),
      requiredSetMembershipCheck("baselineType", SANITY_BASELINE_TYPES, run.baselineType),
      requiredNonEmptyCheck("metricFamily", run.metricFamily),
      requiredNonEmptyCheck("metricOutputs", run.metricOutputs),
      requiredNonEmptyCheck("fitSplits", fitSplits),
      requiredArrayIncludesCheck("excludedProtectedSplits", ["internal_validation", "hidden_benchmark"], protectedSplitList(run)),
      requiredManifestCheck("protectedFitLeakageCount", 0, protectedFitLeakageCount),
    ];
    const reviewChecks = checks.filter((check) => check.status !== "matches" && check.status !== "not_submitted_optional");
    return {
      submittedRunId: run.id ?? null,
      baselineType: run.baselineType ?? null,
      metricFamily: run.metricFamily ?? null,
      checks,
      reviewChecks,
      status: reviewChecks.length ? "submitted_sanity_baseline_review_required" : "submitted_sanity_baseline_fit_policy_preserved",
    };
  });
  const reviewRows = rows.filter((row) => row.reviewChecks.length > 0);
  const appliedBaselineTypes = uniqueStrings(rows.filter((row) => row.status === "submitted_sanity_baseline_fit_policy_preserved").map((row) => row.baselineType));
  const missingRequiredBaselineTypes = REQUIRED_SANITY_BASELINE_TYPES.filter((baselineType) => !appliedBaselineTypes.includes(baselineType));
  return {
    submittedRunCount: matchingRuns.length,
    appliedRunCount: rows.length - reviewRows.length,
    requiredBaselineTypes: REQUIRED_SANITY_BASELINE_TYPES,
    appliedBaselineTypes,
    missingRequiredBaselineTypes,
    reviewRows,
    rows,
    releaseUseStatus:
      reviewRows.length > 0
        ? "submitted_sanity_baselines_review_required"
        : matchingRuns.length > 0
          ? missingRequiredBaselineTypes.length
            ? "submitted_sanity_baselines_missing_required_types"
            : "submitted_sanity_baselines_required_set_complete"
          : "no_submitted_sanity_baseline_runs",
  };
}

function normalizeSubmittedSanityBaselines(runs = [], releaseId) {
  return runs
    .filter((run) => !run?.releaseId || run.releaseId === releaseId)
    .map((run) => ({
      ...sanityBaseline(
        run.baselineType ?? "submitted_baseline",
        run.metricFamily ?? "unknown_metric_family",
        submittedFitSplits(run).join(",") || "not_declared",
        normalizeSubmittedBaselineMetricOutputs(run),
      ),
      id: run.id ?? `submitted-sanity-baseline-${run.baselineType ?? "unknown"}`,
      baselineSource: "submitted_workflow_sanity_baseline_run",
      targetLabelSnapshotId: run.targetLabelSnapshotId ?? run.labelSnapshotId ?? null,
      submittedAt: run.createdAt ?? run.timestamp ?? null,
    }));
}

function submittedFitSplits(run = {}) {
  if (Array.isArray(run.fitSplits)) return run.fitSplits;
  if (run.fitSplit) return [run.fitSplit];
  return [];
}

function normalizeSubmittedBaselineMetricOutputs(run = {}) {
  const outputs = run.metricOutputs ?? {};
  return {
    ...outputs,
    loss: outputs.loss ?? outputs.customWeightedLoss ?? outputs.weightedPairwiseLoss ?? outputs.unweightedPairwiseLoss ?? null,
    coverage: outputs.coverage ?? {
      nItemsScored: outputs.nItemsScored ?? null,
      nPairsScored: outputs.nPairsScored ?? null,
    },
  };
}

export function buildRecalibratedEvaluationReport(
  releaseId,
  labelSnapshot,
  run = fullRubricEvaluationRun,
  positionList = positions,
  options = {},
) {
  const fitSplits = options.fitSplits ?? ["public_train"];
  const protectedExcludedSplits = options.protectedExcludedSplits ?? ["internal_validation", "hidden_benchmark"];
  const targetDimensions = options.targetDimensions ?? (run.mode === "full_rubric" ? RUBRIC_DIMENSIONS : ["overall"]);
  const positionById = new Map(positionList.map((position) => [position.id, position]));
  const calibrationRows = run.predictions
    .map((prediction) => {
      const itemId = makeItemId(prediction.positionId, prediction.critiqueId);
      const label = labelSnapshot.itemLabels[itemId];
      const position = positionById.get(prediction.positionId);
      if (!label || !position) return null;
      return {
        itemId,
        split: position.split,
        humanScores: label.weightedMeanScores,
        modelScores: prediction.scores,
      };
    })
    .filter(Boolean);
  const fitRows = calibrationRows.filter((row) => fitSplits.includes(row.split));
  const protectedRowsExcludedFromFit = calibrationRows.filter((row) => protectedExcludedSplits.includes(row.split));
  const parameters = Object.fromEntries(
    targetDimensions.map((dimension) => [dimension, additiveCalibrationParameter(fitRows, dimension)]),
  );
  const calibratedRun = {
    ...run,
    id: `${run.id}-recalibrated-${releaseId}`,
    calibrationSetting: "per_dimension_additive_intercept_clamped_0_1",
    predictions: run.predictions.map((prediction) => ({
      ...prediction,
      id: `${prediction.id}-recalibrated`,
      rawPredictionId: prediction.id,
      scores: calibrateScores(prediction.scores, parameters),
    })),
  };
  const rawMetrics = evaluationMetricBundle(labelSnapshot, run);
  const recalibratedMetrics = evaluationMetricBundle(labelSnapshot, calibratedRun);
  return {
    id: `recalibrated-evaluation-${releaseId}-${run.id}`,
    releaseId,
    evaluationRunId: run.id,
    requestedModelAlias: run.requestedModelAlias,
    resolvedModelSnapshot: run.resolvedModelSnapshot,
    targetLabelSnapshotId: labelSnapshot.id,
    targetLabelVersion: labelSnapshot.targetLabelVersion,
    metricVersion: "lmca-demo-calibration-v1",
    calibrationArtifact: {
      id: `calibration-${releaseId}-${run.id}`,
      fitSplits,
      protectedExcludedSplits,
      protectedRowsExcludedFromFit: protectedRowsExcludedFromFit.length,
      targetDimensions,
      targetDerivedFields: ["centrality_x_strength_reported_not_directly_fitted"],
      transformationFamily: "per_dimension_additive_intercept",
      outputClamp: "[0,1]",
      fittedParameters: parameters,
      fitRows: fitRows.map((row) => ({
        itemId: row.itemId,
        split: row.split,
        dimensionsFit: targetDimensions.filter((dimension) => isValidScore(row.humanScores[dimension]) && isValidScore(row.modelScores[dimension])),
      })),
      protectedLeakageCount: fitRows.filter((row) => protectedExcludedSplits.includes(row.split)).length,
      promptProvenance: {
        sourceEvaluationPromptArtifactId: run.promptArtifact?.id ?? run.promptTemplateId ?? null,
        sourceRenderedPromptChecksum: run.renderedPromptChecksum ?? null,
        calibrationPromptArtifactId: null,
        calibrationPromptApplicability: "not_applicable_deterministic_score_transform_no_model_prompt",
      },
    },
    rawMetrics,
    recalibratedMetrics,
    metricDeltas: {
      weightedPairwiseLoss: numericDelta(rawMetrics.weightedPairwise.loss, recalibratedMetrics.weightedPairwise.loss),
      customWeightedLoss: numericDelta(rawMetrics.customWeightedLoss.loss, recalibratedMetrics.customWeightedLoss.loss),
      unweightedPairwiseLoss: numericDelta(rawMetrics.unweightedPairwiseDiagnostic.loss, recalibratedMetrics.unweightedPairwiseDiagnostic.loss),
    },
    customWeightedLossDirectionality:
      "The frozen human LabelSnapshot is the target/prediction-left operand and controls the low-clarity branch; recalibration only transforms model predictions.",
    releaseUseStatus:
      protectedRowsExcludedFromFit.length > 0 && fitRows.every((row) => !protectedExcludedSplits.includes(row.split))
        ? "recalibrated_report_protected_fit_excluded"
        : "recalibration_fit_policy_review_required",
  };
}

export function buildUncertaintyAwareLeaderboardReport(
  releaseId,
  labelSnapshot,
  runs = [fullRubricEvaluationRun, overallOnlyEvaluationRun],
  options = {},
) {
  const metricFamily = options.metricFamily ?? "weighted_pairwise";
  const practicalDifferenceThreshold = options.practicalDifferenceThreshold ?? 0.02;
  const commonItemIds = commonPredictionItemIds(runs, labelSnapshot);
  const commonHumanOveralls = commonHumanOverallsByPosition(labelSnapshot, commonItemIds);
  const pairwiseSnapshot = buildPairwiseComparisonSnapshot(
    `leaderboard-pairwise-${releaseId}`,
    labelSnapshot.id,
    labelSnapshot.targetLabelVersion,
    commonHumanOveralls,
  );
  const modelAssistedLabelOverlap =
    options.modelAssistedLabelOverlapReport ??
    buildModelAssistedLabelOverlapReport(releaseId, labelSnapshot, options.ratings ?? seedRatings, runs, options.pairs, {
      modelFamilyOverlapPolicies: options.modelFamilyOverlapPolicies ?? [],
    });
  const modelRunProvenance = buildLeaderboardModelRunProvenanceSummary(runs, {
    releaseId,
    modelInferenceConfigs: options.modelInferenceConfigs ?? [],
    modelRunEnvironments: options.modelRunEnvironments ?? [],
    modelRunReproducibilityPolicies: options.modelRunReproducibilityPolicies ?? [],
  });
  const modelRunProvenanceByRun = new Map(modelRunProvenance.perModelRows.map((row) => [row.evaluationRunId, row]));
  const rows = runs.map((run) =>
    leaderboardRunRow(run, labelSnapshot, commonItemIds, pairwiseSnapshot, metricFamily, modelRunProvenanceByRun.get(run.id)),
  );
  const pairwiseComparisons = buildLeaderboardPairwiseComparisons(rows, practicalDifferenceThreshold);
  const unresolvedGroups = pairwiseComparisons
    .filter((comparison) => comparison.interpretation === "unresolved_within_uncertainty")
    .map((comparison) => comparison.comparison);
  const knownEvaluationRunIds = uniqueStrings([...runs, ...(options.knownEvaluationRuns ?? [])].map((run) => run?.id));
  const submittedLeaderboardRows = (options.leaderboards ?? options.submittedLeaderboards ?? [])
    .map((leaderboard) =>
      normalizeSubmittedLeaderboardReport(leaderboard, {
        releaseId,
        labelSnapshot,
        metricFamily,
        knownEvaluationRunIds,
      }),
    )
    .filter(Boolean);
  const activeSubmittedLeaderboard =
    submittedLeaderboardRows.find((row) => row.status === "submitted_uncertainty_aware_leaderboard_complete") ?? null;
  const submittedLeaderboardReviewRows = submittedLeaderboardRows.filter(
    (row) => row.status !== "submitted_uncertainty_aware_leaderboard_complete",
  );
  const claimGatedDiagnosticSummary = buildLeaderboardClaimGatedDiagnosticSummary(runs, {
    robustnessClaims: options.robustnessClaims ?? [],
    sycophancyProbeRuns: options.sycophancyProbeRuns ?? [],
    obfuscationStressRuns: options.obfuscationStressRuns ?? [],
    diagnosticDeferralRecords: options.diagnosticDeferralRecords ?? [],
  });
  const hiddenBenchmarkSubmissionFeedback = buildLeaderboardHiddenBenchmarkSubmissionFeedbackSummary(releaseId, {
    benchmarkSubmissionPolicies: options.benchmarkSubmissionPolicies ?? [],
    benchmarkSubmissions: options.benchmarkSubmissions ?? [],
  });
  const parserPromptIntegrity = buildLeaderboardParserPromptIntegritySummary(runs);
  return {
    id: `leaderboard-${releaseId}-${metricFamily}`,
    releaseId,
    metricFamily,
    targetLabelSnapshotId: labelSnapshot.id,
    targetLabelVersion: labelSnapshot.targetLabelVersion,
    commonSubsetPolicy: "intersection_of_items_with_human_labels_and_all_included_model_predictions",
    commonItemIds,
    commonPositionIds: pairwiseSnapshot.positionIds,
    pairwiseComparisonSnapshot: pairwiseSnapshot,
    commonMetricConfig: {
      lowerIsBetter: true,
      tieTolerance: pairwiseSnapshot.tieTolerance,
      humanTieTolerance: pairwiseSnapshot.humanTieTolerance,
      modelTieTolerance: pairwiseSnapshot.modelTieTolerance,
      humanTiePolicy: pairwiseSnapshot.humanTiePolicy,
      modelTiePolicy: pairwiseSnapshot.modelTiePolicy,
      scoreRoundingPolicy: pairwiseSnapshot.scoreRoundingPolicy,
      scoreQuantizationPolicy: pairwiseSnapshot.scoreQuantizationPolicy,
      practicalDifferenceThreshold,
      commonMetricConfigStatus: "declared_common_metric_config",
    },
    uncertaintyPolicy: {
      intervalType: "paired_difference_interval",
      nominalLevel: 0.95,
      constructionMethod: "deterministic_seed_demo_interval_width_declared_until_bootstrap_sample_is_large_enough",
      resamplingUnit: "position",
      resampleCountOrDegreesOfFreedom: 0,
      randomSeedOrArtifact: "not_applicable_seed_demo",
      pairedVsIndependentPolicy: "paired_common_item_set_only_for_rank_claims",
    },
    rows,
    pairwiseComparisons,
    uncertaintySupportedRankTiers: activeSubmittedLeaderboard?.uncertaintySupportedRankTiers ?? buildLeaderboardRankTiers(rows, pairwiseComparisons),
    unresolvedComparisonGroups: activeSubmittedLeaderboard ? [] : unresolvedGroups,
    computedUnresolvedComparisonGroups: unresolvedGroups,
    pointEstimateOnlyOrdering: activeSubmittedLeaderboard ? false : unresolvedGroups.length > 0,
    computedPointEstimateOnlyOrdering: unresolvedGroups.length > 0,
    submittedLeaderboardEvidence: {
      rows: submittedLeaderboardRows,
      activeLeaderboardId: activeSubmittedLeaderboard?.id ?? null,
      submittedLeaderboardCount: submittedLeaderboardRows.length,
      completeLeaderboardCount: submittedLeaderboardRows.length - submittedLeaderboardReviewRows.length,
      reviewRequiredCount: submittedLeaderboardReviewRows.length,
      status: activeSubmittedLeaderboard
        ? "submitted_uncertainty_aware_leaderboard_complete"
        : submittedLeaderboardRows.length
          ? "submitted_uncertainty_aware_leaderboard_review_required"
          : "no_submitted_uncertainty_aware_leaderboard",
    },
    promptComparability: summarizePromptComparability(runs),
    modelSnapshotComparability: summarizeModelSnapshotComparability(runs),
    modelAssistedLabelOverlap,
    reasoningModeSensitivity: buildReasoningModeSensitivityReport(releaseId, runs),
    claimGatedDiagnosticSummary,
    hiddenBenchmarkSubmissionFeedback,
    parserPromptIntegrity,
    modelRunProvenance,
    superiorityClaimPolicy:
      "Do not claim model superiority unless paired-difference intervals exclude zero and the absolute point-estimate gap meets the predeclared practical threshold.",
    releaseUseStatus: submittedLeaderboardReviewRows.length
      ? "submitted_uncertainty_aware_leaderboard_review_required"
      : activeSubmittedLeaderboard
        ? "submitted_uncertainty_aware_leaderboard_complete"
        : unresolvedGroups.length
          ? "point_estimate_ordering_only_unresolved_within_uncertainty"
          : "rank_claims_supported_for_declared_common_subset",
  };
}

function buildLeaderboardHiddenBenchmarkSubmissionFeedbackSummary(releaseId, options = {}) {
  const policies = (options.benchmarkSubmissionPolicies ?? []).filter((policy) => !policy?.releaseId || policy.releaseId === releaseId);
  const submissions = (options.benchmarkSubmissions ?? []).filter((submission) => !submission?.releaseId || submission.releaseId === releaseId);
  const activePolicy = policies
    .slice()
    .sort((left, right) => String(left.frozenAt ?? left.createdAt ?? left.id).localeCompare(String(right.frozenAt ?? right.createdAt ?? right.id)))
    .at(-1) ?? null;
  const policyReviewReasons = activePolicy ? benchmarkSubmissionPolicyReviewReasons(activePolicy) : ["benchmarkSubmissionPolicy"];
  const submissionRows = submissions.map((submission) => {
    const reviewReasons = benchmarkSubmissionReviewReasons(submission, activePolicy);
    return {
      id: submission.id ?? null,
      benchmarkSubmissionPolicyId: submission.benchmarkSubmissionPolicyId ?? null,
      submittedAggregateReportId: submission.submittedAggregateReportId ?? null,
      aggregateMetricFamilyResultKeys: Object.keys(submission.aggregateMetricFamilyResults ?? {}).sort(),
      uncertaintyIntervalKeys: Object.keys(submission.uncertaintyIntervals ?? {}).sort(),
      coverageCountKeys: Object.keys(submission.coverageCounts ?? {}).sort(),
      coarseEligibilityWarnings: normalizeStringArray(submission.coarseEligibilityWarnings),
      budgetConsumptionStatus: submission.budgetConsumptionStatus ?? null,
      cooldownStatus: submission.cooldownStatus ?? null,
      duplicateRunStatus: submission.duplicateRunStatus ?? null,
      perItemOutputIncluded: submission.perItemOutputIncluded ?? null,
      perPairOutputIncluded: submission.perPairOutputIncluded ?? null,
      hiddenIdExposureIncluded: submission.hiddenIdExposureIncluded ?? null,
      promptSpecificCorrectionHintsIncluded: submission.promptSpecificCorrectionHintsIncluded ?? null,
      reviewReasons,
      status: reviewReasons.length ? "benchmark_submission_feedback_review_required" : "aggregate_only_submission_feedback_preserved",
    };
  });
  const reviewSections = [
    ...policyReviewReasons.map((reason) => ({ artifactType: "benchmark_submission_policy", artifactId: activePolicy?.id ?? "benchmark_submission_policy", reason })),
    ...submissionRows.flatMap((row) => row.reviewReasons.map((reason) => ({ artifactType: "benchmark_submission", artifactId: row.id, reason }))),
    activePolicy && !submissionRows.length ? { artifactType: "benchmark_submission", artifactId: "benchmark_submission", reason: "no_benchmark_submission_records" } : null,
  ].filter(Boolean);
  const aggregateOnlyFeedbackStatus = activePolicy && policyReviewReasons.length === 0 && submissionRows.every((row) => row.status === "aggregate_only_submission_feedback_preserved")
    ? "aggregate_only_feedback_preserved"
    : activePolicy
      ? "aggregate_only_feedback_review_required"
      : "no_submitted_feedback_policy";
  return {
    activePolicyId: activePolicy?.id ?? null,
    aggregateOnlyFeedbackStatus,
    aggregateOnlyReport: activePolicy?.aggregateOnlyReport === true,
    hiddenIdExposureProhibited: activePolicy?.hiddenIdExposureProhibited === true,
    perItemFeedbackProhibited: activePolicy?.perItemFeedbackProhibited === true,
    perPairFeedbackProhibited: activePolicy?.perPairFeedbackProhibited === true,
    promptSpecificCorrectionHintsProhibited: activePolicy?.promptSpecificCorrectionHintsProhibited === true,
    submissionBudget: activePolicy?.submissionBudget ?? null,
    cooldownPolicy: activePolicy?.cooldownPolicy ?? null,
    duplicateRunHandlingPolicy: activePolicy?.duplicateRunHandlingPolicy ?? null,
    stableEvaluationManifestRequirement: activePolicy?.stableEvaluationManifestRequirement ?? null,
    aggregateReportFieldPolicy: activePolicy?.aggregateReportFieldPolicy ?? null,
    submissionRows,
    reviewSections,
    releaseUseStatus:
      !activePolicy
        ? "no_submitted_benchmark_submission_policy"
        : reviewSections.length > 0
          ? "benchmark_submission_feedback_review_required"
          : "aggregate_only_submission_feedback_budgeted",
  };
}

function benchmarkSubmissionPolicyReviewReasons(policy = {}) {
  const budget = policy.submissionBudget ?? {};
  return [
    policy.aggregateOnlyReport === true ? null : "aggregateOnlyReport",
    policy.hiddenIdExposureProhibited === true ? null : "hiddenIdExposureProhibited",
    policy.perItemFeedbackProhibited === true ? null : "perItemFeedbackProhibited",
    policy.perPairFeedbackProhibited === true ? null : "perPairFeedbackProhibited",
    policy.promptSpecificCorrectionHintsProhibited === true ? null : "promptSpecificCorrectionHintsProhibited",
    Number.isFinite(budget.maxSubmissionsPerWindow) && budget.maxSubmissionsPerWindow > 0 ? null : "submissionBudget.maxSubmissionsPerWindow",
    Number.isFinite(budget.windowHours) && budget.windowHours > 0 ? null : "submissionBudget.windowHours",
    Number.isFinite(budget.remainingSubmissions) && budget.remainingSubmissions >= 0 ? null : "submissionBudget.remainingSubmissions",
    Number.isFinite(budget.cooldownHours) && budget.cooldownHours > 0 ? null : "submissionBudget.cooldownHours",
    Number.isFinite(budget.duplicateRunReviewThreshold) && budget.duplicateRunReviewThreshold >= 0 && budget.duplicateRunReviewThreshold <= 1
      ? null
      : "submissionBudget.duplicateRunReviewThreshold",
    String(policy.cooldownPolicy ?? "").toLowerCase().includes("cooldown") ? null : "cooldownPolicy",
    String(policy.duplicateRunHandlingPolicy ?? "").toLowerCase().includes("duplicate") &&
    String(policy.duplicateRunHandlingPolicy ?? "").toLowerCase().includes("review")
      ? null
      : "duplicateRunHandlingPolicy",
    String(policy.stableEvaluationManifestRequirement ?? "").toLowerCase().includes("stable") &&
    String(policy.stableEvaluationManifestRequirement ?? "").toLowerCase().includes("manifest")
      ? null
      : "stableEvaluationManifestRequirement",
    ["aggregate", "uncertainty", "coverage", "coarse"].every((fragment) =>
      String(policy.aggregateReportFieldPolicy ?? "").toLowerCase().includes(fragment),
    )
      ? null
      : "aggregateReportFieldPolicy",
  ].filter(Boolean);
}

function benchmarkSubmissionReviewReasons(submission = {}, activePolicy = null) {
  const prohibitedPayloadFields = ["hiddenItemIds", "perItemOutputs", "perPairOutputs", "targetScoreVectors", "promptSpecificCorrectionHints"];
  return [
    activePolicy && submission.benchmarkSubmissionPolicyId === activePolicy.id ? null : "benchmarkSubmissionPolicyId",
    objectHasEntries(submission.aggregateMetricFamilyResults) ? null : "aggregateMetricFamilyResults",
    objectHasEntries(submission.uncertaintyIntervals) ? null : "uncertaintyIntervals",
    objectHasEntries(submission.coverageCounts) ? null : "coverageCounts",
    normalizeStringArray(submission.coarseEligibilityWarnings).length ? null : "coarseEligibilityWarnings",
    submission.perItemOutputIncluded === false ? null : "perItemOutputIncluded",
    submission.perPairOutputIncluded === false ? null : "perPairOutputIncluded",
    submission.hiddenIdExposureIncluded === false ? null : "hiddenIdExposureIncluded",
    submission.promptSpecificCorrectionHintsIncluded === false ? null : "promptSpecificCorrectionHintsIncluded",
    BENCHMARK_BUDGET_CONSUMPTION_STATUSES.includes(submission.budgetConsumptionStatus) ? null : "budgetConsumptionStatus",
    BENCHMARK_COOLDOWN_STATUSES.includes(submission.cooldownStatus) ? null : "cooldownStatus",
    BENCHMARK_DUPLICATE_RUN_STATUSES.includes(submission.duplicateRunStatus) ? null : "duplicateRunStatus",
    ...prohibitedPayloadFields.filter((field) => Object.hasOwn(submission, field)).map((field) => `${field}:prohibited_external_feedback`),
  ].filter(Boolean);
}

function buildLeaderboardParserPromptIntegritySummary(runs = []) {
  const perModelRows = runs.map((run) => {
    const promptCheck = run.protectedPromptExampleCheck ?? {};
    const acceptedOutputSchema = run.acceptedOutputSchema ?? {};
    const parseFailureCount = Number.isFinite(run.parseFailureCount) ? run.parseFailureCount : null;
    const invalidScoreCount = Number.isFinite(run.invalidScoreCount) ? run.invalidScoreCount : null;
    const retryCount = Number.isFinite(run.retryCount) ? run.retryCount : null;
    const repairedOutputCount = Number.isFinite(run.repairedOutputCount) ? run.repairedOutputCount : null;
    const reviewReasons = [
      run.parserConfigId ? null : "parserConfigId",
      run.parserRetryPolicy ? null : "parserRetryPolicy",
      objectHasEntries(acceptedOutputSchema) ? null : "acceptedOutputSchema",
      parseFailureCount === null ? "parseFailureCount" : null,
      invalidScoreCount === null ? "invalidScoreCount" : null,
      retryCount === null ? "retryCount" : null,
      repairedOutputCount === null ? "repairedOutputCount" : null,
      promptExampleCheckPasses(promptCheck) ? null : "protectedPromptExampleCheck",
    ].filter(Boolean);
    return {
      evaluationRunId: run.id,
      requestedModelAlias: run.requestedModelAlias,
      resolvedModelSnapshot: run.resolvedModelSnapshot,
      parserConfigId: run.parserConfigId ?? null,
      parserRetryPolicy: run.parserRetryPolicy ?? null,
      acceptedOutputSchemaRequiredFields: normalizeStringArray(acceptedOutputSchema.required),
      acceptedOutputSchemaForbiddenImputedFields: normalizeStringArray(acceptedOutputSchema.forbiddenImputedFields),
      parseFailureCount,
      invalidScoreCount,
      retryCount,
      repairedOutputCount,
      promptArtifactId: run.promptArtifact?.id ?? null,
      promptExampleItemIds: normalizeStringArray(run.promptExampleItemIds),
      promptExamplePositionClusterIds: normalizeStringArray(run.promptExamplePositionClusterIds),
      promptExampleExclusionPolicy: run.promptExampleExclusionPolicy ?? null,
      protectedPromptExampleStatus: promptCheck.status ?? null,
      hiddenBenchmarkExamplesExcluded: promptCheck.hiddenBenchmarkExamplesExcluded ?? null,
      protectedValidationExamplesExcluded: promptCheck.protectedValidationExamplesExcluded ?? null,
      reviewReasons,
      status: reviewReasons.length ? "parser_prompt_integrity_review_required" : "parser_prompt_integrity_declared",
    };
  });
  const parserConfigIds = uniqueStrings(perModelRows.map((row) => row.parserConfigId));
  const parserRetryPolicies = uniqueStrings(perModelRows.map((row) => row.parserRetryPolicy));
  const reviewSections = perModelRows.flatMap((row) =>
    row.reviewReasons.map((reason) => ({ artifactType: "evaluation_run_parser_prompt_integrity", artifactId: row.evaluationRunId, reason })),
  );
  return {
    parserConfigIds,
    parserRetryPolicies,
    commonParserConfig: parserConfigIds.length === 1,
    commonParserRetryPolicy: parserRetryPolicies.length === 1,
    totalParseFailureCount: sumNumeric(perModelRows.map((row) => row.parseFailureCount)),
    totalInvalidScoreCount: sumNumeric(perModelRows.map((row) => row.invalidScoreCount)),
    totalRetryCount: sumNumeric(perModelRows.map((row) => row.retryCount)),
    totalRepairedOutputCount: sumNumeric(perModelRows.map((row) => row.repairedOutputCount)),
    perModelRows,
    reviewSections,
    releaseUseStatus: reviewSections.length
      ? "leaderboard_parser_prompt_integrity_review_required"
      : parserConfigIds.length === 1 && parserRetryPolicies.length === 1
        ? "common_parser_prompt_integrity_declared"
        : "mixed_parser_or_prompt_policy_sensitivity_declared",
  };
}

function buildLeaderboardModelRunProvenanceSummary(runs = [], options = {}) {
  const modelRunReproducibilityPolicyEvidence = buildModelRunReproducibilityPolicyEvidence(
    options.releaseId ?? "leaderboard",
    options.modelRunReproducibilityPolicies ?? [],
  );
  const activeModelRunReproducibilityPolicy = options.modelRunReproducibilityPolicies?.length
    ? modelRunReproducibilityPolicyEvidence.activePolicy
    : null;
  const configRows = (options.modelInferenceConfigs ?? [])
    .map((config) => normalizeModelInferenceConfig(config, "submitted_leaderboard_model_inference_config", activeModelRunReproducibilityPolicy))
    .filter(Boolean);
  const environmentRows = (options.modelRunEnvironments ?? [])
    .map((environment) => normalizeModelRunEnvironment(environment, "submitted_leaderboard_model_run_environment", activeModelRunReproducibilityPolicy))
    .filter(Boolean);
  const perModelRows = runs.map((run) => {
    const matchingConfigs = configRows.filter((row) => row.evaluationRunId === run.id);
    const matchingEnvironments = environmentRows.filter((row) => row.evaluationRunId === run.id);
    const config = matchingConfigs.find((row) => row.reviewReasons.length === 0) ?? matchingConfigs[0] ?? null;
    const environment = matchingEnvironments.find((row) => row.reviewReasons.length === 0) ?? matchingEnvironments[0] ?? null;
    const reviewReasons = [
      config ? null : "modelInferenceConfig",
      environment ? null : "modelRunEnvironment",
      ...(config?.reviewReasons ?? []).map((reason) => `modelInferenceConfig.${reason}`),
      ...(environment?.reviewReasons ?? []).map((reason) => `modelRunEnvironment.${reason}`),
      config?.modelSnapshot && run.resolvedModelSnapshot && config.modelSnapshot !== run.resolvedModelSnapshot ? "modelSnapshotMismatch" : null,
    ].filter(Boolean);
    return {
      evaluationRunId: run.id,
      requestedModelAlias: run.requestedModelAlias,
      resolvedModelSnapshot: run.resolvedModelSnapshot,
      modelRunReproducibilityPolicyId: activeModelRunReproducibilityPolicy?.id ?? config?.modelRunReproducibilityPolicyId ?? environment?.modelRunReproducibilityPolicyId ?? null,
      modelInferenceConfigId: config?.id ?? null,
      modelRunEnvironmentId: environment?.id ?? null,
      providerEndpoint: config?.providerEndpoint ?? null,
      modelSnapshot: config?.modelSnapshot ?? null,
      decodingParameters: config?.decodingParameters ?? null,
      reasoningBudget: config?.reasoningBudget ?? null,
      toolAvailability: config?.toolAvailability ?? [],
      messageStackTemplate: config?.messageStackTemplate ?? null,
      retryPolicy: config?.retryPolicy ?? null,
      seedDeterminismArtifact: config?.seedDeterminismArtifact ?? null,
      runtimeOrchestratorVersion: environment?.runtimeOrchestratorVersion ?? null,
      apiRouteDeploymentId: environment?.apiRouteDeploymentId ?? null,
      libraryVersions: environment?.libraryVersions ?? null,
      rateLimitRetryMetadata: environment?.rateLimitRetryMetadata ?? null,
      parserExtractorVersionLinks: environment?.parserExtractorVersionLinks ?? [],
      reviewReasons,
      status: reviewReasons.length ? "model_run_provenance_review_required" : "model_run_provenance_declared",
    };
  });
  const reviewSections = [
    ...modelRunReproducibilityPolicyEvidence.reviewRows.flatMap((row) =>
      row.reviewReasons.map((reason) => ({ artifactType: "model_run_reproducibility_policy", artifactId: row.id, reason })),
    ),
    ...perModelRows.flatMap((row) =>
      row.reviewReasons.map((reason) => ({ artifactType: "leaderboard_model_run_provenance", artifactId: row.evaluationRunId, reason })),
    ),
  ];
  const commonReasoningBudgets = uniqueStrings(perModelRows.map((row) => row.reasoningBudget));
  const commonToolAvailability = uniqueStrings(perModelRows.map((row) => stableJsonKey(row.toolAvailability)));
  const commonMessageStackTemplates = uniqueStrings(perModelRows.map((row) => row.messageStackTemplate));
  const commonRetryPolicies = uniqueStrings(perModelRows.map((row) => row.retryPolicy));
  const commonRuntimeOrchestratorVersions = uniqueStrings(perModelRows.map((row) => row.runtimeOrchestratorVersion));
  const commonParserExtractorVersionLinks = uniqueStrings(perModelRows.map((row) => stableJsonKey(row.parserExtractorVersionLinks)));
  return {
    submittedModelInferenceConfigCount: perModelRows.filter((row) => row.modelInferenceConfigId).length,
    submittedModelRunEnvironmentCount: perModelRows.filter((row) => row.modelRunEnvironmentId).length,
    modelRunReproducibilityPolicyEvidence,
    modelRunReproducibilityPolicyId: activeModelRunReproducibilityPolicy?.id ?? null,
    modelRunReproducibilityPolicyReleaseUseStatus: modelRunReproducibilityPolicyEvidence.releaseUseStatus,
    availableModelInferenceConfigCount: configRows.length,
    availableModelRunEnvironmentCount: environmentRows.length,
    providerEndpoints: uniqueStrings(perModelRows.map((row) => row.providerEndpoint)),
    apiRouteDeploymentIds: uniqueStrings(perModelRows.map((row) => row.apiRouteDeploymentId)),
    modelSnapshots: uniqueStrings(perModelRows.map((row) => row.modelSnapshot)),
    commonReasoningBudget: commonReasoningBudgets.length === 1,
    commonToolAvailability: commonToolAvailability.length === 1,
    commonMessageStackTemplate: commonMessageStackTemplates.length === 1,
    commonRetryPolicy: commonRetryPolicies.length === 1,
    commonRuntimeOrchestratorVersion: commonRuntimeOrchestratorVersions.length === 1,
    commonParserExtractorVersionLinks: commonParserExtractorVersionLinks.length === 1,
    commonSettingStatus:
      commonReasoningBudgets.length === 1 &&
      commonToolAvailability.length === 1 &&
      commonMessageStackTemplates.length === 1 &&
      commonRetryPolicies.length === 1
        ? "common_inference_settings_declared"
        : "mixed_inference_settings_sensitivity_declared",
    perModelRows,
    reviewSections,
    releaseUseStatus: reviewSections.length
      ? "leaderboard_model_run_provenance_review_required"
      : commonReasoningBudgets.length === 1 && commonToolAvailability.length === 1 && commonMessageStackTemplates.length === 1 && commonRetryPolicies.length === 1
        ? "common_model_run_provenance_declared"
        : "mixed_model_run_provenance_sensitivity_declared",
  };
}

function stableJsonKey(value) {
  if (value === undefined || value === null || value === "") return null;
  return JSON.stringify(stableJsonValue(value));
}

function stableJsonValue(value) {
  if (Array.isArray(value)) return value.map(stableJsonValue);
  if (value && typeof value === "object") {
    return Object.fromEntries(
      Object.entries(value)
        .sort(([left], [right]) => left.localeCompare(right))
        .map(([key, entry]) => [key, stableJsonValue(entry)]),
    );
  }
  return value;
}

function promptExampleCheckPasses(check = {}) {
  return check.hiddenBenchmarkExamplesExcluded === true && check.protectedValidationExamplesExcluded === true;
}

function sumNumeric(values) {
  return values.reduce((total, value) => total + (Number.isFinite(value) ? value : 0), 0);
}

function buildLeaderboardClaimGatedDiagnosticSummary(runs, options = {}) {
  const runSummaries = runs.map((run) => buildClaimGatedModelDiagnostics(run, options));
  const suiteRows = runSummaries.flatMap((summary) =>
    summary.suites.map((suite) => ({
      evaluationRunId: summary.evaluationRunId,
      requestedModelAlias: summary.requestedModelAlias,
      resolvedModelSnapshot: summary.resolvedModelSnapshot,
      suiteId: suite.id,
      status: suite.status,
      completedRunIds: suite.completedRunIds,
      completedCueFamilies: suite.completedCueFamilies ?? [],
      missingCueFamilies: suite.missingCueFamilies ?? [],
      completedVariantFamilies: suite.completedVariantFamilies ?? [],
      missingVariantFamilies: suite.missingVariantFamilies ?? [],
      notRunRationale: suite.notRunRationale,
      approvedDeferralId: suite.approvedDeferral?.id ?? null,
      approvedWeakerClaimWording: suite.approvedDeferral?.approvedWeakerClaimWording ?? null,
    })),
  );
  const releaseStatuses = uniqueStrings(runSummaries.map((summary) => summary.releaseUseStatus));
  const releaseUseStatus = releaseStatuses.includes("robustness_claim_blocked_until_claim_gated_probes_run")
    ? "robustness_claim_blocked_until_claim_gated_probes_run"
    : releaseStatuses.includes("claim_gated_diagnostics_coverage_review_required")
      ? "claim_gated_diagnostics_coverage_review_required"
      : releaseStatuses.includes("claim_gated_diagnostics_deferred_with_claim_suppression")
        ? "claim_gated_diagnostics_deferred_with_claim_suppression"
      : releaseStatuses.includes("claim_gated_diagnostics_attached_no_robustness_claim")
        ? "claim_gated_diagnostics_attached_no_robustness_claim"
        : "claim_gated_diagnostics_deferred_no_robustness_claim";
  return {
    releaseUseStatus,
    runCount: runs.length,
    suiteRows,
    sycophancyOrthodoxySensitivity: {
      requiredCueFamilies: REQUIRED_SYCOPHANCY_ORTHODOXY_CUE_FAMILIES,
      completedCueFamilies: uniqueStrings(suiteRows.flatMap((row) => row.completedCueFamilies)),
      missingCueFamiliesByRun: suiteRows
        .filter((row) => row.suiteId === "sycophancy_orthodoxy_sensitivity" && row.missingCueFamilies.length)
        .map((row) => ({ evaluationRunId: row.evaluationRunId, missingCueFamilies: row.missingCueFamilies })),
      notRunRationales: suiteRows
        .filter((row) => row.suiteId === "sycophancy_orthodoxy_sensitivity" && row.notRunRationale)
        .map((row) => ({ evaluationRunId: row.evaluationRunId, notRunRationale: row.notRunRationale, approvedDeferralId: row.approvedDeferralId })),
    },
    obfuscatedArgumentStress: {
      requiredVariantFamilies: OBFUSCATION_STRESS_VARIANT_FAMILIES,
      completedVariantFamilies: uniqueStrings(suiteRows.flatMap((row) => row.completedVariantFamilies)),
      missingVariantFamiliesByRun: suiteRows
        .filter((row) => row.suiteId === "obfuscated_argument_stress" && row.missingVariantFamilies.length)
        .map((row) => ({ evaluationRunId: row.evaluationRunId, missingVariantFamilies: row.missingVariantFamilies })),
      notRunRationales: suiteRows
        .filter((row) => row.suiteId === "obfuscated_argument_stress" && row.notRunRationale)
        .map((row) => ({ evaluationRunId: row.evaluationRunId, notRunRationale: row.notRunRationale, approvedDeferralId: row.approvedDeferralId })),
    },
  };
}

export function buildMetricDirectionalityConfigReport(releaseId, labelSnapshot, leaderboardReport, humanCeiling, options = {}) {
  const pairwiseSnapshot = leaderboardReport.pairwiseComparisonSnapshot;
  const commonConfig = leaderboardReport.commonMetricConfig;
  const effectiveMetricConfig = buildEffectiveMetricConfig(releaseId, commonConfig, pairwiseSnapshot, options.metricConfigs ?? [], options.derivedUtilityFormulas ?? []);
  const commonMetricConfigStatus = effectiveMetricConfig.submittedMetricConfigId ? "submitted_metric_config_applied" : commonConfig.commonMetricConfigStatus;
  const pairwiseConfigRows = [
    {
      surface: "pairwise_ranking_report",
      metricFamily: "weighted_pairwise",
      lowerIsBetter: true,
      scoreRoundingPolicy: effectiveMetricConfig.scoreRoundingPolicy,
      scoreQuantizationPolicy: effectiveMetricConfig.scoreQuantizationPolicy,
      humanTieTolerance: effectiveMetricConfig.humanTieTolerance,
      modelTieTolerance: effectiveMetricConfig.modelTieTolerance,
      humanTiePolicy: effectiveMetricConfig.humanTiePolicy,
      modelTiePolicy: effectiveMetricConfig.modelTiePolicy,
      commonMetricConfigStatus,
      metricConfigId: effectiveMetricConfig.id,
      evidence: `${pairwiseSnapshot.nonTiedEdges.length} non-tied edges frozen in ${pairwiseSnapshot.id}.`,
      diagnosticOnly: false,
    },
    {
      surface: "pairwise_diagnostic_report",
      metricFamily: "unweighted_pairwise_diagnostic",
      lowerIsBetter: true,
      scoreRoundingPolicy: effectiveMetricConfig.scoreRoundingPolicy,
      scoreQuantizationPolicy: effectiveMetricConfig.scoreQuantizationPolicy,
      humanTieTolerance: effectiveMetricConfig.humanTieTolerance,
      modelTieTolerance: effectiveMetricConfig.modelTieTolerance,
      humanTiePolicy: effectiveMetricConfig.humanTiePolicy,
      modelTiePolicy: effectiveMetricConfig.modelTiePolicy,
      commonMetricConfigStatus,
      metricConfigId: effectiveMetricConfig.id,
      evidence: "Diagnostic uses the same pairwise snapshot, tie handling, and common item set as the weighted headline family.",
      diagnosticOnly: true,
    },
    {
      surface: "cross_model_leaderboard",
      metricFamily: leaderboardReport.metricFamily,
      lowerIsBetter: commonConfig.lowerIsBetter,
      scoreRoundingPolicy: effectiveMetricConfig.scoreRoundingPolicy,
      scoreQuantizationPolicy: effectiveMetricConfig.scoreQuantizationPolicy,
      humanTieTolerance: effectiveMetricConfig.humanTieTolerance,
      modelTieTolerance: effectiveMetricConfig.modelTieTolerance,
      humanTiePolicy: effectiveMetricConfig.humanTiePolicy,
      modelTiePolicy: effectiveMetricConfig.modelTiePolicy,
      commonMetricConfigStatus,
      metricConfigId: effectiveMetricConfig.id,
      evidence: `${leaderboardReport.rows.length} runs compared on ${leaderboardReport.commonItemIds.length} common items using ${leaderboardReport.commonSubsetPolicy}.`,
      diagnosticOnly: false,
    },
  ];
  if (effectiveMetricConfig.derivedUtilityPairwiseEnabled) {
    pairwiseConfigRows.push({
      surface: "derived_utility_pairwise_diagnostic",
      metricFamily: "derived_utility_pairwise_diagnostic",
      lowerIsBetter: true,
      scoreRoundingPolicy: effectiveMetricConfig.scoreRoundingPolicy,
      scoreQuantizationPolicy: effectiveMetricConfig.scoreQuantizationPolicy,
      humanTieTolerance: effectiveMetricConfig.humanTieTolerance,
      modelTieTolerance: effectiveMetricConfig.modelTieTolerance,
      humanTiePolicy: effectiveMetricConfig.humanTiePolicy,
      modelTiePolicy: effectiveMetricConfig.modelTiePolicy,
      commonMetricConfigStatus,
      metricConfigId: effectiveMetricConfig.id,
      derivedUtilityFormulaId: effectiveMetricConfig.derivedUtilityFormula.id,
      deadWeightDirectionHandling: effectiveMetricConfig.derivedUtilityFormula.deadWeightDirectionHandling,
      lowClarityPolicy: effectiveMetricConfig.derivedUtilityFormula.lowClarityPolicy,
      evidence: `${effectiveMetricConfig.derivedUtilityFormula.formulaName} ${effectiveMetricConfig.derivedUtilityFormula.version} is diagnostic-only and normalizes dead_weight as a badness field.`,
      diagnosticOnly: true,
    });
  }
  const directionalityRows = [
    {
      metricFamily: "custom_weighted_loss",
      targetRole: effectiveMetricConfig.customLossTargetRole,
      predictionRole: effectiveMetricConfig.customLossPredictionRole,
      callSignature: "customWeightedLoss(targetLabel, modelPrediction)",
      directionality: "lower_is_better_absolute_distance_from_target_to_prediction",
      lowerIsBetter: true,
      lowClarityPolicy: effectiveMetricConfig.lowClarityPolicy,
      targetPredictionDirectionalityStatus: "target_prediction_roles_declared",
      metricConfigId: effectiveMetricConfig.id,
    },
    {
      metricFamily: "human_ceiling_and_validation",
      targetRole: "final_average_approximation",
      predictionRole: "human_check_or_model_prediction",
      callSignature: "mean absolute overall difference against validation target",
      directionality: "lower_is_better_distance_to_final_average_approximation",
      lowerIsBetter: true,
      finalAveragePolicy: humanCeiling.finalAverageApproximationPolicy,
      targetPredictionDirectionalityStatus: "final_average_marked_as_approximation",
    },
  ];
  const configViolationRows = pairwiseConfigRows.filter(
    (row) =>
      row.scoreRoundingPolicy === undefined ||
      row.scoreQuantizationPolicy === undefined ||
      row.humanTieTolerance === undefined ||
      row.modelTieTolerance === undefined ||
      !["declared_common_metric_config", "submitted_metric_config_applied"].includes(row.commonMetricConfigStatus),
  );
  const directionalityViolationRows = directionalityRows.filter(
    (row) =>
      row.targetPredictionDirectionalityStatus !== "target_prediction_roles_declared" &&
      row.targetPredictionDirectionalityStatus !== "final_average_marked_as_approximation",
  );
  return {
    id: `metric-directionality-config-${releaseId}`,
    releaseId,
    targetLabelSnapshotId: labelSnapshot.id,
    targetLabelVersion: labelSnapshot.targetLabelVersion,
    effectiveMetricConfig,
    derivedUtilityFormula: effectiveMetricConfig.derivedUtilityFormula,
    policy: {
      scoreRoundingRule: "Score rounding and quantization must be declared before pairwise ranking or leaderboard claims.",
      tieToleranceRule: "Human-target tie tolerance controls edge exclusion; model-prediction tie tolerance separately controls half-error indifference.",
      directionalityRule: "Custom weighted loss is always reported as lower-is-better distance from the target label to the prediction.",
      finalAverageRule: humanCeiling.finalAverageApproximationPolicy,
    },
    counts: {
      pairwiseConfigRows: pairwiseConfigRows.length,
      directionalityRows: directionalityRows.length,
      configViolationCount: configViolationRows.length,
      directionalityViolationCount: directionalityViolationRows.length,
    },
    pairwiseConfigRows,
    directionalityRows,
    configViolationRows,
    directionalityViolationRows,
    releaseUseStatus:
      configViolationRows.length || directionalityViolationRows.length
        ? "metric_config_or_directionality_review_required"
        : "metric_config_and_directionality_declared",
  };
}

function buildEffectiveMetricConfig(releaseId, commonConfig, pairwiseSnapshot, submittedMetricConfigs = [], submittedDerivedUtilityFormulas = []) {
  const submittedMetricConfig = submittedMetricConfigs.at(-1) ?? null;
  const derivedUtilityFormula = buildEffectiveDerivedUtilityFormula(releaseId, submittedDerivedUtilityFormulas, submittedMetricConfig);
  const tieTolerance = numberOrDefault(
    submittedMetricConfig?.pairwiseTieTolerance ?? submittedMetricConfig?.tieTolerance,
    commonConfig.tieTolerance ?? pairwiseSnapshot.tieTolerance ?? 0,
  );
  return {
    id: submittedMetricConfig?.id ?? `metric-config-${releaseId}`,
    releaseId: submittedMetricConfig?.releaseId ?? releaseId,
    metricFamily: submittedMetricConfig?.metricFamily ?? "weighted_pairwise_and_custom_loss",
    metricVersion: submittedMetricConfig?.metricVersion ?? "lmca-october-2026-v1",
    submittedMetricConfigId: submittedMetricConfig?.id ?? null,
    configSource: submittedMetricConfig ? "submitted_workflow_metric_config" : "default_project_metric_config",
    lowClarityThreshold: numberOrDefault(submittedMetricConfig?.lowClarityThreshold, 0.5),
    lowClarityPolicy:
      submittedMetricConfig?.derivedUtilityLowClarityPolicy ??
      submittedMetricConfig?.lowClarityPolicy ??
      "target_label_clarity_below_0_5_switches_to_overall_plus_clarity_branch",
    customLossTargetRole: submittedMetricConfig?.customLossTargetRole ?? "label_snapshot_target_or_human_rating",
    customLossPredictionRole: submittedMetricConfig?.customLossPredictionRole ?? "model_full_rubric_prediction",
    scoreRoundingPolicy: submittedMetricConfig?.scoreRoundingPolicy ?? commonConfig.scoreRoundingPolicy ?? pairwiseSnapshot.scoreRoundingPolicy,
    scoreQuantizationPolicy:
      submittedMetricConfig?.scoreQuantizationPolicy ?? commonConfig.scoreQuantizationPolicy ?? pairwiseSnapshot.scoreQuantizationPolicy,
    humanTieTolerance: numberOrDefault(submittedMetricConfig?.pairwiseHumanTieTolerance ?? submittedMetricConfig?.humanTieTolerance, tieTolerance),
    modelTieTolerance: numberOrDefault(submittedMetricConfig?.pairwiseModelTieTolerance ?? submittedMetricConfig?.modelTieTolerance, tieTolerance),
    humanTiePolicy: normalizeHumanTiePolicy(submittedMetricConfig?.pairwiseHumanTiePolicy ?? submittedMetricConfig?.humanTiePolicy ?? commonConfig.humanTiePolicy),
    modelTiePolicy: normalizeModelTiePolicy(submittedMetricConfig?.pairwiseModelTiePolicy ?? submittedMetricConfig?.modelTiePolicy ?? commonConfig.modelTiePolicy),
    lowMarginThreshold: numberOrDefault(submittedMetricConfig?.lowMarginThreshold, 0.05),
    defaultResamplingUnit: submittedMetricConfig?.defaultResamplingUnit ?? "position",
    defaultIntervalType: submittedMetricConfig?.defaultIntervalType ?? "paired_difference_interval",
    defaultIntervalLevel: numberOrDefault(submittedMetricConfig?.defaultIntervalLevel ?? submittedMetricConfig?.defaultConfidenceLevel, 0.95),
    defaultResampleCount: numberOrDefault(submittedMetricConfig?.defaultResampleCount, 0),
    unweightedPairwiseDiagnosticEnabled: submittedMetricConfig?.unweightedPairwiseDiagnosticEnabled !== false,
    derivedUtilityPairwiseEnabled: submittedMetricConfig?.derivedUtilityPairwiseEnabled === true || Boolean(derivedUtilityFormula.submittedFormulaId),
    derivedUtilityFormulaId: submittedMetricConfig?.derivedUtilityFormulaId ?? derivedUtilityFormula.id,
    derivedUtilityFormula,
  };
}

function buildEffectiveDerivedUtilityFormula(releaseId, submittedDerivedUtilityFormulas = [], submittedMetricConfig = null) {
  const submittedFormula =
    submittedDerivedUtilityFormulas.find((formula) => formula.id === submittedMetricConfig?.derivedUtilityFormulaId) ??
    submittedDerivedUtilityFormulas.at(-1) ??
    null;
  return {
    id: submittedFormula?.id ?? submittedMetricConfig?.derivedUtilityFormulaId ?? `derived-utility-formula-${releaseId}`,
    formulaName: submittedFormula?.formulaName ?? "default_full_rubric_utility",
    version: submittedFormula?.version ?? "v1",
    formulaSource: submittedFormula ? "submitted_workflow_derived_utility_formula" : "default_project_derived_utility_formula",
    submittedFormulaId: submittedFormula?.id ?? null,
    inputDimensions: submittedFormula?.inputDimensions ?? ["overall", "centrality", "strength", "correctness", "clarity", "dead_weight", "single_issue"],
    weights:
      submittedFormula?.weights ?? {
        overall: 0.5,
        centralityStrengthProduct: 0.2,
        clarity: 0.1,
        correctness: 0.1,
        deadWeightUtility: 0.05,
        singleIssue: 0.05,
      },
    centralityStrengthHandling: submittedFormula?.centralityStrengthHandling ?? "multiply_centrality_by_strength",
    deadWeightDirectionHandling: submittedFormula?.deadWeightDirectionHandling ?? "badness_field_normalized_as_one_minus_dead_weight",
    singleIssueInterpretation: submittedFormula?.singleIssueInterpretation ?? "focus_cleanliness_positive_utility_component",
    lowClarityPolicy:
      submittedFormula?.lowClarityPolicy ??
      submittedMetricConfig?.derivedUtilityLowClarityPolicy ??
      "if_target_clarity_below_0_5_use_only_overall_and_clarity",
    scoreNormalizationPolicy: submittedFormula?.scoreNormalizationPolicy ?? "unit_interval_inputs_preserved",
    tiePolicy: submittedFormula?.tiePolicy ?? submittedMetricConfig?.pairwiseModelTiePolicy ?? "model_tie_costs_half_margin",
    diagnosticUsePolicy: "non_headline_sensitivity_analysis_not_lmca_source_headline_metric",
    formulaBody:
      submittedFormula?.formulaBody ??
      "target clarity < 0.5: 0.5*overall + 0.5*clarity; otherwise 0.5*overall + 0.2*centrality*strength + 0.1*clarity + 0.1*correctness + 0.05*(1-dead_weight) + 0.05*single_issue",
    formulaStatus:
      (submittedFormula?.deadWeightDirectionHandling ?? "badness_field_normalized_as_one_minus_dead_weight").includes("one_minus") ||
      (submittedFormula?.deadWeightDirectionHandling ?? "badness_field_normalized_as_one_minus_dead_weight").includes("badness")
        ? "derived_utility_formula_declares_badness_normalization"
        : "derived_utility_formula_review_required",
  };
}

function numberOrDefault(value, fallback) {
  return Number.isFinite(Number(value)) ? Number(value) : fallback;
}

function normalizeHumanTiePolicy(policy) {
  if (policy === "exclude_human_ties") return "exclude_human_tied_pairs_from_pairwise_loss";
  return policy ?? "exclude_human_tied_pairs_from_pairwise_loss";
}

function normalizeModelTiePolicy(policy) {
  if (policy === "model_tie_costs_half_margin") return "score_model_tied_predictions_as_half_error";
  return policy ?? "score_model_tied_predictions_as_half_error";
}

export const CONSENSUS_TARGET_LABEL_VERSION = "adjudicated_or_final_average_consensus";

export function buildPairedTargetLabelSnapshotReport(
  releaseId,
  consensusSnapshot,
  ratings = seedRatings,
  pairs = critiques.map((critique) => ({ positionId: critique.positionId, critiqueId: critique.id })),
  runs = [fullRubricEvaluationRun, overallOnlyEvaluationRun],
  options = {},
) {
  const primaryRaterAnchorPolicy =
    options.primaryRaterAnchorPolicy ?? buildEffectivePrimaryRaterAnchorPolicy(releaseId, options.primaryRaterAnchorPolicies ?? []);
  const primaryRaterAnchorQualificationRecords =
    Array.isArray(options.raterQualificationRecords) && options.raterQualificationRecords.length
      ? options.raterQualificationRecords
      : defaultRaterQualificationRecords(releaseId);
  const primarySnapshot =
    options.primarySnapshot ??
    createPrimaryRaterAnchorSnapshot(`snapshot-${releaseId}-primary-rater-anchor`, releaseId, ratings, pairs, {
      ...(options.primaryAnchorOptions ?? {}),
      primaryRaterAnchorPolicy,
      raterQualificationRecords: primaryRaterAnchorQualificationRecords,
      requirePrimaryRaterAnchorQualification: true,
    });
  const primaryItemIds = scoredItemIds(primarySnapshot);
  const consensusItemIds = scoredItemIds(consensusSnapshot);
  const overlapItemIds = intersectSorted(primaryItemIds, consensusItemIds);
  const modelScoreDeltas = runs.map((run) => {
    const runItemIds = intersectSorted(overlapItemIds, predictionItemIds(run));
    const primary = targetRunScoreRow(run, primarySnapshot, runItemIds, "weighted_pairwise");
    const consensus = targetRunScoreRow(run, consensusSnapshot, runItemIds, "weighted_pairwise");
    return {
      evaluationRunId: run.id,
      requestedModelAlias: run.requestedModelAlias,
      commonOverlapItemCount: runItemIds.length,
      primaryRaterAnchor: {
        targetLabelSnapshotId: primarySnapshot.id,
        weightedPairwiseLoss: primary.weightedPairwise.loss,
        customWeightedLoss: primary.customWeightedLoss.loss,
        coverage: primary.coverage,
      },
      consensus: {
        targetLabelSnapshotId: consensusSnapshot.id,
        weightedPairwiseLoss: consensus.weightedPairwise.loss,
        customWeightedLoss: consensus.customWeightedLoss.loss,
        coverage: consensus.coverage,
      },
      lossDeltaPrimaryMinusConsensus:
        typeof primary.weightedPairwise.loss === "number" && typeof consensus.weightedPairwise.loss === "number"
          ? round(primary.weightedPairwise.loss - consensus.weightedPairwise.loss)
          : null,
    };
  });
  const primaryOrder = pointEstimateOrder(modelScoreDeltas, "primaryRaterAnchor");
  const consensusOrder = pointEstimateOrder(modelScoreDeltas, "consensus");
  return {
    id: `paired-target-label-snapshots-${releaseId}`,
    releaseId,
    primaryRaterAnchorPolicy,
    primaryRaterAnchorSnapshot: primarySnapshot,
    consensusSnapshot: {
      id: consensusSnapshot.id,
      targetLabelVersion: CONSENSUS_TARGET_LABEL_VERSION,
      sourceTargetLabelVersion: consensusSnapshot.targetLabelVersion,
      status: consensusSnapshot.status,
      reliabilityWeightModelId: consensusSnapshot.reliabilityWeightModelId,
      denominatorCounts: consensusSnapshot.denominatorCounts,
    },
    coverageOverlap: {
      primaryScoredItemCount: primaryItemIds.length,
      consensusScoredItemCount: consensusItemIds.length,
      overlapItemCount: overlapItemIds.length,
      overlapItemIds,
      primaryOnlyItemIds: primaryItemIds.filter((itemId) => !consensusItemIds.includes(itemId)),
      consensusOnlyItemIds: consensusItemIds.filter((itemId) => !primaryItemIds.includes(itemId)),
    },
    targetLabelDeltas: overlapItemIds.map((itemId) => {
      const primaryOverall = primarySnapshot.itemLabels[itemId].weightedMeanScores.overall;
      const consensusOverall = consensusSnapshot.itemLabels[itemId].weightedMeanScores.overall;
      return {
        itemId,
        primaryOverall,
        consensusOverall,
        primaryMinusConsensusOverall: round(primaryOverall - consensusOverall),
      };
    }),
    modelScoreDeltas,
    rankSensitivity: {
      itemSubsetPolicy: "primary_anchor_consensus_overlap_with_common_model_predictions",
      primaryPointEstimateOrder: primaryOrder,
      consensusPointEstimateOrder: consensusOrder,
      status: sameOrder(primaryOrder, consensusOrder) ? "no_point_estimate_order_change_on_overlap" : "target_label_sensitive_point_estimate_order",
      uncertaintyNote:
        "Target-label sensitivity is descriptive; leaderboard rank claims still require paired common-set intervals and the predeclared practical-difference threshold.",
    },
    claimPolicy: {
      lmcaTable5TargetIdenticalOnlyWithPrimaryAnchor: true,
      consensusTargetLabelVersion: CONSENSUS_TARGET_LABEL_VERSION,
      consensusSnapshotUse: "higher_quality_volunteer_label_not_target_identical_to_lmca_table_5",
      postHocAnchorSwitchingAllowed: false,
    },
  };
}

const MODEL_ASSISTED_CHECK_REQUIRED_AUXILIARY_MATERIALS = ["own_initial_rationale", "assisting_model_commentary"];
const MODEL_ASSISTED_CHECK_REQUIRED_EXPOSURE_TIMING = "post_human_only_self_check_lock";
export const MODEL_FAMILY_OVERLAP_POLICY_VERSION = "model-family-overlap-rlhf90-v1";
export const REQUIRED_MODEL_FAMILY_OVERLAP_MATCH_BASES = [
  "exact_resolved_snapshot",
  "exact_requested_alias",
  "declared_model_family",
  "inferred_model_family",
];
export const REQUIRED_MODEL_FAMILY_OVERLAP_FORBIDDEN_BASES = ["provider_only", "organization_only", "deployment_region_only"];
export const REQUIRED_MODEL_FAMILY_OVERLAP_CLEAN_CLAIM_ACTIONS = [
  "require_human_only_pre_assistance_target",
  "label_overlap_sensitive",
  "suppress_clean_independent_claim",
];
export const REQUIRED_MODEL_FAMILY_OVERLAP_POLICY_RULES = {
  exactSnapshot:
    "An exact resolved model snapshot match between the assisting model and evaluated model is always overlap-sensitive.",
  exactAlias:
    "An exact requested model alias match between the assisting model and evaluated model is overlap-sensitive when a resolved snapshot is absent or shared.",
  familyMatch:
    "Declared or inferred close model-family matches are overlap-sensitive because variants can share training, behavior, or label-assistance contamination.",
  providerOnlyExclusion:
    "Provider-only, organization-only, endpoint-only, and deployment-region-only matches are not sufficient by themselves for close-family overlap.",
  cleanClaim:
    "Clean independent leaderboard claims require an overlap-free target, a human-only pre-assistance target snapshot, or explicit overlap-sensitive labeling.",
  sourceBoundary:
    "Project default close model-family overlap rules are frozen here; LMCA motivates model-assisted contamination separation but does not state exact family-match rules.",
};

function defaultModelFamilyOverlapPolicy(releaseId = "october-2026-demo") {
  return {
    id: `model-family-overlap-policy-${releaseId}`,
    policyVersion: MODEL_FAMILY_OVERLAP_POLICY_VERSION,
    overlapMatchBases: REQUIRED_MODEL_FAMILY_OVERLAP_MATCH_BASES,
    forbiddenOverlapBases: REQUIRED_MODEL_FAMILY_OVERLAP_FORBIDDEN_BASES,
    cleanClaimActions: REQUIRED_MODEL_FAMILY_OVERLAP_CLEAN_CLAIM_ACTIONS,
    policyRules: REQUIRED_MODEL_FAMILY_OVERLAP_POLICY_RULES,
    exactSnapshotRule: REQUIRED_MODEL_FAMILY_OVERLAP_POLICY_RULES.exactSnapshot,
    exactAliasRule: REQUIRED_MODEL_FAMILY_OVERLAP_POLICY_RULES.exactAlias,
    familyMatchRule: REQUIRED_MODEL_FAMILY_OVERLAP_POLICY_RULES.familyMatch,
    providerOnlyExclusionRule: REQUIRED_MODEL_FAMILY_OVERLAP_POLICY_RULES.providerOnlyExclusion,
    cleanClaimRule: REQUIRED_MODEL_FAMILY_OVERLAP_POLICY_RULES.cleanClaim,
    sourceBoundary: REQUIRED_MODEL_FAMILY_OVERLAP_POLICY_RULES.sourceBoundary,
    frozenAt: "2026-10-01T00:00:00.000Z",
  };
}

function normalizeModelFamilyOverlapPolicy(policy, rowSource) {
  const id = policy?.id ?? policy?.modelFamilyOverlapPolicyId ?? policy?.model_family_overlap_policy_id;
  if (!id) return null;
  const overlapMatchBases = uniqueStrings(normalizeStringArray(policy.overlapMatchBases ?? policy.matchBases));
  const forbiddenOverlapBases = uniqueStrings(normalizeStringArray(policy.forbiddenOverlapBases ?? policy.forbiddenBases));
  const cleanClaimActions = uniqueStrings(normalizeStringArray(policy.cleanClaimActions ?? policy.cleanClaimRequirements));
  const policyRules =
    policy.policyRules && typeof policy.policyRules === "object" && !Array.isArray(policy.policyRules) ? policy.policyRules : {};
  const missingMatchBases = REQUIRED_MODEL_FAMILY_OVERLAP_MATCH_BASES.filter((basis) => !overlapMatchBases.includes(basis));
  const missingForbiddenBases = REQUIRED_MODEL_FAMILY_OVERLAP_FORBIDDEN_BASES.filter((basis) => !forbiddenOverlapBases.includes(basis));
  const missingCleanClaimActions = REQUIRED_MODEL_FAMILY_OVERLAP_CLEAN_CLAIM_ACTIONS.filter((action) => !cleanClaimActions.includes(action));
  const missingRuleKeys = Object.keys(REQUIRED_MODEL_FAMILY_OVERLAP_POLICY_RULES).filter((key) => !Object.hasOwn(policyRules, key));
  const reviewReasons = [
    (policy.policyVersion ?? policy.version) === MODEL_FAMILY_OVERLAP_POLICY_VERSION
      ? null
      : `policyVersion:${MODEL_FAMILY_OVERLAP_POLICY_VERSION}`,
    missingMatchBases.length ? `overlapMatchBases:${missingMatchBases.join(",")}` : null,
    stableJsonKey(overlapMatchBases) === stableJsonKey(REQUIRED_MODEL_FAMILY_OVERLAP_MATCH_BASES) ? null : "overlapMatchBases",
    missingForbiddenBases.length ? `forbiddenOverlapBases:${missingForbiddenBases.join(",")}` : null,
    stableJsonKey(forbiddenOverlapBases) === stableJsonKey(REQUIRED_MODEL_FAMILY_OVERLAP_FORBIDDEN_BASES) ? null : "forbiddenOverlapBases",
    missingCleanClaimActions.length ? `cleanClaimActions:${missingCleanClaimActions.join(",")}` : null,
    stableJsonKey(cleanClaimActions) === stableJsonKey(REQUIRED_MODEL_FAMILY_OVERLAP_CLEAN_CLAIM_ACTIONS) ? null : "cleanClaimActions",
    missingRuleKeys.length ? `policyRules:${missingRuleKeys.join(",")}` : null,
    stableJsonKey(policyRules) === stableJsonKey(REQUIRED_MODEL_FAMILY_OVERLAP_POLICY_RULES) ? null : "policyRules",
    policyMentions(policy.exactSnapshotRule ?? policyRules.exactSnapshot, ["exact resolved model snapshot", "overlap-sensitive"])
      ? null
      : "exactSnapshotRule",
    policyMentions(policy.exactAliasRule ?? policyRules.exactAlias, ["exact requested model alias", "overlap-sensitive"])
      ? null
      : "exactAliasRule",
    policyMentions(policy.familyMatchRule ?? policyRules.familyMatch, ["close model-family", "overlap-sensitive"])
      ? null
      : "familyMatchRule",
    policyMentions(policy.providerOnlyExclusionRule ?? policyRules.providerOnlyExclusion, ["provider-only", "not sufficient"])
      ? null
      : "providerOnlyExclusionRule",
    policyMentions(policy.cleanClaimRule ?? policyRules.cleanClaim, ["clean independent", "human-only pre-assistance", "overlap-sensitive"])
      ? null
      : "cleanClaimRule",
    policyMentions(policy.sourceBoundary, ["project default", "lmca", "does not state"]) ? null : "sourceBoundary",
    requiredPromptFieldReason("frozenAt", policy.frozenAt),
  ].filter(Boolean);
  return {
    id,
    rowSource,
    policyVersion: policy.policyVersion ?? policy.version ?? null,
    overlapMatchBases,
    forbiddenOverlapBases,
    cleanClaimActions,
    policyRules,
    exactSnapshotRule: policy.exactSnapshotRule ?? policyRules.exactSnapshot ?? null,
    exactAliasRule: policy.exactAliasRule ?? policyRules.exactAlias ?? null,
    familyMatchRule: policy.familyMatchRule ?? policyRules.familyMatch ?? null,
    providerOnlyExclusionRule: policy.providerOnlyExclusionRule ?? policyRules.providerOnlyExclusion ?? null,
    cleanClaimRule: policy.cleanClaimRule ?? policyRules.cleanClaim ?? null,
    sourceBoundary: policy.sourceBoundary ?? null,
    frozenAt: policy.frozenAt ?? null,
    reviewReasons,
    status: reviewReasons.length ? "model_family_overlap_policy_review_required" : "model_family_overlap_policy_complete",
  };
}

function buildModelFamilyOverlapPolicyEvidence(releaseId, submittedPolicies = []) {
  const submittedRows = submittedPolicies
    .map((policy) => normalizeModelFamilyOverlapPolicy(policy, "submitted_workflow_model_family_overlap_policy"))
    .filter(Boolean);
  const seedRows = [normalizeModelFamilyOverlapPolicy(defaultModelFamilyOverlapPolicy(releaseId), "seed_model_family_overlap_policy")];
  const activePolicy = submittedRows.find((row) => row.reviewReasons.length === 0) ?? seedRows[0];
  const reviewRows = submittedRows.filter((row) => row.reviewReasons.length);
  return {
    id: `model-family-overlap-policy-evidence-${releaseId}`,
    releaseId,
    requiredOverlapMatchBases: REQUIRED_MODEL_FAMILY_OVERLAP_MATCH_BASES,
    requiredForbiddenOverlapBases: REQUIRED_MODEL_FAMILY_OVERLAP_FORBIDDEN_BASES,
    requiredCleanClaimActions: REQUIRED_MODEL_FAMILY_OVERLAP_CLEAN_CLAIM_ACTIONS,
    requiredPolicyRules: REQUIRED_MODEL_FAMILY_OVERLAP_POLICY_RULES,
    policyRows: [...seedRows, ...submittedRows],
    activePolicy,
    activePolicyId: activePolicy?.id ?? null,
    reviewRows,
    counts: {
      submittedPolicyCount: submittedRows.length,
      reviewRequiredPolicyCount: reviewRows.length,
    },
    releaseUseStatus: !submittedRows.length
      ? "seed_model_family_overlap_policy_active"
      : reviewRows.length
        ? "submitted_model_family_overlap_policy_review_required"
        : "submitted_model_family_overlap_policy_active",
  };
}

export function buildModelAssistedLabelOverlapReport(
  releaseId,
  labelSnapshot,
  ratings = seedRatings,
  runs = [fullRubricEvaluationRun, overallOnlyEvaluationRun],
  pairs = critiques.map((critique) => ({ positionId: critique.positionId, critiqueId: critique.id })),
  options = {},
) {
  const snapshotItemIds = new Set(Object.keys(labelSnapshot.itemLabels));
  const ratingById = new Map(ratings.map((rating) => [rating.id, rating]));
  const modelFamilyOverlapPolicyEvidence = buildModelFamilyOverlapPolicyEvidence(releaseId, options.modelFamilyOverlapPolicies ?? []);
  const activeModelFamilyOverlapPolicy = modelFamilyOverlapPolicyEvidence.activePolicy;
  const modelProviderPolicyRows = (options.modelProviderDataHandlingPolicies?.length
    ? options.modelProviderDataHandlingPolicies
    : defaultModelProviderDataHandlingPolicies(releaseId)
  )
    .map((policy) => normalizeModelProviderDataHandlingPolicy(policy, "model_assisted_check_provider_policy"))
    .filter(Boolean);
  const targetModelAssistedRows = [
    ...ratings
    .filter(hasModelAssistedExposure)
    .map((rating) => modelAssistedRatingRow(rating))
      .filter((row) => snapshotItemIds.has(row.itemId)),
    ...(options.ratingChecks ?? [])
      .map((ratingCheck) => modelAssistedRatingCheckRow(ratingCheck, ratingById))
      .filter((row) => row && snapshotItemIds.has(row.itemId)),
  ].map((row) => ({
    ...row,
    modelFamilyOverlapPolicyId: activeModelFamilyOverlapPolicy?.id ?? null,
    modelProviderPolicyBinding: modelProviderPolicyBindingForRunClass(
      { runSource: row.assistanceSource },
      "model_assisted_check",
      row.modelProviderDataHandlingPolicyId,
      modelProviderPolicyRows,
      { requireExplicitPolicyId: row.assistanceSource === "submitted_workflow_rating_check" },
    ),
  }));
  const humanOnlyRatings = ratings.filter((rating) => !hasModelAssistedExposure(rating));
  const humanOnlySnapshot =
    options.humanOnlyPreAssistanceSnapshot ??
    createLabelSnapshot(`snapshot-${releaseId}-human-only-pre-assistance`, releaseId, humanOnlyRatings, pairs, "human_only_pre_assistance");
  const runRows = runs.map((run) => {
    const evaluatedModel = modelIdentityForRun(run);
    const overlapRows = targetModelAssistedRows
      .map((row) => ({
        ...row,
        modelFamilyOverlapPolicyId: activeModelFamilyOverlapPolicy?.id ?? null,
        overlapBasis: modelOverlapBasis(evaluatedModel, row.assistingModel, activeModelFamilyOverlapPolicy),
      }))
      .filter((row) => row.overlapBasis !== "none");
    const status =
      targetModelAssistedRows.length === 0
        ? "no_model_assisted_target_rows"
        : overlapRows.length > 0
          ? "model_assisted_label_overlap_sensitive"
          : "model_assisted_rows_present_no_evaluated_model_overlap";
    return {
      evaluationRunId: run.id,
      requestedModelAlias: run.requestedModelAlias,
      resolvedModelSnapshot: run.resolvedModelSnapshot,
      modelProvider: evaluatedModel.provider,
      modelFamily: evaluatedModel.modelFamily,
      targetModelAssistedRatingCount: targetModelAssistedRows.length,
      overlappingAssistedRatingCount: overlapRows.length,
      overlapItemIds: uniqueStrings(overlapRows.map((row) => row.itemId)).sort(),
      overlapRows,
      status,
      cleanClaimStatus:
        status === "model_assisted_label_overlap_sensitive"
          ? "clean_claim_requires_human_only_pre_assistance_target_or_overlap_sensitive_label"
          : status === "model_assisted_rows_present_no_evaluated_model_overlap"
            ? "clean_claim_allowed_with_assisted_label_rows_disclosed"
            : "clean_claim_allowed_no_model_assisted_label_exposure",
      humanOnlyPreAssistanceTargetRequired: status === "model_assisted_label_overlap_sensitive",
      humanOnlyPreAssistanceTargetSnapshotId: humanOnlySnapshot.id,
    };
  });
  const overlapRunRows = runRows.filter((row) => row.status === "model_assisted_label_overlap_sensitive");
  const reviewSections = targetModelAssistedRows.flatMap((row) =>
    [
      ...(row.reviewReasons ?? []),
      ...(row.modelProviderPolicyBinding?.reviewReasons ?? []).map((reason) => `modelProviderPolicy.${reason}`),
    ].map((reason) => ({
      artifactType: row.assistanceSource,
      artifactId: row.ratingCheckId ?? row.ratingId,
      reason,
    })),
  );
  const policyReviewSections = modelFamilyOverlapPolicyEvidence.reviewRows.flatMap((row) =>
    row.reviewReasons.map((reason) => ({
      artifactType: "model_family_overlap_policy",
      artifactId: row.id,
      reason,
    })),
  );
  const allReviewSections = [...reviewSections, ...policyReviewSections];
  return {
    id: `model-assisted-label-overlap-${releaseId}-${labelSnapshot.id}`,
    releaseId,
    targetLabelSnapshotId: labelSnapshot.id,
    targetLabelVersion: labelSnapshot.targetLabelVersion,
    generatedAt: new Date().toISOString(),
    policy: {
      closeModelFamilyDefinition: activeModelFamilyOverlapPolicy?.familyMatchRule ?? REQUIRED_MODEL_FAMILY_OVERLAP_POLICY_RULES.familyMatch,
      cleanClaimRule: activeModelFamilyOverlapPolicy?.cleanClaimRule ?? REQUIRED_MODEL_FAMILY_OVERLAP_POLICY_RULES.cleanClaim,
      providerOnlyExclusionRule:
        activeModelFamilyOverlapPolicy?.providerOnlyExclusionRule ?? REQUIRED_MODEL_FAMILY_OVERLAP_POLICY_RULES.providerOnlyExclusion,
      modelAssistedRowsIndependentHumanEvidence: false,
      preAssistanceTargetPolicy:
        "Rows with model-assisted exposure are excluded from the human-only/pre-assistance target; blind initial, self-check, expert-check, adjudication, and unassisted revision rows remain eligible.",
    },
    modelFamilyOverlapPolicyEvidence,
    modelFamilyOverlapPolicyId: activeModelFamilyOverlapPolicy?.id ?? null,
    counts: {
      targetLabelItemCount: snapshotItemIds.size,
      targetModelAssistedRatingRows: targetModelAssistedRows.length,
      submittedRatingCheckRows: options.ratingChecks?.length ?? 0,
      submittedModelAssistedRatingCheckRows: targetModelAssistedRows.filter((row) => row.assistanceSource === "submitted_workflow_rating_check").length,
      submittedModelAssistedRatingCheckReviewRows: targetModelAssistedRows.filter(
        (row) => row.assistanceSource === "submitted_workflow_rating_check" && (row.reviewReasons ?? []).length,
      ).length,
      submittedModelAssistedProviderPolicyReviewRows: targetModelAssistedRows.filter(
        (row) => row.assistanceSource === "submitted_workflow_rating_check" && (row.modelProviderPolicyBinding?.reviewReasons ?? []).length,
      ).length,
      evaluatedRunCount: runRows.length,
      overlapSensitiveRunCount: overlapRunRows.length,
      modelFamilyOverlapPolicyReviewRows: modelFamilyOverlapPolicyEvidence.reviewRows.length,
      reviewSectionCount: allReviewSections.length,
    },
    assistanceRows: targetModelAssistedRows,
    runRows,
    reviewSections: allReviewSections,
    humanOnlyPreAssistanceTarget: {
      id: humanOnlySnapshot.id,
      targetLabelVersion: humanOnlySnapshot.targetLabelVersion,
      status: "human_only_pre_assistance",
      itemCount: Object.keys(humanOnlySnapshot.itemLabels).length,
      denominatorCounts: humanOnlySnapshot.denominatorCounts,
      excludedModelAssistedRows: targetModelAssistedRows.length,
      sameAsTargetLabelSnapshot: targetModelAssistedRows.length === 0,
    },
    releaseUseStatus:
      policyReviewSections.length > 0
        ? "model_family_overlap_policy_review_required"
        : reviewSections.length > 0
        ? "model_assisted_rating_check_review_required"
        : overlapRunRows.length > 0
        ? "model_assisted_overlap_sensitive_reports_require_human_only_target"
        : targetModelAssistedRows.length > 0
          ? "model_assisted_rows_disclosed_no_evaluated_model_overlap"
          : "clean_no_model_assisted_label_overlap",
  };
}

export function buildReasoningModeSensitivityReport(
  releaseId,
  runs = [fullRubricEvaluationRun, overallOnlyEvaluationRun],
  options = {},
) {
  const pairedComparisons = options.pairedComparisons ?? [];
  return {
    id: `reasoning-mode-sensitivity-${releaseId}`,
    releaseId,
    table6SourceBaseline: LMCA_BASELINES.reasoningModeTable6,
    runRows: runs.map((run) => ({
      evaluationRunId: run.id,
      requestedModelAlias: run.requestedModelAlias,
      resolvedModelSnapshot: run.resolvedModelSnapshot,
      promptFamily: run.promptFamily,
      promptScope: run.promptScope,
      reasoningMode: run.reasoningMode ?? (run.mode === "overall_only" ? "step_by_step_prompt_text" : "not_requested"),
      reasoningBudgetTokens: run.reasoningBudgetTokens ?? null,
      answerExtractionPolicy:
        run.answerExtractionPolicy ?? (run.mode === "overall_only" ? "extract_overall_json_only_no_full_rubric_imputation" : "extract_all_seven_dimensions_from_json"),
      itemRoleTerminology: run.itemRoleTerminology ?? (run.promptScope === "appendix_g_overall_only_exact" ? "legacy_argument_wording" : "position_critique"),
    })),
    pairedComparisons,
    pairedComparisonPolicy:
      "A reasoning-mode effect requires same base model, same target label snapshot, same prompt family except thinking-mode instructions, same common item set, paired interval, and declared reasoning budget.",
    table6BaselineComparabilityStatus:
      pairedComparisons.length > 0 ? "lmca_table_6_style_seed_pair_available" : "lmca_table_6_anchors_declared_no_seed_pair_available",
    status: pairedComparisons.length > 0 ? "paired_reasoning_mode_sensitivity_reported" : "no_paired_reasoning_mode_run_deferred",
    deferredRationale:
      pairedComparisons.length > 0
        ? null
        : "The seed demo includes mixed prompt families but no same-model with-versus-without-thinking run, so no reasoning-mode benefit or harm is claimed.",
    releaseUseStatus: pairedComparisons.length > 0 ? "reasoning_mode_comparison_claims_limited_to_paired_rows" : "reasoning_mode_claims_not_supported_seed_demo",
  };
}

function buildClaimGatedModelDiagnostics(run, options = {}) {
  const robustnessClaims = options.robustnessClaims ?? [];
  const sycophancyProbeRuns = (options.sycophancyProbeRuns ?? []).filter((probeRun) => probeRunMatchesEvaluation(probeRun, run.id));
  const obfuscationStressRuns = (options.obfuscationStressRuns ?? []).filter((stressRun) => probeRunMatchesEvaluation(stressRun, run.id));
  const approvedDeferrals = (options.diagnosticDeferralRecords ?? [])
    .map((record) => normalizeDiagnosticDeferralRecord(record, null, "submitted_workflow_diagnostic_deferral_record"))
    .filter((row) => row?.status === "diagnostic_deferral_complete" && (!row.evaluationId || row.evaluationId === run.id));
  const sycophancyDeferral = approvedDeferrals.find((row) => diagnosticDeferralMatchesSuite(row, "sycophancy_orthodoxy_sensitivity")) ?? null;
  const obfuscationDeferral = approvedDeferrals.find((row) => diagnosticDeferralMatchesSuite(row, "obfuscated_argument_stress")) ?? null;
  const completedCueFamilies = uniqueStrings(
    sycophancyProbeRuns.flatMap((probeRun) => normalizeSycophancyCueFamilies(probeRun.cueTypesTested ?? probeRun.cueFamiliesTested ?? [])),
  );
  const missingCueFamilies = REQUIRED_SYCOPHANCY_ORTHODOXY_CUE_FAMILIES.filter((cueFamily) => !completedCueFamilies.includes(cueFamily));
  const completedVariantFamilies = uniqueStrings(obfuscationStressRuns.flatMap((stressRun) => stressRun.variantFamilies ?? []));
  const missingVariantFamilies = OBFUSCATION_STRESS_VARIANT_FAMILIES.filter((variantFamily) => !completedVariantFamilies.includes(variantFamily));
  const sycophancyClaimMade = robustnessClaims.some((claimValue) => robustnessClaimRequiresSuite(claimValue, "sycophancy_orthodoxy_sensitivity"));
  const obfuscationClaimMade = robustnessClaims.some((claimValue) => robustnessClaimRequiresSuite(claimValue, "obfuscated_argument_stress"));
  const missingDiagnosticStatus = (claimMade, approvedDeferral) =>
    claimMade
      ? approvedDeferral
        ? "deferred_claim_suppressed_by_ledger"
        : "required_not_run_claim_blocking"
      : "deferred_no_robustness_claim";
  const sycophancyStatus = sycophancyProbeRuns.length
    ? missingCueFamilies.length
      ? "diagnostic_coverage_review_required"
      : "completed_diagnostic_attached"
    : missingDiagnosticStatus(sycophancyClaimMade, sycophancyDeferral);
  const obfuscationStatus = obfuscationStressRuns.length
    ? missingVariantFamilies.length
      ? "diagnostic_coverage_review_required"
      : "completed_diagnostic_attached"
    : missingDiagnosticStatus(obfuscationClaimMade, obfuscationDeferral);
  const coverageReviewRequired = sycophancyStatus === "diagnostic_coverage_review_required" || obfuscationStatus === "diagnostic_coverage_review_required";
  const missingRequiredDiagnostics =
    (sycophancyClaimMade && sycophancyStatus === "required_not_run_claim_blocking") ||
    (obfuscationClaimMade && obfuscationStatus === "required_not_run_claim_blocking");
  const suppressedByLedger =
    sycophancyStatus === "deferred_claim_suppressed_by_ledger" || obfuscationStatus === "deferred_claim_suppressed_by_ledger";
  return {
    evaluationRunId: run.id,
    requestedModelAlias: run.requestedModelAlias,
    resolvedModelSnapshot: run.resolvedModelSnapshot,
    robustnessClaims,
    suites: [
      {
        id: "sycophancy_orthodoxy_sensitivity",
        status: sycophancyStatus,
        completedRunIds: sycophancyProbeRuns.map((probeRun) => probeRun.id),
        cueFamilies: REQUIRED_SYCOPHANCY_ORTHODOXY_CUE_FAMILIES,
        completedCueFamilies,
        missingCueFamilies,
        requiredWhenClaiming: ["deference_robustness", "orthodoxy_robustness", "user_agreement_resistance"],
        pairedCommonSetRequired: true,
        approvedDeferral: sycophancyDeferral ? diagnosticDeferralEvidenceRef(sycophancyDeferral) : null,
        notRunRationale: sycophancyProbeRuns.length
          ? missingCueFamilies.length
            ? `Submitted sycophancy/orthodoxy runs are missing cue families: ${missingCueFamilies.join(", ")}.`
            : null
          : sycophancyStatus === "deferred_claim_suppressed_by_ledger"
            ? sycophancyDeferral.approvedWeakerClaimWording
          : sycophancyClaimMade
            ? "Robustness claims were requested but no paired sycophancy/orthodoxy probe outputs are attached."
            : "The seed demo makes no deference, authority, consensus, safety, or orthodoxy robustness claim.",
      },
      {
        id: "obfuscated_argument_stress",
        status: obfuscationStatus,
        completedRunIds: obfuscationStressRuns.map((stressRun) => stressRun.id),
        variantFamilies: OBFUSCATION_STRESS_VARIANT_FAMILIES,
        completedVariantFamilies,
        missingVariantFamilies,
        requiredWhenClaiming: ["obfuscation_robustness", "style_artifact_robustness", "masked_fallacy_detection"],
        pairedCommonSetRequired: true,
        approvedDeferral: obfuscationDeferral ? diagnosticDeferralEvidenceRef(obfuscationDeferral) : null,
        notRunRationale: obfuscationStressRuns.length
          ? missingVariantFamilies.length
            ? `Submitted obfuscation stress runs are missing variant families: ${missingVariantFamilies.join(", ")}.`
            : null
          : obfuscationStatus === "deferred_claim_suppressed_by_ledger"
            ? obfuscationDeferral.approvedWeakerClaimWording
          : obfuscationClaimMade
            ? "Robustness claims were requested but no paired obfuscated-argument stress outputs are attached."
            : "The seed demo includes obfuscated-style rubric fixtures but does not claim model robustness on stress variants.",
      },
    ],
    releaseUseStatus: missingRequiredDiagnostics
      ? "robustness_claim_blocked_until_claim_gated_probes_run"
      : coverageReviewRequired
        ? "claim_gated_diagnostics_coverage_review_required"
      : suppressedByLedger
        ? "claim_gated_diagnostics_deferred_with_claim_suppression"
      : sycophancyProbeRuns.length || obfuscationStressRuns.length
        ? "claim_gated_diagnostics_attached_no_robustness_claim"
        : "claim_gated_diagnostics_deferred_no_robustness_claim",
  };
}

function robustnessClaimRequiresSuite(claimValue, suiteId) {
  const normalized = normalizeDiagnosticText(claimValue);
  const suiteFragments = diagnosticSuiteFragments(suiteId);
  const anyKnownFragment = [...diagnosticSuiteFragments("sycophancy_orthodoxy_sensitivity"), ...diagnosticSuiteFragments("obfuscated_argument_stress")]
    .some((fragment) => normalized.includes(fragment));
  return suiteFragments.some((fragment) => normalized.includes(fragment)) || !anyKnownFragment;
}

function diagnosticDeferralMatchesSuite(deferral, suiteId) {
  const haystack = normalizeDiagnosticText(`${deferral.diagnosticName ?? ""} ${deferral.claimAffected ?? ""}`);
  return diagnosticSuiteFragments(suiteId).some((fragment) => haystack.includes(fragment));
}

function diagnosticSuiteFragments(suiteId) {
  if (suiteId === "sycophancy_orthodoxy_sensitivity") {
    return ["sycophancy", "orthodoxy", "deference", "authority", "consensus", "user_agreement", "safety_orthodoxy"];
  }
  if (suiteId === "obfuscated_argument_stress") {
    return ["obfuscation", "obfuscated", "style_artifact", "masked_fallacy", "fluent_jargon", "surface_fluency"];
  }
  return [];
}

function normalizeDiagnosticText(value) {
  return String(value ?? "").trim().toLowerCase().replace(/[-\s]+/g, "_");
}

function diagnosticDeferralEvidenceRef(deferral) {
  return {
    id: deferral.id,
    diagnosticName: deferral.diagnosticName,
    claimAffected: deferral.claimAffected,
    notRunReason: deferral.notRunReason,
    approvedWeakerClaimWording: deferral.approvedWeakerClaimWording,
    reviewerId: deferral.reviewerId,
    reviewerRole: deferral.reviewerRole,
  };
}

function normalizeSycophancyCueFamilies(cueTypes = []) {
  return uniqueStrings(
    cueTypes.flatMap((cueType) => {
      if (cueType === "user_endorses_position" || cueType === "user_disagrees_position") return ["user_agreement"];
      if (cueType === "safety_or_orthodoxy_frame") return ["safety_orthodoxy"];
      if (cueType === "majority_consensus" || cueType === "majority_cue") return ["consensus"];
      if (cueType === "expert_authority" || cueType === "institutional_authority") return ["authority"];
      if (cueType === "no_cue_control") return [];
      return [cueType];
    }),
  );
}

function probeRunMatchesEvaluation(probeRun, evaluationRunId) {
  if (!probeRun || typeof probeRun !== "object") return false;
  if (probeRun.evaluationRunId === evaluationRunId) return true;
  if (probeRun.linkedEvaluationRunId === evaluationRunId) return true;
  if (Array.isArray(probeRun.pairedEvaluationRunIds) && probeRun.pairedEvaluationRunIds.includes(evaluationRunId)) return true;
  if (Array.isArray(probeRun.evaluationRunIds) && probeRun.evaluationRunIds.includes(evaluationRunId)) return true;
  return false;
}

export function buildModelFailureAudit(
  releaseId,
  labelSnapshot,
  run = fullRubricEvaluationRun,
  positionList = positions,
  critiqueList = critiques,
  options = {},
) {
  const excludedProtectedSplits = options.excludedProtectedSplits ?? ["internal_validation", "hidden_benchmark"];
  const rowLimit = options.rowLimit ?? 3;
  const positionById = new Map(positionList.map((position) => [position.id, position]));
  const critiqueById = new Map(critiqueList.map((critique) => [critique.id, critique]));
  const modelAssistedLabelOverlapReport =
    options.modelAssistedLabelOverlapReport ??
    buildModelAssistedLabelOverlapReport(
      releaseId,
      labelSnapshot,
      options.ratings ?? seedRatings,
      [run],
      critiqueList.map((critique) => ({ positionId: critique.positionId, critiqueId: critique.id })),
      { modelFamilyOverlapPolicies: options.modelFamilyOverlapPolicies ?? [] },
    );
  const modelAssistedLabelOverlap =
    modelAssistedLabelOverlapReport.runRows.find((row) => row.evaluationRunId === run.id) ??
    modelAssistedLabelOverlapReport.runRows[0] ??
    null;
  const allRows = run.predictions
    .map((prediction) => buildFailureAuditRow(prediction, labelSnapshot, positionById, critiqueById, run))
    .filter(Boolean);
  const protectedRows = allRows.filter((row) => excludedProtectedSplits.includes(row.split));
  const eligibleRows = allRows.filter((row) => !excludedProtectedSplits.includes(row.split));
  const topCustomLossRows = eligibleRows
    .filter((row) => typeof row.customWeightedLoss === "number")
    .sort((a, b) => b.customWeightedLoss - a.customWeightedLoss || b.overallAbsError - a.overallAbsError || a.itemId.localeCompare(b.itemId))
    .slice(0, rowLimit);
  const largestOverallDisagreements = eligibleRows
    .filter((row) => typeof row.overallAbsError === "number")
    .sort((a, b) => b.overallAbsError - a.overallAbsError || a.itemId.localeCompare(b.itemId))
    .slice(0, rowLimit);
  return {
    id: `model-failure-audit-${releaseId}-${run.id}`,
    releaseId,
    evaluationRunId: run.id,
    metricFamilies: run.mode === "full_rubric" ? ["custom_weighted_loss", "overall_disagreement"] : ["overall_disagreement"],
    leaderboardReportId: options.leaderboardReportId ?? null,
    targetLabelSnapshotId: labelSnapshot.id,
    targetLabelVersion: labelSnapshot.targetLabelVersion,
    selectionPolicy: "deterministic_top_loss_then_largest_overall_disagreement",
    commonSubsetPolicy: "non_protected_predictions_with_target_labels",
    promptTemplateId: run.predictions[0]?.promptTemplateId ?? null,
    promptArtifact: run.promptArtifact ?? promptArtifactRef(run.predictions[0]?.promptTemplateId ?? "project-full-rubric-v1"),
    renderedPromptChecksum: run.renderedPromptChecksum ?? run.predictions[0]?.renderedPromptChecksum ?? null,
    promptPolicyComparabilityStatus: run.promptPolicyComparabilityStatus ?? "missing_prompt_policy",
    promptExampleProvenance: run.promptExampleProvenance ?? [],
    protectedPromptExampleCheck: run.protectedPromptExampleCheck ?? null,
    acceptedOutputSchema: run.acceptedOutputSchema ?? null,
    promptFamily: run.promptFamily,
    promptScope: run.promptScope,
    parserConfigId: run.parserConfigId,
    reasoningModeSetting: run.mode === "overall_only" ? "appendix_g_step_by_step_overall_only_baseline" : "project_full_rubric_answer_extraction",
    protectedSplitHandling: {
      excludedProtectedSplits,
      protectedPredictionCount: protectedRows.length,
      protectedItemsRedacted: protectedRows.map((row) => ({ split: row.split, itemHash: `sha256:${row.itemId}:redacted` })),
      policy: "audit rows in release reports exclude protected validation and hidden benchmark contents unless an admin-only report explicitly deprotects the cluster",
    },
    parserAudit: {
      parseFailureCount: run.parseFailureCount,
      invalidScoreCount: run.invalidScoreCount,
      retryCount: run.retryCount,
      repairedOutputCount: run.repairedOutputCount,
    },
    modelAssistedLabelOverlap,
    claimGatedDiagnostics: buildClaimGatedModelDiagnostics(run, options),
    topCustomLossRows,
    largestOverallDisagreements,
    diagnosticOnly: true,
    cannotReplaceAggregateMetrics: true,
    createdBy: "deterministic_local_report",
    createdAt: new Date().toISOString(),
  };
}

export function buildValidationTrancheReport(
  releaseId,
  labelSnapshot,
  ratings = seedRatings,
  positionList = positions,
  critiqueList = critiques,
  memos = adjudicationMemos,
  options = {},
) {
  const positionById = new Map(positionList.map((position) => [position.id, position]));
  const memoByItemId = new Map(memos.map((memo) => [makeItemId(memo.positionId, memo.critiqueId), memo]));
  const validationCritiques = critiqueList.filter((critique) => positionById.get(critique.positionId)?.split === "internal_validation");
  const trancheRows = VALIDATION_TRANCHE_TYPES.map((tranche) => {
    const trancheCritiques = validationCritiques.filter((critique) => validationTrancheForCritique(critique) === tranche);
    const itemIds = trancheCritiques.map((critique) => makeItemId(critique.positionId, critique.id)).sort();
    const positionIds = uniqueStrings(trancheCritiques.map((critique) => critique.positionId)).sort();
    const trancheRatings = ratings.filter((rating) => itemIds.includes(makeItemId(rating.positionId, rating.critiqueId)));
    const comparisonRows = ["blind_initial", "self_check", "expert_check", "model_assisted_check"].map((kind) =>
      humanCeilingComparisonRow(kind, trancheRatings, labelSnapshot, itemIds),
    );
    const unresolvedRows = itemIds
      .map((itemId) => {
        const label = labelSnapshot.itemLabels[itemId];
        const memo = memoByItemId.get(itemId);
        if (!label && !memo) return null;
        return {
          itemId,
          spreadPostDiscussion: label?.spreadPostDiscussion ?? null,
          maxSpreadAbove030: (label?.spreadPostDiscussion ?? 0) > 0.3,
          unresolvedDisagreementClass: memo?.unresolvedDisagreementClass ?? null,
          disagreementTaxonomy: memo?.disagreementTaxonomy ?? [],
        };
      })
      .filter((row) => row && (row.maxSpreadAbove030 || row.unresolvedDisagreementClass));
    const modelAssistedRow = comparisonRows.find((row) => row.ratingKind === "model_assisted_check");
    return {
      tranche,
      selectionPolicy:
        tranche === "random_sentinel"
          ? "random sentinel validation membership hidden until initial ratings lock where feasible"
          : "deliberately selected hard cases reported separately from random sentinel evidence",
      membershipBlindingStatus:
        tranche === "random_sentinel"
          ? "membership_hidden_until_initial_lock_where_feasible"
          : "hard_case_status_admin_only_until_initial_lock",
      positionCount: positionIds.length,
      critiqueCount: trancheCritiques.length,
      itemIds,
      positionIds,
      validationSelectionReasons: uniqueStrings(trancheCritiques.map((critique) => critique.validationSelectionReason)),
      membershipVisibilityPolicies: uniqueStrings(trancheCritiques.map((critique) => critique.validationMembershipVisibility)),
      ratingCountsByKind: countBy(trancheRatings, "kind"),
      comparisonRows,
      initialVsFinal: comparisonRows.find((row) => row.ratingKind === "blind_initial"),
      humanOnlySelfCheckedVsFinal: comparisonRows.find((row) => row.ratingKind === "self_check"),
      expertCheckedVsFinal: comparisonRows.find((row) => row.ratingKind === "expert_check"),
      modelAssistedCheckedVsFinal: modelAssistedRow,
      incrementalPostModelAssistanceDelta:
        modelAssistedRow?.rowCount > 0
          ? {
              status: "model_assisted_delta_rows_available",
              comparisonPolicy: "compare locked pre-assistance rating with post-model-assisted check on the same item",
            }
          : {
              status: "no_model_assisted_checks_in_tranche",
              comparisonPolicy: "do not infer incremental model-assistance value without paired pre/post rows",
            },
      unresolvedPostDiscussionRows: unresolvedRows,
    };
  });
  const randomSentinel = trancheRows.find((row) => row.tranche === "random_sentinel");
  const hardCaseStress = trancheRows.find((row) => row.tranche === "hard_case_stress");
  const submittedEvidenceRows = (options.validationTrancheEvidenceRecords ?? options.validationTrancheEvidence ?? [])
    .map((evidence) => normalizeValidationTrancheEvidence(evidence, releaseId, labelSnapshot))
    .filter(Boolean);
  const activeSubmittedEvidence =
    submittedEvidenceRows.find((row) => row.status === "validation_tranche_evidence_complete") ?? null;
  const reviewSections = submittedEvidenceRows.flatMap((row) =>
    row.reviewReasons.map((reason) => ({ artifactType: "validation_tranche_evidence", artifactId: row.id, reason })),
  );
  return {
    id: `validation-tranches-${releaseId}`,
    releaseId,
    targetLabelSnapshotId: labelSnapshot.id,
    targetLabelVersion: labelSnapshot.targetLabelVersion,
    generatedAt: new Date().toISOString(),
    policy: {
      randomSentinelPurpose: "Measures ordinary validation behavior without telling raters they are in the validation tranche before initial lock.",
      hardCaseStressPurpose: "Retains deliberately difficult or artifact-prone cases without letting them masquerade as random validation evidence.",
      combinedValidationClaimPolicy:
        "Combined validation summaries may be shown, but release claims must keep random-sentinel and hard-case stress metrics separately visible.",
      requiredComparisonRows: ["initial_vs_final", "human_only_self_checked_vs_final", "model_assisted_checked_vs_final", "incremental_post_model_assistance_delta"],
    },
    trancheRows,
    randomSentinel,
    hardCaseStress,
    submittedValidationTrancheEvidence: {
      rows: submittedEvidenceRows,
      activeEvidenceId: activeSubmittedEvidence?.id ?? null,
      submittedEvidenceCount: submittedEvidenceRows.length,
      completeEvidenceCount: submittedEvidenceRows.filter((row) => row.status === "validation_tranche_evidence_complete").length,
      reviewRequiredCount: submittedEvidenceRows.filter((row) => row.status !== "validation_tranche_evidence_complete").length,
      status: activeSubmittedEvidence
        ? "submitted_validation_tranche_evidence_complete"
        : submittedEvidenceRows.length
          ? "submitted_validation_tranche_evidence_review_required"
          : "no_submitted_validation_tranche_evidence",
    },
    reviewSections,
    releaseUseStatus: reviewSections.length
      ? "validation_tranche_evidence_review_required"
      : activeSubmittedEvidence
        ? "submitted_validation_tranche_evidence_complete"
        : randomSentinel?.critiqueCount > 0 && hardCaseStress?.critiqueCount > 0
          ? "validation_tranches_separated_seed_thin"
          : "validation_tranche_design_incomplete",
  };
}

const RELEASE_CYCLE_VALIDATION_POLICY = {
  cadence: "each_public_release_or_leaderboard_cycle",
  carryForwardAllowedReleaseCycles: 0,
  requiredSubsets: ["random_sentinel", "hard_case_stress"],
  requiredComparisons: ["initial_vs_final", "human_only_self_checked_vs_final", "model_assisted_checked_vs_final", "incremental_post_model_assistance_delta"],
  requiredCeilingEvidence: ["human_ceiling_estimate", "per_dimension_rater_calibration", "individual_rater_dominance", "expert_vs_model_agreement"],
  staleEvidenceAction: "rerun_or_rebaseline_before_appendix_c_or_leaderboard_claim",
};

export function buildValidationDesignReport(ratings = seedRatings, positionList = positions, critiqueList = critiques, options = {}) {
  const validationPositionIds = new Set(positionList.filter((position) => position.split === "internal_validation").map((position) => position.id));
  const validationCritiqueIds = critiqueList.filter((critique) => validationPositionIds.has(critique.positionId)).map((critique) => critique.id);
  const validationItemIds = new Set(critiqueList.filter((critique) => validationPositionIds.has(critique.positionId)).map((critique) => makeItemId(critique.positionId, critique.id)));
  const coverageByRater = {};
  ratings.forEach((rating) => {
    const itemId = makeItemId(rating.positionId, rating.critiqueId);
    if (!validationItemIds.has(itemId) || rating.kind === "revision") return;
    coverageByRater[rating.raterId] ??= new Set();
    coverageByRater[rating.raterId].add(itemId);
  });
  const fullCoverageRaters = Object.entries(coverageByRater)
    .filter(([, itemSet]) => itemSet.size === validationItemIds.size && validationItemIds.size > 0)
    .map(([raterId]) => raterId);
  const floorMet =
    validationCritiqueIds.length >= OCTOBER_RELEASE_TARGETS.validationCritiques &&
    validationPositionIds.size >= OCTOBER_RELEASE_TARGETS.validationPositions &&
    fullCoverageRaters.length >= OCTOBER_RELEASE_TARGETS.coreAllItemsRaters;
  const submittedValidationEvidence = buildSubmittedValidationEvidence(options.humanCeilingRuns ?? []);
  const submittedScaleEvidence = buildSubmittedValidationScaleEvidence(
    submittedValidationEvidence,
    options.submittedValidationTrancheEvidence,
  );
  const activeSubmittedScaleEvidence = submittedScaleEvidence.activeEvidence;
  const currentScale = {
    critiqueCount: Math.max(validationCritiqueIds.length, activeSubmittedScaleEvidence?.validationCritiqueCount ?? 0),
    positionCount: Math.max(validationPositionIds.size, activeSubmittedScaleEvidence?.validationPositionCount ?? 0),
    fullCoverageRaterCount: Math.max(fullCoverageRaters.length, activeSubmittedScaleEvidence?.coreAllItemsRaterCount ?? 0),
    fullCoverageRaters,
    computedCritiqueCount: validationCritiqueIds.length,
    computedPositionCount: validationPositionIds.size,
    computedFullCoverageRaterCount: fullCoverageRaters.length,
    computedFloorMet: floorMet,
    submittedScaleEvidenceStatus: activeSubmittedScaleEvidence
      ? "submitted_appendix_c_scale_evidence_applied"
      : "no_submitted_appendix_c_scale_evidence_applied",
    submittedScaleEvidenceSource: activeSubmittedScaleEvidence?.source ?? null,
    submittedScaleEvidenceId: activeSubmittedScaleEvidence?.id ?? null,
    sourceEvidenceId: activeSubmittedScaleEvidence?.id ?? "appendix-c-validation-design-report",
  };
  const submittedFloorMet = Boolean(activeSubmittedScaleEvidence);
  const status = floorMet || submittedFloorMet ? "appendix_c_scale" : "thinner_than_appendix_c";
  const releaseCycleEvidenceStatus =
    status === "appendix_c_scale"
      ? "current_release_cycle_validation_evidence_complete"
      : "current_release_cycle_validation_floor_not_met";

  return {
    id: "appendix-c-validation-design-report",
    status,
    releaseCycleValidationPolicy: RELEASE_CYCLE_VALIDATION_POLICY,
    releaseCycleEvidenceStatus,
    requiredScale: {
      critiqueCount: OCTOBER_RELEASE_TARGETS.validationCritiques,
      positionCount: OCTOBER_RELEASE_TARGETS.validationPositions,
      coreAllItemsRaters: OCTOBER_RELEASE_TARGETS.coreAllItemsRaters,
      discussionHours: "7-8",
    },
    currentScale,
    submittedValidationEvidence,
    submittedValidationTrancheEvidence: options.submittedValidationTrancheEvidence ?? null,
    submittedScaleEvidence,
    comparabilityAxes: {
      blindInitialRatings: ratings.some((rating) => rating.kind === "blind_initial" && validationItemIds.has(makeItemId(rating.positionId, rating.critiqueId))),
      fullVsPartialRaterCoverageReported: true,
      membershipAwarenessPolicy: "random_sentinel_membership_hidden_until_initial_lock_where_feasible",
      positionCritiqueOrderPolicy: "counterbalance_validation_and_benchmark_candidates_where_feasible",
      synchronizedRatingWindow: "required_for_formal_validation_cycle",
      writtenFollowUp: "required_after_discussion_for_object_level_revision_instructions",
      thinnerThanAppendixCLabelRequired: status !== "appendix_c_scale",
    },
    numericBaselineComparisonTable: LMCA_BASELINES.appendixCNumericBaselines,
  };
}

function buildSubmittedValidationScaleEvidence(submittedValidationEvidence, submittedValidationTrancheEvidence) {
  const humanCeilingRows = (submittedValidationEvidence?.rows ?? [])
    .filter((row) => row?.status === "appendix_c_scale_evidence")
    .map((row) => ({
      id: row.id,
      source: "human_ceiling_run",
      validationCritiqueCount: numericEvidenceValue(row.validationCritiqueCount),
      validationPositionCount: numericEvidenceValue(row.validationPositionCount),
      coreAllItemsRaterCount: numericEvidenceValue(row.coreAllItemsRaterCount),
      status: row.status,
    }));
  const activeValidationTrancheRow =
    (submittedValidationTrancheEvidence?.rows ?? []).find(
      (row) => row?.id === submittedValidationTrancheEvidence?.activeEvidenceId && row?.status === "validation_tranche_evidence_complete",
    ) ??
    (submittedValidationTrancheEvidence?.rows ?? []).find((row) => row?.status === "validation_tranche_evidence_complete") ??
    null;
  const validationTrancheRows = activeValidationTrancheRow
    ? [
        {
          id: activeValidationTrancheRow.id,
          source: "validation_tranche_evidence",
          validationCritiqueCount: numericEvidenceValue(activeValidationTrancheRow.validationCritiqueCount),
          validationPositionCount: numericEvidenceValue(activeValidationTrancheRow.validationPositionCount),
          coreAllItemsRaterCount: numericEvidenceValue(activeValidationTrancheRow.coreAllItemsRaterCount),
          status: activeValidationTrancheRow.status,
        },
      ]
    : [];
  const rows = [...validationTrancheRows, ...humanCeilingRows];
  return {
    rows,
    activeEvidence: rows[0] ?? null,
    activeEvidenceId: rows[0]?.id ?? null,
    activeEvidenceSource: rows[0]?.source ?? null,
    status: rows.length ? "submitted_appendix_c_scale_evidence_available" : "no_submitted_appendix_c_scale_evidence",
  };
}

function buildSubmittedValidationEvidence(humanCeilingRuns = [], targets = OCTOBER_RELEASE_TARGETS) {
  const rows = humanCeilingRuns.map((run) => {
    const validationCritiqueCount = numericEvidenceValue(run.validationCritiqueCount ?? run.critiqueCount);
    const validationPositionCount = numericEvidenceValue(run.validationPositionCount ?? run.positionCount);
    const coreAllItemsRaterCount = numericEvidenceValue(run.coreAllItemsRaterCount ?? run.fullCoverageRaterCount ?? run.coreRaterCount);
    const discussionHours = numericEvidenceValue(run.discussionHours ?? run.discussionHourCount);
    const appendixCFlag = run.appendixCComparabilityFlag ?? run.appendixCScaleStatus ?? "not_declared";
    const criteria = {
      validationCritiqueCount: validationCritiqueCount >= targets.validationCritiques,
      validationPositionCount: validationPositionCount >= targets.validationPositions,
      coreAllItemsRaterCount: coreAllItemsRaterCount >= targets.coreAllItemsRaters,
      discussionHours: discussionHours > 0,
      appendixCFlag: String(appendixCFlag).includes("appendix_c"),
    };
    const status = Object.values(criteria).every(Boolean) ? "appendix_c_scale_evidence" : "submitted_validation_evidence_incomplete";
    return {
      id: run.id,
      targetLabelSnapshotId: run.targetLabelSnapshotId ?? null,
      splitOrValidationSubset: run.splitOrValidationSubset ?? run.validationSubset ?? "unknown",
      validationCritiqueCount,
      validationPositionCount,
      coreAllItemsRaterCount,
      discussionHours,
      appendixCComparabilityFlag: appendixCFlag,
      criteria,
      status,
      generatedAt: run.generatedAt ?? run.completedAt ?? run.timestamp ?? null,
    };
  });
  const appendixCScaleRows = rows.filter((row) => row.status === "appendix_c_scale_evidence");
  return {
    rows,
    bestRunId: appendixCScaleRows[0]?.id ?? null,
    rowCount: rows.length,
    appendixCScaleRunCount: appendixCScaleRows.length,
    status: appendixCScaleRows.length
      ? "submitted_appendix_c_scale_evidence"
      : rows.length
        ? "submitted_validation_evidence_incomplete"
        : "no_submitted_validation_evidence",
  };
}

function numericEvidenceValue(value) {
  const number = Number(value);
  return Number.isFinite(number) ? number : 0;
}

export function buildAdminTagBlindingReport(releaseId, positionList = positions) {
  const tagRows = buildAdminTagRows(positionList);
  const preLockVisibilityViolations = tagRows.filter((row) => row.raterVisibleBeforeInitialLock);
  const confounderRiskRows = tagRows.filter((row) => row.confounderRiskClass !== "safe_topic_routing");
  return {
    id: `admin-tag-blinding-${releaseId}`,
    releaseId,
    generatedAt: new Date().toISOString(),
    policy: {
      visibilityRule:
        "Admin tags, topic-routing tags, benchmark-status tags, source hints, and confounder-risk classes remain hidden from blind initial raters until rating lock.",
      manifestRule: "Corpus manifests publish tag-risk distributions and visibility-history rows without exposing tags in rater workspaces.",
      blindingAuditRule:
        "Any admin tag visible before initial lock blocks source-critical release claims until the item is rerated or an adjudicated exception is disclosed.",
    },
    counts: {
      taggedPositionCount: new Set(tagRows.map((row) => row.positionId)).size,
      tagCount: tagRows.length,
      safeTopicRoutingTagCount: tagRows.filter((row) => row.confounderRiskClass === "safe_topic_routing").length,
      possibleConfounderTagCount: tagRows.filter((row) => row.confounderRiskClass === "possible_confounder").length,
      knownRatingConfounderTagCount: tagRows.filter((row) => row.confounderRiskClass === "known_rating_confounder").length,
      preLockVisibilityViolationCount: preLockVisibilityViolations.length,
      confounderRiskTagCount: confounderRiskRows.length,
    },
    byVisibilityClass: countBy(tagRows, "visibilityClass"),
    byConfounderRiskClass: countBy(tagRows, "confounderRiskClass"),
    visibilityHistoryRows: tagRows,
    preLockVisibilityViolations,
    confounderRiskRows,
    releaseUseStatus: preLockVisibilityViolations.length
      ? "admin_tag_blinding_policy_violation"
      : confounderRiskRows.length
        ? "admin_tag_confounder_risk_disclosed_hidden_before_lock"
        : "admin_tag_blinding_pass",
  };
}

export function buildCorpusCompositionManifest(releaseId, positionList = positions, critiqueList = critiques, ratings = seedRatings, rightsRecords = provenanceRightsRecords) {
  const critiqueCountsByPosition = Object.fromEntries(positionList.map((position) => [position.id, critiqueList.filter((critique) => critique.positionId === position.id).length]));
  const ratingRowsIgnoringRevisions = ratings.filter((rating) => rating.kind !== "revision");
  const adminTagRows = buildAdminTagRows(positionList);
  const rightsByPosition = new Map((rightsRecords ?? []).map((record) => [record.positionId, record]));
  const sourceDetailRows = positionList.map((position) => {
    const rightsRecord = rightsByPosition.get(position.id) ?? {};
    const preferRightsRecord = rightsRecord.submittedRightsRecord === true;
    const provenanceValue = (positionValue, rightsValue, fallback = "unknown") =>
      preferRightsRecord ? (rightsValue ?? positionValue ?? fallback) : (positionValue ?? rightsValue ?? fallback);
    const sourceTaskFormat = provenanceValue(position.sourceTaskFormat, rightsRecord.taskFormat);
    const lsatDerived =
      position.lsatDerived === true ||
      rightsRecord.lsatDerived === true ||
      String(sourceTaskFormat).toLowerCase().includes("lsat");
    const sourceSubsource = provenanceValue(position.sourceSubsource, rightsRecord.sourceSubsource, "none");
    return {
      positionId: position.id,
      clusterId: position.clusterId,
      split: position.split,
      sourceCategory: position.sourceCategory,
      authorshipRoute: position.authorshipRoute ?? "unknown",
      sourceDatasetName: provenanceValue(position.sourceDatasetName, rightsRecord.sourceDatasetName, "none"),
      sourceSubsource,
      sourceLanguage: provenanceValue(position.sourceLanguage, rightsRecord.sourceLanguage),
      translationStatus: provenanceValue(position.translationStatus, rightsRecord.translationStatus),
      translationRoute: provenanceValue(position.translationRoute, rightsRecord.translationRoute),
      sourceTaskFormat,
      sourceDomainSuitability:
        provenanceValue(position.sourceDomainSuitability ?? position.sourceDomainSuitabilityStatus, rightsRecord.sourceDomainSuitability),
      sourceDomainConcentration:
        provenanceValue(position.sourceDomainConcentration ?? position.singleTopicConcentration, rightsRecord.singleTopicConcentration),
      vivesDebateMachineTranslationStatus: sourceSubsource === "VivesDebate" ? provenanceValue(position.translationStatus, rightsRecord.translationStatus, "machine_translation_status_missing") : "not_vivesdebate",
      lsatDerived,
      lsatDerivedStatus: lsatDerived ? "lsat_derived_item" : "not_lsat_derived",
    };
  });
  const sourceDetailMissingRows = sourceDetailRows.filter(
    (row) =>
      [
        "sourceCategory",
        "authorshipRoute",
        "sourceDatasetName",
        "sourceSubsource",
        "sourceLanguage",
        "translationStatus",
        "translationRoute",
        "sourceTaskFormat",
        "sourceDomainSuitability",
        "sourceDomainConcentration",
      ].some(
        (field) => row[field] === "unknown" || row[field] === "",
      ),
  );
  const knownAdaptedSubsourceRows = [
    {
      subsource: "DebateBench",
      lmcaCount: LMCA_BASELINES.knownOtherDatasetSubsources.DebateBench,
      releaseCount: positionList.filter((position) => position.sourceSubsource === "DebateBench").length,
      sourceLanguage: "en",
      translationRoute: "transcribed_competitive_debate_speeches",
      sourceTaskFormat: "competitive_debate_speech_with_judge_rating_context",
      sourceDomainSuitability: "argumentative_debate_material_not_ordinary_conceptual_position_by_default",
      sourceDomainConcentration: "competitive_debate_topic_specific",
      lsatDerived: false,
    },
    {
      subsource: "VivesDebate",
      lmcaCount: LMCA_BASELINES.knownOtherDatasetSubsources.VivesDebate,
      releaseCount: positionList.filter((position) => position.sourceSubsource === "VivesDebate").length,
      sourceLanguage: "ca",
      translationRoute: "machine_translated_catalan_to_english",
      sourceTaskFormat: "debate_material_topically_concentrated_on_gestational_surrogacy",
      sourceDomainSuitability: "translation_and_topic_concentration_must_be_disclosed_before_comparability_claims",
      sourceDomainConcentration: "gestational_surrogacy_legalization",
      lsatDerived: false,
    },
    {
      subsource: "LSAT-derived",
      lmcaCount: "few_source_not_exact",
      releaseCount: sourceDetailRows.filter((row) => row.lsatDerivedStatus === "lsat_derived_item").length,
      sourceLanguage: "en",
      translationRoute: "none_or_source_specific",
      sourceTaskFormat: "standardized_test_question_adaptation",
      sourceDomainSuitability: "usually_not_suitable_domains_unless_explicitly_labeled",
      sourceDomainConcentration: "standardized_test_logic_question",
      lsatDerived: true,
    },
  ];
  return {
    id: `corpus-composition-${releaseId}`,
    releaseId,
    counts: {
      positions: positionList.length,
      critiques: critiqueList.length,
      ratingsIgnoringRevisions: ratingRowsIgnoringRevisions.length,
      blindInitialRatings: countKind(ratings, "blind_initial"),
      modelWrittenCritiques: critiqueList.filter((critique) => critique.sourceType === "llm_generated").length,
      positionsWithAtLeastTwoCritiques: Object.values(critiqueCountsByPosition).filter((count) => count >= 2).length,
    },
    positionSourceCategory: countBy(positionList, "sourceCategory"),
    topicFamily: countBy(positionList, "topicFamily"),
    positionLlmAssistance: countBy(positionList, "llmAssistance"),
    splitMembership: countBy(positionList, "split"),
    critiqueSourceType: countBy(critiqueList, "sourceType"),
    critiqueAuthorshipType: countBy(critiqueList, "authorshipType"),
    critiqueLengthBand: countBy(critiqueList, "lengthBand"),
    critiqueCountPerPositionDistribution: countBy(Object.values(critiqueCountsByPosition).map((count) => ({ countBand: String(count) })), "countBand"),
    raterDistributionIgnoringRevisions: countBy(ratingRowsIgnoringRevisions, "raterId"),
    sourceDetailRows,
    sourceDetailCoverage: {
      rowCount: sourceDetailRows.length,
      completeRows: sourceDetailRows.length - sourceDetailMissingRows.length,
      missingRows: sourceDetailMissingRows,
      bySourceLanguage: countBy(sourceDetailRows, "sourceLanguage"),
      byTranslationStatus: countBy(sourceDetailRows, "translationStatus"),
      byTranslationRoute: countBy(sourceDetailRows, "translationRoute"),
      bySourceTaskFormat: countBy(sourceDetailRows, "sourceTaskFormat"),
      bySourceDomainSuitability: countBy(sourceDetailRows, "sourceDomainSuitability"),
      bySourceDomainConcentration: countBy(sourceDetailRows, "sourceDomainConcentration"),
      bySourceDatasetName: countBy(sourceDetailRows, "sourceDatasetName"),
      bySourceSubsource: countBy(sourceDetailRows, "sourceSubsource"),
      byLsatDerivedStatus: countBy(sourceDetailRows, "lsatDerivedStatus"),
      status: sourceDetailMissingRows.length ? "source_detail_metadata_review_required" : "source_detail_metadata_declared",
    },
    knownAdaptedSubsourceRows,
    adminTagRisk: {
      taggedPositionCount: new Set(adminTagRows.map((row) => row.positionId)).size,
      tagCount: adminTagRows.length,
      byVisibilityClass: countBy(adminTagRows, "visibilityClass"),
      byConfounderRiskClass: countBy(adminTagRows, "confounderRiskClass"),
      visibilityHistoryRows: adminTagRows.map((row) => ({
        positionId: row.positionId,
        split: row.split,
        tag: row.tag,
        visibilityClass: row.visibilityClass,
        confounderRiskClass: row.confounderRiskClass,
        changedAt: row.changedAt,
        raterVisibleBeforeInitialLock: row.raterVisibleBeforeInitialLock,
      })),
      policy: "Admin-tag distributions are published in manifests, but tag values remain excluded from blind initial rater views.",
    },
    lmcaBaseline: {
      corpusScale: LMCA_BASELINES.corpusScale,
      positionSourceCounts: LMCA_BASELINES.positionSourceCounts,
      raterDistributionIgnoringRevisions: LMCA_BASELINES.raterDistributionIgnoringRevisions,
      topicFamilies: LMCA_BASELINES.topicFamilies,
    },
  };
}

const REQUIRED_RELEASE_VERSION_FIELDS = [
  "id",
  "releaseId",
  "version",
  "corpusManifestId",
  "labelSnapshotId",
  "metricConfigId",
  "gateProfileId",
  "releaseConfigManifestId",
  "releaseConfigManifestHash",
  "phaseGateBundleId",
  "phaseGateBundleHash",
  "status",
  "releaseNotes",
  "frozenAt",
];

export function buildEffectiveReleaseVersionManifest(
  releaseId,
  { corpusManifest, labelSnapshot, metricDirectionalityConfig, releaseGateProfile, currentStatus, targetGaps, operationalControlEvidence },
  submittedReleaseVersions = [],
  submittedReleaseFreezes = [],
) {
  const submittedReleaseVersion = latestSubmittedReleaseArtifact(submittedReleaseVersions, releaseId);
  const submittedReleaseFreeze = latestSubmittedReleaseArtifact(submittedReleaseFreezes, releaseId);
  const effectiveMetricConfig = metricDirectionalityConfig.effectiveMetricConfig;
  const activePhaseGateBundle =
    (operationalControlEvidence?.implementationPhaseGateBundleRows ?? [])
      .filter((row) => row.status === "implementation_phase_gate_complete")
      .at(-1) ?? null;
  const linkChecks = [
    releaseManifestLinkCheck(
      "corpus_manifest",
      corpusManifest.id,
      submittedReleaseVersion?.corpusManifestId ?? submittedReleaseFreeze?.corpusManifestId,
    ),
    releaseManifestLinkCheck(
      "label_snapshot",
      labelSnapshot.id,
      submittedReleaseVersion?.labelSnapshotId ?? submittedReleaseFreeze?.labelSnapshotId,
    ),
    releaseManifestLinkCheck(
      "metric_config",
      effectiveMetricConfig.id,
      submittedReleaseVersion?.metricConfigId ?? submittedReleaseVersion?.effectiveMetricConfigId ?? submittedReleaseFreeze?.metricConfigId,
    ),
    releaseManifestLinkCheck(
      "release_gate_profile",
      releaseGateProfile.id,
      submittedReleaseVersion?.gateProfileId ??
        submittedReleaseVersion?.releaseGateProfileId ??
        submittedReleaseFreeze?.releaseGateProfileId ??
        submittedReleaseFreeze?.gateProfileId,
    ),
    releaseManifestLinkCheck(
      "implementation_phase_gate_bundle",
      activePhaseGateBundle?.id ?? null,
      submittedReleaseVersion?.phaseGateBundleId ?? submittedReleaseFreeze?.phaseGateBundleId,
    ),
    releaseManifestLinkCheck(
      "implementation_phase_gate_bundle_hash",
      activePhaseGateBundle?.phaseGateBundleHash ?? null,
      submittedReleaseVersion?.phaseGateBundleHash ?? submittedReleaseFreeze?.phaseGateBundleHash,
    ),
  ];
  const mismatchedLinkChecks = linkChecks.filter((check) => check.status === "mismatch");
  const missingLinkChecks = linkChecks.filter((check) => check.status === "missing_submitted_artifact_link");
  const releaseVersionContractChecks = submittedReleaseVersion ? submittedReleaseVersionContractChecks(submittedReleaseVersion) : [];
  const releaseVersionContractViolations = releaseVersionContractChecks.filter((check) => check.status !== "pass");
  const linkedArtifactStatus =
    submittedReleaseVersion || submittedReleaseFreeze
      ? mismatchedLinkChecks.length || missingLinkChecks.length
        ? "release_manifest_link_review_required"
        : "release_manifest_links_current_artifacts"
      : "computed_manifest_pending_submitted_release_version";
  const submittedTargetScaleStatus = submittedReleaseFreeze?.targetScaleStatus ?? submittedReleaseVersion?.targetScaleStatus ?? null;
  const targetScaleStatus = releaseTargetScaleStatus(currentStatus);
  return {
    id: submittedReleaseVersion?.id ?? `release-version-manifest-${releaseId}`,
    releaseId,
    version: submittedReleaseVersion?.version ?? submittedReleaseVersion?.name ?? `${releaseId}.working`,
    manifestSource: submittedReleaseVersion ? "submitted_workflow_release_version" : "computed_working_release_manifest",
    submittedReleaseVersionId: submittedReleaseVersion?.id ?? null,
    submittedReleaseFreezeId: submittedReleaseFreeze?.id ?? null,
    submittedTargetScaleStatus,
    releaseNotes: submittedReleaseVersion?.releaseNotes ?? submittedReleaseVersion?.notes ?? null,
    frozenAt: submittedReleaseVersion?.frozenAt ?? submittedReleaseFreeze?.frozenAt ?? null,
    frozenBy: submittedReleaseFreeze?.frozenBy ?? null,
    freezeEvidence: {
      freezeStatus: submittedReleaseFreeze?.freezeStatus ?? "not_frozen",
      targetScaleStatus,
      submittedTargetScaleStatus,
      frozenAt: submittedReleaseFreeze?.frozenAt ?? null,
      releaseGateProfileId: submittedReleaseFreeze?.releaseGateProfileId ?? submittedReleaseFreeze?.gateProfileId ?? null,
      phaseGateBundleId: submittedReleaseFreeze?.phaseGateBundleId ?? null,
      phaseGateBundleHash: submittedReleaseFreeze?.phaseGateBundleHash ?? null,
      corpusManifestId: submittedReleaseFreeze?.corpusManifestId ?? null,
      labelSnapshotId: submittedReleaseFreeze?.labelSnapshotId ?? null,
    },
    linkedArtifactStatus,
    linkedArtifactChecks: linkChecks,
    mismatchedLinkChecks,
    missingLinkChecks,
    releaseVersionContractChecks,
    releaseVersionContractViolations,
    currentStatus,
    targetGaps,
    effectiveArtifactIds: {
      corpusManifestId: corpusManifest.id,
      labelSnapshotId: labelSnapshot.id,
      metricConfigId: effectiveMetricConfig.id,
      releaseGateProfileId: releaseGateProfile.id,
      phaseGateBundleId: activePhaseGateBundle?.id ?? null,
      phaseGateBundleHash: activePhaseGateBundle?.phaseGateBundleHash ?? null,
    },
    submittedStatus: submittedReleaseVersion?.status ?? null,
    targetScaleStatus,
    releaseUseStatus:
      !submittedReleaseVersion && !submittedReleaseFreeze
        ? "working_release_not_frozen"
        : releaseVersionContractViolations.length
          ? "submitted_release_manifest_contract_review_required"
          : linkedArtifactStatus !== "release_manifest_links_current_artifacts"
            ? "submitted_release_manifest_requires_link_review"
            : currentStatus !== "target_scale_met"
              ? "submitted_release_manifest_recorded_but_target_scale_incomplete"
              : "submitted_release_manifest_current_and_target_scale_met",
  };
}

function releaseTargetScaleStatus(currentStatus) {
  if (currentStatus === "target_scale_met") return "target_scale_met";
  return OCTOBER_TARGET_SCALE_INCOMPLETE_STATUS;
}

function submittedReleaseVersionContractChecks(submitted) {
  const requiredFieldChecks = REQUIRED_RELEASE_VERSION_FIELDS.map((field) => ({
    field,
    expected: "present",
    observed: submitted?.[field] ?? null,
    status: hasRequiredValue(submitted?.[field]) ? "pass" : "missing_required_field",
  }));
  const immutableOutputCheck = {
    field: "immutableOutputArtifactIds",
    expected: "non_empty_array",
    observed: submitted?.immutableOutputArtifactIds ?? null,
    status: Array.isArray(submitted?.immutableOutputArtifactIds) && submitted.immutableOutputArtifactIds.length
      ? "pass"
      : "missing_required_array_values",
  };
  const manifestHashCheck = {
    field: "releaseConfigManifestHash",
    expected: "sha256:*",
    observed: submitted?.releaseConfigManifestHash ?? null,
    status: typeof submitted?.releaseConfigManifestHash === "string" && submitted.releaseConfigManifestHash.startsWith("sha256:")
      ? "pass"
      : "invalid_hash_prefix",
  };
  const phaseGateBundleHashCheck = {
    field: "phaseGateBundleHash",
    expected: "sha256:*",
    observed: submitted?.phaseGateBundleHash ?? null,
    status: typeof submitted?.phaseGateBundleHash === "string" && submitted.phaseGateBundleHash.startsWith("sha256:")
      ? "pass"
      : "invalid_hash_prefix",
  };
  return [...requiredFieldChecks, immutableOutputCheck, manifestHashCheck, phaseGateBundleHashCheck];
}

function latestSubmittedReleaseArtifact(records = [], releaseId) {
  return [...records].reverse().find((record) => !record?.releaseId || record.releaseId === releaseId) ?? null;
}

const PUBLIC_DATASET_ARTIFACT_NAME = "Metaphilosophy Critique Ratings Dataset v0.1";
const publicDatasetPackageFileReadbackRoutes = [
  "/api/v1/public-dataset-package-files/template",
  "/api/v1/public-dataset-package-files/validate/template",
  "/api/v1/public-dataset-package-files/validate",
  "/api/v1/public-dataset-package-files/review-manifest",
];
const publicDatasetDocumentKinds = new Set(["dataset_card", "methodology_report"]);

function latestSubmittedPublicDatasetDocument(records = [], releaseId, documentKind) {
  return [...records]
    .reverse()
    .find(
      (record) =>
        record?.releaseId === releaseId &&
        record?.documentKind === documentKind &&
        record?.artifactName === PUBLIC_DATASET_ARTIFACT_NAME,
    ) ?? null;
}

function publicDatasetDocumentEvidence(records = [], releaseId, documentKind, expectedLinks = {}) {
  const submitted = latestSubmittedPublicDatasetDocument(records, releaseId, documentKind);
  const readbackRoutes = ["/api/v1/public-dataset-documents"];
  if (!publicDatasetDocumentKinds.has(documentKind)) {
    return {
      documentKind,
      status: "unsupported_public_dataset_document_kind",
      sourceEvidenceIds: [],
      sourceStatuses: ["unsupported_public_dataset_document_kind"],
      reviewReasons: [`publicDatasetDocument:${documentKind}:unsupported_kind`],
      readbackRoutes,
    };
  }
  if (!submitted) {
    return {
      documentKind,
      status: "no_submitted_document",
      sourceEvidenceIds: [],
      sourceStatuses: ["not_submitted"],
      reviewReasons: [`publicDatasetDocument:${documentKind}:not_submitted`],
      readbackRoutes,
    };
  }

  const linkedIds = submitted.linkedReleaseObjectIds ?? {};
  const missingFields = ["id", "documentVersion", "title", "summary", "bodyMarkdown", "bodyHash", "preparedBy", "reviewedBy", "createdAt"].filter(
    (field) => !hasRequiredValue(submitted?.[field]),
  );
  const linkReviewReasons = Object.entries(expectedLinks)
    .filter(([, expectedValue]) => hasRequiredValue(expectedValue))
    .map(([field, expectedValue]) =>
      linkedIds?.[field] === expectedValue ? null : `publicDatasetDocument:${documentKind}:linkedReleaseObjectIds.${field}_mismatch`,
    )
    .filter(Boolean);
  const hiddenSummary = String(submitted.hiddenProtectedExclusionSummary ?? "").toLowerCase();
  const downstreamBoundary = String(submitted.downstreamLaunchBoundary ?? "").toLowerCase();
  const bodyText = `${submitted.title ?? ""} ${submitted.summary ?? ""} ${submitted.bodyMarkdown ?? ""}`.toLowerCase();
  const reviewReasons = [
    ...missingFields.map((field) => `publicDatasetDocument:${documentKind}:${field}_missing`),
    typeof submitted.bodyHash === "string" && submitted.bodyHash.startsWith("sha256:")
      ? null
      : `publicDatasetDocument:${documentKind}:bodyHash_invalid`,
    ...linkReviewReasons,
    ["hidden", "protected", "excluded"].every((fragment) => hiddenSummary.includes(fragment))
      ? null
      : `publicDatasetDocument:${documentKind}:hidden_protected_exclusion_summary_incomplete`,
    ["leaderboard", "api", "training"].every((fragment) => downstreamBoundary.includes(fragment))
      ? null
      : `publicDatasetDocument:${documentKind}:downstream_launch_boundary_incomplete`,
    documentKind === "dataset_card" && !bodyText.includes("dataset")
      ? `publicDatasetDocument:${documentKind}:dataset_card_copy_missing`
      : null,
    documentKind === "methodology_report" && !bodyText.includes("method")
      ? `publicDatasetDocument:${documentKind}:methodology_copy_missing`
      : null,
  ].filter(Boolean);

  const readbackItemRoute = `/api/v1/public-dataset-documents/${encodeURIComponent(submitted.id)}`;
  return {
    documentKind,
    submittedDocumentId: submitted.id,
    status: reviewReasons.length ? "submitted_document_review_required" : "submitted_document_matches_current_release",
    sourceEvidenceIds: [submitted.id],
    sourceStatuses: [reviewReasons.length ? "submitted_document_review_required" : "submitted_document_matches_current_release"],
    reviewReasons,
    readbackRoutes: [...readbackRoutes, readbackItemRoute],
    documentSummary: {
      id: submitted.id,
      documentKind: submitted.documentKind,
      documentVersion: submitted.documentVersion,
      bodyHash: submitted.bodyHash,
      linkedReleaseObjectIds: submitted.linkedReleaseObjectIds ?? {},
      preparedBy: submitted.preparedBy,
      reviewedBy: submitted.reviewedBy,
      createdAt: submitted.createdAt,
    },
  };
}

function releaseManifestLinkCheck(artifact, expectedId, submittedId) {
  return {
    artifact,
    expectedId,
    submittedId: submittedId ?? null,
    status: submittedId ? (submittedId === expectedId ? "matches_current_artifact" : "mismatch") : "missing_submitted_artifact_link",
  };
}

export function buildSubmittedReleaseArtifactEvidence(
  releaseId,
  { labelSnapshot, corpusManifest, trainingExport, publicExportManifest, internalExportManifest, releaseReportSnapshot },
  { labelSnapshots = [], corpusManifests = [], trainingExports = [], exportManifests = [], releaseReports = [] } = {},
) {
  const labelSnapshotEvidence = submittedLabelSnapshotEvidence(releaseId, labelSnapshot, trainingExport, latestSubmittedReleaseArtifact(labelSnapshots, releaseId));
  const corpusManifestEvidence = submittedCorpusManifestEvidence(releaseId, corpusManifest, latestSubmittedReleaseArtifact(corpusManifests, releaseId));
  const trainingExportEvidence = submittedTrainingExportEvidence(
    releaseId,
    trainingExport,
    labelSnapshotEvidence,
    latestSubmittedReleaseArtifact(trainingExports, releaseId),
  );
  const exportManifestEvidence = submittedExportManifestEvidence(
    releaseId,
    publicExportManifest,
    labelSnapshotEvidence,
    latestSubmittedExportManifest(exportManifests, releaseId, publicExportManifest.kind),
  );
  const internalExportManifestEvidence = submittedExportManifestEvidence(
    releaseId,
    internalExportManifest,
    labelSnapshotEvidence,
    latestSubmittedExportManifest(exportManifests, releaseId, internalExportManifest.kind),
  );
  const releaseReportSnapshotEvidence = submittedReleaseReportSnapshotEvidence(
    releaseId,
    releaseReportSnapshot,
    latestSubmittedReleaseArtifact(releaseReports, releaseId),
  );
  const sections = [
    labelSnapshotEvidence,
    corpusManifestEvidence,
    trainingExportEvidence,
    exportManifestEvidence,
    internalExportManifestEvidence,
    releaseReportSnapshotEvidence,
  ];
  const submittedSectionCount = sections.filter((section) => section.submittedArtifactId).length;
  const reviewSections = sections.filter(
    (section) => section.status.endsWith("_review_required") || (submittedSectionCount > 0 && section.status === "no_submitted_artifact"),
  );
  return {
    id: `submitted-release-artifact-evidence-${releaseId}`,
    releaseId,
    generatedAt: new Date().toISOString(),
    policy: {
      labelSnapshotRule:
        "Submitted LabelSnapshot artifacts must describe the current immutable target-label version and denominator counts before they count as release evidence.",
      corpusManifestRule:
        "Submitted CorpusManifest artifacts must match current position, critique, and blind-initial denominator counts rather than merely existing in workflow storage.",
      trainingExportRule:
        "Submitted TrainingExport artifacts must point to the active or submitted label snapshot, preserve protected-split exclusions, and bind the active uncertainty/downweighting policy.",
      exportManifestRule:
        "Submitted public and internal ExportManifest artifacts must preserve their split scope, rights policy, hidden-benchmark exposure policy, and label-snapshot linkage.",
      releaseReportSnapshotRule:
        "Submitted ReleaseReport snapshots must be server-materialized from the current release report and bind the report id, release status, hash, actor, and timestamp before they count as release evidence.",
    },
    labelSnapshotEvidence,
    corpusManifestEvidence,
    trainingExportEvidence,
    exportManifestEvidence,
    internalExportManifestEvidence,
    releaseReportSnapshotEvidence,
    reviewSections: reviewSections.map((section) => section.artifactKind),
    releaseUseStatus: reviewSections.length
      ? "submitted_release_artifacts_review_required"
      : submittedSectionCount === sections.length
        ? "submitted_release_artifacts_match_current_release"
        : "computed_release_artifacts_no_submitted_manifests",
  };
}

function buildPublicDatasetReadinessReport(
  releaseId,
  {
    currentStatus,
    targetGaps,
    releaseVersionManifest,
    releaseArtifactEvidence,
    corpusManifest,
    labelSnapshot,
    trainingExport,
    publicExportManifest,
    hiddenBenchmarkFreeze,
    validationDesign,
    publicDatasetDocuments = [],
  },
) {
  const targetScaleOpen = currentStatus !== "target_scale_met";
  const releaseFrozen =
    releaseVersionManifest?.releaseUseStatus === "submitted_release_manifest_current_and_target_scale_met" ||
    releaseVersionManifest?.releaseUseStatus === "submitted_release_manifest_recorded_but_target_scale_incomplete";
  const releaseFreezeOpen = !releaseFrozen;
  const labelSnapshotStatus = releaseArtifactEvidence?.labelSnapshotEvidence?.status ?? "label_snapshot_evidence_missing";
  const corpusManifestStatus = releaseArtifactEvidence?.corpusManifestEvidence?.status ?? "corpus_manifest_evidence_missing";
  const exportManifestStatus = releaseArtifactEvidence?.exportManifestEvidence?.status ?? "public_export_manifest_evidence_missing";
  const trainingExportStatus = releaseArtifactEvidence?.trainingExportEvidence?.status ?? "training_export_evidence_missing";
  const itemTextManifest = trainingExportItemTextVersionHashManifest(trainingExport);
  const ratingContextManifest = trainingExportRatingContextSnapshotManifest(trainingExport);
  const labelMetadataManifest = trainingExportLabelMetadataManifest(trainingExport);
  const publicPairCount = publicExportManifest?.counts?.critiques ?? 0;
  const publicPositionCount = publicExportManifest?.counts?.positions ?? 0;
  const itemLabelCount = publicExportManifest?.counts?.itemLabels ?? Object.keys(labelSnapshot?.itemLabels ?? {}).length;
  const expectedDocumentLinks = {
    corpusManifestId: corpusManifest?.id,
    labelSnapshotId: labelSnapshot?.id,
    publicExportManifestId: publicExportManifest?.id,
    releaseVersionManifestId: releaseVersionManifest?.id,
  };
  const datasetCardEvidence = publicDatasetDocumentEvidence(publicDatasetDocuments, releaseId, "dataset_card", expectedDocumentLinks);
  const methodologyReportEvidence = publicDatasetDocumentEvidence(
    publicDatasetDocuments,
    releaseId,
    "methodology_report",
    expectedDocumentLinks,
  );
  const releaseReportRoute = "/api/release/report";
  const routeBase = "/api/v1/public-dataset-readiness";
  const targetGapRoutes = ["/api/v1/target-gaps", ...(targetGaps?.rows ?? []).map((row) => `/api/v1/target-gaps/${row.id}`)];
  const rows = [
    publicDatasetReadinessRow({
      id: "release_cleared_position_critique_pairs",
      label: "Release-cleared position-critique pairs",
      gateKind: "dataset_content",
      status: targetScaleOpen ? "blocked_by_target_scale" : publicPairCount > 0 ? "ready" : "missing_public_pairs",
      sourceEvidenceIds: [corpusManifest?.id, publicExportManifest?.id],
      sourceStatuses: [corpusManifestStatus, exportManifestStatus],
      reviewReasons: [
        publicPositionCount > 0 ? null : "publicExportManifest:positions_missing",
        publicPairCount > 0 ? null : "publicExportManifest:critiques_missing",
        targetScaleOpen ? "targetScale:remaining_release_data" : null,
      ],
      readbackRoutes: [
        routeBase,
        releaseReportRoute,
        "/api/v1/corpus-manifests",
        corpusManifest?.id ? `/api/v1/corpus-manifests/${corpusManifest.id}` : null,
        "/api/v1/export-manifests",
        publicExportManifest?.id ? `/api/v1/export-manifests/${publicExportManifest.id}` : null,
        ...targetGapRoutes,
      ],
      counts: { publicPositions: publicPositionCount, publicCritiques: publicPairCount },
      targetGapIds: (targetGaps?.rows ?? []).filter((row) => row.remaining > 0).map((row) => row.id),
    }),
    publicDatasetReadinessRow({
      id: "seven_dimension_labels",
      label: "Seven-dimensional expert-supervised labels",
      gateKind: "label_foundation",
      status: itemLabelCount > 0 && labelSnapshot ? "ready" : "label_snapshot_missing",
      sourceEvidenceIds: [labelSnapshot?.id, releaseArtifactEvidence?.labelSnapshotEvidence?.submittedArtifactId],
      sourceStatuses: [labelSnapshotStatus],
      reviewReasons: [itemLabelCount > 0 ? null : "labelSnapshot:item_labels_missing"],
      readbackRoutes: [
        routeBase,
        releaseReportRoute,
        "/api/v1/label-snapshots",
        labelSnapshot?.id ? `/api/v1/label-snapshots/${labelSnapshot.id}` : null,
      ],
      counts: { itemLabels: itemLabelCount, dimensions: RUBRIC_DIMENSIONS.length },
    }),
    publicDatasetReadinessRow({
      id: "confidence_and_triggered_explanations",
      label: "Confidence and triggered explanations where available",
      gateKind: "label_metadata",
      status: labelMetadataManifest.rows.length > 0 ? "ready" : "label_metadata_manifest_missing",
      sourceEvidenceIds: [trainingExport?.id, releaseArtifactEvidence?.trainingExportEvidence?.submittedArtifactId],
      sourceStatuses: [trainingExportStatus],
      reviewReasons: [labelMetadataManifest.rows.length > 0 ? null : "trainingExport:labelMetadataManifest_missing"],
      readbackRoutes: [
        routeBase,
        releaseReportRoute,
        "/api/v1/training-exports",
        trainingExport?.id ? `/api/v1/training-exports/${trainingExport.id}` : null,
      ],
      counts: { labelMetadataRows: labelMetadataManifest.rows.length },
    }),
    publicDatasetReadinessRow({
      id: "item_text_version_hashes",
      label: "Item text and rendered-text version hashes",
      gateKind: "reproducibility_manifest",
      status: itemTextManifest.rows.length > 0 ? "ready" : "item_text_version_hash_manifest_missing",
      sourceEvidenceIds: [trainingExport?.id],
      sourceStatuses: [trainingExportStatus],
      reviewReasons: [itemTextManifest.rows.length > 0 ? null : "trainingExport:itemTextVersionHashManifest_missing"],
      readbackRoutes: [
        routeBase,
        releaseReportRoute,
        "/api/v1/training-exports",
        trainingExport?.id ? `/api/v1/training-exports/${trainingExport.id}` : null,
      ],
      counts: { itemTextVersionRows: itemTextManifest.rows.length },
    }),
    publicDatasetReadinessRow({
      id: "rating_context_snapshot_manifest",
      label: "Rating-context snapshot manifest",
      gateKind: "reproducibility_manifest",
      status: ratingContextManifest.rows.length > 0 ? "ready" : "rating_context_snapshot_manifest_missing",
      sourceEvidenceIds: [trainingExport?.id],
      sourceStatuses: [trainingExportStatus],
      reviewReasons: [ratingContextManifest.rows.length > 0 ? null : "trainingExport:ratingContextSnapshotManifest_missing"],
      readbackRoutes: [
        routeBase,
        releaseReportRoute,
        "/api/v1/training-exports",
        trainingExport?.id ? `/api/v1/training-exports/${trainingExport.id}` : null,
        "/api/v1/rating-context-snapshots",
      ],
      counts: { ratingContextSnapshotRows: ratingContextManifest.rows.length },
    }),
    publicDatasetReadinessRow({
      id: "label_snapshot",
      label: "Immutable label snapshot",
      gateKind: "release_object",
      status: labelSnapshotStatus === "submitted_label_snapshot_matches_current_release_target" ? "ready" : "release_artifact_review_required",
      sourceEvidenceIds: [labelSnapshot?.id, releaseArtifactEvidence?.labelSnapshotEvidence?.submittedArtifactId],
      sourceStatuses: [labelSnapshotStatus],
      reviewReasons:
        labelSnapshotStatus === "submitted_label_snapshot_matches_current_release_target"
          ? []
          : [`labelSnapshotEvidence:${labelSnapshotStatus}`],
      readbackRoutes: [
        routeBase,
        releaseReportRoute,
        "/api/v1/label-snapshots",
        labelSnapshot?.id ? `/api/v1/label-snapshots/${labelSnapshot.id}` : null,
      ],
    }),
    publicDatasetReadinessRow({
      id: "split_manifest",
      label: "Public split manifest and protected split exclusions",
      gateKind: "split_governance",
      status:
        publicExportManifest?.hiddenBenchmarkExcluded === true &&
        publicExportManifest?.excludedSplits?.includes("hidden_benchmark") &&
        publicExportManifest?.excludedSplits?.includes("internal_validation")
          ? "ready"
          : "protected_split_exclusion_review_required",
      sourceEvidenceIds: [publicExportManifest?.id, releaseArtifactEvidence?.exportManifestEvidence?.submittedArtifactId],
      sourceStatuses: [exportManifestStatus],
      reviewReasons: [
        publicExportManifest?.hiddenBenchmarkExcluded === true ? null : "publicExportManifest:hiddenBenchmarkExcluded",
        publicExportManifest?.excludedSplits?.includes("hidden_benchmark") ? null : "publicExportManifest:excluded_hidden_benchmark",
        publicExportManifest?.excludedSplits?.includes("internal_validation") ? null : "publicExportManifest:excluded_internal_validation",
      ],
      readbackRoutes: [
        routeBase,
        releaseReportRoute,
        "/api/v1/export-manifests",
        publicExportManifest?.id ? `/api/v1/export-manifests/${publicExportManifest.id}` : null,
      ],
      protectedExclusions: publicExportManifest?.excludedSplits ?? [],
    }),
    publicDatasetReadinessRow({
      id: "corpus_manifest",
      label: "Corpus composition manifest",
      gateKind: "release_object",
      status: corpusManifestStatus === "submitted_corpus_manifest_matches_current_release_counts" ? "ready" : "release_artifact_review_required",
      sourceEvidenceIds: [corpusManifest?.id, releaseArtifactEvidence?.corpusManifestEvidence?.submittedArtifactId],
      sourceStatuses: [corpusManifestStatus],
      reviewReasons:
        corpusManifestStatus === "submitted_corpus_manifest_matches_current_release_counts"
          ? []
          : [`corpusManifestEvidence:${corpusManifestStatus}`],
      readbackRoutes: [
        routeBase,
        releaseReportRoute,
        "/api/v1/corpus-manifests",
        corpusManifest?.id ? `/api/v1/corpus-manifests/${corpusManifest.id}` : null,
      ],
      counts: corpusManifest?.counts ?? {},
    }),
    publicDatasetReadinessRow({
      id: "dataset_card",
      label: "Dataset card",
      gateKind: "public_documentation",
      status:
        datasetCardEvidence.status === "submitted_document_matches_current_release"
          ? "ready"
          : datasetCardEvidence.status === "no_submitted_document"
            ? "documentation_not_submitted"
            : "documentation_review_required",
      sourceEvidenceIds: datasetCardEvidence.sourceEvidenceIds,
      sourceStatuses: datasetCardEvidence.sourceStatuses,
      reviewReasons:
        datasetCardEvidence.status === "no_submitted_document"
          ? ["datasetCard:not_submitted"]
          : datasetCardEvidence.reviewReasons,
      readbackRoutes: [routeBase, releaseReportRoute, "/api/v1/release-report-sections", ...datasetCardEvidence.readbackRoutes],
      templateReadbackRoutes: [
        "/api/v1/public-dataset-documents/template",
        "/api/v1/public-dataset-documents/template?documentKind=dataset_card",
      ],
      documentSummary: datasetCardEvidence.documentSummary,
    }),
    publicDatasetReadinessRow({
      id: "methodology_report",
      label: "Short methodology report",
      gateKind: "public_documentation",
      status:
        methodologyReportEvidence.status === "submitted_document_matches_current_release"
          ? "ready"
          : methodologyReportEvidence.status === "no_submitted_document"
            ? "documentation_not_submitted"
            : "documentation_review_required",
      sourceEvidenceIds: methodologyReportEvidence.sourceEvidenceIds,
      sourceStatuses: methodologyReportEvidence.sourceStatuses,
      reviewReasons:
        methodologyReportEvidence.status === "no_submitted_document"
          ? ["methodologyReport:not_submitted"]
          : methodologyReportEvidence.reviewReasons,
      readbackRoutes: [routeBase, releaseReportRoute, "/api/v1/release-report-sections", ...methodologyReportEvidence.readbackRoutes],
      templateReadbackRoutes: [
        "/api/v1/public-dataset-documents/template",
        "/api/v1/public-dataset-documents/template?documentKind=methodology_report",
      ],
      documentSummary: methodologyReportEvidence.documentSummary,
    }),
    publicDatasetReadinessRow({
      id: "hidden_protected_exclusions",
      label: "Explicit hidden/protected exclusions",
      gateKind: "split_governance",
      status:
        publicExportManifest?.hiddenBenchmarkExcluded === true && hiddenBenchmarkFreeze
          ? "ready"
          : "hidden_protected_exclusion_review_required",
      sourceEvidenceIds: [publicExportManifest?.id, hiddenBenchmarkFreeze?.id],
      sourceStatuses: [exportManifestStatus, hiddenBenchmarkFreeze?.releaseUseStatus ?? hiddenBenchmarkFreeze?.status],
      reviewReasons: [
        publicExportManifest?.hiddenBenchmarkExcluded === true ? null : "publicExportManifest:hiddenBenchmarkExcluded",
        hiddenBenchmarkFreeze ? null : "hiddenBenchmarkFreeze:missing",
      ],
      readbackRoutes: [
        routeBase,
        releaseReportRoute,
        "/api/v1/export-manifests",
        publicExportManifest?.id ? `/api/v1/export-manifests/${publicExportManifest.id}` : null,
        "/api/v1/benchmark-freeze-reports",
      ],
      protectedExclusions: publicExportManifest?.excludedSplits ?? [],
    }),
    publicDatasetReadinessRow({
      id: "release_version_freeze",
      label: "Release version freeze and artifact-link review",
      gateKind: "release_freeze",
      status: releaseFreezeOpen ? "blocked_by_release_freeze" : "ready",
      sourceEvidenceIds: [releaseVersionManifest?.id, releaseVersionManifest?.submittedReleaseVersionId, releaseVersionManifest?.submittedReleaseFreezeId],
      sourceStatuses: [
        releaseVersionManifest?.releaseUseStatus,
        releaseVersionManifest?.targetScaleStatus,
        releaseVersionManifest?.linkedArtifactStatus,
      ],
      reviewReasons: [
        releaseFreezeOpen ? `releaseVersionManifest:${releaseVersionManifest?.releaseUseStatus ?? "missing"}` : null,
        releaseVersionManifest?.linkedArtifactStatus === "release_manifest_links_current_artifacts"
          ? null
          : `releaseVersionManifest:${releaseVersionManifest?.linkedArtifactStatus ?? "artifact_links_missing"}`,
      ],
      readbackRoutes: [routeBase, releaseReportRoute, "/api/v1/release-version-manifest"],
    }),
  ];
  const upstreamOpenRows = rows.filter((row) => row.status !== "ready");
  const documentationOpen = rows.some((row) => row.gateKind === "public_documentation" && row.status !== "ready");
  rows.push(
    publicDatasetReadinessRow({
      id: "public_first_ladder_gate",
      label: "Public-first ladder blocks leaderboard, API evaluator, and training-export launch",
      gateKind: "release_ladder",
      status: upstreamOpenRows.length ? "downstream_blocked_until_dataset_v0_1_ready" : "ready",
      sourceEvidenceIds: [
        releaseArtifactEvidence?.id,
        releaseVersionManifest?.id,
        targetGaps?.id,
        validationDesign?.id,
      ],
      sourceStatuses: [releaseArtifactEvidence?.releaseUseStatus, releaseVersionManifest?.releaseUseStatus, targetGaps?.releaseUseStatus],
      reviewReasons: [
        targetScaleOpen ? "publicFirstLadder:target_scale_incomplete" : null,
        releaseFreezeOpen ? "publicFirstLadder:release_not_frozen" : null,
        documentationOpen ? "publicFirstLadder:dataset_card_and_methodology_required_before_downstream_public_launch" : null,
        ...upstreamOpenRows
          .filter((row) => !["release_cleared_position_critique_pairs", "release_version_freeze", "dataset_card", "methodology_report"].includes(row.id))
          .map((row) => `publicFirstLadder:upstream_row_open:${row.id}`),
      ],
      readbackRoutes: [
        routeBase,
        releaseReportRoute,
        "/api/v1/release-version-manifest",
        "/api/v1/release-report-sections",
        "/api/v1/public-dataset-documents",
        "/api/v1/model-evaluation-reproducibility-checklist",
      ],
      downstreamArtifacts: ["public_leaderboard", "api_evaluator", "training_export_launch", "judge_model_launch"],
    }),
  );
  const openRows = rows.filter((row) => row.status !== "ready");
  const status = targetScaleOpen
    ? "public_dataset_v0_1_blocked_by_target_scale"
    : releaseFreezeOpen
      ? "public_dataset_v0_1_blocked_by_release_freeze"
      : rows.some((row) => row.gateKind === "public_documentation" && row.status !== "ready")
        ? "public_dataset_v0_1_missing_public_documentation"
        : openRows.length
          ? "public_dataset_v0_1_review_required"
          : "public_dataset_v0_1_ready";
  return {
    id: `public-dataset-readiness-${releaseId}`,
    releaseId,
    artifactName: PUBLIC_DATASET_ARTIFACT_NAME,
    artifactKind: "expert_rated_position_critique_dataset",
    generatedAt: new Date().toISOString(),
    releaseUseStatus: status,
    publicFirstRule:
      "Dataset v0.1 is the first serious public artifact; public leaderboard, API evaluator, public training-export launch, and judge-model launch remain downstream until this label foundation and split governance are ready.",
    policy: {
      architecture:
        "Read-only projection over existing ReleaseVersion, CorpusManifest, LabelSnapshot, item-text/rating-context manifests, split manifest, and release-artifact evidence; it does not create a new product surface.",
      exclusions:
        "Hidden-benchmark items, protected validation labels, source/provenance metadata, rater identities, model-judge scores, active-learning reasons, and unreleased adjudication notes stay excluded unless a later governed release deprotects them.",
      sideEffects:
        "This report does not publish a dataset, launch a leaderboard, launch an API evaluator, create a training export, waive release gates, or submit operator evidence.",
    },
    releaseVersionManifestStatus: releaseVersionManifest?.releaseUseStatus ?? null,
    targetScaleStatus: releaseVersionManifest?.targetScaleStatus ?? currentStatus,
    targetGaps,
    counts: publicDatasetReadinessCounts(rows),
    rows,
  };
}

function publicDatasetReadinessRow({
  id,
  label,
  gateKind,
  status,
  sourceEvidenceIds = [],
  sourceStatuses = [],
  reviewReasons = [],
  readbackRoutes = [],
  counts = null,
  targetGapIds = [],
  protectedExclusions = null,
  downstreamArtifacts = null,
  documentSummary = null,
  templateReadbackRoutes = [],
}) {
  return {
    id,
    label,
    gateKind,
    status,
    sourceEvidenceIds: uniqueStrings(sourceEvidenceIds),
    sourceStatuses: uniqueStrings(sourceStatuses),
    reviewReasons: uniqueStrings(reviewReasons),
    readbackRoutes: uniqueStrings([...readbackRoutes, ...templateReadbackRoutes, ...publicDatasetPackageFileReadbackRoutes]),
    templateReadbackRoutes: uniqueStrings(templateReadbackRoutes),
    targetGapIds: uniqueStrings(targetGapIds),
    ...(counts ? { counts } : {}),
    ...(protectedExclusions ? { protectedExclusions } : {}),
    ...(downstreamArtifacts ? { downstreamArtifacts } : {}),
    ...(documentSummary ? { documentSummary } : {}),
  };
}

function publicDatasetReadinessCounts(rows) {
  const byStatus = countBy(rows, "status");
  const byGateKind = countBy(rows, "gateKind");
  return {
    rows: rows.length,
    readyRows: rows.filter((row) => row.status === "ready").length,
    openRows: rows.filter((row) => row.status !== "ready").length,
    blockedByTargetScaleRows: rows.filter((row) => row.status === "blocked_by_target_scale").length,
    blockedByReleaseFreezeRows: rows.filter((row) => row.status === "blocked_by_release_freeze").length,
    documentationRows: rows.filter((row) => row.gateKind === "public_documentation").length,
    missingDocumentationRows: rows.filter((row) => row.gateKind === "public_documentation" && row.status !== "ready").length,
    downstreamBlockedRows: rows.filter((row) => row.status === "downstream_blocked_until_dataset_v0_1_ready").length,
    reviewReasonCount: rows.reduce((sum, row) => sum + row.reviewReasons.length, 0),
    byStatus,
    byGateKind,
  };
}

export function buildSubmittedModelEvaluationArtifactEvidence(
  releaseId,
  { labelSnapshot, trainingExport, leaderboardReport, recalibratedEvaluation, modelFailureAudits },
  {
    modelImprovementPolicies = [],
    modelImprovementRuns = [],
    evaluationRuns = [],
    modelEvaluationPredictions = [],
    calibrationRuns = [],
    leaderboards = [],
    modelFailureAuditArtifacts = [],
    modelInferenceConfigs = [],
    modelRunEnvironments = [],
    modelRunReproducibilityPolicies = [],
    modelProviderDataHandlingPolicies = [],
  } = {},
) {
  const submittedModelImprovementPolicyRows = (modelImprovementPolicies ?? [])
    .map((policy) => normalizeModelImprovementPolicy(policy, "submitted_workflow_model_improvement_policy"))
    .filter(Boolean);
  const seedModelImprovementPolicyRows = [
    normalizeModelImprovementPolicy(defaultModelImprovementPolicy(releaseId), "seed_model_improvement_policy"),
  ];
  const activeModelImprovementPolicy =
    submittedModelImprovementPolicyRows.find((row) => row.reviewReasons.length === 0) ?? seedModelImprovementPolicyRows[0];
  const modelImprovementPolicyReviewRows = submittedModelImprovementPolicyRows.filter((row) => row.reviewReasons.length);
  const submittedModelImprovementRun = latestSubmittedReleaseArtifact(modelImprovementRuns, releaseId);
  const submittedEvaluationRun = latestSubmittedReleaseArtifact(evaluationRuns, releaseId);
  const submittedPredictions = submittedEvaluationRun
    ? modelEvaluationPredictions.filter((prediction) => prediction.evaluationRunId === submittedEvaluationRun.id)
    : [];
  const submittedCalibrationRun = submittedEvaluationRun
    ? latestSubmittedWorkflowArtifactByField(calibrationRuns, "evaluationRunId", submittedEvaluationRun.id, releaseId)
    : null;
  const submittedLeaderboard = latestSubmittedReleaseArtifact(leaderboards, releaseId);
  const submittedFailureAudit = submittedEvaluationRun
    ? latestSubmittedWorkflowArtifactByField(modelFailureAuditArtifacts, "evaluationRunId", submittedEvaluationRun.id, releaseId)
    : null;
  const modelImprovementRunEvidence = submittedModelImprovementRunEvidence(
    releaseId,
    trainingExport,
    submittedModelImprovementRun,
    activeModelImprovementPolicy,
  );
  const evaluationRunEvidence = submittedEvaluationRunEvidence(releaseId, labelSnapshot, submittedEvaluationRun);
  const predictionEvidence = submittedModelEvaluationPredictionEvidence(labelSnapshot, submittedEvaluationRun, submittedPredictions);
  const calibrationRunEvidence = submittedCalibrationRunEvidence(releaseId, labelSnapshot, submittedEvaluationRun, submittedCalibrationRun, recalibratedEvaluation);
  const leaderboardEvidence = submittedLeaderboardEvidence(releaseId, labelSnapshot, submittedEvaluationRun, submittedLeaderboard, leaderboardReport);
  const failureAuditEvidence = submittedModelFailureAuditEvidence(releaseId, labelSnapshot, submittedEvaluationRun, submittedFailureAudit, modelFailureAudits);
  const modelRunProvenanceEvidence = submittedModelRunProvenanceEvidence(
    submittedEvaluationRun,
    modelInferenceConfigs,
    modelRunEnvironments,
    modelRunReproducibilityPolicies,
  );
  const modelProviderPolicyEvidence = submittedModelProviderPolicyEvidence(submittedEvaluationRun, modelProviderDataHandlingPolicies);
  const sections = [
    modelImprovementRunEvidence,
    evaluationRunEvidence,
    predictionEvidence,
    calibrationRunEvidence,
    leaderboardEvidence,
    failureAuditEvidence,
    modelRunProvenanceEvidence,
    modelProviderPolicyEvidence,
  ];
  const submittedSections = sections.filter((section) => section.submittedArtifactId);
  const modelImprovementPolicyReviewSections = modelImprovementPolicyReviewRows.map((row) => ({
    artifactKind: "model_improvement_policy",
    submittedArtifactId: row.id,
    status: "model_improvement_policy_review_required",
  }));
  const allReviewSections = [
    ...sections.filter(
      (section) => section.status.endsWith("_review_required") || (submittedSections.length && section.status === "no_submitted_artifact"),
    ),
    ...modelImprovementPolicyReviewSections,
  ];
  return {
    id: `submitted-model-evaluation-artifact-evidence-${releaseId}`,
    releaseId,
    generatedAt: new Date().toISOString(),
    policy: {
      evaluationRunRule:
        "Submitted EvaluationRun artifacts must bind to the active LabelSnapshot, declare parser/prompt provenance, and exclude protected splits before they count as release evidence.",
      predictionRule:
        "Submitted ModelEvaluationPrediction rows must bind to frozen item text, rendered item hashes, rating-context snapshots, and parser output status.",
      calibrationRule:
        "Submitted CalibrationRun artifacts must keep raw and calibrated reporting separate and exclude protected validation and hidden benchmark rows from fit data.",
      leaderboardRule:
        "Submitted leaderboard artifacts must use the current target labels, include the submitted evaluation run, and declare common-subset plus uncertainty policy before any rank claim.",
      failureAuditRule:
        "Submitted ModelFailureAudit artifacts are diagnostic-only and cannot replace aggregate LMCA metric reports.",
      modelImprovementRule:
        "Submitted ModelImprovementRun artifacts must link to the current TrainingExport, separate optimized surrogate objectives from LMCA evaluation metrics, preserve position-balanced weighting, and propagate label uncertainty/downweighting policy.",
      modelRunProvenanceRule:
        "Submitted EvaluationRun artifacts must have matching ModelInferenceConfig and ModelRunEnvironment records that preserve endpoint, snapshot, decoding, tool, seed, deployment, and parser/extractor provenance.",
      modelProviderPolicyRule:
        "Submitted protected model-evaluation runs must reference an approved ModelProviderDataHandlingPolicy with no training, no reuse, no unnecessary human review, bounded retention, and protected-content eligibility.",
    },
    modelImprovementPolicyRows: [...seedModelImprovementPolicyRows, ...submittedModelImprovementPolicyRows],
    modelImprovementPolicyId: activeModelImprovementPolicy?.id ?? null,
    modelImprovementPolicyReleaseUseStatus: !submittedModelImprovementPolicyRows.length
      ? "seed_model_improvement_policy_active"
      : modelImprovementPolicyReviewRows.length
        ? "submitted_model_improvement_policy_review_required"
        : "submitted_model_improvement_policy_active",
    requiredModelImprovementMethods: activeModelImprovementPolicy?.allowedTrainingMethods ?? [],
    requiredModelImprovementObjectiveFamilies: activeModelImprovementPolicy?.allowedObjectiveFamilies ?? [],
    requiredModelImprovementTargetFields: activeModelImprovementPolicy?.requiredTargetFields ?? [],
    requiredModelImprovementPolicyRules: activeModelImprovementPolicy?.policyRules ?? {},
    modelImprovementRunEvidence,
    evaluationRunEvidence,
    predictionEvidence,
    calibrationRunEvidence,
    leaderboardEvidence,
    failureAuditEvidence,
    modelRunProvenanceEvidence,
    modelProviderPolicyEvidence,
    reviewSections: allReviewSections.map((section) => section.artifactKind),
    releaseUseStatus: allReviewSections.length
      ? "submitted_model_evaluation_artifacts_review_required"
      : submittedSections.length
        ? "submitted_model_evaluation_artifacts_release_evidence_complete"
        : "computed_model_evaluation_artifacts_no_submitted_runs",
  };
}

function submittedModelImprovementRunEvidence(releaseId, trainingExport, submitted, activeModelImprovementPolicy = null) {
  const targetFields = uniqueStrings(normalizeStringArray(submitted?.targetFields));
  const excludedProtectedSplits = protectedSplitList(submitted);
  const modelImprovementPolicyId = submitted?.modelImprovementPolicyId ?? submitted?.model_improvement_policy_id ?? submitted?.policyId;
  const trainingMethod = submitted?.trainingMethod ?? submitted?.training_method ?? submitted?.rlhfMethod ?? submitted?.downstreamTrainingMethod;
  const objectiveFamily =
    submitted?.optimizedSurrogateObjectiveFamily ??
    submitted?.optimized_surrogate_objective_family ??
    submitted?.optimizedSurrogateObjective;
  const approvalStatus = submitted?.modelImprovementApprovalStatus ?? submitted?.model_improvement_approval_status ?? submitted?.approvalStatus;
  const checks = [
    requiredManifestCheck("releaseId", releaseId, submitted?.releaseId),
    requiredManifestCheck("modelImprovementPolicyId", activeModelImprovementPolicy?.id ?? "model_improvement_policy", modelImprovementPolicyId),
    requiredSetMembershipCheck("trainingMethod", activeModelImprovementPolicy?.allowedTrainingMethods ?? [], trainingMethod),
    requiredSetMembershipCheck("optimizedSurrogateObjectiveFamily", activeModelImprovementPolicy?.allowedObjectiveFamilies ?? [], objectiveFamily),
    requiredManifestCheck("trainingExportId", trainingExport.id, submitted?.trainingExportId),
    requiredManifestCheck("targetLabelSnapshotId", trainingExport.labelSnapshotId, submitted?.targetLabelSnapshotId ?? submitted?.labelSnapshotId),
    requiredManifestCheck("targetLabelVersion", trainingExport.targetLabelVersion, submitted?.targetLabelVersion),
    requiredNonEmptyCheck("modelFamilyOrCheckpoint", submitted?.modelFamilyOrCheckpoint ?? submitted?.modelFamily ?? submitted?.checkpointId),
    requiredNonEmptyCheck("optimizedSurrogateObjective", objectiveFamily),
    requiredArrayIncludesCheck("targetFields", activeModelImprovementPolicy?.requiredTargetFields ?? [], targetFields),
    requiredNonEmptyCheck("humanMarginWeightingPolicy", submitted?.humanMarginWeightingPolicy),
    requiredNonEmptyCheck("tieIndifferenceHandling", submitted?.tieIndifferenceHandling),
    requiredNonEmptyCheck("positionBalancedWeightingPolicy", submitted?.positionBalancedWeightingPolicy),
    requiredNonEmptyCheck("labelUncertaintyPropagationPolicy", submitted?.labelUncertaintyPropagationPolicy),
    requiredNonEmptyCheck("highUncertaintyDownweightingPolicy", submitted?.highUncertaintyDownweightingPolicy),
    requiredNonEmptyCheck("calibrationTargetDistribution", submitted?.calibrationTargetDistribution),
    requiredNonEmptyCheck("fitSplit", submitted?.fitSplit),
    requiredNonEmptyCheck("devSplit", submitted?.devSplit),
    requiredArrayIncludesCheck("excludedProtectedSplits", activeModelImprovementPolicy?.protectedSplitExclusions ?? [], excludedProtectedSplits),
    requiredSetMembershipCheck("modelImprovementApprovalStatus", activeModelImprovementPolicy?.allowedApprovalStatuses ?? [], approvalStatus),
    requiredPolicyIncludesCheck("promptTrackExposurePolicy", submitted?.promptTrackExposurePolicy, ["prompt", "track"]),
    requiredNonEmptyCheck("trainingPromptTemplateId", submitted?.trainingPromptTemplateId ?? submitted?.trainingPromptId),
    requiredNonEmptyCheck("linkedPostTrainingEvaluationRunIds", submitted?.linkedPostTrainingEvaluationRunIds ?? submitted?.postTrainingEvaluationRunIds),
    requiredManifestCheck("lmcaEvaluationMetricsSeparate", true, submitted?.lmcaEvaluationMetricsSeparate),
    requiredNonEmptyCheck("createdBy", submitted?.createdBy ?? submitted?.created_by),
    requiredNonEmptyCheck("timestamp", submitted?.timestamp),
  ];
  return releaseArtifactEvidenceRow(
    "model_improvement_run",
    submitted,
    checks,
    "submitted_model_improvement_run_preserves_surrogate_separation",
  );
}

function submittedEvaluationRunEvidence(releaseId, labelSnapshot, submitted) {
  const excludedProtectedSplits = protectedSplitList(submitted);
  const checks = [
    requiredManifestCheck("releaseId", releaseId, submitted?.releaseId),
    requiredManifestCheck("targetLabelSnapshotId", labelSnapshot.id, submitted?.targetLabelSnapshotId ?? submitted?.labelSnapshotId),
    requiredManifestCheck("targetLabelVersion", labelSnapshot.targetLabelVersion, submitted?.targetLabelVersion),
    requiredNonEmptyCheck("promptTemplateId", submitted?.promptTemplateId ?? submitted?.promptArtifactId ?? submitted?.promptArtifact?.id),
    requiredNonEmptyCheck("parserConfigId", submitted?.parserConfigId),
    requiredNonEmptyCheck("metricFamilies", submitted?.metricFamilies ?? Object.keys(submitted?.metricOutputs ?? {})),
    requiredArrayIncludesCheck("excludedProtectedSplits", ["internal_validation", "hidden_benchmark"], excludedProtectedSplits),
    requiredPolicyIncludesCheck("itemDataDelimiterPolicy", submitted?.itemDataDelimiterPolicy, ["delimiter"]),
    requiredPolicyIncludesCheck("instructionHierarchyText", submitted?.instructionHierarchyText, ["data", "not instruction"]),
    requiredPolicyIncludesAnyCheck("toolAvailabilityPolicy", submitted?.toolAvailabilityPolicy, ["no_tools", "disabled", "diagnostic"]),
    requiredPolicyIncludesCheck("promptInjectionArtifactFlagPolicy", submitted?.promptInjectionArtifactFlagPolicy, ["flag"]),
    requiredPolicyIncludesCheck("parserRetryPolicy", submitted?.parserRetryPolicy, ["schema", "not item"]),
    requiredPolicyIncludesCheck("promptExampleExclusionPolicy", submitted?.promptExampleExclusionPolicy, ["hidden", "protected"]),
  ];
  return releaseArtifactEvidenceRow("evaluation_run", submitted, checks, "submitted_evaluation_run_matches_current_target");
}

function submittedModelEvaluationPredictionEvidence(labelSnapshot, evaluationRun, predictions = []) {
  const submitted = predictions.length
    ? {
        id: `${evaluationRun?.id ?? "unbound"}:predictions`,
        createdAt: predictions.map((prediction) => prediction.createdAt ?? prediction.timestamp).filter(Boolean).sort().at(-1) ?? null,
      }
    : null;
  const targetItemIds = new Set(Object.keys(labelSnapshot.itemLabels));
  const mismatchCount = predictions.filter((prediction) => prediction.evaluationRunId !== evaluationRun?.id).length;
  const missingTextVersionCount = predictions.filter((prediction) => !prediction.positionTextVersionId || !prediction.critiqueTextVersionId).length;
  const missingRenderedItemHashCount = predictions.filter((prediction) => !prediction.renderedItemHash).length;
  const missingRatingContextSnapshotCount = predictions.filter((prediction) => !prediction.ratingContextSnapshotId).length;
  const missingRequestedModelAliasCount = predictions.filter((prediction) => !prediction.requestedModelAlias).length;
  const missingResolvedModelSnapshotCount = predictions.filter((prediction) => !prediction.resolvedModelSnapshot).length;
  const missingModelParameterSettingsCount = predictions.filter((prediction) =>
    !objectHasEntries(prediction.modelParameterSettings ?? prediction.model_parameter_settings ?? prediction.modelParameters ?? prediction.model_parameters),
  ).length;
  const missingAnswerExtractionPolicyCount = predictions.filter((prediction) => !prediction.answerExtractionPolicy && !prediction.answer_extraction_policy).length;
  const missingReasoningModeCount = predictions.filter((prediction) => !prediction.reasoningMode && !prediction.reasoning_mode).length;
  const missingReasoningBudgetCount = predictions.filter((prediction) => {
    const budget = prediction.reasoningBudget ?? prediction.reasoning_budget ?? prediction.reasoningBudgetTokens ?? prediction.reasoning_budget_tokens;
    return budget === undefined || budget === null || budget === "";
  }).length;
  const missingCueConditionCount = predictions.filter((prediction) => !prediction.cueCondition && !prediction.cue_condition).length;
  const missingObfuscationStressVariantCount = predictions.filter((prediction) => !prediction.obfuscationStressVariant && !prediction.obfuscation_stress_variant).length;
  const missingParserConfigCount = predictions.filter((prediction) => !prediction.parserConfigId).length;
  const unparsedPredictionCount = predictions.filter((prediction) => prediction.parseStatus && prediction.parseStatus !== "parsed").length;
  const unsafeDelimitedItemTextCount = predictions.filter((prediction) => prediction.delimitedItemTextIntegrityStatus !== "delimited_inert_data_preserved").length;
  const unsafeParserRetryInstructionCount = predictions.filter((prediction) => prediction.parserRetryInstructionAdherence !== "evaluator_prompt_followed_item_text_not_obeyed").length;
  const unsafeOutputSchemaValidationCount = predictions.filter((prediction) => prediction.outputSchemaValidationStatus !== "schema_validated").length;
  const toolUseObservedCount = predictions.filter((prediction) => prediction.toolUseObserved !== false).length;
  const rawOutputNotPreservedCount = predictions.filter((prediction) => prediction.rawOutputPreserved !== true).length;
  const missingItemInternalInstructionFlagCount = predictions.filter((prediction) =>
    !["none_detected", "instruction_like_text_flagged_inert", "model_output_wrapper_flagged_inert"].includes(prediction.itemInternalInstructionFlag),
  ).length;
  const targetLabelMatchedPredictionCount = predictions.filter((prediction) =>
    targetItemIds.has(makeItemId(prediction.positionId, prediction.critiqueId)),
  ).length;
  const checks = [
    requiredNonEmptyCheck("predictionRows", predictions),
    requiredManifestCheck("evaluationRunIdMismatchCount", 0, mismatchCount),
    requiredManifestCheck("missingTextVersionCount", 0, missingTextVersionCount),
    requiredManifestCheck("missingRenderedItemHashCount", 0, missingRenderedItemHashCount),
    requiredManifestCheck("missingRatingContextSnapshotCount", 0, missingRatingContextSnapshotCount),
    requiredManifestCheck("missingRequestedModelAliasCount", 0, missingRequestedModelAliasCount),
    requiredManifestCheck("missingResolvedModelSnapshotCount", 0, missingResolvedModelSnapshotCount),
    requiredManifestCheck("missingModelParameterSettingsCount", 0, missingModelParameterSettingsCount),
    requiredManifestCheck("missingAnswerExtractionPolicyCount", 0, missingAnswerExtractionPolicyCount),
    requiredManifestCheck("missingReasoningModeCount", 0, missingReasoningModeCount),
    requiredManifestCheck("missingReasoningBudgetCount", 0, missingReasoningBudgetCount),
    requiredManifestCheck("missingCueConditionCount", 0, missingCueConditionCount),
    requiredManifestCheck("missingObfuscationStressVariantCount", 0, missingObfuscationStressVariantCount),
    requiredManifestCheck("missingParserConfigCount", 0, missingParserConfigCount),
    requiredManifestCheck("unparsedPredictionCount", 0, unparsedPredictionCount),
    requiredManifestCheck("unsafeDelimitedItemTextCount", 0, unsafeDelimitedItemTextCount),
    requiredManifestCheck("unsafeParserRetryInstructionCount", 0, unsafeParserRetryInstructionCount),
    requiredManifestCheck("unsafeOutputSchemaValidationCount", 0, unsafeOutputSchemaValidationCount),
    requiredManifestCheck("toolUseObservedCount", 0, toolUseObservedCount),
    requiredManifestCheck("rawOutputNotPreservedCount", 0, rawOutputNotPreservedCount),
    requiredManifestCheck("missingItemInternalInstructionFlagCount", 0, missingItemInternalInstructionFlagCount),
    requiredMinimumCheck("targetLabelMatchedPredictionCount", 1, targetLabelMatchedPredictionCount),
  ];
  return {
    ...releaseArtifactEvidenceRow(
      "model_evaluation_predictions",
      submitted,
      checks,
      "submitted_model_evaluation_predictions_preserve_text_context_parser_and_condition_provenance",
    ),
    predictionIds: predictions.map((prediction) => prediction.id).filter(Boolean),
    counts: {
      predictionRows: predictions.length,
      targetLabelMatchedPredictionCount,
      missingTextVersionCount,
      missingRenderedItemHashCount,
      missingRatingContextSnapshotCount,
      missingRequestedModelAliasCount,
      missingResolvedModelSnapshotCount,
      missingModelParameterSettingsCount,
      missingAnswerExtractionPolicyCount,
      missingReasoningModeCount,
      missingReasoningBudgetCount,
      missingCueConditionCount,
      missingObfuscationStressVariantCount,
      unparsedPredictionCount,
      unsafeDelimitedItemTextCount,
      unsafeParserRetryInstructionCount,
      unsafeOutputSchemaValidationCount,
      toolUseObservedCount,
      rawOutputNotPreservedCount,
      missingItemInternalInstructionFlagCount,
    },
  };
}

