    pass: { sourceCriticalCoreGatePassCountMin: 5, requiredMetricFamilyCountMin: 2 },
    partial: { sourceCriticalCoreGatePassCountMin: 4, requiredMetricFamilyCountMin: 1 },
    fail: { sourceCriticalCoreGatePassCountMax: 3 },
