export function buildOperationalControlEvidenceReport(releaseId, options = {}) {
  const submittedActionRows = (options.policyActionKinds ?? [])
    .map((record) => normalizePolicyActionKind(record, "submitted_workflow_policy_action_kind"))
    .filter(Boolean);
  const seedActionRows = defaultPolicyActionKindRecords(releaseId).map((record) => normalizePolicyActionKind(record, "seed_policy_action_kind"));
  const actionRowsForGate = submittedActionRows.length ? submittedActionRows : seedActionRows;
  const submittedDecisionRows = (options.policyDecisionRecords ?? [])
    .map((record) => normalizePolicyDecisionRecord(record, actionRowsForGate, "submitted_workflow_policy_decision"))
    .filter(Boolean);
  const seedDecisionRows = defaultPolicyDecisionRecords(releaseId, seedActionRows).map((record) =>
    normalizePolicyDecisionRecord(record, seedActionRows, "seed_policy_decision"),
  );
  const decisionRowsForGate = [...seedDecisionRows, ...submittedDecisionRows];
  const submittedConsumptionRows = (options.policyDecisionConsumptions ?? [])
    .map((record) => normalizePolicyDecisionConsumption(record, decisionRowsForGate, "submitted_workflow_policy_decision_consumption"))
    .filter(Boolean);
  const submittedPhaseRows = (options.implementationPhaseGateBundles ?? [])
    .map((bundle) => normalizeImplementationPhaseGateBundle(bundle, "submitted_workflow_implementation_phase_gate_bundle"))
    .filter(Boolean);
  const seedPhaseRows = [normalizeImplementationPhaseGateBundle(defaultImplementationPhaseGateBundle(releaseId), "seed_implementation_phase_gate_bundle")];
  const submittedQueueRows = (options.queueFreshnessPolicies ?? [])
    .map((policy) => normalizeQueueFreshnessPolicy(policy, "submitted_workflow_queue_freshness_policy"))
    .filter(Boolean);
  const seedQueueRows = defaultQueueFreshnessPolicies(releaseId).map((policy) => normalizeQueueFreshnessPolicy(policy, "seed_queue_freshness_policy"));
  const queueRowsForGate = submittedQueueRows.length ? submittedQueueRows : seedQueueRows;
  const submittedScanRows = (options.queueStaleByDelayScans ?? [])
    .map((scan) => normalizeQueueStaleByDelayScan(scan, queueRowsForGate, "submitted_workflow_queue_stale_by_delay_scan"))
    .filter(Boolean);
  const seedScanRows = defaultQueueStaleByDelayScans(releaseId, defaultQueueFreshnessPolicies(releaseId)).map((scan) =>
    normalizeQueueStaleByDelayScan(scan, seedQueueRows, "seed_queue_stale_by_delay_scan"),
  );
  const scanRowsForGate = submittedScanRows.length ? submittedScanRows : submittedQueueRows.length ? [] : seedScanRows;
  const submittedClientPolicyRows = (options.clientSurfaceIntegrityPolicies ?? [])
    .map((policy) => normalizeClientSurfaceIntegrityPolicy(policy, "submitted_workflow_client_surface_integrity_policy"))
    .filter(Boolean);
  const seedClientPolicyRows = defaultClientSurfaceIntegrityPolicies(releaseId).map((policy) =>
    normalizeClientSurfaceIntegrityPolicy(policy, "seed_client_surface_integrity_policy"),
  );
  const clientPolicyRowsForGate = submittedClientPolicyRows.length ? submittedClientPolicyRows : seedClientPolicyRows;
  const submittedClientCheckRows = (options.clientSurfaceIntegrityChecks ?? [])
    .map((check) => normalizeClientSurfaceIntegrityCheck(check, clientPolicyRowsForGate, "submitted_workflow_client_surface_integrity_check"))
    .filter(Boolean);
  const seedClientCheckRows = defaultClientSurfaceIntegrityChecks(releaseId, defaultClientSurfaceIntegrityPolicies(releaseId)).map((check) =>
    normalizeClientSurfaceIntegrityCheck(check, seedClientPolicyRows, "seed_client_surface_integrity_check"),
  );
  const clientCheckRowsForGate = submittedClientCheckRows.length ? submittedClientCheckRows : seedClientCheckRows;
  const submittedCloudSecurityBudgetPolicyRows = (options.cloudSecurityBudgetPolicies ?? [])
    .map((policy) => normalizeCloudSecurityBudgetPolicy(policy, "submitted_workflow_cloud_security_budget_policy"))
    .filter(Boolean);
  const seedCloudSecurityBudgetPolicyRows = [
    normalizeCloudSecurityBudgetPolicy(defaultCloudSecurityBudgetPolicy(releaseId), "seed_cloud_security_budget_policy"),
  ];
  const activeCloudSecurityBudgetPolicy =
    submittedCloudSecurityBudgetPolicyRows.find((row) => row.reviewReasons.length === 0) ?? seedCloudSecurityBudgetPolicyRows[0];
  const submittedExternalWormAuditLogPolicyRows = (options.externalWormAuditLogPolicies ?? [])
    .map((policy) => normalizeExternalWormAuditLogPolicy(policy, "submitted_workflow_external_worm_audit_log_policy"))
    .filter(Boolean);
  const seedExternalWormAuditLogPolicyRows = [
    normalizeExternalWormAuditLogPolicy(defaultExternalWormAuditLogPolicy(releaseId), "seed_external_worm_audit_log_policy"),
  ];
  const activeExternalWormAuditLogPolicy =
    submittedExternalWormAuditLogPolicyRows.find((row) => row.reviewReasons.length === 0) ?? seedExternalWormAuditLogPolicyRows[0];
  const externalWormAuditLogPolicyRowsForGate = [...seedExternalWormAuditLogPolicyRows, ...submittedExternalWormAuditLogPolicyRows];
  const submittedAuditGovernanceRows = (options.governanceApprovalRecords ?? [])
    .map((record) => normalizeAuditChainGovernanceApprovalRecord(record, "submitted_workflow_audit_chain_governance_approval"))
    .filter(Boolean);
  const seedAuditGovernanceRows = defaultSensitiveAuditChainGovernanceApprovalRecords(releaseId).map((record) =>
    normalizeAuditChainGovernanceApprovalRecord(record, "seed_audit_chain_governance_approval"),
  );
  const auditGovernanceRowsForGate = [...seedAuditGovernanceRows, ...submittedAuditGovernanceRows];
  const submittedAuditRows = (options.sensitiveAuditChainEvents ?? [])
    .map((event) =>
      normalizeSensitiveAuditChainEvent(
        event,
        "submitted_workflow_sensitive_audit_chain_event",
        decisionRowsForGate,
        auditGovernanceRowsForGate,
        externalWormAuditLogPolicyRowsForGate,
      ),
    )
    .filter(Boolean);
  const seedAuditRows = defaultSensitiveAuditChainEvents(releaseId, defaultExternalWormAuditLogPolicy(releaseId)).map((event) =>
    normalizeSensitiveAuditChainEvent(
      event,
      "seed_sensitive_audit_chain_event",
      decisionRowsForGate,
      auditGovernanceRowsForGate,
      seedExternalWormAuditLogPolicyRows,
    ),
  );
  const auditRowsForGate = submittedAuditRows.length ? submittedAuditRows : seedAuditRows;
  const submittedAuditVerificationRows = (options.sensitiveAuditChainVerifications ?? [])
    .map((verification) => normalizeSensitiveAuditChainVerification(verification, auditRowsForGate, "submitted_workflow_sensitive_audit_chain_verification"))
    .filter(Boolean);
  const seedAuditVerificationRows = [
    normalizeSensitiveAuditChainVerification(defaultSensitiveAuditChainVerification(releaseId, seedAuditRows), seedAuditRows, "seed_sensitive_audit_chain_verification"),
  ];
  const submittedOperationalControlPackagePresent =
    submittedActionRows.length > 0 ||
    submittedPhaseRows.length > 0 ||
    submittedQueueRows.length > 0 ||
    submittedScanRows.length > 0 ||
    submittedClientPolicyRows.length > 0 ||
    submittedClientCheckRows.length > 0 ||
    submittedCloudSecurityBudgetPolicyRows.length > 0 ||
    submittedExternalWormAuditLogPolicyRows.length > 0 ||
    submittedAuditGovernanceRows.length > 0 ||
    submittedAuditRows.length > 0 ||
    submittedAuditVerificationRows.length > 0;
  const actionKindRows = REQUIRED_POLICY_ACTION_KINDS.map((actionKind) =>
    policyActionKindEvidenceRow(actionKind, actionRowsForGate, decisionRowsForGate, submittedConsumptionRows),
  );
  const policyActionConsumptionRows = REQUIRED_POLICY_ACTION_KINDS.map((actionKind) =>
    policyActionConsumptionEvidenceRow(actionKind, actionRowsForGate, decisionRowsForGate, submittedConsumptionRows),
  );
  const phaseLaneRows = REQUIRED_PHASE_GATE_LANE_KINDS.map((laneKind) => implementationPhaseLaneEvidenceRow(laneKind, submittedPhaseRows.length ? submittedPhaseRows : seedPhaseRows));
  const queueLaneRows = REQUIRED_QUEUE_FRESHNESS_LANES.map((lane) => queueFreshnessLaneEvidenceRow(lane, queueRowsForGate, scanRowsForGate));
  const clientSurfaceRows = REQUIRED_CLIENT_SURFACES.map((surface) => clientSurfaceEvidenceRow(surface, clientPolicyRowsForGate, clientCheckRowsForGate));
  const auditKindRows = REQUIRED_AUDIT_CHAIN_EVENT_KINDS.map((eventKind) => auditChainKindEvidenceRow(eventKind, auditRowsForGate));
  const auditVerificationRowsForGate = submittedAuditVerificationRows.length ? submittedAuditVerificationRows : seedAuditVerificationRows;
  const reviewSections = [
    ...submittedActionRows.flatMap((row) => row.reviewReasons.map((reason) => ({ artifactType: "policy_action_kind", artifactId: row.id, reason }))),
    ...submittedDecisionRows.flatMap((row) => row.reviewReasons.map((reason) => ({ artifactType: "policy_decision", artifactId: row.id, reason }))),
    ...submittedConsumptionRows.flatMap((row) => row.reviewReasons.map((reason) => ({ artifactType: "policy_decision_consumption", artifactId: row.id, reason }))),
    ...(submittedOperationalControlPackagePresent
      ? policyActionConsumptionRows.filter((row) => row.status !== "policy_action_consumption_covered").map((row) => ({
          artifactType: "policy_action_consumption_gate",
          artifactId: row.actionKind,
          reason: row.status,
        }))
      : []),
    ...submittedPhaseRows.flatMap((row) => row.reviewReasons.map((reason) => ({ artifactType: "implementation_phase_gate_bundle", artifactId: row.id, reason }))),
    ...submittedQueueRows.flatMap((row) => row.reviewReasons.map((reason) => ({ artifactType: "queue_freshness_policy", artifactId: row.id, reason }))),
    ...submittedScanRows.flatMap((row) => row.reviewReasons.map((reason) => ({ artifactType: "queue_stale_by_delay_scan", artifactId: row.id, reason }))),
    ...submittedClientPolicyRows.flatMap((row) => row.reviewReasons.map((reason) => ({ artifactType: "client_surface_integrity_policy", artifactId: row.id, reason }))),
    ...submittedClientCheckRows.flatMap((row) => row.reviewReasons.map((reason) => ({ artifactType: "client_surface_integrity_check", artifactId: row.id, reason }))),
    ...submittedCloudSecurityBudgetPolicyRows.flatMap((row) =>
      row.reviewReasons.map((reason) => ({ artifactType: "cloud_security_budget_policy", artifactId: row.id, reason })),
    ),
    ...submittedExternalWormAuditLogPolicyRows.flatMap((row) =>
      row.reviewReasons.map((reason) => ({ artifactType: "external_worm_audit_log_policy", artifactId: row.id, reason })),
    ),
    ...submittedAuditGovernanceRows.flatMap((row) => row.reviewReasons.map((reason) => ({ artifactType: "audit_chain_governance_approval", artifactId: row.id, reason }))),
    ...submittedAuditRows.flatMap((row) => row.reviewReasons.map((reason) => ({ artifactType: "sensitive_audit_chain_event", artifactId: row.id, reason }))),
    ...submittedAuditVerificationRows.flatMap((row) => row.reviewReasons.map((reason) => ({ artifactType: "sensitive_audit_chain_verification", artifactId: row.id, reason }))),
    ...actionKindRows.filter((row) => row.status !== "policy_action_kind_gate_complete").map((row) => ({
      artifactType: "policy_action_kind_gate",
      artifactId: row.actionKind,
      reason: row.status,
    })),
    ...phaseLaneRows.filter((row) => row.status !== "implementation_phase_lane_complete").map((row) => ({
      artifactType: "implementation_phase_lane",
      artifactId: row.laneKind,
      reason: row.status,
    })),
    ...queueLaneRows.filter((row) => row.status !== "queue_freshness_lane_complete").map((row) => ({
      artifactType: "queue_freshness_lane",
      artifactId: row.lane,
      reason: row.status,
    })),
    ...clientSurfaceRows.filter((row) => row.status !== "client_surface_integrity_complete").map((row) => ({
      artifactType: "client_surface",
      artifactId: row.surface,
      reason: row.status,
    })),
    ...auditKindRows.filter((row) => row.status !== "sensitive_audit_chain_kind_complete").map((row) => ({
      artifactType: "sensitive_audit_chain_kind",
      artifactId: row.eventKind,
      reason: row.status,
    })),
    auditVerificationRowsForGate.some((row) => row.reviewReasons.length === 0)
      ? null
      : { artifactType: "sensitive_audit_chain_verification", artifactId: "sensitive_audit_chain", reason: "missing_complete_audit_chain_verification" },
  ].filter(Boolean);
  const submittedEvidenceComplete =
    submittedActionRows.length > 0 &&
    submittedDecisionRows.length > 0 &&
    submittedConsumptionRows.length > 0 &&
    submittedPhaseRows.length > 0 &&
    submittedQueueRows.length > 0 &&
    submittedScanRows.length > 0 &&
    submittedClientPolicyRows.length > 0 &&
    submittedClientCheckRows.length > 0 &&
    submittedCloudSecurityBudgetPolicyRows.length > 0 &&
    submittedExternalWormAuditLogPolicyRows.length > 0 &&
    submittedAuditGovernanceRows.length > 0 &&
    submittedAuditRows.length > 0 &&
    submittedAuditVerificationRows.length > 0 &&
    policyActionConsumptionRows.every((row) => row.status === "policy_action_consumption_covered") &&
    reviewSections.length === 0;
  return {
    id: `operational-control-evidence-${releaseId}`,
    releaseId,
    generatedAt: new Date().toISOString(),
    requiredPolicyActionKinds: REQUIRED_POLICY_ACTION_KINDS,
    requiredPhaseGateLaneKinds: REQUIRED_PHASE_GATE_LANE_KINDS,
	    requiredQueueFreshnessLanes: REQUIRED_QUEUE_FRESHNESS_LANES,
	    requiredQueueRevalidationChecks: REQUIRED_QUEUE_REVALIDATION_CHECKS,
	    requiredClientSurfaces: REQUIRED_CLIENT_SURFACES,
	    requiredClientSurfaceChecks: REQUIRED_CLIENT_SURFACE_CHECKS,
    requiredClientSurfaceIntegrityPolicyVersion: CLIENT_SURFACE_INTEGRITY_POLICY_VERSION,
    requiredClientSurfaceCspDirectives: REQUIRED_CLIENT_SURFACE_CSP_DIRECTIVES,
    requiredClientSurfaceTelemetryAllowlist: REQUIRED_CLIENT_SURFACE_TELEMETRY_ALLOWLIST,
    requiredClientSurfaceReferrerPolicy: REQUIRED_CLIENT_SURFACE_REFERRER_POLICY,
    requiredClientSurfaceCachePolicy: REQUIRED_CLIENT_SURFACE_CACHE_POLICY,
    requiredClientSurfaceUrlIdentifierPolicy: REQUIRED_CLIENT_SURFACE_URL_IDENTIFIER_POLICY,
    requiredCloudSecurityBudgetRangeUsd: REQUIRED_CLOUD_SECURITY_BUDGET_RANGE_USD,
    requiredCloudSecurityBudgetCategoryMinimumUsd: REQUIRED_CLOUD_SECURITY_BUDGET_CATEGORY_MINIMUM_USD,
    requiredCloudSecurityControls: REQUIRED_CLOUD_SECURITY_CONTROLS,
    requiredCloudSecurityApprovalStatuses: REQUIRED_CLOUD_SECURITY_APPROVAL_STATUSES,
    cloudSecurityBudgetPolicyId: activeCloudSecurityBudgetPolicy?.id ?? null,
    cloudSecurityBudgetPolicyReleaseUseStatus: submittedCloudSecurityBudgetPolicyRows.find((row) => row.reviewReasons.length === 0)
      ? "submitted_cloud_security_budget_policy_active"
      : submittedCloudSecurityBudgetPolicyRows.length
        ? "submitted_cloud_security_budget_policy_review_required"
        : "seed_cloud_security_budget_policy_active",
    externalWormAuditLogPolicyId: activeExternalWormAuditLogPolicy?.id ?? null,
    externalWormAuditLogPolicyReleaseUseStatus: submittedExternalWormAuditLogPolicyRows.find((row) => row.reviewReasons.length === 0)
      ? "submitted_external_worm_audit_log_policy_active"
      : submittedExternalWormAuditLogPolicyRows.length
        ? "submitted_external_worm_audit_log_policy_review_required"
        : "seed_external_worm_audit_log_policy_active",
    requiredExternalWormAuditLogPolicyVersion: EXTERNAL_WORM_AUDIT_LOG_POLICY_VERSION,
    requiredExternalWormAuditLedgerBackend: REQUIRED_EXTERNAL_WORM_AUDIT_LEDGER_BACKEND,
    requiredExternalWormAuditPointerPrefix: REQUIRED_EXTERNAL_WORM_AUDIT_POINTER_PREFIX,
    requiredExternalWormAuditRetentionYears: REQUIRED_EXTERNAL_WORM_AUDIT_RETENTION_YEARS,
    requiredExternalWormAuditReceiptHashAlgorithm: REQUIRED_EXTERNAL_WORM_AUDIT_RECEIPT_HASH_ALGORITHM,
    requiredExternalWormAuditReceiptFields: REQUIRED_EXTERNAL_WORM_AUDIT_RECEIPT_FIELDS,
    requiredExternalWormAuditVerificationCadence: REQUIRED_EXTERNAL_WORM_AUDIT_VERIFICATION_CADENCE,
    requiredExternalWormAuditFallbackRule: REQUIRED_EXTERNAL_WORM_AUDIT_FALLBACK_RULE,
	    requiredAuditChainEventKinds: REQUIRED_AUDIT_CHAIN_EVENT_KINDS,
    policyActionKindRows: [...seedActionRows, ...submittedActionRows],
    policyDecisionRows: [...seedDecisionRows, ...submittedDecisionRows],
    policyDecisionConsumptionRows: submittedConsumptionRows,
    policyActionConsumptionRows,
    implementationPhaseGateBundleRows: [...seedPhaseRows, ...submittedPhaseRows],
    queueFreshnessPolicyRows: [...seedQueueRows, ...submittedQueueRows],
    queueStaleByDelayScanRows: [...seedScanRows, ...submittedScanRows],
    clientSurfaceIntegrityPolicyRows: [...seedClientPolicyRows, ...submittedClientPolicyRows],
    clientSurfaceIntegrityCheckRows: [...seedClientCheckRows, ...submittedClientCheckRows],
    cloudSecurityBudgetPolicyRows: [...seedCloudSecurityBudgetPolicyRows, ...submittedCloudSecurityBudgetPolicyRows],
    externalWormAuditLogPolicyRows: [...seedExternalWormAuditLogPolicyRows, ...submittedExternalWormAuditLogPolicyRows],
    sensitiveAuditChainGovernanceApprovalRows: [...seedAuditGovernanceRows, ...submittedAuditGovernanceRows],
    sensitiveAuditChainEventRows: [...seedAuditRows, ...submittedAuditRows],
    sensitiveAuditChainVerificationRows: [...seedAuditVerificationRows, ...submittedAuditVerificationRows],
    actionKindRows,
    phaseLaneRows,
    queueLaneRows,
    clientSurfaceRows,
    auditKindRows,
    counts: {
      submittedPolicyActionKindCount: submittedActionRows.length,
      submittedPolicyDecisionCount: submittedDecisionRows.length,
      submittedPolicyDecisionConsumptionCount: submittedConsumptionRows.length,
      submittedImplementationPhaseGateBundleCount: submittedPhaseRows.length,
      submittedQueueFreshnessPolicyCount: submittedQueueRows.length,
      submittedQueueStaleByDelayScanCount: submittedScanRows.length,
      submittedClientSurfaceIntegrityPolicyCount: submittedClientPolicyRows.length,
      submittedClientSurfaceIntegrityCheckCount: submittedClientCheckRows.length,
      submittedCloudSecurityBudgetPolicyCount: submittedCloudSecurityBudgetPolicyRows.length,
      cloudSecurityBudgetPolicyReviewRows: submittedCloudSecurityBudgetPolicyRows.filter((row) => row.reviewReasons.length).length,
      submittedExternalWormAuditLogPolicyCount: submittedExternalWormAuditLogPolicyRows.length,
      externalWormAuditLogPolicyReviewRows: submittedExternalWormAuditLogPolicyRows.filter((row) => row.reviewReasons.length).length,
      submittedSensitiveAuditChainGovernanceApprovalCount: submittedAuditGovernanceRows.length,
      submittedSensitiveAuditChainEventCount: submittedAuditRows.length,
      submittedSensitiveAuditChainVerificationCount: submittedAuditVerificationRows.length,
      passingPolicyActionKindCount: actionKindRows.filter((row) => row.status === "policy_action_kind_gate_complete").length,
      passingPolicyActionConsumptionCount: policyActionConsumptionRows.filter((row) => row.status === "policy_action_consumption_covered").length,
      passingPhaseLaneCount: phaseLaneRows.filter((row) => row.status === "implementation_phase_lane_complete").length,
      passingQueueFreshnessLaneCount: queueLaneRows.filter((row) => row.status === "queue_freshness_lane_complete").length,
      passingClientSurfaceCount: clientSurfaceRows.filter((row) => row.status === "client_surface_integrity_complete").length,
      passingAuditChainKindCount: auditKindRows.filter((row) => row.status === "sensitive_audit_chain_kind_complete").length,
      reviewSectionCount: reviewSections.length,
    },
    reviewSections,
    releaseUseStatus: reviewSections.length
      ? "operational_control_review_required"
      : submittedEvidenceComplete
        ? "submitted_operational_control_evidence_complete"
        : "seed_operational_control_evidence_complete",
  };
}

function normalizePolicyActionKind(record, rowSource) {
  const id = record?.id ?? record?.policyActionKindId;
  if (!id) return null;
  const actionKind = record.actionKind ?? record.kind ?? null;
  const reviewReasons = [
    REQUIRED_POLICY_ACTION_KINDS.includes(actionKind) ? null : "actionKind",
    record.requiresCurrentDecision === true ? null : "requiresCurrentDecision",
	    record.requiresManifestBinding === true ? null : "requiresManifestBinding",
	    record.requiresActorBinding === true ? null : "requiresActorBinding",
	    record.requiresOutputSchemaBinding === true ? null : "requiresOutputSchemaBinding",
	    record.requiresPhaseGateBinding === true ? null : "requiresPhaseGateBinding",
	    record.requiresIdempotencyBinding === true ? null : "requiresIdempotencyBinding",
	    ["single_use", "idempotency_bound"].includes(record.replayProtection) ? null : "replayProtection",
	    record.wrongScopeBehavior === "fail_closed" ? null : "wrongScopeBehavior",
	    requiredPromptFieldReason("activatedAt", record.activatedAt),
  ].filter(Boolean);
  return {
    id,
    rowSource,
    actionKind,
    sideEffecting: record.sideEffecting === true,
    protectedRender: record.protectedRender === true,
    replayProtection: record.replayProtection ?? null,
    reviewReasons,
    status: reviewReasons.length ? "policy_action_kind_review_required" : "policy_action_kind_complete",
  };
}

function normalizePolicyDecisionRecord(record, actionRows, rowSource) {
  const id = record?.id ?? record?.policyDecisionRecordId;
  if (!id) return null;
  const actionKindId = record.actionKindId ?? record.policyActionKindId ?? null;
  const actionKind = record.actionKind ?? actionRows.find((row) => row.id === actionKindId)?.actionKind ?? null;
  const actionRow = actionRows.find((row) => row.id === actionKindId || row.actionKind === actionKind);
  const reviewReasons = [
    actionRow && actionRow.reviewReasons.length === 0 ? null : "actionKindId",
	    record.decisionStatus === "allow" ? null : "decisionStatus",
	    requiredPromptFieldReason("actorId", record.actorId),
	    requiredPromptFieldReason("manifestId", record.manifestId),
	    typeof record.manifestHash === "string" && record.manifestHash.startsWith("sha256:") ? null : "manifestHash",
	    requiredPromptFieldReason("phaseGateBundleId", record.phaseGateBundleId),
	    typeof record.phaseGateBundleHash === "string" && record.phaseGateBundleHash.startsWith("sha256:") ? null : "phaseGateBundleHash",
	    requiredPromptFieldReason("releaseId", record.releaseId),
	    requiredPromptFieldReason("outputSchemaVersion", record.outputSchemaVersion),
	    typeof record.outputSchemaHash === "string" && record.outputSchemaHash.startsWith("sha256:") ? null : "outputSchemaHash",
	    normalizeStringArray(record.targetArtifactIds).length ? null : "targetArtifactIds",
	    record.singleUse === true || requiredPromptFieldReason("idempotencyKey", record.idempotencyKey) === null ? null : "idempotencyKey",
	    record.replayStatus === "unused" ? null : "replayStatus",
	    record.manifestBindingStatus === "matched" ? null : "manifestBindingStatus",
	    record.outputSchemaBindingStatus === "matched" ? null : "outputSchemaBindingStatus",
	    record.phaseGateBindingStatus === "matched" ? null : "phaseGateBindingStatus",
	    record.idempotencyBindingStatus === "matched" ? null : "idempotencyBindingStatus",
	    requiredPromptFieldReason("expiresAt", record.expiresAt),
	    requiredPromptFieldReason("decidedAt", record.decidedAt),
	  ].filter(Boolean);
  return {
    id,
    rowSource,
    actionKindId,
    actionKind,
    decisionStatus: record.decisionStatus ?? null,
    actorId: record.actorId ?? null,
	    actorRole: record.actorRole ?? null,
	    manifestId: record.manifestId ?? null,
	    manifestHash: record.manifestHash ?? null,
	    phaseGateBundleId: record.phaseGateBundleId ?? null,
	    phaseGateBundleHash: record.phaseGateBundleHash ?? null,
	    releaseId: record.releaseId ?? null,
	    outputSchemaVersion: record.outputSchemaVersion ?? null,
	    outputSchemaHash: record.outputSchemaHash ?? null,
	    targetArtifactIds: normalizeStringArray(record.targetArtifactIds),
	    idempotencyKey: record.idempotencyKey ?? null,
	    singleUse: record.singleUse === true,
	    replayStatus: record.replayStatus ?? null,
	    manifestBindingStatus: record.manifestBindingStatus ?? null,
	    outputSchemaBindingStatus: record.outputSchemaBindingStatus ?? null,
	    phaseGateBindingStatus: record.phaseGateBindingStatus ?? null,
	    idempotencyBindingStatus: record.idempotencyBindingStatus ?? null,
	    expiresAt: record.expiresAt ?? null,
	    consumedAt: record.consumedAt ?? null,
	    reviewReasons,
    status: reviewReasons.length ? "policy_decision_review_required" : "policy_decision_allow_current",
  };
}

function normalizePolicyDecisionConsumption(record, decisionRows, rowSource) {
  const id = record?.id ?? record?.policyDecisionConsumptionId;
  if (!id) return null;
  const decisionId = record.decisionId ?? record.policyDecisionId ?? null;
  const decisionRow = decisionRows.find((row) => row.id === decisionId);
	  const reviewReasons = [
	    decisionRow && decisionRow.reviewReasons.length === 0 ? null : "decisionId",
	    record.actionKind === decisionRow?.actionKind ? null : "actionKind",
	    record.manifestId === decisionRow?.manifestId ? null : "manifestId",
	    record.manifestHash === decisionRow?.manifestHash ? null : "manifestHash",
	    record.phaseGateBundleId === decisionRow?.phaseGateBundleId ? null : "phaseGateBundleId",
	    record.phaseGateBundleHash === decisionRow?.phaseGateBundleHash ? null : "phaseGateBundleHash",
	    record.outputSchemaVersion === decisionRow?.outputSchemaVersion ? null : "outputSchemaVersion",
	    record.outputSchemaHash === decisionRow?.outputSchemaHash ? null : "outputSchemaHash",
	    record.idempotencyKey === decisionRow?.idempotencyKey ? null : "idempotencyKey",
	    record.replayRejected === false ? null : "replayRejected",
	    record.scopeMatched === true ? null : "scopeMatched",
	    requiredPromptFieldReason("consumedAt", record.consumedAt),
  ].filter(Boolean);
  return {
    id,
    rowSource,
	    decisionId,
	    actionKind: record.actionKind ?? decisionRow?.actionKind ?? null,
	    manifestId: record.manifestId ?? null,
	    manifestHash: record.manifestHash ?? null,
	    phaseGateBundleId: record.phaseGateBundleId ?? null,
	    phaseGateBundleHash: record.phaseGateBundleHash ?? null,
	    outputSchemaVersion: record.outputSchemaVersion ?? null,
	    outputSchemaHash: record.outputSchemaHash ?? null,
	    idempotencyKey: record.idempotencyKey ?? null,
	    replayRejected: record.replayRejected === true,
	    scopeMatched: record.scopeMatched === true,
    consumedAt: record.consumedAt ?? null,
    reviewReasons,
    status: reviewReasons.length ? "policy_decision_consumption_review_required" : "policy_decision_consumed_once",
  };
}

function normalizeImplementationPhaseGateBundle(bundle, rowSource) {
  const id = bundle?.id ?? bundle?.implementationPhaseGateBundleId;
  if (!id) return null;
  const laneStates = Array.isArray(bundle.laneStates) ? bundle.laneStates : [];
  const coveredLaneKinds = laneStates.map((lane) => lane.laneKind).filter(Boolean);
  const missingLaneKinds = REQUIRED_PHASE_GATE_LANE_KINDS.filter((laneKind) => !coveredLaneKinds.includes(laneKind));
  const unsafeDisabledLanes = laneStates
    .filter((lane) => ["disabled_stub", "blocked"].includes(lane.phaseState))
    .filter((lane) => lane.failClosed !== true || lane.noSideEffectsWhenDisabled !== true || lane.labelsExposedWhenDisabled === true || lane.supportsReleaseClaimsWhenDisabled === true)
    .map((lane) => lane.laneKind ?? lane.laneId ?? "unknown");
  const reviewReasons = [
    requiredPromptFieldReason("releaseId", bundle.releaseId),
    requiredPromptFieldReason("manifestId", bundle.manifestId),
    requiredPromptFieldReason("version", bundle.version),
    missingLaneKinds.length ? `laneStates:${missingLaneKinds.join(",")}` : null,
    unsafeDisabledLanes.length ? `disabledLaneFailClosed:${unsafeDisabledLanes.join(",")}` : null,
    bundle.futurePhaseDefault === "blocked" ? null : "futurePhaseDefault",
    bundle.broadeningRequiresManifestActivation === true ? null : "broadeningRequiresManifestActivation",
    requiredPromptFieldReason("frozenAt", bundle.frozenAt),
  ].filter(Boolean);
  return {
    id,
    rowSource,
    releaseId: bundle.releaseId ?? null,
    manifestId: bundle.manifestId ?? null,
    version: bundle.version ?? null,
    phaseGateBundleHash:
      bundle.phaseGateBundleHash ?? bundle.canonicalBundleHash ?? bundle.bundleHash ?? `sha256:${id}`,
    laneStates,
    missingLaneKinds,
    unsafeDisabledLanes,
    futurePhaseDefault: bundle.futurePhaseDefault ?? null,
    reviewReasons,
    status: reviewReasons.length ? "implementation_phase_gate_review_required" : "implementation_phase_gate_complete",
  };
}

function normalizeQueueFreshnessPolicy(policy, rowSource) {
  const id = policy?.id ?? policy?.queueFreshnessPolicyId;
  if (!id) return null;
  const lane = policy.lane ?? policy.queueLane ?? null;
  const dependencyRevalidationChecks = normalizeStringArray(policy.dependencyRevalidationChecks);
  const queueHealthChecks = normalizeStringArray(policy.queueHealthChecks);
  const missingChecks = REQUIRED_QUEUE_REVALIDATION_CHECKS.filter((check) => !dependencyRevalidationChecks.includes(check));
  const missingHealthChecks = REQUIRED_QUEUE_HEALTH_CHECKS.filter((check) => !queueHealthChecks.includes(check));
  const reviewReasons = [
    REQUIRED_QUEUE_FRESHNESS_LANES.includes(lane) ? null : "lane",
    Number.isFinite(policy.freshnessWindowMinutes) && policy.freshnessWindowMinutes > 0 ? null : "freshnessWindowMinutes",
    missingChecks.length ? `dependencyRevalidationChecks:${missingChecks.join(",")}` : null,
    Number.isFinite(policy.backpressureThreshold) && policy.backpressureThreshold > 0 ? null : "backpressureThreshold",
    ["stale", "paused", "pause", "cancel", "cancelled", "recompute", "suppress"].includes(policy.staleBehavior) ? null : "staleBehavior",
    policyMentions(policy.sideChannelSafeNotificationBehavior, ["generic"]) && policyMentions(policy.sideChannelSafeNotificationBehavior, ["protected"])
      ? null
      : "sideChannelSafeNotificationBehavior",
    missingHealthChecks.length ? `queueHealthChecks:${missingHealthChecks.join(",")}` : null,
    policy.workerConsumeRevalidationRequired === true ? null : "workerConsumeRevalidationRequired",
    policy.renderRevalidationRequired === true ? null : "renderRevalidationRequired",
    policy.submitRevalidationRequired === true ? null : "submitRevalidationRequired",
    policyMentions(policy.backpressureBehavior, ["pause"]) || policyMentions(policy.backpressureBehavior, ["recompute"]) ? null : "backpressureBehavior",
    requiredPromptFieldReason("createdBy", policy.createdBy ?? policy.created_by),
    requiredPromptFieldReason("frozenAt", policy.frozenAt ?? policy.frozen_at),
  ].filter(Boolean);
  return {
    id,
    rowSource,
    releaseId: policy.releaseId ?? null,
    lane,
    freshnessWindowMinutes: policy.freshnessWindowMinutes ?? null,
    dependencyRevalidationChecks,
    missingChecks,
    backpressureThreshold: policy.backpressureThreshold ?? null,
    staleBehavior: policy.staleBehavior ?? null,
    sideChannelSafeNotificationBehavior: policy.sideChannelSafeNotificationBehavior ?? null,
    queueHealthChecks,
    missingHealthChecks,
    workerConsumeRevalidationRequired: policy.workerConsumeRevalidationRequired === true,
    renderRevalidationRequired: policy.renderRevalidationRequired === true,
    submitRevalidationRequired: policy.submitRevalidationRequired === true,
    createdBy: policy.createdBy ?? policy.created_by ?? null,
    frozenAt: policy.frozenAt ?? policy.frozen_at ?? null,
    reviewReasons,
    status: reviewReasons.length ? "queue_freshness_policy_review_required" : "queue_freshness_policy_complete",
  };
}

function normalizeQueueStaleByDelayScan(scan, policyRows, rowSource) {
  const id = scan?.id ?? scan?.queueStaleByDelayScanId;
  if (!id) return null;
  const lane = scan.lane ?? null;
  const policyRow = policyRows.find((row) => row.lane === lane && row.reviewReasons.length === 0);
  const staleCount = Number(scan.staleCount ?? 0);
  const dependencyRevalidationChecks = normalizeStringArray(scan.dependencyRevalidationChecks);
  const queueHealthChecks = normalizeStringArray(scan.queueHealthChecks);
  const staleTransitionOutcomes = normalizeStringArray(scan.staleTransitionOutcomes);
  const missingChecks = REQUIRED_QUEUE_REVALIDATION_CHECKS.filter((check) => !dependencyRevalidationChecks.includes(check));
  const missingHealthChecks = REQUIRED_QUEUE_HEALTH_CHECKS.filter((check) => !queueHealthChecks.includes(check));
  const missingTransitionOutcomes = REQUIRED_QUEUE_STALE_TRANSITION_OUTCOMES.filter((outcome) => !staleTransitionOutcomes.includes(outcome));
  const reviewReasons = [
    policyRow ? null : "lane",
    policyRow && scan.policyId === policyRow.id ? null : "policyId",
    scan.scanStatus === "passed" ? null : "scanStatus",
    Number.isFinite(staleCount) && staleCount > 0 ? null : "staleCount",
    policyRow && Number.isFinite(scan.maxObservedAgeMinutes) && scan.maxObservedAgeMinutes >= policyRow.freshnessWindowMinutes ? null : "maxObservedAgeMinutes",
    policyRow && scan.backpressureThreshold === policyRow.backpressureThreshold ? null : "backpressureThreshold",
    missingChecks.length ? `dependencyRevalidationChecks:${missingChecks.join(",")}` : null,
    scan.staleTransitionBehavior === policyRow?.staleBehavior ? null : "staleTransitionBehavior",
    missingTransitionOutcomes.length ? `staleTransitionOutcomes:${missingTransitionOutcomes.join(",")}` : null,
    missingHealthChecks.length ? `queueHealthChecks:${missingHealthChecks.join(",")}` : null,
    scan.workerConsumeRevalidationConfirmed === true ? null : "workerConsumeRevalidationConfirmed",
    scan.sideEffectSuppressionConfirmed === true ? null : "sideEffectSuppressionConfirmed",
    scan.sideChannelSafeNotificationConfirmed === true ? null : "sideChannelSafeNotificationConfirmed",
    requiredPromptFieldReason("scannedAt", scan.scannedAt),
  ].filter(Boolean);
  return {
    id,
    rowSource,
    policyId: scan.policyId ?? null,
    lane,
    scanStatus: scan.scanStatus ?? null,
    staleCount,
    maxObservedAgeMinutes: scan.maxObservedAgeMinutes ?? null,
    backpressureThreshold: scan.backpressureThreshold ?? null,
    dependencyRevalidationChecks,
    missingChecks,
    staleTransitionBehavior: scan.staleTransitionBehavior ?? null,
    staleTransitionOutcomes,
    missingTransitionOutcomes,
    queueHealthChecks,
    missingHealthChecks,
    workerConsumeRevalidationConfirmed: scan.workerConsumeRevalidationConfirmed === true,
    sideEffectSuppressionConfirmed: scan.sideEffectSuppressionConfirmed === true,
    sideChannelSafeNotificationConfirmed: scan.sideChannelSafeNotificationConfirmed === true,
    scannedAt: scan.scannedAt ?? null,
    reviewReasons,
    status: reviewReasons.length ? "queue_stale_by_delay_scan_review_required" : "queue_stale_by_delay_scan_complete",
  };
}

function normalizeClientSurfaceIntegrityPolicy(policy, rowSource) {
  const id = policy?.id ?? policy?.clientSurfaceIntegrityPolicyId;
  if (!id) return null;
  const surface = policy.surface ?? policy.screenKind ?? null;
  const cspDirectives =
    policy.cspDirectives && typeof policy.cspDirectives === "object" && !Array.isArray(policy.cspDirectives)
      ? policy.cspDirectives
      : {};
  const firstPartyTelemetryAllowlist = normalizeStringArray(policy.firstPartyTelemetryAllowlist);
	  const reviewReasons = [
      (policy.policyVersion ?? policy.version) === CLIENT_SURFACE_INTEGRITY_POLICY_VERSION
        ? null
        : `policyVersion:${CLIENT_SURFACE_INTEGRITY_POLICY_VERSION}`,
	    REQUIRED_CLIENT_SURFACES.includes(surface) ? null : "surface",
	    policy.thirdPartyAnalyticsProhibited === true ? null : "thirdPartyAnalyticsProhibited",
	    policy.thirdPartyPixelsProhibited === true ? null : "thirdPartyPixelsProhibited",
	    policy.thirdPartyResourcesProhibited === true ? null : "thirdPartyResourcesProhibited",
	    Array.isArray(policy.thirdPartyResourceAllowlist) && policy.thirdPartyResourceAllowlist.length === 0 ? null : "thirdPartyResourceAllowlist",
	    policy.sessionReplayProhibited === true ? null : "sessionReplayProhibited",
	    policy.heatmapTrackingProhibited === true ? null : "heatmapTrackingProhibited",
	    policy.domCaptureProhibited === true ? null : "domCaptureProhibited",
	    policy.keystrokeLoggingProhibited === true ? null : "keystrokeLoggingProhibited",
	    policy.sensitiveUrlIdsProhibited === true ? null : "sensitiveUrlIdsProhibited",
    policy.urlIdentifierPolicy === REQUIRED_CLIENT_SURFACE_URL_IDENTIFIER_POLICY ? null : "urlIdentifierPolicy",
	    policy.referrerLeakageBlocked === true ? null : "referrerLeakageBlocked",
    policy.referrerPolicy === REQUIRED_CLIENT_SURFACE_REFERRER_POLICY ? null : "referrerPolicy",
	    policy.persistentOfflineCacheProhibited === true ? null : "persistentOfflineCacheProhibited",
    policy.cacheOfflineStoragePolicy === REQUIRED_CLIENT_SURFACE_CACHE_POLICY ? null : "cacheOfflineStoragePolicy",
	    policy.firstPartyTelemetryOnly === true ? null : "firstPartyTelemetryOnly",
	    policy.telemetryAllowlistEnforced === true ? null : "telemetryAllowlistEnforced",
	    policy.screenStateOutputSchemaBound === true ? null : "screenStateOutputSchemaBound",
	    policy.nonStaffPromotionBlockedOnViolation === true ? null : "nonStaffPromotionBlockedOnViolation",
	    policy.cspEnforced === true ? null : "cspEnforced",
    stableJsonKey(cspDirectives) === stableJsonKey(REQUIRED_CLIENT_SURFACE_CSP_DIRECTIVES) ? null : "cspDirectives",
	    stableJsonKey(firstPartyTelemetryAllowlist) === stableJsonKey(REQUIRED_CLIENT_SURFACE_TELEMETRY_ALLOWLIST) ? null : "firstPartyTelemetryAllowlist",
	  ].filter(Boolean);
  return {
    id,
    rowSource,
	    releaseId: policy.releaseId ?? null,
    policyVersion: policy.policyVersion ?? policy.version ?? null,
	    surface,
	    thirdPartyResourceAllowlist: normalizeStringArray(policy.thirdPartyResourceAllowlist),
    cspDirectives,
    urlIdentifierPolicy: policy.urlIdentifierPolicy ?? null,
    referrerPolicy: policy.referrerPolicy ?? null,
    cacheOfflineStoragePolicy: policy.cacheOfflineStoragePolicy ?? null,
	    firstPartyTelemetryAllowlist,
	    reviewReasons,
	    status: reviewReasons.length ? "client_surface_integrity_policy_review_required" : "client_surface_integrity_policy_complete",
	  };
}

function normalizeClientSurfaceIntegrityCheck(check, policyRows, rowSource) {
  const id = check?.id ?? check?.clientSurfaceIntegrityCheckId;
  if (!id) return null;
  const clientSurfaceId = check.clientSurfaceId ?? check.policyId ?? null;
  const surface = check.surface ?? policyRows.find((row) => row.id === clientSurfaceId)?.surface ?? null;
  const policyRow = policyRows.find((row) => row.id === clientSurfaceId || row.surface === surface);
	  const failures = Array.isArray(check.failures) ? check.failures : [];
	  const checksPassed = normalizeStringArray(check.checksPassed);
	  const missingChecks = REQUIRED_CLIENT_SURFACE_CHECKS.filter((requiredCheck) => !checksPassed.includes(requiredCheck));
	  const reviewReasons = [
	    policyRow && policyRow.reviewReasons.length === 0 ? null : "clientSurfaceId",
	    check.checkStatus === "passed" ? null : "checkStatus",
	    ...missingChecks,
	    failures.length ? "failures" : null,
	    requiredPromptFieldReason("checkedAt", check.checkedAt),
	  ].filter(Boolean);
  return {
    id,
    rowSource,
    clientSurfaceId,
    surface,
    checkStatus: check.checkStatus ?? null,
    checksPassed,
    failures,
    checkedAt: check.checkedAt ?? null,
    reviewReasons,
    status: reviewReasons.length ? "client_surface_integrity_check_review_required" : "client_surface_integrity_check_passed",
  };
}

function normalizeCloudSecurityBudgetPolicy(policy, rowSource) {
  const id = policy?.id ?? policy?.cloudSecurityBudgetPolicyId;
  if (!id) return null;
  const totalBudgetRangeUsd =
    policy.totalBudgetRangeUsd && typeof policy.totalBudgetRangeUsd === "object" && !Array.isArray(policy.totalBudgetRangeUsd)
      ? policy.totalBudgetRangeUsd
      : {};
  const categoryMinimumUsd =
    policy.categoryMinimumUsd && typeof policy.categoryMinimumUsd === "object" && !Array.isArray(policy.categoryMinimumUsd)
      ? policy.categoryMinimumUsd
      : {};
  const requiredControls = normalizeStringArray(policy.requiredControls);
  const approvalStatuses = normalizeStringArray(policy.approvalStatuses);
  const missingCategoryKeys = Object.keys(REQUIRED_CLOUD_SECURITY_BUDGET_CATEGORY_MINIMUM_USD).filter((key) => !Object.hasOwn(categoryMinimumUsd, key));
  const missingControls = REQUIRED_CLOUD_SECURITY_CONTROLS.filter((control) => !requiredControls.includes(control));
  const missingApprovalStatuses = REQUIRED_CLOUD_SECURITY_APPROVAL_STATUSES.filter((status) => !approvalStatuses.includes(status));
  const reviewReasons = [
    (policy.policyVersion ?? policy.version) === CLOUD_SECURITY_BUDGET_POLICY_VERSION ? null : `policyVersion:${CLOUD_SECURITY_BUDGET_POLICY_VERSION}`,
    requiredPromptFieldReason("releaseId", policy.releaseId),
    policy.currency === "USD" ? null : "currency",
    requiredPromptFieldReason("budgetWindow", policy.budgetWindow),
    stableJsonKey(totalBudgetRangeUsd) === stableJsonKey(REQUIRED_CLOUD_SECURITY_BUDGET_RANGE_USD) ? null : "totalBudgetRangeUsd",
    missingCategoryKeys.length ? `categoryMinimumUsd:${missingCategoryKeys.join(",")}` : null,
    stableJsonKey(categoryMinimumUsd) === stableJsonKey(REQUIRED_CLOUD_SECURITY_BUDGET_CATEGORY_MINIMUM_USD) ? null : "categoryMinimumUsd",
    missingControls.length ? `requiredControls:${missingControls.join(",")}` : null,
    missingApprovalStatuses.length ? `approvalStatuses:${missingApprovalStatuses.join(",")}` : null,
    policy.monthlySpendReviewRequired === true ? null : "monthlySpendReviewRequired",
    policy.protectedSplitCostIsolationRequired === true ? null : "protectedSplitCostIsolationRequired",
    policy.productionReleaseBlockedUntilReserved === true ? null : "productionReleaseBlockedUntilReserved",
    policy.externalWormAuditLogFundingRequired === true ? null : "externalWormAuditLogFundingRequired",
    policyMentions(policy.overrunEscalationRule, ["overrun", "blocks", "release"]) ? null : "overrunEscalationRule",
    policyMentions(policy.productionReleaseBlockRule, ["release", "reserved", "cloud"]) ? null : "productionReleaseBlockRule",
    policyMentions(policy.protectedSplitIsolationFundingRule, ["hidden", "protected", "funded"]) ? null : "protectedSplitIsolationFundingRule",
    policyMentions(policy.sourceBoundary, ["Project default", "LMCA", "spend"]) ? null : "sourceBoundary",
    requiredPromptFieldReason("owner", policy.owner),
    requiredPromptFieldReason("approver", policy.approver),
    requiredPromptFieldReason("frozenAt", policy.frozenAt),
  ].filter(Boolean);
  return {
    id,
    rowSource,
    releaseId: policy.releaseId ?? null,
    policyVersion: policy.policyVersion ?? policy.version ?? null,
    currency: policy.currency ?? null,
    budgetWindow: policy.budgetWindow ?? null,
    totalBudgetRangeUsd,
    categoryMinimumUsd,
    requiredControls,
    approvalStatuses,
    monthlySpendReviewRequired: policy.monthlySpendReviewRequired === true,
    protectedSplitCostIsolationRequired: policy.protectedSplitCostIsolationRequired === true,
    productionReleaseBlockedUntilReserved: policy.productionReleaseBlockedUntilReserved === true,
    externalWormAuditLogFundingRequired: policy.externalWormAuditLogFundingRequired === true,
    overrunEscalationRule: policy.overrunEscalationRule ?? null,
    productionReleaseBlockRule: policy.productionReleaseBlockRule ?? null,
    protectedSplitIsolationFundingRule: policy.protectedSplitIsolationFundingRule ?? null,
    sourceBoundary: policy.sourceBoundary ?? null,
    owner: policy.owner ?? null,
    approver: policy.approver ?? null,
    frozenAt: policy.frozenAt ?? null,
    reviewReasons,
    status: reviewReasons.length ? "cloud_security_budget_policy_review_required" : "cloud_security_budget_policy_complete",
  };
}

